    public StormaktGame(int width, int height, SpritePack? sprites, StormaktMusicLoop? audio)
    {
        _width = width;
        _height = height;
        _stars = new Star[width <= 320 ? 92 : 128];
        _sprites = sprites;
        _audio = audio;
        Reset();
        _inLevelSelect = true;
        _audio?.SwitchMusic(StormaktMusicTrack.Menu);
    }

    public void Step(uint buttons, RtsPointer pointer = default, ControllerInput controller = default)
    {
        if (_inSilverkroppenSelect)
        {
            StepSilverkroppenSelect(buttons);
            return;
        }
        if (_inCopenhagenSelect)
        {
            StepCopenhagenSelect(buttons);
            return;
        }
        if (_inLevelPreview)
        {
            StepLevelPreview(buttons);
            return;
        }
        if (_inLevelSelect)
        {
            StepLevelSelect(buttons);
            return;
        }
        if (_gameOver)
        {
            if (Pressed(buttons, Start))
            {
                Reset();
                _audio?.Trigger(StormaktSound.Deploy);
            }
            _previousButtons = buttons;
            return;
        }
        if (_stageClear)
        {
            if (Pressed(buttons, Start))
            {
                ReturnToCampaignSelect(Math.Min(_levelId + 1, CampaignNames.Length - 1));
                _audio?.Trigger(StormaktSound.Deploy);
            }
            else
            {
                _stageClearAge++;
                StepStars();
            }
            _previousButtons = buttons;
            return;
        }

        if (_developerMode && _levelId == 3 && _dungeon is not null)
        {
            if (Pressed(buttons, DeveloperSave))
            {
                if (_dungeon.Health > 0 && _dungeon.DeathAge == 0)
                {
                    WriteDungeonSave(_dungeon, "developer");
                    SetDungeonDeveloperNotice(_dungeon, "F1  DEVSTATE SPARAT");
                    _audio?.Trigger(StormaktSound.Deploy);
                }
                _previousButtons = buttons;
                return;
            }
            if (Pressed(buttons, DeveloperLoad))
            {
                if (TryLoadDungeonSave("developer", out DungeonState? loaded) && loaded is not null)
                {
                    _dungeon = loaded;
                    _paused = false;
                    _audio?.SetPaused(false);
                    bool bossActive = loaded.Enemies.Any(enemy => enemy.Depth == loaded.Depth &&
                        enemy.State != DungeonEnemyState.Dead &&
                        enemy.Type is DungeonEnemyType.TuonelaSwan or DungeonEnemyType.Louhi) ||
                        (loaded.LoreMask & DungeonLouhiPhaseThreeMask) != 0 &&
                        (loaded.LoreMask & DungeonEpilogueCompleteMask) == 0;
                    _audio?.SwitchMusic(bossActive ? StormaktMusicTrack.Boss : StormaktMusicTrack.Dungeon);
                    SetDungeonDeveloperNotice(loaded, "F2  DEVSTATE LADDAT");
                    _audio?.Trigger(StormaktSound.Deploy);
                }
                else
                {
                    SetDungeonDeveloperNotice(_dungeon, "F2  INGET DEVSTATE");
                }
                _previousButtons = buttons;
                return;
            }
        }

        if (_levelId == 4 && _titheWorld is TitheWorldState titheChoice && titheChoice.ChoosingUpgrade)
        {
            StepTitheUpgradeChoice(titheChoice, buttons);
            _previousButtons = buttons;
            return;
        }

        if (Pressed(buttons, Start))
        {
            _paused = !_paused;
            _audio?.SetPaused(_paused);
            _previousButtons = buttons;
            return;
        }
        if (_paused)
        {
            _previousButtons = buttons;
            return;
        }

        if (_levelId == 3)
        {
            if (_dungeon is not null) StepDungeon(buttons, pointer);
            else StepRts(buttons, pointer);
            _previousButtons = buttons;
            return;
        }
        StepRadio();

        if (_levelId == 6 && _copenhagenWorld is CopenhagenWorldState { GroundActive: true } groundWorld)
        {
            StepCopenhagenGround(groundWorld, buttons, pointer, controller);
            StepStars();
            _previousButtons = buttons;
            return;
        }

        int speed = (buttons & Slow) != 0 ? (_width <= 320 ? 2 : 3) : (_width <= 320 ? 4 : 5);
        int precisionSpeed = (buttons & Slow) != 0 ? 1 : 2;
        uint directions = Up | Down | Left | Right;
        uint controllerDirections = controller.Buttons & directions;
        uint keyboardDirections = (buttons & directions) & ~controllerDirections;
        int moveX = ((keyboardDirections & Right) != 0 ? speed : 0) - ((keyboardDirections & Left) != 0 ? speed : 0);
        int moveY = ((keyboardDirections & Down) != 0 ? speed : 0) - ((keyboardDirections & Up) != 0 ? speed : 0);
        (int analogX, int analogY, bool analogActive) = ControllerStickMovement(controller.LeftX, controller.LeftY, speed);
        if (analogActive)
        {
            moveX += analogX;
            moveY += analogY;
        }
        else
        {
            moveX += ((controllerDirections & Right) != 0 ? precisionSpeed : 0) - ((controllerDirections & Left) != 0 ? precisionSpeed : 0);
            moveY += ((controllerDirections & Down) != 0 ? precisionSpeed : 0) - ((controllerDirections & Up) != 0 ? precisionSpeed : 0);
        }
        _shipX += moveX;
        _shipY += moveY;
        _shipX = Math.Clamp(_shipX, 22, _width - 22);
        _shipY = Math.Clamp(_shipY, 48, _height - 18);

        bool snapphaneRescueChanneling = IsSnapphaneRescueChanneling();
        _cooldown = Math.Max(0, _cooldown - 1);
        _altCooldown = Math.Max(0, _altCooldown - 1);
        int heatDecay = 1;
        if (_activeLoadout is StormaktLoadout heatState)
        {
            if ((buttons & (Fire | AltFire)) != 0) heatState.WeaponIdleAge = 0;
            else heatState.WeaponIdleAge++;
            heatDecay = heatState.ShipModule switch
            {
                TitheShipModule.SilverCooler when heatState.WeaponIdleAge >= 18 => 3,
                TitheShipModule.SeizureArmor => (_missionFrame & 1) == 0 ? 1 : 0,
                _ => 1,
            };
        }
        _heat = Math.Max(0, _heat - heatDecay);
        _invulnerabilityFrames = Math.Max(0, _invulnerabilityFrames - 1);
        if ((buttons & Fire) != 0 && _cooldown == 0)
        {
            TithePrimaryModule module = _activeLoadout?.PrimaryModule ?? TithePrimaryModule.Standard;
            if (module == TithePrimaryModule.CrownDrill)
            {
                _shots.Add(new Shot(_shipX - 5, _shipY - 12, 0, -7, 0xffffd66b, 3));
                _shots.Add(new Shot(_shipX + 5, _shipY - 12, 0, -7, 0xffffd66b, 3));
                _shots.Add(new Shot(_shipX, _shipY - 17, 0, -9, 0xffbdf8ff, 7, TitheShotDrillBolt));
                _cooldown = 9;
                if (snapphaneRescueChanneling) _cooldown *= 2;
                _heat = Math.Min(120, _heat + 11);
                _audio?.Trigger(StormaktSound.TitheCrownDrill);
            }
            else if (module == TithePrimaryModule.VolleyDirector)
            {
                _shots.Add(new Shot(_shipX - 7, _shipY - 12, -1, -7, 0xffffd66b, 2, TitheShotVolleyShell));
                _shots.Add(new Shot(_shipX, _shipY - 15, 0, -8, 0xff9bd4dc, 2, TitheShotVolleyShell));
                _shots.Add(new Shot(_shipX + 7, _shipY - 12, 1, -7, 0xffffd66b, 2, TitheShotVolleyShell));
                _cooldown = 4;
                if (snapphaneRescueChanneling) _cooldown *= 2;
                _heat = Math.Min(120, _heat + 9);
                _audio?.Trigger(StormaktSound.TitheVolleyDirector);
            }
            else
            {
                _shots.Add(new Shot(_shipX - 4, _shipY - 12, 0, -7, 0xffffd66b, 3));
                _shots.Add(new Shot(_shipX + 4, _shipY - 12, 0, -7, 0xffffd66b, 3));
                _cooldown = 6;
                if (snapphaneRescueChanneling) _cooldown *= 2;
                _heat = Math.Min(120, _heat + 7);
                _audio?.Trigger(StormaktSound.TwinCannon);
            }
        }
        if ((buttons & AltFire) != 0 && _altCooldown == 0 && !snapphaneRescueChanneling)
        {
            TitheBroadsideModule broadside = _activeLoadout?.BroadsideModule ?? TitheBroadsideModule.Standard;
            if (broadside == TitheBroadsideModule.MagnetBroadside)
            {
                _shots.Add(new Shot(_shipX - 14, _shipY - 7, -1, -4, 0xff65c5ca, 6, TitheShotMagnetRing));
                _shots.Add(new Shot(_shipX + 14, _shipY - 7, 1, -4, 0xffbdf8ff, 6, TitheShotMagnetRing));
                ReflectTitheLightShots();
                _altCooldown = 26;
                _heat = Math.Min(120, _heat + 24);
                _audio?.Trigger(StormaktSound.TitheMagnetBroadside);
            }
            else if (broadside == TitheBroadsideModule.ChainCanister)
            {
                _shots.Add(new Shot(_shipX - 12, _shipY - 5, -3, -5, 0xffffd66b, 8, TitheShotChainShot));
                _shots.Add(new Shot(_shipX - 6, _shipY - 8, -1, -6, 0xff9bd4dc, 8, TitheShotChainShot));
                _shots.Add(new Shot(_shipX, _shipY - 10, 0, -7, 0xffffec9a, 8, TitheShotChainShot));
                _shots.Add(new Shot(_shipX + 6, _shipY - 8, 1, -6, 0xff9bd4dc, 8, TitheShotChainShot));
                _shots.Add(new Shot(_shipX + 12, _shipY - 5, 3, -5, 0xffffd66b, 8, TitheShotChainShot));
                _altCooldown = 30;
                _heat = Math.Min(120, _heat + 20);
                _audio?.Trigger(StormaktSound.TitheChainCanister);
            }
            else
            {
                _shots.Add(new Shot(_shipX - 11, _shipY - 5, -2, -5, 0xff7fc7ff, 5));
                _shots.Add(new Shot(_shipX + 11, _shipY - 5, 2, -5, 0xff7fc7ff, 5));
                _altCooldown = 18;
                _heat = Math.Min(120, _heat + 15);
                _audio?.Trigger(StormaktSound.Broadside);
            }
        }

        StepShots();
        if (_levelId == 6)
        {
            StepCopenhagenWorld();
            StepStars();
            _previousButtons = buttons;
            return;
        }
        if (_levelId == 5)
        {
            StepSnapphaneWorld();
            StepStars();
            _previousButtons = buttons;
            return;
        }
        StepTitheWorld();
        StepOresundBridgeSection();
        StepEnemyShots();
        StepEnemies();
        StepGroundTargets();
        StepSorenRival();
        StepOresundSoren();
        StepGlimminge();
        StepBoss();
        StepAnchorHazards();
        StepCrystalSpears();
        SpawnEnemies();
        SpawnGroundEncounters();
        SpawnBoss();
        StepLevelTimeline();
        StepStars();
        _previousButtons = buttons;
    }

    public void Render(uint[] frame, ulong frameIndex)
    {
        Clear(frame, 0xff061018);
        if (_inSilverkroppenSelect)
        {
            DrawSky(frame);
            DrawNebula(frame);
            DrawSilverkroppenSelect(frame);
            return;
        }
        if (_inCopenhagenSelect)
        {
            DrawSky(frame);
            DrawNebula(frame);
            DrawCopenhagenSelect(frame);
            return;
        }
        if (_levelId == 3 && !_inLevelSelect && !_inLevelPreview)
        {
            if (_dungeon is not null) DrawDungeon(frame);
            else
            {
                DrawRts(frame);
                DrawStageClear(frame);
            }
            DrawPause(frame);
            return;
        }
        if (_levelId == 4 && !_inLevelSelect && !_inLevelPreview)
        {
            DrawTitheWorld(frame);
            return;
        }
        if (_levelId == 5 && !_inLevelSelect && !_inLevelPreview)
        {
            DrawSnapphaneWorld(frame);
            return;
        }
        if (_levelId == 6 && !_inLevelSelect && !_inLevelPreview)
        {
            DrawCopenhagenWorld(frame);
            return;
        }
        DrawSky(frame);
        DrawNebula(frame);
        if (_levelId != 1)
        {
            DrawStars(frame);
        }
        if (_inLevelSelect)
        {
            DrawLevelSelect(frame);
            return;
        }
        if (_inLevelPreview)
        {
            DrawLevelPreview(frame);
            return;
        }
        DrawBeltRuins(frame);
        DrawSorenBackgroundPass(frame);
        DrawGroundTargets(frame);
        DrawOresundBridgeSection(frame);
        DrawSorenRival(frame);
        DrawGlimminge(frame);
        DrawBoss(frame);
        DrawShots(frame);
        DrawEnemyShots(frame);
        DrawAnchorHazards(frame);
        DrawCrystalSpears(frame);
        DrawEnemies(frame);
        DrawShip(frame);
        DrawBorder(frame);
        DrawHud(frame);
        DrawBossHud(frame);
        DrawBossIntroduction(frame);
        DrawMissionTitle(frame);
        DrawRadio(frame);
        DrawStageClear(frame);
        DrawPause(frame);
        if (_gameOver)
        {
            int panelX = (_width - 168) / 2;
            int panelY = (_height - 42) / 2;
            DrawRect(frame, panelX, panelY, 168, 42, 0xdd090b10);
            DrawText(frame, panelX + 16, panelY + 10, "FLOTTAN FÖLL", 0xffff6b7f);
            DrawText(frame, panelX + 22, panelY + 26, "START ÅTERKALLAR", 0xffffd66b);
        }
    }

    private void Reset()
    {
        StormaktLoadout? previousLoadout = _activeLoadout;
        _shots.Clear();
        _enemies.Clear();
        _enemyShots.Clear();
        _groundTargets.Clear();
        _anchorHazards.Clear();
        _crystalSpears.Clear();
        _random = new Random(_levelId switch { 1 => 3202, 2 => 3303, 3 => 3404, 4 => 3505, 5 => 3606, 6 => 3707, _ => 3020 });
        for (int i = 0; i < _stars.Length; i++)
        {
            _stars[i] = new Star(_random.Next(_width), _random.Next(_height), 1 + _random.Next(3), _random.Next(50, 180));
        }
        _shipX = _width / 2;
        _shipY = _height - 36;
        _cooldown = 0;
        _altCooldown = 0;
        _score = 0;
        _lives = 3;
        _heat = 0;
        _missionFrame = 0;
        _invulnerabilityFrames = 0;
        _boss = null;
        _sorenRival = null;
        _oresundSoren = null;
        _oresundBoss = null;
        _glimminge = null;
        _bridgeSection = _levelId == 2 ? new BridgeSectionState() : null;
        _rts = _levelId == 3
            ? new RtsState
            {
                MapWidth = _width + (_width <= 320 ? 400 : 500),
                MapHeight = _height - 28,
                CursorX = 74,
                CursorY = _height - 82,
                LandingX = 74,
                LandingY = _height - 82,
            }
            : null;
        _dungeon = null;
        _titheWorld = _levelId == 4 ? new TitheWorldState() : null;
        _snapphaneWorld = _levelId == 5 ? new SnapphaneWorldState() : null;
        _copenhagenWorld = _levelId == 6 ? new CopenhagenWorldState() : null;
        _activeLoadout = _levelId is 4 or 5 or 6
            ? previousLoadout?.Clone() ?? new StormaktLoadout()
            : null;
        if (_copenhagenWorld is CopenhagenWorldState resetCopenhagen)
        {
            ResetCopenhagenWorld(resetCopenhagen);
            if (_copenhagenGateTestMode)
            {
                resetCopenhagen.Age = 300;
                resetCopenhagen.GateActive = true;
                resetCopenhagen.GateIntroAge = 120;
                for (int node = 0; node < resetCopenhagen.GateHealth.Length; node++)
                    resetCopenhagen.GateHealth[node] = 36;
            }
            if (_copenhagenAdmiraltyTestMode)
            {
                resetCopenhagen.Age = 900;
                resetCopenhagen.GateActive = true;
                resetCopenhagen.GateIntroAge = 500;
                resetCopenhagen.GateFallAge = 240;
                for (int node = 0; node < resetCopenhagen.GateHealth.Length; node++)
                    resetCopenhagen.GateHealth[node] = 0;
                BeginCopenhagenAdmiralty(resetCopenhagen, testFixture: true);
            }
            if (_copenhagenFrederikTestMode)
            {
                resetCopenhagen.Age = 1_800;
                resetCopenhagen.GateActive = true;
                resetCopenhagen.GateIntroAge = 500;
                resetCopenhagen.GateFallAge = 240;
                resetCopenhagen.AdmiraltyActive = true;
                resetCopenhagen.AdmiraltyAge = 1_200;
                resetCopenhagen.AdmiraltyHealth = 0;
                resetCopenhagen.AdmiraltyDeathAge = 300;
                for (int node = 0; node < resetCopenhagen.GateHealth.Length; node++)
                    resetCopenhagen.GateHealth[node] = 0;
                BeginCopenhagenFrederik(resetCopenhagen, testFixture: true);
            }
            if (_copenhagenEyeTestMode)
            {
                resetCopenhagen.Age = 2_700;
                resetCopenhagen.GateActive = true;
                resetCopenhagen.AdmiraltyActive = true;
                resetCopenhagen.AdmiraltyHealth = 0;
                resetCopenhagen.AdmiraltyDeathAge = 300;
                resetCopenhagen.FrederikActive = true;
                resetCopenhagen.FrederikHealth = 0;
                resetCopenhagen.FrederikDeathAge = 360;
                BeginCopenhagenEye(resetCopenhagen, testFixture: true);
            }
            if (_copenhagenDannebrogTestMode)
            {
                resetCopenhagen.Age = 3_600;
                resetCopenhagen.GateActive = true;
                resetCopenhagen.AdmiraltyActive = true;
                resetCopenhagen.AdmiraltyHealth = 0;
                resetCopenhagen.AdmiraltyDeathAge = 300;
                resetCopenhagen.FrederikActive = true;
                resetCopenhagen.FrederikHealth = 0;
                resetCopenhagen.FrederikDeathAge = 360;
                resetCopenhagen.EyeActive = true;
                resetCopenhagen.EyeHealth = 0;
                resetCopenhagen.EyeDeathAge = 360;
                BeginCopenhagenDannebrog(resetCopenhagen, testFixture: true);
            }
            if (_copenhagenDuoTestMode)
            {
                resetCopenhagen.Age = 4_500;
