    private void RestartDungeonAfterDeath(DungeonState fallen)
    {
        if ((fallen.LoreMask & DungeonLouhiPhaseThreeMask) != 0 &&
            (fallen.LoreMask & DungeonEpilogueCompleteMask) == 0 &&
            TryLoadDungeonSave("autosave", out DungeonState? escapeRetry) && escapeRetry is not null)
        {
            escapeRetry.Health = escapeRetry.MaxHealth;
            escapeRetry.DeathAge = 0;
            escapeRetry.HurtAge = 60;
            escapeRetry.CollapseAge = 1;
            escapeRetry.TargetX = escapeRetry.KarlX;
            escapeRetry.TargetY = escapeRetry.KarlY;
            escapeRetry.PickupNotice = "TEMPLET RASAR  FÖRSÖK IGEN";
            escapeRetry.PickupNoticeAge = 180;
            _dungeon = escapeRetry;
            _audio?.SwitchMusic(StormaktMusicTrack.Boss);
            return;
        }
        var restarted = new DungeonState
        {
            Age = 150,
            RoomWidth = 720,
            RoomHeight = 440,
            KarlX = 92,
            KarlY = 228,
            TargetX = 92,
            TargetY = 228,
            Facing = DungeonFacing.South,
            Health = Math.Max(100, fallen.MaxHealth),
            MaxHealth = Math.Max(100, fallen.MaxHealth),
            Power = 35,
            Depth = 1,
            DoorHealth = 0,
            DoorReady = true,
            DescentWarningPlayed = true,
            Level = fallen.Level,
            Experience = fallen.Experience,
            NextItemId = fallen.NextItemId,
            NextEnemyId = fallen.NextEnemyId,
        };
        foreach (DungeonItem item in fallen.Items.Where(item => !item.OnGround))
        {
            item.OnGround = false;
            restarted.Items.Add(item);
        }
        if (restarted.Items.Count == 0) SeedDungeonInventory(restarted);
        SeedDungeonEncounter(restarted);
        _dungeon = restarted;
        _audio?.SwitchMusic(StormaktMusicTrack.Dungeon);
        ActivateBossRadio(DungeonNearDeathRadio);
        WriteDungeonSave(restarted, "autosave");
    }

    private static void EnsureDungeonRecoveryChest(DungeonState dungeon)
    {
        if (dungeon.Depth is not (1 or 2) || dungeon.Depth == 1 && !dungeon.DoorReady) return;
        DungeonChest? existing = dungeon.Chests.FirstOrDefault(chest => chest.Id == 10 && chest.Depth == dungeon.Depth);
        if (existing is not null)
        {
            // Migrate the first version, which was placed below the initial
            // camera. Move both the chest and any uncollected sword it spilled.
            if (dungeon.Depth == 1 && existing.Y > 260)
            {
                dungeon.Chests.Remove(existing);
                dungeon.Chests.Add(new DungeonChest(10, 180, 185)
                    { Depth = 1, Open = existing.Open, OpenAge = existing.OpenAge });
                foreach (DungeonItem item in dungeon.Items.Where(item => item.OnGround &&
                    item.Definition == 0 && DistanceSquared(item.WorldX, item.WorldY, existing.X, existing.Y) < 70 * 70))
                {
                    item.WorldX = 180;
                    item.WorldY = 205;
                }
                dungeon.PickupNotice = "FÖRRÅDSKISTAN STÅR VID HISSEN";
                dungeon.PickupNoticeAge = 180;
                WriteDungeonSave(dungeon, "autosave");
            }
            return;
        }
        bool hasSword = dungeon.Items.Any(item => !item.OnGround && !item.InStash &&
            item.Definition is 0 or 1);
        if (hasSword) return;
        (int chestX, int chestY) = dungeon.Depth == 1 ? (180, 185) : (180, 410);
        dungeon.Chests.Add(new DungeonChest(10, chestX, chestY) { Depth = dungeon.Depth });
        dungeon.PickupNotice = "RESERVVÄRJA I FÖRRÅDSKISTAN";
        dungeon.PickupNoticeAge = 180;
        WriteDungeonSave(dungeon, "autosave");
    }

