    private void StepDungeonTempleAmbush(DungeonState dungeon)
    {
        if (dungeon.Depth != 4) return;
        DungeonEnemy? shadow = dungeon.Enemies.FirstOrDefault(enemy =>
            enemy.Depth == 4 && enemy.Type == DungeonEnemyType.LemminkainenShadow && enemy.State != DungeonEnemyState.Dead);
        if (shadow is null || shadow.Phase != 0 || dungeon.KarlX < 900) return;
        shadow.Phase = 1;
        shadow.X = Math.Max(760, dungeon.KarlX - 82);
        shadow.Y = Math.Clamp(dungeon.KarlY + 24, 100, dungeon.RoomHeight - 70);
        shadow.State = DungeonEnemyState.Telegraph;
        shadow.StateAge = 0;
        shadow.SpecialSerial = 0;
        dungeon.TargetX = dungeon.KarlX;
        dungeon.TargetY = dungeon.KarlY;
        _audio?.Trigger(StormaktSound.DungeonSilverShatter);
        WriteDungeonSave(dungeon, "autosave");
    }

    private void StepDungeonTempleSigil(DungeonState dungeon)
    {
        if (dungeon.Depth != 4 || (dungeon.LoreMask & DungeonFirstSigilMask) != 0) return;
        bool shadowDefeated = dungeon.Enemies.Any(enemy => enemy.Depth == 4 &&
            enemy.Type == DungeonEnemyType.LemminkainenShadow && enemy.State == DungeonEnemyState.Dead);
        bool courtyardClear = dungeon.Enemies.Where(enemy => enemy.Depth == 4 && enemy.Zone == 44)
            .All(enemy => enemy.State == DungeonEnemyState.Dead);
        if (!shadowDefeated || !courtyardClear ||
            DistanceSquared(1580, 380, dungeon.KarlX, dungeon.KarlY) >= 84 * 84) return;
        dungeon.LoreMask |= DungeonFirstSigilMask;
        dungeon.Curse = Math.Max(0, dungeon.Curse - 35);
        DungeonItem fragment = AddDungeonItem(dungeon, 11, -1, -1, DungeonEquipmentSlot.None,
            DungeonItemRarity.Runic);
        fragment.OnGround = true;
        fragment.WorldX = 1580;
        fragment.WorldY = 410;
        ActivateBossRadio(DungeonFirstSigilRadio);
        _audio?.Trigger(StormaktSound.DungeonSilverShatter);
        WriteDungeonSave(dungeon, "autosave");
    }

    private static int DungeonSecondRuneProgress(DungeonState dungeon) =>
        (dungeon.LoreMask & DungeonSecondRuneProgressMask) >> DungeonSecondRuneShift;

    private static void SetDungeonSecondRuneProgress(DungeonState dungeon, int progress)
    {
        dungeon.LoreMask = (dungeon.LoreMask & ~DungeonSecondRuneProgressMask) |
            (Math.Clamp(progress, 0, 3) << DungeonSecondRuneShift);
    }

    private static bool DungeonSecondCourtyardClear(DungeonState dungeon) => dungeon.Enemies
        .Where(enemy => enemy.Depth == 4 && enemy.Zone is 45 or 46)
        .All(enemy => enemy.State == DungeonEnemyState.Dead);

    private bool TryRescueTempleFogde(DungeonState dungeon)
    {
        if (dungeon.Depth != 4 || (dungeon.LoreMask & DungeonFirstSigilMask) == 0 ||
            (dungeon.LoreMask & DungeonFogdeRescuedMask) != 0 ||
            DistanceSquared(1850, 150, dungeon.KarlX, dungeon.KarlY) >= 82 * 82) return false;
        dungeon.LoreMask |= DungeonFogdeRescuedMask;
        dungeon.Curse = Math.Max(0, dungeon.Curse - 20);
        ActivateBossRadio(DungeonFogdeRescueRadio);
        _audio?.Trigger(StormaktSound.DungeonSilverShatter);
        WriteDungeonSave(dungeon, "autosave");
        return true;
    }

    private bool TrySpeakTempleFogde(DungeonState dungeon)
    {
        if (dungeon.Depth != 4 || (dungeon.LoreMask & DungeonFogdeRescuedMask) == 0 ||
            DistanceSquared(1905, 220, dungeon.KarlX, dungeon.KarlY) >= 78 * 78) return false;
        dungeon.LoreMask |= DungeonFogdeSpokenMask;
        ActivateBossRadio(DungeonFogdeTalkRadio);
        WriteDungeonSave(dungeon, "autosave");
        return true;
    }

    private bool TryActivateNearbySecondTempleRune(DungeonState dungeon)
    {
        int rune = Array.FindIndex(DungeonSecondTempleRunes, candidate =>
            DistanceSquared(candidate.X, candidate.Y, dungeon.KarlX, dungeon.KarlY) < 82 * 82);
        return rune >= 0 && TryActivateSecondTempleRune(dungeon, rune);
    }

    private bool TryActivateSecondTempleRune(DungeonState dungeon, int rune)
    {
        if (dungeon.Depth != 4 || rune < 0 || rune >= DungeonSecondTempleRunes.Length ||
            (dungeon.LoreMask & DungeonFogdeSpokenMask) == 0 ||
            (dungeon.LoreMask & DungeonSecondSigilMask) != 0 ||
            DistanceSquared(DungeonSecondTempleRunes[rune].X, DungeonSecondTempleRunes[rune].Y,
                dungeon.KarlX, dungeon.KarlY) >= 82 * 82 || !DungeonSecondCourtyardClear(dungeon)) return false;

        int progress = DungeonSecondRuneProgress(dungeon);
        // Touching an already completed rune again must not erase a valid
        // partial sequence. Only a genuinely premature future rune resets it.
        if (rune < progress) return true;
        if (rune != progress)
        {
            SetDungeonSecondRuneProgress(dungeon, 0);
            ResurrectSecondTempleGuards(dungeon);
            _audio?.Trigger(StormaktSound.DungeonSilverShatter);
            WriteDungeonSave(dungeon, "autosave");
            return true;
        }

        progress++;
        SetDungeonSecondRuneProgress(dungeon, progress);
        if (progress < 3) ResurrectSecondTempleGuards(dungeon);
        dungeon.Curse = Math.Max(0, dungeon.Curse - 8);
        _audio?.Trigger(StormaktSound.DungeonSilverShatter);
        WriteDungeonSave(dungeon, "autosave");
        return true;
    }

    private static void ResurrectSecondTempleGuards(DungeonState dungeon)
    {
        foreach (DungeonEnemy enemy in dungeon.Enemies.Where(enemy => enemy.Depth == 4 && enemy.Zone is 45 or 46))
        {
            enemy.Health = enemy.MaxHealth;
            enemy.State = DungeonEnemyState.Telegraph;
            enemy.StateAge = 0;
            enemy.SpecialKind = 0;
            enemy.SpecialAge = 0;
            enemy.LootDropped = true;
            enemy.ExperienceAwarded = true;
        }
    }

    private void StepDungeonSecondTempleSigil(DungeonState dungeon)
    {
        if (dungeon.Depth != 4 || (dungeon.LoreMask & DungeonSecondSigilMask) != 0 ||
            DungeonSecondRuneProgress(dungeon) < 3 || !DungeonSecondCourtyardClear(dungeon) ||
            DistanceSquared(2280, 380, dungeon.KarlX, dungeon.KarlY) >= 84 * 84) return;
        dungeon.LoreMask |= DungeonSecondSigilMask;
        dungeon.Curse = Math.Max(0, dungeon.Curse - 35);
        DungeonItem fragment = AddDungeonItem(dungeon, 11, -1, -1, DungeonEquipmentSlot.None,
            DungeonItemRarity.Runic);
        fragment.OnGround = true;
        fragment.WorldX = 2280;
        fragment.WorldY = 410;
        ActivateBossRadio(DungeonSecondSigilRadio);
        _audio?.Trigger(StormaktSound.DungeonSilverShatter);
        WriteDungeonSave(dungeon, "autosave");
    }

    private static int DungeonThirdVerseProgress(DungeonState dungeon) =>
        (dungeon.LoreMask & DungeonThirdVerseProgressMask) >> DungeonThirdVerseShift;

    private static void SetDungeonThirdVerseProgress(DungeonState dungeon, int progress)
    {
        dungeon.LoreMask = (dungeon.LoreMask & ~DungeonThirdVerseProgressMask) |
            (Math.Clamp(progress, 0, 3) << DungeonThirdVerseShift);
    }

    private bool TryActivateNearbyThirdTempleVerse(DungeonState dungeon)
    {
        int verse = Array.FindIndex(DungeonThirdTempleSteles, candidate =>
            DistanceSquared(candidate.X, candidate.Y, dungeon.KarlX, dungeon.KarlY) < 76 * 76);
        return verse >= 0 && TryActivateThirdTempleVerse(dungeon, verse);
    }

    private bool TryActivateThirdTempleVerse(DungeonState dungeon, int verse)
    {
        if (dungeon.Depth != 4 || verse < 0 || verse >= DungeonThirdTempleSteles.Length ||
            (dungeon.LoreMask & DungeonSecondSigilMask) == 0 ||
            (dungeon.LoreMask & DungeonThirdSigilMask) != 0 ||
            DistanceSquared(DungeonThirdTempleSteles[verse].X, DungeonThirdTempleSteles[verse].Y,
                dungeon.KarlX, dungeon.KarlY) >= 76 * 76) return false;

        int progress = DungeonThirdVerseProgress(dungeon);
        if (verse < progress)
        {
            // A completed inscription can be read again without destroying
            // the valid sequence. Replay Ebba's interpretation as feedback.
            ActivateBossRadio(DungeonThirdVerseCards[verse]);
            return true;
        }
        if (verse != progress)
        {
            SetDungeonThirdVerseProgress(dungeon, 0);
            ApplyDungeonCurse(dungeon, 18);
            _audio?.Trigger(StormaktSound.DungeonSilverShatter);
            WriteDungeonSave(dungeon, "autosave");
            return true;
        }

        SetDungeonThirdVerseProgress(dungeon, progress + 1);
        dungeon.Curse = Math.Max(0, dungeon.Curse - 6);
        ActivateBossRadio(DungeonThirdVerseCards[verse]);
        _audio?.Trigger(StormaktSound.DungeonSilverShatter);
        WriteDungeonSave(dungeon, "autosave");
        return true;
    }

    private void StepDungeonThirdTempleSigil(DungeonState dungeon)
    {
        if (dungeon.Depth != 4 || (dungeon.LoreMask & DungeonThirdSigilMask) != 0 ||
            DungeonThirdVerseProgress(dungeon) < 3 ||
            DistanceSquared(3030, 380, dungeon.KarlX, dungeon.KarlY) >= 84 * 84) return;
        dungeon.LoreMask |= DungeonThirdSigilMask;
        dungeon.Curse = Math.Max(0, dungeon.Curse - 35);
        DungeonItem fragment = AddDungeonItem(dungeon, 11, -1, -1, DungeonEquipmentSlot.None,
            DungeonItemRarity.Unique);
        fragment.OnGround = true;
        fragment.WorldX = 3030;
        fragment.WorldY = 410;
        ActivateBossRadio(DungeonThirdSigilRadio);
        _audio?.Trigger(StormaktSound.DungeonSilverShatter);
        WriteDungeonSave(dungeon, "autosave");
    }

    private void StepDungeonSwanReveal(DungeonState dungeon)
    {
        if (dungeon.Depth != 4 || (dungeon.LoreMask & DungeonThirdSigilMask) == 0 ||
            (dungeon.LoreMask & DungeonSwanRevealedMask) != 0 || dungeon.KarlX < 3260) return;
        dungeon.LoreMask |= DungeonSwanRevealedMask;
        EnsureDungeonSwanEncounter(dungeon);
        dungeon.TargetX = dungeon.KarlX;
        dungeon.TargetY = dungeon.KarlY;
        ActivateBossRadio(DungeonSwanRevealRadio);
        _audio?.SwitchMusic(StormaktMusicTrack.Boss);
        _audio?.Trigger(StormaktSound.DungeonSilverShatter);
        WriteDungeonSave(dungeon, "autosave");
    }

    private static DungeonEnemy EnsureDungeonSwanEncounter(DungeonState dungeon)
    {
        DungeonEnemy? existing = dungeon.Enemies.FirstOrDefault(enemy =>
            enemy.Depth == 4 && enemy.Type == DungeonEnemyType.TuonelaSwan);
        if (existing is not null)
        {
            if (existing.State != DungeonEnemyState.Dead && existing.SpecialKind != 0 &&
                Math.Abs(existing.VelocityX) < 0.01 && Math.Abs(existing.VelocityY) < 0.01)
            {
                existing.State = DungeonEnemyState.Approach;
                existing.StateAge = 0;
                existing.SpecialKind = 0;
                existing.SpecialCooldown = 30;
            }
            return existing;
        }
        AddDungeonEnemy(dungeon, 3400, 380, DungeonEnemyType.TuonelaSwan, 720, 48);
        DungeonEnemy swan = dungeon.Enemies.Last();
        swan.Phase = 1;
        swan.SpecialCooldown = 80;
        return swan;
    }

    private static void ReturnToDungeonDepthThree(DungeonState dungeon)
    {
        dungeon.Depth = 3; dungeon.RoomWidth = 1400; dungeon.RoomHeight = 900;
        dungeon.SilverWaves.Clear();
        dungeon.KarlX = 1260; dungeon.KarlY = 450; dungeon.TargetX = 1260; dungeon.TargetY = 450;
        dungeon.CameraX = 1000; dungeon.CameraY = 310; dungeon.PendingTempleReturn = false;
        WriteDungeonSave(dungeon, "autosave");
    }

    private void OpenDungeonChest(DungeonState dungeon, DungeonChest chest)
    {
        if (chest.Open) return;
        chest.Open = true;
        chest.OpenAge = 1;
        _audio?.Trigger(StormaktSound.Deploy);
        int[] definitions = chest.Id switch
        {
            1 => [5, 10], 2 => [2, 9], 3 => [6, 11],
            10 => [0],
            31 => [10, 11], 32 => [6, 10], 41 => [10, 11], 42 => [4, 12], _ => [11, 9],
        };
        for (int index = 0; index < definitions.Length; index++)
        {
            DungeonItem loot = AddDungeonItem(dungeon, definitions[index], -1, -1, DungeonEquipmentSlot.None,
                chest.Id is 3 or >= 31 ? DungeonItemRarity.Runic : DungeonItemRarity.Silverbound);
            loot.OnGround = true;
            loot.WorldX = chest.X + (index == 0 ? -13 : 13);
            loot.WorldY = chest.Y + 16;
        }
        WriteDungeonSave(dungeon, "autosave");
    }

    private static int DungeonZone(DungeonState dungeon) => dungeon.Depth switch
    {
        2 => DungeonZoneFromX(dungeon.KarlX),
        3 => dungeon.KarlX < 500 ? 31 : dungeon.KarlX < 850 ? 32 : dungeon.KarlX < 1150 ? 33 : 34,
        4 => dungeon.KarlX < 600 ? 41 : dungeon.KarlX < 900 ? 42 : dungeon.KarlX < 1200 ? 43 :
            dungeon.KarlX < 1760 ? 44 : dungeon.KarlX < 2100 ? 45 : dungeon.KarlX < 2440 ? 46 :
            dungeon.KarlX < 3150 ? 47 : dungeon.KarlX < 3950 ? 48 : 49,
        _ => 0,
    };
    private static int DungeonZoneFromX(double x) => x < 520 ? 1 : x < 900 ? 2 : 3;

    private static readonly (int X, int Y)[] DungeonSilverVents =
        [(410, 320), (655, 590), (900, 220), (1110, 610)];
    private static readonly (int X, int Y)[] DungeonBlackWaters =
        [(360, 350), (720, 610), (1040, 360)];
    private static readonly (int X, int Y)[] DungeonHolyShrines =
        [(500, 150), (900, 740)];
    private static readonly (int X, int Y)[] DungeonTempleWaters =
        [(350, 410), (775, 185), (990, 505), (1370, 150), (1660, 570), (1900, 390), (2135, 350),
         (2530, 390), (2770, 190), (2910, 560), (3300, 340), (3410, 430), (3490, 320),
         (3700, 155), (3700, 605), (4070, 150), (4300, 610)];
    private static readonly (int X, int Y)[] DungeonTempleShrines =
        [(210, 600), (660, 600), (1090, 165), (1580, 380), (2280, 380), (3030, 380)];
    private static readonly (int X, int Y)[] DungeonTempleGuardianStatues =
        [(1275, 190), (1660, 190)];
    private static readonly (int X, int Y)[] DungeonTempleClosedSarcophagi =
        [(1290, 645), (1650, 650), (2010, 680), (2290, 675), (2600, 680)];
    private static readonly (int X, int Y)[] DungeonTempleOpenSarcophagi =
        [(1450, 135), (1850, 150), (2850, 135)];
    private static readonly (int X, int Y)[] DungeonSecondTempleRunes =
        [(2030, 155), (1870, 610), (2200, 610)];
    private static readonly (int X, int Y)[] DungeonThirdTempleSteles =
        [(2520, 180), (2720, 610), (2920, 180)];
    private static readonly (int X, int Y)[] DungeonLouhiProcessionStatues =
        [(3680, 130), (3680, 630), (3860, 130), (3860, 630)];
    private static readonly (int X, int Y)[] DungeonLouhiProcessionSarcophagi =
        [(3760, 220), (3760, 540)];
    private static readonly (int X, int Y)[] DungeonLouhiHearts =
        [(4170, 205), (4350, 380), (4170, 555), (3990, 380)];

    private static void StepDungeonCurse(DungeonState dungeon)
    {
        if (dungeon.Depth is not (3 or 4)) return;
        (int X, int Y)[] waters = dungeon.Depth == 3 ? DungeonBlackWaters : DungeonTempleWaters;
        (int X, int Y)[] shrines = dungeon.Depth == 3 ? DungeonHolyShrines : DungeonTempleShrines;
        bool inWater = waters.Any(water =>
            DistanceSquared(water.X, water.Y, dungeon.KarlX, dungeon.KarlY) < 72 * 72);
        bool inLight = shrines.Any(shrine =>
            DistanceSquared(shrine.X, shrine.Y, dungeon.KarlX, dungeon.KarlY) < 74 * 74);
        if (dungeon.Age % 10 == 0)
        {
            if (inLight) dungeon.Curse = Math.Max(0, dungeon.Curse - 4);
            else if (inWater) ApplyDungeonCurse(dungeon, 3);
            else if (dungeon.Curse > 0 && dungeon.Age % 30 == 0) dungeon.Curse--;
        }
        if (dungeon.Curse >= 100 && dungeon.Age % 30 == 0)
        {
            ApplyDungeonDamage(dungeon, 6);
            dungeon.HurtAge = 12;
        }
    }

    private static int DungeonArmor(DungeonState dungeon) => dungeon.Items
        .Where(item => item.Equipped != DungeonEquipmentSlot.None)
        .Sum(item => DungeonItemDefinitions[item.Definition].Armor + (int)item.Rarity * 2);

    private static int DungeonCurseWard(DungeonState dungeon) => Math.Min(75, dungeon.Items
        .Where(item => item.Equipped != DungeonEquipmentSlot.None)
        .Sum(item => DungeonItemDefinitions[item.Definition].CurseWard));

    private static int DungeonRequiredLevel(DungeonItem item) => Math.Max(
        DungeonItemDefinitions[item.Definition].RequiredLevel,
        item.Rarity >= DungeonItemRarity.Runic ? 2 : 1);

    private static void ApplyDungeonDamage(DungeonState dungeon, int rawDamage)
    {
        int reduction = Math.Min(rawDamage - 1, DungeonArmor(dungeon) / 12);
        dungeon.Health = Math.Max(0, dungeon.Health - Math.Max(1, rawDamage - reduction));
    }

    private static void ApplyDungeonCurse(DungeonState dungeon, int rawCurse)
    {
        int applied = Math.Max(1, rawCurse * (100 - DungeonCurseWard(dungeon)) / 100);
        dungeon.Curse = Math.Min(100, dungeon.Curse + applied);
    }

    private void StepDungeonSilverVents(DungeonState dungeon)
    {
        foreach (DungeonSilverWave wave in dungeon.SilverWaves)
        {
            wave.Age++;
            wave.X += wave.Dx * 3.2;
            wave.Y += wave.Dy * 3.2;
            if (!wave.HitKarl && DistanceSquared(wave.X, wave.Y, dungeon.KarlX, dungeon.KarlY) < 22 * 22)
            {
                wave.HitKarl = true;
                if (!_invincibleTestMode) ApplyDungeonDamage(dungeon, 10 + wave.Phase * 2);
                dungeon.HurtAge = 14;
            }
        }
        dungeon.SilverWaves.RemoveAll(wave => wave.Age > 95 ||
            wave.X < 20 || wave.X > dungeon.RoomWidth - 20 || wave.Y < 40 || wave.Y > dungeon.RoomHeight - 20);
        foreach (DungeonChest chest in dungeon.Chests)
            if (chest.OpenAge > 0 && chest.OpenAge < 45) chest.OpenAge++;
        if (dungeon.Depth != 2) return;
        if (dungeon.ForcedVentAge > 0) dungeon.ForcedVentAge--;
        int zone = DungeonZone(dungeon);
        if (zone > dungeon.MaxZoneReached)
        {
            dungeon.MaxZoneReached = zone;
            WriteDungeonSave(dungeon, "autosave");
        }
        for (int index = 0; index < DungeonSilverVents.Length; index++)
        {
            (int ventX, int ventY) = DungeonSilverVents[index];
            int cycle = (dungeon.Age + index * 43) % 180;
            bool forced = dungeon.ForcedVentAge > 0;
            if ((!forced && (cycle is < 54 or >= 102)) || (forced ? dungeon.ForcedVentAge : cycle) % 15 != 0) continue;
            if (DistanceSquared(ventX, ventY, dungeon.KarlX, dungeon.KarlY) < 54 * 54)
            {
                ApplyDungeonDamage(dungeon, 4);
                dungeon.HurtAge = Math.Max(dungeon.HurtAge, 9);
            }
            foreach (DungeonEnemy enemy in dungeon.Enemies.Where(enemy => enemy.State != DungeonEnemyState.Dead &&
                DistanceSquared(ventX, ventY, enemy.X, enemy.Y) < 58 * 58))
            {
                enemy.Health -= 6;
                enemy.State = enemy.Health <= 0 ? DungeonEnemyState.Dead : DungeonEnemyState.Stagger;
                enemy.StateAge = 0;
                if (enemy.State == DungeonEnemyState.Dead) DefeatDungeonEnemy(dungeon, enemy);
            }
        }
    }

    private bool StepSilverFogdeSpecial(DungeonState dungeon, DungeonEnemy fogde)
    {
        fogde.Phase = fogde.Health <= fogde.MaxHealth * 3 / 10 ? 3 :
            fogde.Health <= fogde.MaxHealth * 6 / 10 ? 2 : 1;
        if (fogde.SpecialKind == 0)
        {
            if (fogde.SpecialCooldown > 0) { fogde.SpecialCooldown--; return false; }
            fogde.SpecialSerial++;
            fogde.SpecialKind = fogde.Phase >= 2 && fogde.SpecialSerial % 2 == 0 ? 2 : 1;
            fogde.SpecialAge = 1;
            fogde.State = DungeonEnemyState.Telegraph;
            return true;
        }
        fogde.SpecialAge++;
        fogde.State = fogde.SpecialAge < 34 ? DungeonEnemyState.Telegraph : DungeonEnemyState.Attack;
        if (fogde.SpecialAge == 36)
        {
            _audio?.Trigger(StormaktSound.DungeonSilverWave);
            if (fogde.SpecialKind == 1)
            {
                double dx = dungeon.KarlX - fogde.X;
                double dy = dungeon.KarlY - fogde.Y;
                double length = Math.Max(0.1, Math.Sqrt(dx * dx + dy * dy));
                double angle = Math.Atan2(dy, dx);
                int count = fogde.Phase == 1 ? 1 : fogde.Phase == 2 ? 3 : 5;
                for (int index = 0; index < count; index++)
                {
                    double spread = (index - (count - 1) / 2.0) * 0.18;
                    dungeon.SilverWaves.Add(new DungeonSilverWave(fogde.X, fogde.Y,
                        Math.Cos(angle + spread), Math.Sin(angle + spread), fogde.Phase));
                }
            }
            else dungeon.ForcedVentAge = fogde.Phase == 2 ? 75 : 105;
        }
        if (fogde.SpecialAge <= 72) return true;
        fogde.SpecialKind = 0;
        fogde.SpecialAge = 0;
        fogde.SpecialCooldown = fogde.Phase switch { 1 => 150, 2 => 105, _ => 72 };
        fogde.State = DungeonEnemyState.Approach;
        fogde.StateAge = 0;
        return false;
    }

    private static bool DungeonSwanVulnerable(DungeonEnemy swan) =>
        swan.Phase < 3 || swan.State == DungeonEnemyState.Recover && swan.SpecialKind == 3 && swan.StateAge < 100;

    private void DamageDungeonSwan(DungeonState dungeon, DungeonEnemy swan, int damage, bool hammer)
    {
        swan.Health -= damage;
        dungeon.Power = Math.Min(100, dungeon.Power + 7);
        dungeon.HitStop = hammer ? 5 : 3;
        _audio?.Trigger(hammer ? StormaktSound.DungeonHammerImpact : StormaktSound.DungeonSwordHit);
        if (swan.Phase == 1 && swan.Health <= 480)
        {
            swan.Health = 480;
            BeginDungeonSwanPhase(swan, 2);
            dungeon.BlackWaterHazards.Clear();
            _audio?.Trigger(StormaktSound.DungeonSilverShatter);
        }
        else if (swan.Phase == 2 && swan.Health <= 240)
        {
            swan.Health = 240;
            BeginDungeonSwanPhase(swan, 3);
            dungeon.BlackWaterHazards.Clear();
            _audio?.Trigger(StormaktSound.DungeonSilverShatter);
        }
        else if (swan.Phase == 3 && swan.Health <= 0)
        {
            swan.Health = 0;
            swan.State = DungeonEnemyState.Dead;
            swan.StateAge = 0;
            swan.SpecialKind = 0;
            dungeon.BlackWaterHazards.Clear();
            dungeon.TargetX = dungeon.KarlX;
            dungeon.TargetY = dungeon.KarlY;
            _audio?.Trigger(StormaktSound.DungeonSilverShatter);
        }
    }

    private static void BeginDungeonSwanPhase(DungeonEnemy swan, int phase)
    {
        swan.Phase = phase;
        swan.State = DungeonEnemyState.Recover;
        swan.StateAge = 0;
        swan.SpecialKind = 0;
        swan.SpecialCooldown = phase == 3 ? 45 : 70;
    }

    private void StepDungeonSwan(DungeonState dungeon, DungeonEnemy swan)
    {
        swan.X = 3400;
        swan.Y = 380;
        if (swan.State == DungeonEnemyState.Dead)
        {
            if (swan.StateAge >= 150 && (dungeon.LoreMask & DungeonSwanDefeatedMask) == 0)
            {
                dungeon.LoreMask |= DungeonSwanDefeatedMask | DungeonLouhiHeardMask;
                DefeatDungeonEnemy(dungeon, swan);
                dungeon.Curse = Math.Max(0, dungeon.Curse - 50);
                ActivateBossRadio(DungeonLouhiInvitationRadio);
                _audio?.SwitchMusic(StormaktMusicTrack.Dungeon);
                WriteDungeonSave(dungeon, "autosave");
            }
            return;
        }

        if (swan.State == DungeonEnemyState.Approach)
        {
            if (swan.SpecialCooldown > 0) { swan.SpecialCooldown--; return; }
            swan.SpecialSerial++;
            swan.SpecialKind = swan.Phase switch
            {
                1 => 1,
                2 => swan.SpecialSerial % 2 == 0 ? 2 : 1,
                _ => 3,
            };
            swan.State = DungeonEnemyState.Telegraph;
            swan.StateAge = 0;
            swan.VelocityX = dungeon.KarlX;
            swan.VelocityY = dungeon.KarlY;
            if (swan.SpecialKind == 1) SpawnDungeonSwanWingPools(dungeon, swan);
            return;
        }

        if (swan.State == DungeonEnemyState.Telegraph)
        {
            int warning = swan.SpecialKind switch { 1 => 46, 2 => 40, _ => 54 };
            if (swan.StateAge >= warning)
            {
                swan.State = DungeonEnemyState.Attack;
                swan.StateAge = 0;
            }
            return;
        }

        if (swan.State == DungeonEnemyState.Attack)
        {
            if (swan.SpecialKind == 2 && swan.StateAge == 9)
                StrikeDungeonSwanNeck(dungeon, swan);
            if (swan.SpecialKind == 3)
                StepDungeonSwanHeartWaves(dungeon, swan);
            int duration = swan.SpecialKind switch { 1 => 28, 2 => 22, _ => 78 };
            if (swan.StateAge >= duration)
            {
                swan.State = DungeonEnemyState.Recover;
                swan.StateAge = 0;
            }
            return;
        }

        if (swan.State == DungeonEnemyState.Recover)
        {
            int recovery = swan.SpecialKind == 3 ? 110 : swan.Phase == 2 ? 42 : 56;
            if (swan.StateAge >= recovery)
            {
                swan.State = DungeonEnemyState.Approach;
                swan.StateAge = 0;
                swan.SpecialCooldown = swan.Phase == 3 ? 24 : 38;
            }
        }
    }

    private static void SpawnDungeonSwanWingPools(DungeonState dungeon, DungeonEnemy swan)
    {
        double baseAngle = Math.Atan2(swan.VelocityY - swan.Y, swan.VelocityX - swan.X);
        for (int ring = 0; ring < 3; ring++)
        for (int side = -1; side <= 1; side += 2)
        {
            double angle = baseAngle + side * (0.20 + ring * 0.12);
            double distance = 72 + ring * 44;
            dungeon.BlackWaterHazards.Add(new DungeonBlackWaterHazard(
                Math.Clamp(swan.X + Math.Cos(angle) * distance, 3195, 3515),
                Math.Clamp(swan.Y + Math.Sin(angle) * distance, 90, 670),
                28 + ring * 3, 46, 185, 14 + swan.Phase * 2));
        }
    }

    private void StepDungeonSwanHazards(DungeonState dungeon)
    {
        foreach (DungeonBlackWaterHazard hazard in dungeon.BlackWaterHazards)
        {
            hazard.Age++;
            if (hazard.Age < hazard.ArmAge || hazard.Age >= hazard.Lifetime || hazard.Age % 8 != 0 ||
                dungeon.HurtAge > 0 || DistanceSquared(hazard.X, hazard.Y, dungeon.KarlX, dungeon.KarlY) >= hazard.Radius * hazard.Radius)
                continue;
            if (!_invincibleTestMode) ApplyDungeonDamage(dungeon, hazard.Damage);
            ApplyDungeonCurse(dungeon, 6);
            dungeon.HurtAge = 18;
            dungeon.HitStop = 2;
        }
        dungeon.BlackWaterHazards.RemoveAll(hazard => hazard.Age >= hazard.Lifetime);
    }

    private void StrikeDungeonSwanNeck(DungeonState dungeon, DungeonEnemy swan)
    {
        if (DistancePointToSegmentSquared(dungeon.KarlX, dungeon.KarlY,
            swan.X, swan.Y - 18, swan.VelocityX, swan.VelocityY) > 24 * 24) return;
        if (dungeon.Guarding)
        {
            dungeon.Power = Math.Min(100, dungeon.Power + 15);
            dungeon.HitStop = 3;
            _audio?.Trigger(StormaktSound.DungeonParry);
            return;
        }
        if (!_invincibleTestMode) ApplyDungeonDamage(dungeon, 22);
        ApplyDungeonCurse(dungeon, 10);
        dungeon.HurtAge = 20;
        dungeon.HitStop = 4;
    }

    private void StepDungeonSwanHeartWaves(DungeonState dungeon, DungeonEnemy swan)
    {
        if (dungeon.HurtAge > 0) return;
        double distance = Math.Sqrt(DistanceSquared(swan.X, swan.Y, dungeon.KarlX, dungeon.KarlY));
        foreach (int offset in new[] { 0, 24, 48 })
        {
            int waveAge = swan.StateAge - offset;
            if (waveAge is < 1 or > 62 || Math.Abs(distance - waveAge * 4) > 5) continue;
            if (!_invincibleTestMode) ApplyDungeonDamage(dungeon, 18);
            ApplyDungeonCurse(dungeon, 8);
            dungeon.HurtAge = 18;
            dungeon.HitStop = 2;
            break;
        }
    }

    private void DamageDungeonLouhi(DungeonState dungeon, DungeonEnemy louhi, int damage, bool hammer)
    {
        if (louhi.Phase is not (1 or 2 or 3) || louhi.State == DungeonEnemyState.Dead) return;
        if (louhi.Phase == 3 && (louhi.SpecialAge <= 0 || hammer))
        {
            dungeon.HitStop = 3;
            dungeon.PickupNotice = louhi.SpecialAge > 0 ? "BYT TILL VÄRJA" : "SKÖLDAD  SÖK ALTARHJÄRTAT";
            dungeon.PickupNoticeAge = 75;
            _audio?.Trigger(StormaktSound.DungeonParry);
            return;
        }
        louhi.Health -= damage;
        dungeon.Power = Math.Min(100, dungeon.Power + 7);
        dungeon.HitStop = hammer ? 5 : 3;
        _audio?.Trigger(hammer ? StormaktSound.DungeonHammerImpact : StormaktSound.DungeonSwordHit);
        if (louhi.Health > 0)
        {
            louhi.State = DungeonEnemyState.Stagger;
            louhi.StateAge = 0;
            return;
        }

        if (louhi.Phase == 1)
        {
            dungeon.LoreMask |= DungeonLouhiPhaseOneMask;
            BeginDungeonLouhiIronBird(louhi, 105);
            dungeon.Curse = Math.Max(0, dungeon.Curse - 25);
            ActivateBossRadio(DungeonLouhiPhaseOneRadio);
        }
        else if (louhi.Phase == 2)
        {
            dungeon.LoreMask |= DungeonLouhiPhaseTwoMask;
            BeginDungeonLouhiOreMother(louhi, 105);
            dungeon.Curse = Math.Max(0, dungeon.Curse - 35);
            ActivateBossRadio(DungeonLouhiPhaseTwoRadio);
        }
        else
        {
            louhi.Health = 0;
            louhi.Phase = 4;
            louhi.State = DungeonEnemyState.Dead;
            louhi.StateAge = 0;
            louhi.SpecialKind = 0;
            louhi.SpecialAge = 0;
            dungeon.LoreMask |= DungeonLouhiPhaseThreeMask;
            dungeon.Curse = 0;
            if (dungeon.Items.All(item => item.Definition != 16))
            {
                DungeonItem ring = AddDungeonItem(dungeon, 16, -1, -1,
                    DungeonEquipmentSlot.None, DungeonItemRarity.Unique);
                ring.OnGround = true;
                ring.WorldX = 4170;
                ring.WorldY = 415;
            }
            dungeon.PickupNotice = "MALMMODERN LÄMNAR EN RUNRING";
            dungeon.PickupNoticeAge = 240;
            ActivateBossRadio(DungeonLouhiFinalRadio);
            louhi.SpecialCooldown = 0;
            dungeon.CollapseAge = 1;
        }
        dungeon.LouhiRunes.Clear();
        dungeon.LouhiVeins.Clear();
        dungeon.BlackWaterHazards.Clear();
        dungeon.SilverWaves.Clear();
        dungeon.LouhiGreedAge = 0;
        dungeon.GreedAttackSlow = false;
        dungeon.TargetX = dungeon.KarlX;
        dungeon.TargetY = dungeon.KarlY;
        _audio?.Trigger(StormaktSound.DungeonSilverShatter);
        WriteDungeonSave(dungeon, "autosave");
    }

    private void StepDungeonLouhi(DungeonState dungeon, DungeonEnemy louhi)
    {
        // Saves written by the old phase-one stub contain a dead phase-two
        // Louhi. Upgrade them in place the first frame they are resumed.
        if (louhi.State == DungeonEnemyState.Dead && louhi.Phase == 2 &&
            (dungeon.LoreMask & DungeonLouhiPhaseOneMask) != 0 &&
            (dungeon.LoreMask & DungeonLouhiPhaseTwoMask) == 0)
            BeginDungeonLouhiIronBird(louhi, 75);
        // The previously shipped phase-two ending used dead phase 3 as a
        // placeholder. Resume those saves directly at the real final form.
        if (louhi.State == DungeonEnemyState.Dead && louhi.Phase == 3 &&
            (dungeon.LoreMask & DungeonLouhiPhaseTwoMask) != 0 &&
            (dungeon.LoreMask & DungeonLouhiPhaseThreeMask) == 0)
            BeginDungeonLouhiOreMother(louhi, 75);
        if (louhi.State == DungeonEnemyState.Dead) return;
        if (louhi.Phase == 3)
        {
            StepDungeonLouhiOreMother(dungeon, louhi);
            return;
        }
        if (louhi.Phase == 2)
        {
            StepDungeonLouhiIronBird(dungeon, louhi);
            return;
        }
        if (louhi.Phase != 1) return;
        if (louhi.State == DungeonEnemyState.Stagger)
        {
            if (louhi.StateAge >= 14)
            {
                louhi.State = DungeonEnemyState.Recover;
                louhi.StateAge = 0;
                louhi.SpecialCooldown = 28;
            }
            return;
        }
        if (louhi.State == DungeonEnemyState.Recover)
        {
            if (louhi.SpecialCooldown > 0) { louhi.SpecialCooldown--; return; }
            louhi.State = DungeonEnemyState.Approach;
            louhi.StateAge = 0;
        }
        if (louhi.State == DungeonEnemyState.Approach)
        {
            louhi.SpecialSerial++;
            louhi.SpecialKind = (louhi.SpecialSerial - 1) % 4 + 1;
            louhi.State = DungeonEnemyState.Telegraph;
            louhi.StateAge = 0;
            louhi.VelocityX = dungeon.KarlX;
            louhi.VelocityY = dungeon.KarlY;
            if (louhi.SpecialKind == 2) SpawnDungeonLouhiRunes(dungeon, louhi);
            if (louhi.SpecialKind == 3)
            {
                (int X, int Y)[] destinations = [(4050, 215), (4280, 205), (4280, 555), (4050, 545)];
                (int X, int Y) target = destinations[louhi.SpecialSerial % destinations.Length];
                louhi.VelocityX = target.X;
                louhi.VelocityY = target.Y;
            }
            if (louhi.SpecialKind == 4 && !dungeon.LouhiGreedSpoken)
            {
                dungeon.LouhiGreedSpoken = true;
                ActivateBossRadio(DungeonLouhiGreedRadio);
            }
            return;
        }
        if (louhi.State == DungeonEnemyState.Telegraph)
        {
            int warning = louhi.SpecialKind switch { 1 => 34, 2 => 48, 3 => 38, _ => 42 };
            if (louhi.StateAge >= warning)
            {
                louhi.State = DungeonEnemyState.Attack;
                louhi.StateAge = 0;
            }
            return;
        }
        if (louhi.State == DungeonEnemyState.Attack)
        {
            if (louhi.StateAge == 8)
            {
                if (louhi.SpecialKind == 1) StrikeDungeonLouhiStaff(dungeon, louhi);
                else if (louhi.SpecialKind == 3) TeleportDungeonLouhi(dungeon, louhi);
                else if (louhi.SpecialKind == 4) ApplyDungeonLouhiGreed(dungeon);
            }
            int duration = louhi.SpecialKind switch { 1 => 22, 2 => 34, 3 => 28, _ => 24 };
            if (louhi.StateAge >= duration)
            {
                louhi.State = DungeonEnemyState.Recover;
                louhi.StateAge = 0;
                louhi.SpecialCooldown = 36;
            }
        }
    }

    private void StepDungeonLouhiIronBird(DungeonState dungeon, DungeonEnemy louhi)
    {
        if (louhi.State == DungeonEnemyState.Stagger)
        {
            if (louhi.StateAge >= 10)
            {
                louhi.State = DungeonEnemyState.Recover;
                louhi.StateAge = 0;
                louhi.SpecialCooldown = 20;
            }
            return;
        }
        if (louhi.State == DungeonEnemyState.Recover)
        {
            if (louhi.SpecialCooldown > 0) { louhi.SpecialCooldown--; return; }
            louhi.State = DungeonEnemyState.Approach;
            louhi.StateAge = 0;
        }
        if (louhi.State == DungeonEnemyState.Approach)
        {
            louhi.SpecialSerial++;
            louhi.SpecialKind = 5 + (louhi.SpecialSerial - 1) % 3;
            louhi.State = DungeonEnemyState.Telegraph;
            louhi.StateAge = 0;
            louhi.VelocityX = dungeon.KarlX;
            louhi.VelocityY = dungeon.KarlY;
            if (louhi.SpecialKind == 7)
            {
                louhi.VelocityX = Math.Clamp(dungeon.KarlX, 4010, 4370);
                louhi.VelocityY = Math.Clamp(dungeon.KarlY, 105, 655);
            }
            return;
        }
        if (louhi.State == DungeonEnemyState.Telegraph)
        {
            int warning = louhi.SpecialKind switch { 5 => 42, 6 => 48, _ => 54 };
            if (louhi.StateAge >= warning)
            {
                louhi.State = DungeonEnemyState.Attack;
                louhi.StateAge = 0;
            }
            return;
        }
        if (louhi.State != DungeonEnemyState.Attack) return;
        if (louhi.StateAge == 8)
        {
            if (louhi.SpecialKind == 5) StrikeDungeonLouhiIronWing(dungeon, louhi);
            else if (louhi.SpecialKind == 6) SpawnDungeonLouhiIronFeathers(dungeon, louhi);
            else DiveDungeonLouhiIronBird(dungeon, louhi);
        }
        int duration = louhi.SpecialKind switch { 5 => 28, 6 => 34, _ => 30 };
        if (louhi.StateAge >= duration)
        {
            louhi.State = DungeonEnemyState.Recover;
            louhi.StateAge = 0;
            louhi.SpecialCooldown = 28;
        }
    }

    private void StepDungeonLouhiOreMother(DungeonState dungeon, DungeonEnemy louhi)
    {
        if (louhi.SpecialAge > 0)
        {
            louhi.SpecialAge--;
            louhi.State = DungeonEnemyState.Recover;
            if (louhi.SpecialAge == 0)
            {
                louhi.SpecialSerial = (louhi.SpecialSerial + 1) % DungeonLouhiHearts.Length;
                // Mark the newly selected heart as unannounced. Normal attack
                // recovery keeps SpecialKind 8/9 and must not restart the card.
                louhi.SpecialKind = 0;
                louhi.SpecialCooldown = 48;
                dungeon.PickupNotice = "MALMMODERN SLUTER SIG";
                dungeon.PickupNoticeAge = 60;
            }
            return;
        }
        if (louhi.State == DungeonEnemyState.Stagger)
        {
            if (louhi.StateAge >= 12)
            {
                louhi.State = DungeonEnemyState.Recover;
                louhi.StateAge = 0;
                louhi.SpecialCooldown = 18;
            }
            return;
        }
        if (louhi.State == DungeonEnemyState.Recover)
        {
            if (louhi.SpecialCooldown > 0) { louhi.SpecialCooldown--; return; }
            bool announceHeart = louhi.SpecialKind == 0;
            louhi.State = DungeonEnemyState.Approach;
            louhi.StateAge = 0;
            if (announceHeart)
                ActivateBossRadio(DungeonLouhiHeartCards[louhi.SpecialSerial % DungeonLouhiHeartCards.Length]);
            return;
        }
        if (louhi.State == DungeonEnemyState.Approach)
        {
            louhi.SpecialKind = 8 + louhi.SpecialSerial % 2;
            louhi.State = DungeonEnemyState.Telegraph;
            louhi.StateAge = 0;
            louhi.VelocityX = dungeon.KarlX;
            louhi.VelocityY = dungeon.KarlY;
            return;
        }
        if (louhi.State == DungeonEnemyState.Telegraph)
        {
            int warning = louhi.SpecialKind == 8 ? 44 : 54;
            if (louhi.StateAge >= warning)
            {
                louhi.State = DungeonEnemyState.Attack;
                louhi.StateAge = 0;
            }
            return;
        }
        if (louhi.State != DungeonEnemyState.Attack) return;
        if (louhi.StateAge == 6) SpawnDungeonLouhiVeins(dungeon, louhi, louhi.SpecialKind == 9);
        if (louhi.StateAge >= 32)
        {
            louhi.State = DungeonEnemyState.Recover;
            louhi.StateAge = 0;
            louhi.SpecialCooldown = 34;
        }
    }

    private static void SpawnDungeonLouhiVeins(DungeonState dungeon, DungeonEnemy louhi, bool fromHearts)
    {
        if (fromHearts)
        {
            foreach ((int heartX, int heartY) in DungeonLouhiHearts)
                dungeon.LouhiVeins.Add(new DungeonLouhiVein(heartX, heartY,
                    Math.Clamp(louhi.VelocityX, 3995, 4385), Math.Clamp(louhi.VelocityY, 95, 665), 22, 76, 20));
            return;
        }
        double angle = Math.Atan2(louhi.VelocityY - louhi.Y, louhi.VelocityX - louhi.X);
        for (int index = -1; index <= 1; index++)
        {
            double ray = angle + index * 0.18;
            dungeon.LouhiVeins.Add(new DungeonLouhiVein(louhi.X, louhi.Y - 12,
                Math.Clamp(louhi.X + Math.Cos(ray) * 360, 3995, 4385),
                Math.Clamp(louhi.Y + Math.Sin(ray) * 360, 95, 665), 20, 72, 22));
        }
    }

    private bool TryStrikeDungeonLouhiHeart(DungeonState dungeon)
    {
        DungeonEnemy? louhi = dungeon.Enemies.FirstOrDefault(enemy => enemy.Depth == dungeon.Depth &&
            enemy.Type == DungeonEnemyType.Louhi && enemy.Phase == 3 &&
            enemy.State != DungeonEnemyState.Dead && enemy.SpecialAge <= 0);
        if (louhi is null) return false;
        (double fx, double fy) = DungeonFacingVector(dungeon.Facing);
        int struck = -1;
        for (int index = 0; index < DungeonLouhiHearts.Length; index++)
        {
            double dx = DungeonLouhiHearts[index].X - dungeon.KarlX;
            double dy = DungeonLouhiHearts[index].Y - dungeon.KarlY;
            double distance = Math.Sqrt(dx * dx + dy * dy);
            if (distance <= 70 && distance > 0.1 && (dx * fx + dy * fy) / distance > 0.05)
            {
                struck = index;
                break;
            }
        }
        if (struck < 0) return false;
        dungeon.HitStop = 6;
        _audio?.Trigger(StormaktSound.DungeonSilverShatter);
        if (struck != louhi.SpecialSerial % DungeonLouhiHearts.Length)
        {
            ApplyDungeonCurse(dungeon, 10);
            dungeon.PickupNotice = "FALSKT HJÄRTA";
            dungeon.PickupNoticeAge = 75;
            (int x, int y) = DungeonLouhiHearts[struck];
            dungeon.LouhiVeins.Add(new DungeonLouhiVein(x, y, dungeon.KarlX, dungeon.KarlY, 4, 30, 16));
            return true;
        }
        louhi.SpecialAge = 210;
        louhi.State = DungeonEnemyState.Recover;
        louhi.StateAge = 0;
        louhi.SpecialKind = 0;
        dungeon.LouhiVeins.Clear();
        dungeon.PickupNotice = "HJÄRTAT ÖPPET  BYT TILL VÄRJA";
        dungeon.PickupNoticeAge = 150;
        return true;
    }

    private void StrikeDungeonLouhiIronWing(DungeonState dungeon, DungeonEnemy louhi)
    {
        if (DistanceSquared(louhi.X, louhi.Y, dungeon.KarlX, dungeon.KarlY) > 104 * 104) return;
        if (dungeon.Guarding)
        {
            dungeon.Power = Math.Min(100, dungeon.Power + 18);
            dungeon.HitStop = 4;
            _audio?.Trigger(StormaktSound.DungeonParry);
            return;
        }
        if (!_invincibleTestMode) ApplyDungeonDamage(dungeon, 24);
        ApplyDungeonCurse(dungeon, 8);
        dungeon.HurtAge = 20;
        dungeon.HitStop = 4;
    }

    private void SpawnDungeonLouhiIronFeathers(DungeonState dungeon, DungeonEnemy louhi)
    {
        double angle = Math.Atan2(louhi.VelocityY - louhi.Y, louhi.VelocityX - louhi.X);
        for (int index = -3; index <= 3; index++)
        {
            double ray = angle + index * 0.16;
            dungeon.SilverWaves.Add(new DungeonSilverWave(louhi.X, louhi.Y - 12,
                Math.Cos(ray), Math.Sin(ray), 4));
        }
        _audio?.Trigger(StormaktSound.DungeonSilverWave);
    }

    private void DiveDungeonLouhiIronBird(DungeonState dungeon, DungeonEnemy louhi)
    {
        louhi.X = louhi.VelocityX;
        louhi.Y = louhi.VelocityY;
        for (int index = 0; index < 8; index++)
        {
            double angle = index * Math.PI / 4;
            dungeon.SilverWaves.Add(new DungeonSilverWave(louhi.X, louhi.Y,
                Math.Cos(angle), Math.Sin(angle), 3));
        }
        if (DistanceSquared(louhi.X, louhi.Y, dungeon.KarlX, dungeon.KarlY) < 54 * 54)
        {
            if (dungeon.Guarding)
            {
                dungeon.Power = Math.Min(100, dungeon.Power + 20);
                dungeon.HitStop = 5;
                _audio?.Trigger(StormaktSound.DungeonParry);
            }
            else
            {
                if (!_invincibleTestMode) ApplyDungeonDamage(dungeon, 27);
                ApplyDungeonCurse(dungeon, 10);
                dungeon.HurtAge = 22;
                dungeon.HitStop = 5;
            }
        }
        _audio?.Trigger(StormaktSound.DungeonSilverShatter);
    }

    private static void SpawnDungeonLouhiRunes(DungeonState dungeon, DungeonEnemy louhi)
    {
        double baseAngle = Math.Atan2(dungeon.KarlY - louhi.Y, dungeon.KarlX - louhi.X);
        for (int index = 0; index < 6; index++)
        {
            double angle = baseAngle + (index - 2.5) * 0.42;
            double distance = 78 + index % 2 * 54;
            dungeon.LouhiRunes.Add(new DungeonLouhiRune(
                Math.Clamp(dungeon.KarlX + Math.Cos(angle) * distance, 3985, 4390),
                Math.Clamp(dungeon.KarlY + Math.Sin(angle) * distance, 105, 655), 44 + index * 8));
        }
    }

    private void StepDungeonLouhiHazards(DungeonState dungeon)
    {
        foreach (DungeonLouhiRune rune in dungeon.LouhiRunes)
        {
            rune.Age++;
            if (rune.HitKarl || rune.Age != rune.ArmAge || dungeon.HurtAge > 0 ||
                DistanceSquared(rune.X, rune.Y, dungeon.KarlX, dungeon.KarlY) > 38 * 38) continue;
            rune.HitKarl = true;
            if (!_invincibleTestMode) ApplyDungeonDamage(dungeon, 17);
            ApplyDungeonCurse(dungeon, 9);
            dungeon.HurtAge = 18;
            dungeon.HitStop = 3;
            _audio?.Trigger(StormaktSound.DungeonSilverWave);
        }
        dungeon.LouhiRunes.RemoveAll(rune => rune.Age > rune.ArmAge + 18);
    }

    private void StepDungeonLouhiVeins(DungeonState dungeon)
    {
        foreach (DungeonLouhiVein vein in dungeon.LouhiVeins)
        {
            vein.Age++;
            if (vein.Age < vein.ArmAge || vein.Age > vein.Lifetime || vein.HitKarl ||
                dungeon.HurtAge > 0 || DistancePointToSegmentSquared(dungeon.KarlX, dungeon.KarlY,
                    vein.AX, vein.AY, vein.BX, vein.BY) > 13 * 13) continue;
            vein.HitKarl = true;
            if (dungeon.Guarding)
            {
                dungeon.Power = Math.Min(100, dungeon.Power + 14);
                dungeon.HitStop = 3;
                _audio?.Trigger(StormaktSound.DungeonParry);
                continue;
            }
            if (!_invincibleTestMode) ApplyDungeonDamage(dungeon, vein.Damage);
            ApplyDungeonCurse(dungeon, 7);
            dungeon.HurtAge = 18;
            dungeon.HitStop = 3;
            _audio?.Trigger(StormaktSound.DungeonSilverWave);
        }
        dungeon.LouhiVeins.RemoveAll(vein => vein.Age > vein.Lifetime);
    }

    private void StrikeDungeonLouhiStaff(DungeonState dungeon, DungeonEnemy louhi)
    {
        if (DistancePointToSegmentSquared(dungeon.KarlX, dungeon.KarlY,
            louhi.X, louhi.Y - 16, louhi.VelocityX, louhi.VelocityY) > 22 * 22) return;
        if (dungeon.Guarding)
        {
            dungeon.LouhiGreedAge = 0;
            dungeon.Power = Math.Min(100, dungeon.Power + 16);
            dungeon.HitStop = 3;
            _audio?.Trigger(StormaktSound.DungeonParry);
            return;
        }
        if (!_invincibleTestMode) ApplyDungeonDamage(dungeon, 21);
        ApplyDungeonCurse(dungeon, 12);
        dungeon.HurtAge = 20;
        dungeon.HitStop = 4;
    }

    private void TeleportDungeonLouhi(DungeonState dungeon, DungeonEnemy louhi)
    {
        double oldX = louhi.X;
        double oldY = louhi.Y;
        louhi.X = louhi.VelocityX;
        louhi.Y = louhi.VelocityY;
        dungeon.BlackWaterHazards.Add(new DungeonBlackWaterHazard(oldX, oldY, 34, 0, 64, 13));
        dungeon.BlackWaterHazards.Add(new DungeonBlackWaterHazard(louhi.X, louhi.Y, 34, 0, 64, 13));
        if (DistanceSquared(louhi.X, louhi.Y, dungeon.KarlX, dungeon.KarlY) < 48 * 48 && dungeon.HurtAge == 0)
        {
            if (dungeon.Guarding)
            {
                dungeon.Power = Math.Min(100, dungeon.Power + 12);
                _audio?.Trigger(StormaktSound.DungeonParry);
            }
            else
            {
                if (!_invincibleTestMode) ApplyDungeonDamage(dungeon, 18);
                dungeon.HurtAge = 18;
            }
        }
        _audio?.Trigger(StormaktSound.DungeonSilverWave);
    }

    private void ApplyDungeonLouhiGreed(DungeonState dungeon)
    {
        if (dungeon.Guarding)
        {
            dungeon.LouhiGreedAge = 0;
            dungeon.Power = Math.Min(100, dungeon.Power + 10);
            _audio?.Trigger(StormaktSound.DungeonParry);
            return;
        }
        dungeon.LouhiGreedAge = 240;
        ApplyDungeonCurse(dungeon, 15);
        _audio?.Trigger(StormaktSound.DungeonSilverWave);
    }

    private static double DistancePointToSegmentSquared(double px, double py,
        double ax, double ay, double bx, double by)
    {
        double dx = bx - ax;
        double dy = by - ay;
        double lengthSquared = dx * dx + dy * dy;
        if (lengthSquared < 0.001) return DistanceSquared(px, py, ax, ay);
        double t = Math.Clamp(((px - ax) * dx + (py - ay) * dy) / lengthSquared, 0, 1);
        return DistanceSquared(px, py, ax + dx * t, ay + dy * t);
    }

    private void StartDungeonAttack(DungeonState dungeon, RtsPointer pointer)
    {
        if (pointer.Inside)
        {
            double aimX = pointer.X + dungeon.CameraX - dungeon.KarlX;
            double aimY = pointer.Y + dungeon.CameraY - dungeon.KarlY;
            dungeon.Facing = Math.Abs(aimX) > Math.Abs(aimY)
                ? aimX < 0 ? DungeonFacing.West : DungeonFacing.East
                : aimY < 0 ? DungeonFacing.North : DungeonFacing.South;
        }
        if (dungeon.AttackAge > 0)
        {
            if (dungeon.AttackAge >= 10) dungeon.AttackQueued = true;
            return;
        }
        dungeon.AttackAge = 1;
        if (dungeon.LouhiGreedAge > 0)
        {
            dungeon.GreedAttackSlow = true;
            dungeon.LouhiGreedAge = 0;
        }
        dungeon.AttackSerial++;
        dungeon.AttackCombo = dungeon.AttackCombo % 3 + 1;
        dungeon.TargetX = dungeon.KarlX;
        dungeon.TargetY = dungeon.KarlY;
        dungeon.Guarding = false;
        bool hammer = dungeon.Items.Any(item => item.Equipped == DungeonEquipmentSlot.MainHand && item.Definition == 3);
        _audio?.Trigger(hammer ? StormaktSound.DungeonHammerImpact : StormaktSound.DungeonSwordSlash);
    }

    private void StepDungeonCombat(DungeonState dungeon)
    {
        bool hammer = dungeon.Items.Any(item => item.Equipped == DungeonEquipmentSlot.MainHand && item.Definition == 3);
        int contactAge = hammer ? 14 : 9;
        int endAge = hammer ? 31 : 23;
        if (dungeon.AttackAge > 0)
        {
            if (dungeon.AttackAge == contactAge)
            {
                if (hammer) TryStrikeDungeonLouhiHeart(dungeon);
                (double fx, double fy) = DungeonFacingVector(dungeon.Facing);
                int weaponDamage = dungeon.Items.Where(item => item.Equipped == DungeonEquipmentSlot.MainHand)
                    .Select(item => DungeonItemDefinitions[item.Definition].Damage + item.PowerRoll / 3)
                    .DefaultIfEmpty(8).Max() + Math.Max(0, dungeon.Level - 1) * 2;
                foreach (DungeonEnemy enemy in dungeon.Enemies.Where(enemy => enemy.Depth == dungeon.Depth &&
                    enemy.State != DungeonEnemyState.Dead))
                {
                    double dx = enemy.X - dungeon.KarlX;
                    double dy = enemy.Y - dungeon.KarlY;
                    double range = hammer ? 53 : 47;
                    double distance = Math.Sqrt(dx * dx + dy * dy);
                    if (distance > range || distance < 0.1 || (dx * fx + dy * fy) / distance < 0.22 || enemy.LastHitSerial == dungeon.AttackSerial) continue;
                    if (enemy.Type == DungeonEnemyType.TuonelaSwan)
                    {
                        enemy.LastHitSerial = dungeon.AttackSerial;
                        if (!DungeonSwanVulnerable(enemy))
                        {
                            dungeon.HitStop = 2;
                            _audio?.Trigger(StormaktSound.DungeonParry);
                            continue;
                        }
                        DamageDungeonSwan(dungeon, enemy, weaponDamage, hammer);
                        continue;
                    }
                    if (enemy.Type == DungeonEnemyType.Louhi)
                    {
                        enemy.LastHitSerial = dungeon.AttackSerial;
                        DamageDungeonLouhi(dungeon, enemy, weaponDamage, hammer);
                        continue;
                    }
                    enemy.LastHitSerial = dungeon.AttackSerial;
                    enemy.Health -= weaponDamage;
                    enemy.State = enemy.Health <= 0 ? DungeonEnemyState.Dead : DungeonEnemyState.Stagger;
                    enemy.StateAge = 0;
                    if (enemy.State == DungeonEnemyState.Dead) DefeatDungeonEnemy(dungeon, enemy);
                    dungeon.Power = Math.Min(100, dungeon.Power + 5);
                    dungeon.HitStop = hammer ? 4 : 2;
                    _audio?.Trigger(hammer ? StormaktSound.DungeonHammerImpact : StormaktSound.DungeonSwordHit);
                }
                if (dungeon.Depth == 1 && dungeon.RoomClear && !dungeon.DoorReady)
                {
                    double doorDx = 650 - dungeon.KarlX;
                    double doorDy = 218 - dungeon.KarlY;
                    double doorDistance = Math.Sqrt(doorDx * doorDx + doorDy * doorDy);
                    if (doorDistance < 58 && doorDistance > 0.1 && (doorDx * fx + doorDy * fy) / doorDistance > 0.2)
                    {
                        dungeon.DoorHealth = Math.Max(0, dungeon.DoorHealth - (hammer ? 2 : 1));
                        _audio?.Trigger(hammer ? StormaktSound.DungeonHammerImpact : StormaktSound.DungeonSwordHit);
                        if (dungeon.DoorHealth == 0)
                        {
                            dungeon.DoorReady = true;
                            dungeon.DescentWarningPlayed = true;
                            dungeon.PendingDoorEntry = false;
                            ActivateBossRadio(DungeonDepthTwoWarningRadio);
                            WriteDungeonSave(dungeon, "autosave");
                        }
                    }
                }
            }
            if (!dungeon.GreedAttackSlow || dungeon.Age % 2 == 0) dungeon.AttackAge++;
            if (dungeon.AttackAge > endAge)
            {
                dungeon.AttackAge = 0;
                dungeon.GreedAttackSlow = false;
                if (dungeon.AttackQueued)
                {
                    dungeon.AttackQueued = false;
                    dungeon.AttackAge = 1;
                    dungeon.AttackSerial++;
                    dungeon.AttackCombo = dungeon.AttackCombo % 3 + 1;
                }
            }
        }

        foreach (DungeonEnemy enemy in dungeon.Enemies.Where(enemy => enemy.Depth == dungeon.Depth))
        {
            if (enemy.Type == DungeonEnemyType.LemminkainenShadow && enemy.Phase == 0) continue;
            enemy.StateAge++;
            if (enemy.Type == DungeonEnemyType.TuonelaSwan)
            {
                StepDungeonSwan(dungeon, enemy);
                continue;
            }
            if (enemy.Type == DungeonEnemyType.Louhi)
            {
                StepDungeonLouhi(dungeon, enemy);
                continue;
            }
            if (enemy.State == DungeonEnemyState.Dead)
            {
                if (enemy.Type == DungeonEnemyType.BlindShepherd && enemy.StateAge == 20 &&
                    (dungeon.LoreMask & DungeonShepherdHeardMask) == 0)
                {
                    dungeon.LoreMask |= DungeonShepherdHeardMask;
                    ActivateBossRadio(DungeonShepherdDeathRadio);
                    WriteDungeonSave(dungeon, "autosave");
                }
                if (enemy.Type == DungeonEnemyType.SilverFogde && enemy.StateAge == 80 && !dungeon.DepthThreeOpen)
                {
                    dungeon.DepthThreeOpen = true;
                    _audio?.Trigger(StormaktSound.DungeonSilverShatter);
                    WriteDungeonSave(dungeon, "autosave");
                }
                if (enemy.Type == DungeonEnemyType.BlindShepherd && enemy.StateAge == 90 && !dungeon.TempleOpen)
                {
                    dungeon.TempleOpen = true;
                    WriteDungeonSave(dungeon, "autosave");
                }
                continue;
            }
            if (enemy.State == DungeonEnemyState.Stagger)
            {
                if (enemy.StateAge > 18) { enemy.State = DungeonEnemyState.Approach; enemy.StateAge = 0; }
                continue;
            }
            if (enemy.Type == DungeonEnemyType.SilverFogde && StepSilverFogdeSpecial(dungeon, enemy)) continue;
            double dx = dungeon.KarlX - enemy.X;
            double dy = dungeon.KarlY - enemy.Y;
            double distance = Math.Sqrt(dx * dx + dy * dy);
            int currentZone = DungeonZone(dungeon);
            if (dungeon.Depth >= 2 && enemy.Zone != currentZone && distance > 180) continue;
            enemy.FacingLeft = dx < 0;
            double attackRange = enemy.Type switch
            {
                DungeonEnemyType.Pikeman => 54, DungeonEnemyType.SilverFogde => 48,
                DungeonEnemyType.TuonelaGuard => 62, DungeonEnemyType.BlindShepherd => 92,
                DungeonEnemyType.LemminkainenShadow => 74,
                DungeonEnemyType.UndeadMiner => 38, _ => 35,
            };
            if (enemy.State == DungeonEnemyState.Approach)
            {
                if (distance <= attackRange)
                {
                    enemy.State = DungeonEnemyState.Telegraph;
                    enemy.StateAge = 0;
                }
                else if (distance > 0.1)
                {
                    // Advance in weighted steps instead of homing straight at Karl every frame.
                    // Each soldier has his own cadence and yields to nearby comrades.
                    int stridePhase = (enemy.StateAge + enemy.Id * 13) % 54;
                    double cadence = stridePhase >= 47 ? 0.0 : stridePhase is < 5 or > 40 ? 0.55 : 1.0;
                    double speed = (enemy.Type switch
                    {
                        DungeonEnemyType.Pikeman => 0.27, DungeonEnemyType.SilverFogde => 0.22,
                        DungeonEnemyType.TuonelaGuard => 0.24, DungeonEnemyType.BlindShepherd => 0.18,
                        DungeonEnemyType.LemminkainenShadow => 0.34,
                        DungeonEnemyType.UndeadMiner => 0.30, _ => 0.39,
                    }) * cadence;
                    double desiredX = dx / distance * speed;
                    double desiredY = dy / distance * speed;
                    foreach (DungeonEnemy other in dungeon.Enemies)
                    {
                        if (other.Id == enemy.Id || other.State == DungeonEnemyState.Dead) continue;
                        double apartX = enemy.X - other.X;
                        double apartY = enemy.Y - other.Y;
                        double apartSquared = apartX * apartX + apartY * apartY;
                        if (apartSquared is > 0.01 and < 28 * 28)
                        {
                            double apart = Math.Sqrt(apartSquared);
                            double push = (28 - apart) / 28.0 * 0.24;
                            desiredX += apartX / apart * push;
                            desiredY += apartY / apart * push;
                        }
                    }
                    enemy.VelocityX += (desiredX - enemy.VelocityX) * 0.18;
                    enemy.VelocityY += (desiredY - enemy.VelocityY) * 0.18;
                    double beforeX = enemy.X;
                    double beforeY = enemy.Y;
                    MoveDungeonEnemy(dungeon, enemy, enemy.VelocityX, enemy.VelocityY);
                    enemy.GaitDistance += Math.Sqrt((enemy.X - beforeX) * (enemy.X - beforeX) + (enemy.Y - beforeY) * (enemy.Y - beforeY));
                }
            }
            else if (enemy.State == DungeonEnemyState.Telegraph && enemy.StateAge >
                (enemy.Type switch
                {
                    DungeonEnemyType.Pikeman => 30, DungeonEnemyType.SilverFogde => 42,
                    DungeonEnemyType.TuonelaGuard => 34, DungeonEnemyType.BlindShepherd => 52,
                    DungeonEnemyType.LemminkainenShadow => 30,
                    DungeonEnemyType.UndeadMiner => 26, _ => 22,
                }))
            {
                enemy.State = DungeonEnemyState.Attack;
                enemy.StateAge = 0;
            }
            else if (enemy.State == DungeonEnemyState.Attack)
            {
                int impact = enemy.Type switch
                {
                    DungeonEnemyType.Pikeman => 12, DungeonEnemyType.SilverFogde => 18,
                    DungeonEnemyType.TuonelaGuard => 15, DungeonEnemyType.BlindShepherd => 24,
                    DungeonEnemyType.LemminkainenShadow => 13,
                    DungeonEnemyType.UndeadMiner => 10, _ => 8,
                };
                if (enemy.StateAge == impact && distance <= attackRange + 9)
                {
                    if (dungeon.Guarding)
                    {
                        enemy.State = DungeonEnemyState.Stagger;
                        enemy.StateAge = 0;
                        dungeon.Power = Math.Min(100, dungeon.Power + 10);
                        dungeon.HitStop = 2;
                        _audio?.Trigger(StormaktSound.DungeonParry);
                    }
                    else
                    {
                        int damage = enemy.Type switch
                        {
                            DungeonEnemyType.Pikeman => 11, DungeonEnemyType.SilverFogde => 18,
                            DungeonEnemyType.TuonelaGuard => 12, DungeonEnemyType.BlindShepherd => 19,
                            DungeonEnemyType.LemminkainenShadow => 16,
                            DungeonEnemyType.UndeadMiner => 9, _ => 7,
                        };
                        ApplyDungeonDamage(dungeon, damage);
                        if (enemy.Type == DungeonEnemyType.TuonelaGuard) ApplyDungeonCurse(dungeon, 8);
                        if (enemy.Type == DungeonEnemyType.BlindShepherd) ApplyDungeonCurse(dungeon, 20);
                        if (enemy.Type == DungeonEnemyType.LemminkainenShadow) ApplyDungeonCurse(dungeon, 12);
                        dungeon.HurtAge = 18;
                        dungeon.HitStop = 3;
                    }
                }
                if (enemy.State == DungeonEnemyState.Attack && enemy.StateAge > impact + 8)
                {
                    enemy.State = DungeonEnemyState.Recover;
                    enemy.StateAge = 0;
                }
            }
            else if (enemy.State == DungeonEnemyState.Recover && enemy.StateAge > 24)
            {
                if (enemy.Type == DungeonEnemyType.LemminkainenShadow && enemy.SpecialSerial++ % 3 == 2)
                {
                    // The shadow slips sideways after every third assault;
                    // enough to unsettle without teleporting onto Karl.
                    double side = enemy.SpecialSerial % 2 == 0 ? 72 : -72;
                    double destinationX = Math.Clamp(enemy.X + side, 70, dungeon.RoomWidth - 70);
                    if (!DungeonBlocked(dungeon, destinationX, enemy.Y)) enemy.X = destinationX;
                }
                enemy.State = DungeonEnemyState.Approach;
                enemy.StateAge = 0;
            }
            if (enemy.State != DungeonEnemyState.Approach)
            {
                enemy.VelocityX *= 0.65;
                enemy.VelocityY *= 0.65;
            }
        }
        SeparateDungeonEnemies(dungeon);
        List<DungeonEnemy> roomEnemies = dungeon.Enemies.Where(enemy => enemy.Depth == dungeon.Depth).ToList();
        dungeon.RoomClear = roomEnemies.Count > 0 && roomEnemies.All(enemy => enemy.State == DungeonEnemyState.Dead);
        if (dungeon.RoomClear && !dungeon.RoomClearSaved)
        {
            dungeon.RoomClearSaved = true;
            WriteDungeonSave(dungeon, "autosave");
        }
    }

    private static void DropDungeonEnemyLoot(DungeonState dungeon, DungeonEnemy enemy)
    {
        if (enemy.LootDropped) return;
        enemy.LootDropped = true;
        int definition = enemy.Type switch
        {
            DungeonEnemyType.TuonelaSwan => 15,
            DungeonEnemyType.SilverFogde => 11,
            DungeonEnemyType.BlindShepherd => 12,
            DungeonEnemyType.LemminkainenShadow => 11,
            DungeonEnemyType.TuonelaGuard => 10,
            DungeonEnemyType.Pikeman => 4,
            _ => enemy.Id % 2 == 0 ? 7 : 8,
        };
        DungeonItemRarity rarity = enemy.Type switch
        {
            DungeonEnemyType.TuonelaSwan => DungeonItemRarity.Unique,
            DungeonEnemyType.SilverFogde => DungeonItemRarity.Unique,
            DungeonEnemyType.BlindShepherd => DungeonItemRarity.Unique,
            DungeonEnemyType.LemminkainenShadow => DungeonItemRarity.Unique,
            DungeonEnemyType.TuonelaGuard => DungeonItemRarity.Runic,
            DungeonEnemyType.Pikeman => DungeonItemRarity.Silverbound,
            _ => DungeonItemRarity.Iron,
        };
        DungeonItem loot = AddDungeonItem(dungeon, definition, -1, -1, DungeonEquipmentSlot.None, rarity);
        loot.OnGround = true;
        loot.WorldX = enemy.X;
        loot.WorldY = enemy.Y + 7;
        if (DungeonBlocked(dungeon, loot.WorldX, loot.WorldY))
        {
            (loot.WorldX, loot.WorldY) = FindNearestDungeonFloor(dungeon, enemy.X, enemy.Y);
        }
        int tinctureChance = dungeon.Health * 100 / Math.Max(1, dungeon.MaxHealth) < 45 ? 42 : 22;
        if (enemy.Type is DungeonEnemyType.SilverFogde or DungeonEnemyType.BlindShepherd or
            DungeonEnemyType.LemminkainenShadow or DungeonEnemyType.TuonelaSwan)
            tinctureChance = Math.Max(tinctureChance, 55);
        if (Random.Shared.Next(100) < tinctureChance)
        {
            DungeonItem tincture = AddDungeonItem(dungeon, 14, -1, -1, DungeonEquipmentSlot.None,
                DungeonItemRarity.Carolean);
            tincture.OnGround = true;
            tincture.WorldX = loot.WorldX + 15;
            tincture.WorldY = loot.WorldY + 4;
            if (DungeonBlocked(dungeon, tincture.WorldX, tincture.WorldY))
                (tincture.WorldX, tincture.WorldY) = FindNearestDungeonFloor(dungeon, enemy.X, enemy.Y);
        }
    }

    private static void DefeatDungeonEnemy(DungeonState dungeon, DungeonEnemy enemy)
    {
        DropDungeonEnemyLoot(dungeon, enemy);
        if (enemy.ExperienceAwarded) return;
        if (enemy.Type == DungeonEnemyType.BlindShepherd)
        {
            DungeonItem key = AddDungeonItem(dungeon, 13, -1, -1, DungeonEquipmentSlot.None, DungeonItemRarity.Unique);
            key.OnGround = true; key.WorldX = enemy.X + 18; key.WorldY = enemy.Y + 8;
        }
        enemy.ExperienceAwarded = true;
        dungeon.Experience += enemy.Type switch
        {
            DungeonEnemyType.TuonelaSwan => 600,
            DungeonEnemyType.SilverFogde => 180,
            DungeonEnemyType.BlindShepherd => 260,
            DungeonEnemyType.LemminkainenShadow => 340,
            DungeonEnemyType.TuonelaGuard => 65,
            DungeonEnemyType.UndeadMiner => 40,
            DungeonEnemyType.Pikeman => 45,
            _ => 30,
        };
        while (dungeon.Experience >= dungeon.Level * 100)
        {
            dungeon.Experience -= dungeon.Level * 100;
            dungeon.Level++;
            dungeon.MaxHealth += 15;
            dungeon.Health = dungeon.MaxHealth;
            dungeon.LevelPulse = 120;
        }
    }

    private static (double X, double Y) FindDungeonPickupApproach(DungeonState dungeon, DungeonItem item)
    {
        (double X, double Y) best = (item.WorldX, item.WorldY);
        double bestDistance = double.MaxValue;
        for (int index = 0; index < 16; index++)
        {
            double angle = index * Math.PI * 2 / 16;
            double x = item.WorldX + Math.Cos(angle) * 27;
            double y = item.WorldY + Math.Sin(angle) * 27;
            if (DungeonBlocked(dungeon, x, y)) continue;
            double distance = DistanceSquared(x, y, dungeon.KarlX, dungeon.KarlY);
            if (distance < bestDistance) { best = (x, y); bestDistance = distance; }
        }
        return best;
    }

    private static (double X, double Y) FindNearestDungeonFloor(DungeonState dungeon, double originX, double originY)
    {
        for (int radius = 12; radius <= 60; radius += 12)
        for (int index = 0; index < 16; index++)
        {
            double angle = index * Math.PI * 2 / 16;
            double x = originX + Math.Cos(angle) * radius;
            double y = originY + Math.Sin(angle) * radius;
            if (!DungeonBlocked(dungeon, x, y)) return (x, y);
        }
        return (originX, originY);
    }

    private static (double X, double Y) DungeonFacingVector(DungeonFacing facing) => facing switch
    {
        DungeonFacing.North => (0, -1), DungeonFacing.East => (1, 0),
        DungeonFacing.West => (-1, 0), _ => (0, 1),
    };

    private static void MoveDungeonEnemy(DungeonState dungeon, DungeonEnemy enemy, double dx, double dy)
    {
        bool recoveringFromObstacle = DungeonBlocked(dungeon, enemy.X, enemy.Y);
        if (recoveringFromObstacle || !DungeonBlocked(dungeon, enemy.X + dx, enemy.Y)) enemy.X += dx;
        recoveringFromObstacle = DungeonBlocked(dungeon, enemy.X, enemy.Y);
        if (recoveringFromObstacle || !DungeonBlocked(dungeon, enemy.X, enemy.Y + dy)) enemy.Y += dy;
    }

    private static void SeparateDungeonEnemies(DungeonState dungeon)
    {
        List<DungeonEnemy> enemies = dungeon.Enemies.Where(enemy => enemy.Depth == dungeon.Depth &&
            enemy.State != DungeonEnemyState.Dead &&
            enemy.Type is not (DungeonEnemyType.TuonelaSwan or DungeonEnemyType.Louhi))
            .OrderBy(enemy => enemy.Id).ToList();
        const double minimumDistance = 34;
        for (int left = 0; left < enemies.Count; left++)
        for (int right = left + 1; right < enemies.Count; right++)
        {
            DungeonEnemy a = enemies[left];
            DungeonEnemy b = enemies[right];
            double dx = b.X - a.X;
            double dy = b.Y - a.Y;
            double distanceSquared = dx * dx + dy * dy;
            if (distanceSquared >= minimumDistance * minimumDistance) continue;
            if (distanceSquared < 0.01)
            {
                dx = (a.Id + b.Id) % 2 == 0 ? 1 : -1;
                dy = (a.Id * 3 + b.Id) % 2 == 0 ? 0.5 : -0.5;
                distanceSquared = dx * dx + dy * dy;
            }
            double distance = Math.Sqrt(distanceSquared);
            double push = (minimumDistance - distance) * 0.5;
            double pushX = dx / distance * push;
            double pushY = dy / distance * push;
            MoveDungeonEnemy(dungeon, a, -pushX, -pushY);
            MoveDungeonEnemy(dungeon, b, pushX, pushY);
        }
    }

    private static void MoveDungeonKarl(DungeonState dungeon, double dx, double dy)
    {
        // Asset updates can make an old save start inside a newly enlarged
        // obstacle. Let that actor walk out, while still preventing entry from
        // every valid floor position.
        bool recoveringFromObstacle = DungeonBlocked(dungeon, dungeon.KarlX, dungeon.KarlY);
        double nextX = dungeon.KarlX + dx;
        if (recoveringFromObstacle || !DungeonBlocked(dungeon, nextX, dungeon.KarlY)) dungeon.KarlX = nextX;
        recoveringFromObstacle = DungeonBlocked(dungeon, dungeon.KarlX, dungeon.KarlY);
        double nextY = dungeon.KarlY + dy;
        if (recoveringFromObstacle || !DungeonBlocked(dungeon, dungeon.KarlX, nextY)) dungeon.KarlY = nextY;
    }

    private static bool DungeonBlocked(DungeonState dungeon, double x, double y)
    {
        if (x < 30 || x > dungeon.RoomWidth - 30 || y < 52 || y > dungeon.RoomHeight - 30) return true;
        if (dungeon.Depth == 2)
        {
            // Each visible timber is a separate horizontal obstacle. The old
            // implementation joined each pair into one tall invisible wall,
            // blocking the clearly visible passage between the sprites.
            ReadOnlySpan<(int X, int Y)> timbers =
            [
                (285, 175), (285, 245), (535, 470), (535, 610),
                (795, 165), (795, 310), (1030, 545), (1030, 675),
            ];
            foreach ((int timberX, int timberY) in timbers)
                if (Math.Abs(x - timberX) < 34 && Math.Abs(y - timberY) < 12) return true;
            return false;
        }
        if (dungeon.Depth == 3)
        {
            foreach ((int obstacleX, int obstacleY) in new[] { (300, 120), (610, 410), (850, 180), (1080, 650) })
                if (Math.Abs(x - obstacleX) < 35 && Math.Abs(y - obstacleY) < 22) return true;
            foreach ((int obstacleX, int obstacleY) in new[] { (260, 650), (700, 250), (1010, 580), (1220, 210) })
                if (Math.Abs(x - obstacleX) < 30 && Math.Abs(y - obstacleY) < 24) return true;
            return false;
        }
        if (dungeon.Depth == 4)
        {
            bool shadowDefeated = dungeon.Enemies.Any(enemy => enemy.Depth == 4 &&
                enemy.Type == DungeonEnemyType.LemminkainenShadow && enemy.State == DungeonEnemyState.Dead);
            if (!shadowDefeated && x is > 1145 and < 1185) return true;
            if ((dungeon.LoreMask & DungeonFirstSigilMask) == 0 && x is > 1685 and < 1725) return true;
            if ((dungeon.LoreMask & DungeonSecondSigilMask) == 0 && x is > 2365 and < 2405) return true;
            if ((dungeon.LoreMask & DungeonThirdSigilMask) == 0 && x is > 3130 and < 3170) return true;
            if ((dungeon.LoreMask & DungeonSwanDefeatedMask) == 0 && x is > 3535 and < 3575) return true;
            if ((dungeon.LoreMask & DungeonLouhiStartedMask) != 0 &&
                (dungeon.LoreMask & DungeonLouhiPhaseThreeMask) == 0 && dungeon.KarlX >= 3990 &&
                x is > 3950 and < 3990) return true;
            foreach ((int obstacleX, int obstacleY) in new[] { (455, 360), (810, 500), (1050, 275) })
                if (Math.Abs(x - obstacleX) < 35 && Math.Abs(y - obstacleY) < 22) return true;
            foreach ((int obstacleX, int obstacleY) in new[] { (300, 650), (700, 110), (1110, 600) })
                if (Math.Abs(x - obstacleX) < 30 && Math.Abs(y - obstacleY) < 24) return true;
            foreach ((int obstacleX, int obstacleY) in DungeonTempleGuardianStatues)
                if (Math.Abs(x - obstacleX) < 44 && Math.Abs(y - obstacleY) < 62) return true;
            foreach ((int altarX, int altarY) in new[] { (1580, 380), (2280, 380), (3030, 380) })
                if (Math.Abs(x - altarX) < 60 && Math.Abs(y - altarY) < 46) return true;
            foreach ((int obstacleX, int obstacleY) in DungeonTempleClosedSarcophagi)
                if (Math.Abs(x - obstacleX) < 62 && Math.Abs(y - obstacleY) < 48) return true;
            foreach ((int obstacleX, int obstacleY) in DungeonTempleOpenSarcophagi)
                if (Math.Abs(x - obstacleX) < 66 && Math.Abs(y - obstacleY) < 56) return true;
            foreach ((int obstacleX, int obstacleY) in DungeonSecondTempleRunes)
                if (Math.Abs(x - obstacleX) < 44 && Math.Abs(y - obstacleY) < 62) return true;
            foreach ((int obstacleX, int obstacleY) in DungeonThirdTempleSteles)
                if (Math.Abs(x - obstacleX) < 22 && Math.Abs(y - obstacleY) < 12) return true;
            foreach ((int obstacleX, int obstacleY) in DungeonLouhiProcessionStatues)
                if (Math.Abs(x - obstacleX) < 30 && Math.Abs(y - obstacleY) < 40) return true;
            foreach ((int obstacleX, int obstacleY) in DungeonLouhiProcessionSarcophagi)
                if (Math.Abs(x - obstacleX) < 62 && Math.Abs(y - obstacleY) < 48) return true;
            // Only the grounded feet block movement; Karl may walk close to the broad wings.
            if ((dungeon.LoreMask & DungeonSwanDefeatedMask) == 0 &&
                Math.Abs(x - 3400) < 30 && Math.Abs(y - 380) < 18) return true;
            if (Math.Abs(x - 4170) < 30 && Math.Abs(y - 380) < 18) return true;
            DungeonEnemy? louhi = dungeon.Enemies.FirstOrDefault(enemy => enemy.Depth == 4 &&
                enemy.Type == DungeonEnemyType.Louhi && enemy.State != DungeonEnemyState.Dead);
            if (louhi is not null && Math.Abs(x - louhi.X) < 24 && Math.Abs(y - louhi.Y) < 17) return true;
            return false;
        }
        bool leftPillar = x > 253 && x < 307 && y > 124 && y < 212;
        bool rightStore = x > 438 && x < 507 && y > 268 && y < 340;
        return leftPillar || rightStore;
    }

    private static void WriteDungeonSave(DungeonState dungeon, string slot)
    {
        ValidateDungeonInventory(dungeon);
        try
        {
            string stateRoot = Environment.GetEnvironmentVariable("XDG_STATE_HOME") ??
                Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), ".local", "state");
            string directory = Path.Combine(stateRoot, "waylandforge", "stormakt3020", "saves");
            Directory.CreateDirectory(directory);
            string path = Path.Combine(directory, slot + ".json");
            string temporary = path + ".tmp";
            string backup = path + ".bak";
            var snapshot = new DungeonSave(11, dungeon.Age, dungeon.RoomWidth, dungeon.RoomHeight,
                dungeon.KarlX, dungeon.KarlY, dungeon.TargetX, dungeon.TargetY, dungeon.Facing,
                dungeon.Health, dungeon.MaxHealth, dungeon.Power, dungeon.NextItemId,
                dungeon.Items.Select(item => new DungeonItemSave(item.Id, item.Definition, item.GridX, item.GridY,
                    item.Equipped, item.Rarity, item.PowerRoll, item.OnGround, item.InStash, item.WorldX, item.WorldY,
                    item.QuickSlot)).ToList(),
                dungeon.NextEnemyId, dungeon.AttackSerial, dungeon.AttackCombo, dungeon.RoomClear, dungeon.DoorReady,
                dungeon.Depth, dungeon.DoorHealth, dungeon.DescentWarningPlayed, dungeon.MaxZoneReached,
                dungeon.Level, dungeon.Experience, dungeon.DepthThreeOpen, dungeon.ForcedVentAge,
                dungeon.Curse, dungeon.TempleOpen, dungeon.LoreMask,
                dungeon.Enemies.Select(enemy => new DungeonEnemySave(enemy.Id, enemy.X, enemy.Y, enemy.Type,
                    enemy.Health, enemy.MaxHealth, enemy.State, enemy.StateAge, enemy.LastHitSerial, enemy.FacingLeft,
                    enemy.LootDropped, enemy.Zone, enemy.ExperienceAwarded, enemy.Phase, enemy.SpecialKind,
                    enemy.SpecialAge, enemy.SpecialCooldown, enemy.SpecialSerial, enemy.Depth)).ToList(),
                dungeon.Chests.Select(chest => new DungeonChestSave(chest.Id, chest.X, chest.Y, chest.Open,
                    chest.OpenAge, chest.Depth)).ToList());
            File.WriteAllText(temporary, JsonSerializer.Serialize(snapshot));
            if (File.Exists(path)) File.Copy(path, backup, true);
            File.Move(temporary, path, true);
        }
        catch (IOException exception)
        {
            Console.Error.WriteLine($"Stormakt save warning: {exception.Message}");
        }
    }

    private static void ValidateDungeonInventory(DungeonState dungeon)
    {
        if (dungeon.Items.Select(item => item.Id).Distinct().Count() != dungeon.Items.Count)
            throw new InvalidOperationException("Dungeon inventory contains duplicate item ids.");
        if (dungeon.Items.Where(item => item.Equipped != DungeonEquipmentSlot.None)
            .GroupBy(item => item.Equipped).Any(group => group.Count() > 1))
            throw new InvalidOperationException("Dungeon inventory contains duplicate equipment slots.");
        if (dungeon.Items.Where(item => item.QuickSlot >= 0).Any(item => item.Definition != 14 || item.QuickSlot >= 4) ||
            dungeon.Items.Where(item => item.QuickSlot >= 0).GroupBy(item => item.QuickSlot).Any(group => group.Count() > 1))
            throw new InvalidOperationException("Dungeon potion belt contains an invalid quick slot.");
        foreach (DungeonItem item in dungeon.Items)
        {
            int owners = (item.OnGround ? 1 : 0) + (item.Equipped != DungeonEquipmentSlot.None ? 1 : 0) +
                (item.QuickSlot >= 0 ? 1 : 0) +
                (!item.OnGround && item.Equipped == DungeonEquipmentSlot.None && item.QuickSlot < 0 && item.GridX >= 0 ? 1 : 0);
            if (owners != 1) throw new InvalidOperationException($"Dungeon item {item.Id} has invalid ownership.");
            if (item.GridX >= 0 && !CanPlaceDungeonItem(dungeon, item, item.GridX, item.GridY))
                throw new InvalidOperationException($"Dungeon item {item.Id} overlaps or exceeds its container.");
        }
        if (dungeon.Enemies.Select(enemy => enemy.Id).Distinct().Count() != dungeon.Enemies.Count)
            throw new InvalidOperationException("Dungeon encounter contains duplicate enemy ids.");
    }

    private static bool TryLoadDungeonSave(string slot, out DungeonState? dungeon)
    {
        dungeon = null;
        string path = DungeonSavePath(slot);
        foreach (string candidate in new[] { path, path + ".bak" })
        {
            try
            {
                if (!File.Exists(candidate)) continue;
                DungeonSave save = JsonSerializer.Deserialize<DungeonSave>(File.ReadAllText(candidate));
                if (save.Schema is < 1 or > 11 || save.RoomWidth < 320 || save.RoomHeight < 220) continue;
                dungeon = new DungeonState
                {
                    Age = save.Age,
                    RoomWidth = save.RoomWidth,
                    RoomHeight = save.RoomHeight,
                    KarlX = save.KarlX,
                    KarlY = save.KarlY,
                    TargetX = save.TargetX,
                    TargetY = save.TargetY,
                    Facing = save.Facing,
                    Health = save.Schema >= 2 ? save.Health : 100,
                    MaxHealth = save.Schema >= 2 ? save.MaxHealth : 100,
                    Power = save.Schema >= 2 ? save.Power : 35,
                    NextItemId = save.Schema >= 2 ? save.NextItemId : 1,
                    NextEnemyId = save.Schema >= 3 ? save.NextEnemyId : 1,
                    AttackSerial = save.Schema >= 3 ? save.AttackSerial : 0,
                    AttackCombo = save.Schema >= 3 ? save.AttackCombo : 0,
                    RoomClear = save.Schema >= 3 && save.RoomClear,
                    RoomClearSaved = save.Schema >= 3 && save.RoomClear,
                    DoorReady = save.Schema >= 4 && save.DoorReady,
                    Depth = save.Schema >= 5 ? save.Depth : 1,
                    DoorHealth = save.Schema >= 5 ? save.DoorHealth : save.DoorReady ? 0 : 3,
                    DescentWarningPlayed = save.Schema >= 6 ? save.DescentWarningPlayed : save.DoorReady,
                    MaxZoneReached = save.Schema >= 7 ? save.MaxZoneReached : save.Depth == 2 ? DungeonZoneFromX(save.KarlX) : 0,
                    Level = save.Schema >= 8 ? Math.Max(1, save.Level) : 1,
                    Experience = save.Schema >= 8 ? Math.Max(0, save.Experience) : 0,
                    DepthThreeOpen = save.Schema >= 9 && save.DepthThreeOpen,
                    ForcedVentAge = save.Schema >= 9 ? save.ForcedVentAge : 0,
                    Curse = save.Schema >= 10 ? save.Curse : 0,
                    TempleOpen = save.Schema >= 10 && save.TempleOpen,
                    LoreMask = save.Schema >= 10 ? save.LoreMask : 0,
                };
                if (save.Schema >= 2 && save.Items is not null)
                {
                    bool templeKeyLoaded = false;
                    foreach (DungeonItemSave item in save.Items)
                    {
                        if (item.Definition < 0 || item.Definition >= DungeonItemDefinitions.Length) continue;
                        if (item.Definition == 13 && templeKeyLoaded) continue;
                        if (item.Definition == 13) templeKeyLoaded = true;
                        dungeon.Items.Add(new DungeonItem
                        {
                            Id = item.Id, Definition = item.Definition, GridX = item.GridX, GridY = item.GridY,
                            Equipped = item.Equipped, Rarity = item.Rarity, PowerRoll = item.PowerRoll,
                            OnGround = item.OnGround, InStash = item.InStash, WorldX = item.WorldX, WorldY = item.WorldY,
                            QuickSlot = save.Schema >= 11 ? item.QuickSlot : -1,
                        });
                    }
                }
                else SeedDungeonInventory(dungeon);
                if (save.Schema >= 3 && save.Enemies is not null)
                {
                    foreach (DungeonEnemySave enemy in save.Enemies)
                    {
                        var loaded = new DungeonEnemy(enemy.X, enemy.Y, enemy.Type, enemy.MaxHealth)
                        {
                            Id = enemy.Id, Health = enemy.Health, State = enemy.State, StateAge = enemy.StateAge,
                            LastHitSerial = enemy.LastHitSerial, FacingLeft = enemy.FacingLeft,
                            LootDropped = save.Schema >= 4 && enemy.LootDropped,
                            Zone = save.Schema >= 7 ? enemy.Zone : save.Depth == 2 ? DungeonZoneFromX(enemy.X) : 0,
                            ExperienceAwarded = save.Schema >= 8 && enemy.ExperienceAwarded,
                            Phase = save.Schema >= 9 ? enemy.Phase : 1,
                            SpecialKind = save.Schema >= 9 ? enemy.SpecialKind : 0,
                            SpecialAge = save.Schema >= 9 ? enemy.SpecialAge : 0,
                            SpecialCooldown = save.Schema >= 9 ? enemy.SpecialCooldown : 0,
                            SpecialSerial = save.Schema >= 9 ? enemy.SpecialSerial : 0,
                            Depth = save.Schema >= 10 ? enemy.Depth : enemy.Type is DungeonEnemyType.Stormer or
                                DungeonEnemyType.Pikeman or DungeonEnemyType.SilverFogde ? 2 : save.Depth,
                        };
                        dungeon.Enemies.Add(loaded);
                    }
                }
                else SeedDungeonEncounter(dungeon);
                if (save.Schema < 7 && dungeon.Depth == 2 &&
                    dungeon.Enemies.All(enemy => enemy.Type != DungeonEnemyType.SilverFogde))
                {
                    AddDungeonEnemy(dungeon, 1060, 390, DungeonEnemyType.SilverFogde, 240, 3);
                    dungeon.RoomClear = false;
                    dungeon.RoomClearSaved = false;
                }
                if (save.Schema >= 5 && save.Chests is not null)
                    foreach (DungeonChestSave chest in save.Chests)
                        dungeon.Chests.Add(new DungeonChest(chest.Id, chest.X, chest.Y)
                            { Open = chest.Open, OpenAge = save.Schema >= 7 ? chest.OpenAge : chest.Open ? 45 : 0,
                              Depth = save.Schema >= 10 ? chest.Depth : chest.Id <= 3 ? 2 : save.Depth });
                if (dungeon.Depth == 4)
                {
                    dungeon.RoomWidth = Math.Max(4480, dungeon.RoomWidth);
                    dungeon.RoomHeight = Math.Max(760, dungeon.RoomHeight);
                    if (!dungeon.Enemies.Any(enemy => enemy.Depth == 4 && enemy.Type == DungeonEnemyType.LemminkainenShadow))
                    {
                        AddDungeonEnemy(dungeon, 1040, 380, DungeonEnemyType.LemminkainenShadow, 420, 43);
                        dungeon.Enemies.Last().Phase = 0;
                    }
                    if (dungeon.Chests.All(chest => chest.Id != 41))
                        dungeon.Chests.Add(new DungeonChest(41, 610, 135) { Depth = 4 });
                    if (dungeon.Chests.All(chest => chest.Id != 42))
                        dungeon.Chests.Add(new DungeonChest(42, 1010, 665) { Depth = 4 });
                    EnsureDungeonFirstSigilEncounter(dungeon);
                    EnsureDungeonSecondSigilEncounter(dungeon);
                    if ((dungeon.LoreMask & DungeonSwanRevealedMask) != 0 &&
                        (dungeon.LoreMask & DungeonSwanDefeatedMask) == 0)
                        EnsureDungeonSwanEncounter(dungeon);
                    if ((dungeon.LoreMask & DungeonLouhiStartedMask) != 0)
                        EnsureDungeonLouhiEncounter(dungeon);
                }
                dungeon.CameraX = Math.Clamp((int)Math.Round(dungeon.KarlX - 200), 0, Math.Max(0, dungeon.RoomWidth - 400));
                dungeon.CameraY = Math.Clamp((int)Math.Round(dungeon.KarlY - 140), 0, Math.Max(0, dungeon.RoomHeight - 280));
                return true;
            }
            catch (JsonException)
            {
                // Try the backup before giving up.
            }
            catch (IOException)
            {
                // A temporarily unavailable save must not block a fresh campaign.
            }
        }
        return false;
    }

    private static string DungeonSavePath(string slot)
    {
        string stateRoot = Environment.GetEnvironmentVariable("XDG_STATE_HOME") ??
            Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), ".local", "state");
        return Path.Combine(stateRoot, "waylandforge", "stormakt3020", "saves", slot + ".json");
    }

    private void WriteCampaignSave(int freedShips)
    {
        if (_suppressCampaignWrites || _activeLoadout is not StormaktLoadout loadout) return;
        try
        {
            string path = DungeonSavePath("campaign");
            Directory.CreateDirectory(Path.GetDirectoryName(path)!);
            string temporary = path + ".tmp";
            var save = new StormaktCampaignSave(2, loadout.PrimaryModule, loadout.BroadsideModule,
                loadout.ShipModule, Math.Max(0, freedShips),
                _snapphaneWorld?.Route ?? SnapphaneRoute.None,
                Math.Max(0, _snapphaneWorld?.SnapphaneAllies ?? 0),
                _snapphaneWorld?.SorenOathComplete ?? false);
            File.WriteAllText(temporary, JsonSerializer.Serialize(save));
            File.Move(temporary, path, true);
        }
        catch (IOException exception)
        {
            Console.Error.WriteLine($"Stormakt campaign save warning: {exception.Message}");
        }
    }

    private static bool TryLoadCampaignSave(out StormaktCampaignSave save)
    {
        save = default;
        try
        {
            string path = DungeonSavePath("campaign");
            if (!File.Exists(path)) return false;
            save = JsonSerializer.Deserialize<StormaktCampaignSave>(File.ReadAllText(path));
            return save.Schema is 1 or 2 && Enum.IsDefined(save.PrimaryModule) &&
                Enum.IsDefined(save.BroadsideModule) && Enum.IsDefined(save.ShipModule) &&
                (save.Schema == 1 || Enum.IsDefined(save.SnapphaneRoute));
        }
        catch (JsonException)
        {
            return false;
        }
        catch (IOException)
        {
            return false;
        }
    }

