    private static bool TryLoadCopenhagenGroundSave(out CopenhagenGroundSave save)
    {
        save = default;
        string path = DungeonSavePath("copenhagen-holmen");
        foreach (string candidate in new[] { path, path + ".bak" })
        {
            try
            {
                if (!File.Exists(candidate)) continue;
                save = JsonSerializer.Deserialize<CopenhagenGroundSave>(File.ReadAllText(candidate));
                if (save.Schema is >= 1 and <= 8 && save.Width >= 320 && save.Height >= 224 && save.MaxHealth > 0 &&
                    save.Enemies is { Count: <= 16 } && Enum.IsDefined(save.ActiveMarginal) &&
                    Enum.IsDefined(save.ActiveLegend) && Enum.IsDefined(save.CompiledLegend) &&
                    Enum.IsDefined(save.LocalLaw) && Enum.IsDefined(save.KorrektoriusCorruption) &&
                    Enum.IsDefined(save.WrathRoyalLaw) &&
                    (save.KorrektoriusPenHealth is null or { Length: <= 4 }) &&
                    (save.WrathWordHealth is null or { Length: <= 3 })) return true;
            }
            catch (JsonException)
            {
            }
            catch (IOException)
            {
            }
        }
        save = default;
        return false;
    }

    private void RestoreCopenhagenGround(CopenhagenWorldState state, CopenhagenGroundSave save)
    {
        state.GroundActive = true;
        state.LandingActive = false;
        double scaleX = _width / (double)save.Width;
        double scaleY = _height / (double)save.Height;
        var ground = new CopenhagenGroundState
        {
            Age = Math.Max(0, save.Age),
            KarlX = Math.Clamp(save.KarlX * scaleX, 18, _width - 18),
            KarlY = Math.Clamp(save.KarlY * scaleY, 47, _height - 17),
            Health = Math.Clamp(save.Health, 1, save.MaxHealth),
            MaxHealth = save.MaxHealth,
            Potions = Math.Max(0, save.Potions),
            RoomClear = save.RoomClear,
            DoorReady = save.DoorReady,
            FacingX = 0,
            FacingY = -1,
            Room = save.Schema >= 2 ? Math.Clamp(save.Room, 0, save.Schema >= 8 ? 7 : 6) : 0,
            ActiveMarginal = save.Schema >= 2 ? save.ActiveMarginal : CopenhagenMarginalLaw.None,
            HeartPortOpen = save.Schema >= 2 && save.HeartPortOpen,
            ArsenalCannonHealth = save.Schema >= 2 ? Math.Max(0, save.ArsenalCannonHealth) : 0,
            RosenborgCoreHealth = save.Schema >= 3 ? Math.Max(0, save.RosenborgCoreHealth) : 0,
            MaterialShieldCooldown = save.Schema >= 3 ? Math.Max(0, save.MaterialShieldCooldown) : 0,
            ActiveLegend = save.Schema >= 4 ? save.ActiveLegend : CopenhagenLegend.None,
            LegendIntegrity = save.Schema >= 4 ? Math.Max(0, save.LegendIntegrity) : 0,
            LegendX = save.Schema >= 4 ? Math.Clamp(save.LegendX * scaleX, 18, _width - 18) : _width / 2.0,
            LegendY = save.Schema >= 4 ? Math.Clamp(save.LegendY * scaleY, 47, _height - 17) : _height - 72,
            LegendCorrupted = save.Schema >= 4 && save.LegendCorrupted,
            LegendLastOrderAge = save.Schema >= 4 ? Math.Max(0, save.LegendLastOrderAge) : 0,
            LegendVx = save.Schema >= 4 ? save.LegendVx : 0,
            LegendVy = save.Schema >= 4 ? save.LegendVy : -1,
            CompiledLegend = save.Schema >= 5 ? save.CompiledLegend : save.ActiveLegend,
            SagaKingHealth = save.Schema >= 5 ? Math.Max(0, save.SagaKingHealth) : 0,
            SagaKingAge = save.Schema >= 5 ? Math.Max(0, save.SagaKingAge) : 0,
            SagaTargetX = save.Schema >= 5 ? save.SagaTargetX * scaleX : _width / 2.0,
            SagaTargetY = save.Schema >= 5 ? save.SagaTargetY * scaleY : _height / 2.0,
            SagaOrderSerial = save.Schema >= 5 ? Math.Max(0, save.SagaOrderSerial) : 0,
            SagaHorseX = save.Schema >= 5 ? save.SagaHorseX * scaleX : _width / 2.0,
            SagaHorseDirection = save.Schema >= 5 && save.SagaHorseDirection < 0 ? -1 : 1,
            LocalLaw = save.Schema >= 6 ? save.LocalLaw : CopenhagenLocalLaw.None,
            KorrektoriusHealth = save.Schema >= 6 ? Math.Max(0, save.KorrektoriusHealth) : 0,
            KorrektoriusAge = save.Schema >= 6 ? Math.Max(0, save.KorrektoriusAge) : 0,
            KorrektoriusActivePen = save.Schema >= 6 ? Math.Clamp(save.KorrektoriusActivePen, -1, 3) : -1,
            KorrektoriusOrderSerial = save.Schema >= 6 ? Math.Max(0, save.KorrektoriusOrderSerial) : 0,
            KorrektoriusCorruption = save.Schema >= 6
                ? save.KorrektoriusCorruption : CopenhagenCorruption.None,
            KorrektoriusCorruptionAge = save.Schema >= 6 ? Math.Max(0, save.KorrektoriusCorruptionAge) : 0,
            KorrektoriusTargetX = save.Schema >= 6 ? save.KorrektoriusTargetX * scaleX : _width / 2.0,
            KorrektoriusTargetY = save.Schema >= 6 ? save.KorrektoriusTargetY * scaleY : _height / 2.0,
            WrathHealth = save.Schema >= 7 ? Math.Max(0, save.WrathHealth) : 0,
            WrathAge = save.Schema >= 7 ? Math.Max(0, save.WrathAge) : 0,
            WrathRoyalLaw = save.Schema >= 7 ? save.WrathRoyalLaw : CopenhagenRoyalLaw.FlightClaim,
            WrathOrderSerial = save.Schema >= 7 ? Math.Max(0, save.WrathOrderSerial) : 0,
            WrathTargetX = save.Schema >= 7 ? save.WrathTargetX * scaleX : _width / 2.0,
            WrathTargetY = save.Schema >= 7 ? save.WrathTargetY * scaleY : _height / 2.0,
            WrathCircuitStandAge = save.Schema >= 7 ? Math.Max(0, save.WrathCircuitStandAge) : 0,
            CodexOpened = save.Schema >= 8 && save.CodexOpened,
            CodexAge = save.Schema >= 8 ? Math.Max(0, save.CodexAge) : 0,
        };
        if (save.Schema >= 6 && save.KorrektoriusPenHealth is { } savedPens)
            for (int pen = 0; pen < Math.Min(ground.KorrektoriusPenHealth.Length, savedPens.Length); pen++)
                ground.KorrektoriusPenHealth[pen] = Math.Max(0, savedPens[pen]);
        if (ground.Room == 5 && ground.LocalLaw == CopenhagenLocalLaw.None)
        {
            ground.LocalLawChoosing = true;
            ground.LocalLawSelection = 0;
        }
        if (save.Schema >= 7 && save.WrathWordHealth is { } savedWords)
            for (int word = 0; word < Math.Min(ground.WrathWordHealth.Length, savedWords.Length); word++)
                ground.WrathWordHealth[word] = Math.Max(0, savedWords[word]);
        if (ground.LegendCorrupted && Math.Abs(ground.LegendVx) + Math.Abs(ground.LegendVy) < 0.1)
            ground.LegendVx = 3.4;
        ground.TargetX = ground.KarlX;
        ground.TargetY = ground.KarlY;
        foreach (CopenhagenGroundEnemySave enemy in save.Enemies)
        {
            var restored = new CopenhagenGroundEnemy(enemy.Id,
                Math.Clamp(enemy.X * scaleX, 18, _width - 18),
                Math.Clamp(enemy.Y * scaleY, 47, _height - 17), Math.Max(1, enemy.MaxHealth))
            {
                Health = Math.Clamp(enemy.Health, 0, Math.Max(1, enemy.MaxHealth)),
                DeathAge = Math.Max(0, enemy.DeathAge),
            };
            ground.Enemies.Add(restored);
        }
        state.Ground = ground;
        _enemyShots.Clear();
        _shots.Clear();
    }

    private static double DistanceSquared(double x1, double y1, double x2, double y2)
    {
        double dx = x2 - x1;
        double dy = y2 - y1;
        return dx * dx + dy * dy;
    }

    private static (double X, double Y) MoveRtsAroundTerrain(
        RtsState rts, double x, double y, double stepX, double stepY, double radius)
    {
        if (!RtsTerrainBlocked(rts, x + stepX, y + stepY, radius)) return (x + stepX, y + stepY);
        double sideX = -stepY;
        double sideY = stepX;
        if (!RtsTerrainBlocked(rts, x + sideX, y + sideY, radius)) return (x + sideX, y + sideY);
        if (!RtsTerrainBlocked(rts, x - sideX, y - sideY, radius)) return (x - sideX, y - sideY);
        return (x, y);
    }

    private static bool RtsTerrainBlocked(RtsState rts, double x, double y, double radius) =>
        rts.Props.Any(prop => prop.BlockRadius > 0 &&
            DistanceSquared(x, y, prop.X, prop.Y) < (radius + prop.BlockRadius) * (radius + prop.BlockRadius));

    private static bool RtsHasPower(RtsState rts)
    {
        int total = rts.Buildings.Any(building => building.Type == RtsBuildingType.SteamPlant) ? 100 : 0;
        int used = rts.Buildings.Sum(building => building.Type switch
        {
            RtsBuildingType.SilverCrusher => 40,
            RtsBuildingType.Barracks => 20,
            RtsBuildingType.AnimalHall => 30,
            RtsBuildingType.DefenseTower => 10,
            _ => 0,
        });
        return total >= used;
    }

    private void StepRadio()
    {
        StepBossRadioQueue();
        ReadOnlySpan<RadioCard> cards = _levelId switch
        {
            1 => SkanskaRadioCards,
            2 => OresundRadioCards,
            4 => TitheRadioCards,
            5 => [],
            6 => [],
            _ => RadioCards,
        };
        foreach (RadioCard card in cards)
        {
            if (_missionFrame == card.StartFrame)
            {
                if (card.Voice is StormaktVoice voice)
                {
                    _audio?.TriggerVoice(voice);
                }
            }
        }
        _missionFrame++;
    }

    private void ActivateBossRadio(RadioCard card)
    {
        if (_bossRadioCard is not null)
        {
            if (_bossRadioCard.Value.Equals(card) || _bossRadioQueue.Contains(card)) return;
            _bossRadioQueue.Enqueue(card);
            return;
        }
        StartBossRadio(card);
    }

    private void StartBossRadio(RadioCard card)
    {
        _bossRadioCard = card;
        _bossRadioAge = 0;
        if (card.Voice is StormaktVoice voice)
        {
            _audio?.TriggerVoice(voice);
        }
    }

    private void StepBossRadioQueue()
    {
        if (_bossRadioCard is not RadioCard active) return;
        if (++_bossRadioAge < active.DurationFrames) return;
        _bossRadioCard = null;
        _bossRadioAge = 0;
        if (_bossRadioQueue.Count > 0) StartBossRadio(_bossRadioQueue.Dequeue());
    }

    private void ClearBossRadio()
    {
        _bossRadioCard = null;
        _bossRadioAge = 0;
        _bossRadioQueue.Clear();
    }

    private void StepLevelTimeline()
    {
        if (_levelId == 2 && _missionFrame == 600 && _bridgeSection is BridgeSectionState section)
        {
            BeginOresundBridgeSection(section);
        }
        if (_levelId == 2 && _missionFrame == 1_800 && _bridgeSection is BridgeSectionState flapSection)
        {
            BeginOresundFlapSection(flapSection);
        }
        if (_levelId == 2 && _missionFrame == 2_700 && _bridgeSection is BridgeSectionState trainSection)
        {
            BeginOresundTrainSection(trainSection);
        }
        if (_levelId == 2 && _missionFrame == 3_540 && _bridgeSection is BridgeSectionState resolvedSection)
        {
            BeginOresundSoren(resolvedSection);
        }
        if (_levelId == 2 && _missionFrame == 4_500 && _oresundBoss is null)
        {
            BeginOresundFortressBoss();
        }
        if (_levelId == 2 && _missionFrame >= FlythroughFrames && _oresundBoss is null && !_stageClear)
        {
            _stageClear = true;
            _stageClearAge = 0;
            _enemies.Clear();
            _enemyShots.Clear();
            _shots.Clear();
            _audio?.Trigger(StormaktSound.Deploy);
            return;
        }
        if (_levelId == 1 && _missionFrame == 2_700 && _sorenRival is null)
        {
            _sorenRival = new SorenRivalState
            {
                X = _width / 2.0,
                Y = 68,
                Health = 140,
            };
            _enemies.Clear();
            _audio?.Trigger(StormaktSound.Deploy);
        }
    }

    private void ResetCopenhagenWorld(CopenhagenWorldState state)
    {
        state.Age = 0;
        state.GateHealth[0] = CopenhagenGateNodeMaxHealth;
        state.GateHealth[1] = CopenhagenGateNodeMaxHealth;
        state.GateHealth[2] = CopenhagenGateNodeMaxHealth;
    }

    private void StepCopenhagenWorld()
    {
        if (_copenhagenWorld is not CopenhagenWorldState state || _stageClear) return;

        state.Age++;
        if (state.Age == 20) ActivateBossRadio(CopenhagenApproachRadio);
        if (!state.GateActive && state.Age >= 240)
        {
            state.GateActive = true;
            state.GateIntroAge = 0;
            _enemyShots.Clear();
            ActivateBossRadio(CopenhagenGateRadio);
            _audio?.SwitchMusic(StormaktMusicTrack.Boss);
            _audio?.Trigger(StormaktSound.Deploy);
        }

        if (!state.GateActive)
        {
            StepEnemyShots();
            return;
        }

        if (state.LandingActive)
        {
            StepCopenhagenLanding(state);
            StepEnemyShots();
            return;
        }

        if (state.SuperActive)
        {
            StepCopenhagenSuperfrigate(state);
            StepEnemyShots();
            return;
        }

        if (state.DuoActive)
        {
            StepCopenhagenDuo(state);
            StepEnemyShots();
            return;
        }

        if (state.DannebrogActive)
        {
            StepCopenhagenDannebrog(state);
            StepEnemyShots();
            return;
        }

        if (state.EyeActive)
        {
            StepCopenhagenEye(state);
            StepEnemyShots();
            return;
        }

        if (state.FrederikActive)
        {
            StepCopenhagenFrederik(state);
            StepEnemyShots();
            return;
        }

        if (state.AdmiraltyActive)
        {
            StepCopenhagenAdmiralty(state);
            StepEnemyShots();
            return;
        }

        state.GateIntroAge++;
        state.HitFlash = Math.Max(0, state.HitFlash - 1);
        state.RepairFlash = Math.Max(0, state.RepairFlash - 1);
        state.BarrierFlash = Math.Max(0, state.BarrierFlash - 1);
        StepCopenhagenGateShots(state);
        StepCopenhagenGateAttacks(state);
        StepCopenhagenBarrier(state);
        StepEnemyShots();

        if (state.GateHealth.Any(health => health > 0)) return;

        state.GateFallAge++;
        if (state.GateFallAge == 1)
        {
            _enemyShots.Clear();
            _shots.Clear();
            _score += 2_000;
            ActivateBossRadio(CopenhagenGateFallRadio);
            _audio?.Trigger(StormaktSound.Broadside);
        }
        if (state.GateFallAge is 24 or 52 or 86)
            _audio?.Trigger(StormaktSound.EnemyExplosion);
        if (state.GateFallAge < 240 || _bossRadioCard is not null) return;
        BeginCopenhagenAdmiralty(state);
    }

    private void BeginCopenhagenAdmiralty(CopenhagenWorldState state, bool testFixture = false)
    {
        state.AdmiraltyActive = true;
        state.AdmiraltyAge = 0;
        state.AdmiraltyHealth = testFixture ? 96 : CopenhagenAdmiraltyMaxHealth;
        state.AdmiraltyDeathAge = 0;
        state.AdmiraltyHitFlash = 0;
        state.CurrentHour = 0;
        for (int hour = 0; hour < state.HourHealth.Length; hour++)
        {
            state.HourHealth[hour] = testFixture ? 9 : CopenhagenHourMarkMaxHealth;
            state.HourArmed[hour] = false;
        }
        _enemyShots.Clear();
        _shots.Clear();
        if (testFixture) return;
        ActivateBossRadio(CopenhagenAdmiraltyRadio);
        _audio?.Trigger(StormaktSound.OresundFortressLock);
    }

    private void StepCopenhagenAdmiralty(CopenhagenWorldState state)
    {
        state.AdmiraltyAge++;
        state.AdmiraltyHitFlash = Math.Max(0, state.AdmiraltyHitFlash - 1);
        state.HourHitFlash = Math.Max(0, state.HourHitFlash - 1);
        state.NoonFlash = Math.Max(0, state.NoonFlash - 1);

        if (state.AdmiraltyDeathAge > 0)
        {
            _shots.Clear();
            int deathAge = state.AdmiraltyDeathAge++;
            if (deathAge is 24 or 58 or 96 or 144)
                _audio?.Trigger(StormaktSound.EnemyExplosion);
            if (deathAge == 1)
            {
                _enemyShots.Clear();
                _shots.Clear();
                _score += 3_200;
                ActivateBossRadio(CopenhagenAdmiraltyFallRadio);
                _audio?.Trigger(StormaktSound.Broadside);
            }
            if (deathAge < 240 || _bossRadioCard is not null) return;
            BeginCopenhagenFrederik(state);
            return;
        }

        int hour = Math.Min(11, state.AdmiraltyAge / 90 % 12);
        if (hour != state.CurrentHour || state.AdmiraltyAge == 1)
        {
            state.CurrentHour = hour;
            if (state.HourHealth[hour] > 0) state.HourArmed[hour] = true;
            _audio?.Trigger(StormaktSound.TitheRegisterSwitch);
        }

        StepCopenhagenAdmiraltyShots(state);
        StepCopenhagenAdmiraltyAttacks(state);
        if (state.AdmiraltyHealth > 0) return;
        state.AdmiraltyHealth = 0;
        state.AdmiraltyDeathAge = 1;
    }

    private void StepCopenhagenAdmiraltyShots(CopenhagenWorldState state)
    {
        (double centerX, double centerY) = CopenhagenAdmiraltyCenter(state);
        for (int shotIndex = _shots.Count - 1; shotIndex >= 0; shotIndex--)
        {
            Shot shot = _shots[shotIndex];
            int hitHour = -1;
            for (int hour = 0; hour < state.HourHealth.Length; hour++)
            {
                if (state.HourHealth[hour] <= 0) continue;
                (double hourX, double hourY) = CopenhagenHourPosition(hour, centerX, centerY);
                if (DistanceSquared(shot.X, shot.Y, hourX, hourY) < 11 * 11)
                {
                    hitHour = hour;
                    break;
                }
            }
            if (hitHour >= 0)
            {
                state.HourHealth[hitHour] = Math.Max(0, state.HourHealth[hitHour] - shot.Power);
                state.HourHitFlash = 5;
                state.LastHitHour = hitHour;
                _shots.RemoveAt(shotIndex);
                if (state.HourHealth[hitHour] == 0)
                {
                    state.HourArmed[hitHour] = false;
                    _score += 180;
                    _audio?.Trigger(StormaktSound.OresundSwitchBreak);
                }
                continue;
            }
            if (DistanceSquared(shot.X, shot.Y, centerX, centerY) >= 24 * 24) continue;
            state.AdmiraltyHealth = Math.Max(0, state.AdmiraltyHealth - shot.Power);
            state.AdmiraltyHitFlash = 5;
            _shots.RemoveAt(shotIndex);
        }
    }

    private void StepCopenhagenAdmiraltyAttacks(CopenhagenWorldState state)
    {
        if (state.AdmiraltyAge < 90) return;
        (double centerX, double centerY) = CopenhagenAdmiraltyCenter(state);
        (double hourX, double hourY) = CopenhagenHourPosition(state.CurrentHour, centerX, centerY);
        int withinHour = state.AdmiraltyAge % 90;
        if (state.HourHealth[state.CurrentHour] > 0 && withinHour is 18 or 30 or 42)
        {
            double dx = _shipX - hourX;
            double dy = _shipY - hourY;
            double length = Math.Max(1.0, Math.Sqrt(dx * dx + dy * dy));
            double vx = dx / length;
            double vy = dy / length;
            double spread = (withinHour - 30) / 120.0;
            _enemyShots.Add(new EnemyShot(hourX, hourY, (vx - vy * spread) * 2.05, (vy + vx * spread) * 2.05, 2));
        }

        if (state.AdmiraltyAge % 1_080 != 0) return;
        state.NoonFlash = 90;
        ActivateBossRadio(CopenhagenNoonRadio);
        for (int hour = 0; hour < state.HourArmed.Length; hour++)
        {
            if (!state.HourArmed[hour] || state.HourHealth[hour] <= 0) continue;
            (double x, double y) = CopenhagenHourPosition(hour, centerX, centerY);
            double angle = Math.Atan2(y - centerY, x - centerX);
            for (int ray = -1; ray <= 1; ray++)
            {
                double shotAngle = angle + Math.PI / 2.0 + ray * 0.22;
                _enemyShots.Add(new EnemyShot(x, y, Math.Cos(shotAngle) * 1.8, Math.Sin(shotAngle) * 1.8, 4));
            }
        }
        _audio?.Trigger(StormaktSound.Broadside);
    }

    private (double X, double Y) CopenhagenAdmiraltyCenter(CopenhagenWorldState state)
    {
        double entry = Math.Min(1.0, state.AdmiraltyAge / 90.0);
        double eased = entry * entry * (3.0 - 2.0 * entry);
        return (_width / 2.0, -46 + 126 * eased);
    }

    private static (double X, double Y) CopenhagenHourPosition(int hour, double centerX, double centerY)
    {
        double angle = -Math.PI / 2.0 + hour * Math.PI * 2.0 / 12.0;
        return (centerX + Math.Cos(angle) * 102.0, centerY + Math.Sin(angle) * 50.0);
    }

    private void BeginCopenhagenFrederik(CopenhagenWorldState state, bool testFixture = false)
    {
        state.FrederikActive = true;
        state.FrederikTestFixture = testFixture;
        state.FrederikAge = 0;
        state.FrederikPhase = 1;
        state.FrederikPhaseAge = 0;
        state.FrederikHealth = testFixture ? 180 : CopenhagenFrederikMaxHealth;
        state.FrederikDeathAge = 0;
        state.FrederikHitFlash = 0;
        state.FrederikSeizedMask = 0;
        state.FrederikChains.Clear();
        _enemyShots.Clear();
        _shots.Clear();
        if (testFixture) return;
        ActivateBossRadio(CopenhagenFrederikRadio);
        _audio?.Trigger(StormaktSound.OresundFortressLock);
    }

    private void StepCopenhagenFrederik(CopenhagenWorldState state)
    {
        state.FrederikAge++;
        state.FrederikPhaseAge++;
        state.FrederikHitFlash = Math.Max(0, state.FrederikHitFlash - 1);
        state.FrederikRepairFlash = Math.Max(0, state.FrederikRepairFlash - 1);

        if (state.FrederikDeathAge > 0)
        {
            _shots.Clear();
            int deathAge = state.FrederikDeathAge++;
            if (deathAge == 1)
            {
                _enemyShots.Clear();
                _shots.Clear();
                state.FrederikChains.Clear();
                _score += 6_000;
                ActivateBossRadio(CopenhagenFrederikFallRadio);
                _audio?.Trigger(StormaktSound.Broadside);
            }
            if (deathAge is 28 or 61 or 103 or 158 or 220)
                _audio?.Trigger(StormaktSound.EnemyExplosion);
            if (deathAge < 280 || _bossRadioCard is not null) return;
            BeginCopenhagenEye(state);
            return;
        }

        StepCopenhagenFrederikShots(state);
        if (state.FrederikPhase == 1) StepCopenhagenFrederikSeizure(state);
        else if (state.FrederikPhase == 2) StepCopenhagenFrederikBlades(state);
        else StepCopenhagenFrederikRepair(state);

        int phaseTwoHealth = state.FrederikTestFixture ? 120 : CopenhagenFrederikPhaseTwoHealth;
        if (state.FrederikPhase == 1 && state.FrederikHealth <= phaseTwoHealth)
        {
            state.FrederikHealth = phaseTwoHealth;
            state.FrederikPhase = 2;
            state.FrederikPhaseAge = 0;
            state.FrederikLeftBladeHealth = state.FrederikTestFixture ? 18 : CopenhagenFrederikBladeHealth;
            state.FrederikRightBladeHealth = state.FrederikTestFixture ? 18 : CopenhagenFrederikBladeHealth;
            state.FrederikChains.Clear();
            _enemyShots.Clear();
            ActivateBossRadio(CopenhagenFrederikBladesRadio);
            _audio?.Trigger(StormaktSound.TitheBossPhaseBreak);
        }
        if (state.FrederikPhase == 2 && state.FrederikLeftBladeHealth <= 0 && state.FrederikRightBladeHealth <= 0)
        {
            state.FrederikPhase = 3;
            state.FrederikPhaseAge = 0;
            ResetCopenhagenFrederikRepairCycle(state);
            _enemyShots.Clear();
            ActivateBossRadio(CopenhagenFrederikRepairRadio);
            _audio?.Trigger(StormaktSound.TitheLedgerShatter);
        }
        if (state.FrederikPhase == 3 && state.FrederikHealth <= 0)
        {
            state.FrederikHealth = 0;
            state.FrederikDeathAge = 1;
        }
    }

    private void StepCopenhagenFrederikShots(CopenhagenWorldState state)
    {
        (double centerX, double centerY) = CopenhagenFrederikCenter(state);
        for (int shotIndex = _shots.Count - 1; shotIndex >= 0; shotIndex--)
        {
            Shot shot = _shots[shotIndex];
            CopenhagenSeizureChain? chain = state.FrederikChains.FirstOrDefault(candidate =>
                candidate.Health > 0 && !candidate.Completed &&
                DistanceSquared(shot.X, shot.Y, CopenhagenFrederikChainTipX(state, candidate, centerX),
                    CopenhagenFrederikChainTipY(state, candidate, centerY)) < 12 * 12);
            if (chain is not null)
            {
                chain.Health -= shot.Power;
                _shots.RemoveAt(shotIndex);
                if (chain.Health <= 0)
                {
                    _score += 240;
                    _audio?.Trigger(StormaktSound.TitheChainLockBreak);
                }
                continue;
            }

            if (state.FrederikPhase == 2)
            {
                (double leftX, double leftY) = CopenhagenFrederikBladePosition(state, false, centerX, centerY);
                (double rightX, double rightY) = CopenhagenFrederikBladePosition(state, true, centerX, centerY);
                bool leftHit = state.FrederikLeftBladeHealth > 0 && DistanceSquared(shot.X, shot.Y, leftX, leftY) < 19 * 19;
                bool rightHit = state.FrederikRightBladeHealth > 0 && DistanceSquared(shot.X, shot.Y, rightX, rightY) < 19 * 19;
                if (leftHit || rightHit)
                {
                    if (leftHit) state.FrederikLeftBladeHealth = Math.Max(0, state.FrederikLeftBladeHealth - shot.Power);
                    else state.FrederikRightBladeHealth = Math.Max(0, state.FrederikRightBladeHealth - shot.Power);
                    _shots.RemoveAt(shotIndex);
                    state.FrederikHitFlash = 5;
                    continue;
                }
                continue;
            }

            if (state.FrederikPhase == 3)
            {
                int hitNode = CopenhagenFrederikHitRepairNode(state, shot.X, shot.Y, centerX, centerY);
                if (hitNode >= 0)
                {
                    _shots.RemoveAt(shotIndex);
                    if (hitNode == state.FrederikActiveRepairNode)
                    {
                        state.FrederikRepairHealth[hitNode] = Math.Max(0,
                            state.FrederikRepairHealth[hitNode] - shot.Power);
                        if (state.FrederikRepairHealth[hitNode] == 0)
                        {
                            _score += 300;
                            _audio?.Trigger(StormaktSound.TitheRegisterSwitch);
                        }
                    }
                    else
                    {
                        FireAimedCopenhagenShot(centerX + (hitNode - 1) * 54, centerY + 40, 2.35, 3);
                    }
                    continue;
                }
            }

            if (DistanceSquared(shot.X, shot.Y, centerX, centerY) >= 43 * 43) continue;
            state.FrederikHealth = Math.Max(0, state.FrederikHealth - shot.Power);
            state.FrederikHitFlash = 5;
            _shots.RemoveAt(shotIndex);
        }
    }

    private void StepCopenhagenFrederikSeizure(CopenhagenWorldState state)
    {
        (double centerX, double centerY) = CopenhagenFrederikCenter(state);
        int supportCount = Math.Clamp(Math.Max(1, state.IncomingFreedShips), 1, 3);
        if (state.FrederikPhaseAge > 90 && state.FrederikPhaseAge % 180 == 30)
        {
            int target = state.FrederikChainSerial++ % supportCount;
            bool alreadySeized = (state.FrederikSeizedMask & (1 << target)) != 0;
            bool alreadyChained = state.FrederikChains.Any(chain => chain.Target == target && chain.Health > 0 && !chain.Completed);
            if (!alreadySeized && !alreadyChained)
                state.FrederikChains.Add(new CopenhagenSeizureChain(target,
                    state.FrederikTestFixture ? 9 : 36));
        }
        foreach (CopenhagenSeizureChain chain in state.FrederikChains)
        {
            if (chain.Health <= 0 || chain.Completed) continue;
            chain.Age++;
            if (chain.Age < 120) continue;
            chain.Completed = true;
            state.FrederikSeizedMask |= 1 << chain.Target;
            _audio?.Trigger(StormaktSound.TitheCustomsGate);
        }
        state.FrederikChains.RemoveAll(chain => chain.Health <= 0 && chain.Age++ > 45);

        if (state.FrederikPhaseAge > 90 && state.FrederikPhaseAge % 72 == 0)
            FireAimedCopenhagenShot(centerX, centerY + 28, 2.15, 2);
        for (int support = 0; support < supportCount; support++)
        {
            if ((state.FrederikSeizedMask & (1 << support)) == 0 ||
                (state.FrederikPhaseAge + support * 21) % 96 != 0) continue;
            (double supportX, double supportY) = CopenhagenFrederikSupportPosition(support, supportCount);
            FireAimedCopenhagenShot(supportX, supportY, 2.0, 4);
        }
    }

    private void StepCopenhagenFrederikBlades(CopenhagenWorldState state)
    {
        (double centerX, double centerY) = CopenhagenFrederikCenter(state);
        (double leftX, double leftY) = CopenhagenFrederikBladePosition(state, false, centerX, centerY);
        (double rightX, double rightY) = CopenhagenFrederikBladePosition(state, true, centerX, centerY);
        if (state.FrederikLeftBladeHealth > 0 && DistanceSquared(_shipX, _shipY, leftX, leftY) < 23 * 23) DamageShip();
        if (state.FrederikRightBladeHealth > 0 && DistanceSquared(_shipX, _shipY, rightX, rightY) < 23 * 23) DamageShip();
        if (state.FrederikPhaseAge % 105 == 0)
        {
            if (state.FrederikLeftBladeHealth > 0) FireAimedCopenhagenShot(leftX, leftY, 2.2, 3);
            if (state.FrederikRightBladeHealth > 0) FireAimedCopenhagenShot(rightX, rightY, 2.2, 3);
        }
    }

    private void StepCopenhagenFrederikRepair(CopenhagenWorldState state)
    {
        int cycle = state.FrederikPhaseAge % 240;
        if (cycle == 0) ResetCopenhagenFrederikRepairCycle(state);
        if (cycle == 180 && state.FrederikRepairHealth[state.FrederikActiveRepairNode] > 0)
        {
            int heal = state.FrederikTestFixture ? 24 : 105;
            int ceiling = state.FrederikTestFixture ? 120 : CopenhagenFrederikPhaseTwoHealth;
            state.FrederikHealth = Math.Min(ceiling, state.FrederikHealth + heal);
            state.FrederikRepairFlash = 45;
            _audio?.Trigger(StormaktSound.TitheUpgradeInstall);
        }
        if (cycle is 72 or 84 or 96)
        {
            (double centerX, double centerY) = CopenhagenFrederikCenter(state);
            int node = state.FrederikActiveRepairNode;
            FireAimedCopenhagenShot(centerX + (node - 1) * 54, centerY + 40, 2.0, 2);
        }
    }

    private void ResetCopenhagenFrederikRepairCycle(CopenhagenWorldState state)
    {
        state.FrederikRepairCycle++;
        state.FrederikActiveRepairNode = state.FrederikRepairCycle * 2 % 3;
        int health = state.FrederikTestFixture ? 9 : CopenhagenFrederikRepairNodeHealth;
        for (int node = 0; node < state.FrederikRepairHealth.Length; node++)
            state.FrederikRepairHealth[node] = health;
    }

    private int CopenhagenFrederikHitRepairNode(
        CopenhagenWorldState state, double shotX, double shotY, double centerX, double centerY)
    {
        for (int node = 0; node < state.FrederikRepairHealth.Length; node++)
        {
            if (node == state.FrederikActiveRepairNode && state.FrederikRepairHealth[node] <= 0) continue;
            double x = centerX + (node - 1) * 54;
            double y = centerY + 40;
            if (DistanceSquared(shotX, shotY, x, y) < 13 * 13) return node;
        }
        return -1;
    }

    private (double X, double Y) CopenhagenFrederikCenter(CopenhagenWorldState state)
    {
        double entry = Math.Min(1.0, state.FrederikAge / 105.0);
        double eased = entry * entry * (3.0 - 2.0 * entry);
        double sway = state.FrederikAge < 105 ? 0 : Math.Sin(state.FrederikAge * 0.011) * 31;
        return (_width / 2.0 + sway, -72 + 150 * eased);
    }

    private static (double X, double Y) CopenhagenFrederikBladePosition(
        CopenhagenWorldState state, bool right, double centerX, double centerY)
    {
        int offset = right ? 90 : 0;
        int cycle = (state.FrederikPhaseAge + offset) % 180;
        double thrust = cycle < 60 ? cycle / 60.0 : cycle < 105 ? 1.0 - (cycle - 60) / 45.0 : 0;
        double side = right ? 1 : -1;
        return (centerX + side * (62 - thrust * 24), centerY + 22 + thrust * 118);
    }

    private (double X, double Y) CopenhagenFrederikSupportPosition(int support, int count)
    {
        double spacing = Math.Min(74, (_width - 100.0) / Math.Max(1, count));
        return (_width / 2.0 + (support - (count - 1) / 2.0) * spacing, 42 + support % 2 * 23);
    }

    private double CopenhagenFrederikChainTipX(
        CopenhagenWorldState state, CopenhagenSeizureChain chain, double centerX)
    {
        int count = Math.Clamp(Math.Max(1, state.IncomingFreedShips), 1, 3);
        (double targetX, _) = CopenhagenFrederikSupportPosition(chain.Target, count);
        double progress = Math.Min(1.0, chain.Age / 120.0);
        return centerX + (targetX - centerX) * progress;
    }

    private double CopenhagenFrederikChainTipY(
        CopenhagenWorldState state, CopenhagenSeizureChain chain, double centerY)
    {
        int count = Math.Clamp(Math.Max(1, state.IncomingFreedShips), 1, 3);
        (_, double targetY) = CopenhagenFrederikSupportPosition(chain.Target, count);
        double progress = Math.Min(1.0, chain.Age / 120.0);
        return centerY + (targetY - centerY) * progress;
    }

    private void FireAimedCopenhagenShot(double x, double y, double speed, int kind)
    {
        double dx = _shipX - x;
        double dy = _shipY - y;
        double length = Math.Max(1.0, Math.Sqrt(dx * dx + dy * dy));
        _enemyShots.Add(new EnemyShot(x, y, dx / length * speed, dy / length * speed, kind));
    }

    private void BeginCopenhagenEye(CopenhagenWorldState state, bool testFixture = false)
    {
        state.EyeActive = true;
        state.EyeTestFixture = testFixture;
        state.EyeAge = 0;
        state.EyePhase = 1;
        state.EyePhaseAge = 0;
        state.EyeHealth = testFixture ? 180 : CopenhagenEyeMaxHealth;
        state.EyeDeathAge = 0;
        state.EyeHitFlash = 0;
        state.EyeLastShipX = _shipX;
        state.EyeLastShipY = _shipY;
        state.EyePredictedX = _shipX;
        state.EyePredictedY = _shipY;
        state.EyeWalls.Clear();
        Array.Clear(state.EyeDirectionVotes);
        Array.Clear(state.EyeLensHealth);
        _enemyShots.Clear();
        _shots.Clear();
        if (testFixture) return;
        ActivateBossRadio(CopenhagenEyeRadio);
        _audio?.Trigger(StormaktSound.OresundCrownCoreOpen);
    }

    private void StepCopenhagenEye(CopenhagenWorldState state)
    {
        state.EyeAge++;
        state.EyePhaseAge++;
        state.EyeHitFlash = Math.Max(0, state.EyeHitFlash - 1);
        state.EyePredictionFlash = Math.Max(0, state.EyePredictionFlash - 1);
        state.EyeLensHitFlash = Math.Max(0, state.EyeLensHitFlash - 1);
        StepCopenhagenEyePrediction(state);

        if (state.EyeDeathAge > 0)
        {
            _shots.Clear();
            int deathAge = state.EyeDeathAge++;
            if (deathAge == 1)
            {
                _enemyShots.Clear();
                state.EyeWalls.Clear();
                _score += 7_500;
                ActivateBossRadio(CopenhagenEyeFallRadio);
                _audio?.Trigger(StormaktSound.Broadside);
            }
            if (deathAge is 26 or 63 or 108 or 171 or 236)
                _audio?.Trigger(StormaktSound.EnemyExplosion);
            if (deathAge < 280 || _bossRadioCard is not null) return;
            BeginCopenhagenDannebrog(state);
            return;
        }

        StepCopenhagenEyeShots(state);
        StepCopenhagenEyeWalls(state);
        StepCopenhagenEyeAttacks(state);

        int phaseTwoHealth = state.EyeTestFixture ? 120 : CopenhagenEyePhaseTwoHealth;
        if (state.EyePhase == 1 && state.EyeHealth <= phaseTwoHealth)
        {
            state.EyeHealth = phaseTwoHealth;
            state.EyePhase = 2;
            state.EyePhaseAge = 0;
            int lensHealth = state.EyeTestFixture ? 12 : CopenhagenEyeLensHealth;
            for (int lens = 0; lens < state.EyeLensHealth.Length; lens++) state.EyeLensHealth[lens] = lensHealth;
            _enemyShots.Clear();
            state.EyeWalls.Clear();
            ActivateBossRadio(CopenhagenEyeLensRadio);
            _audio?.Trigger(StormaktSound.OresundFortressLock);
        }
        if (state.EyePhase == 2 && state.SorenOathComplete && !state.EyeSorenLensBroken && state.EyePhaseAge >= 90)
        {
            state.EyeSorenLensBroken = true;
            state.EyeLensHealth[0] = 0;
            _score += 240;
            ActivateBossRadio(CopenhagenEyeSorenRadio);
            _audio?.Trigger(StormaktSound.OresundSwitchBreak);
        }
        if (state.EyePhase == 2 && state.EyeLensHealth.All(health => health <= 0))
        {
            state.EyePhase = 3;
            state.EyePhaseAge = 0;
            state.EyeWalls.Clear();
            _enemyShots.Clear();
            _audio?.Trigger(StormaktSound.TitheBossPhaseBreak);
        }
        if (state.EyePhase == 3 && state.EyeHealth <= 0)
        {
            state.EyeHealth = 0;
            state.EyeDeathAge = 1;
        }
    }

    private void StepCopenhagenEyePrediction(CopenhagenWorldState state)
    {
        if (state.EyeAge % 10 != 0) return;
        int dx = _shipX - state.EyeLastShipX;
        int dy = _shipY - state.EyeLastShipY;
        for (int index = 0; index < state.EyeDirectionVotes.Length; index++)
            state.EyeDirectionVotes[index] = Math.Max(0, state.EyeDirectionVotes[index] - 1);
        if (Math.Abs(dx) >= Math.Abs(dy) && Math.Abs(dx) >= 3)
            state.EyeDirectionVotes[dx < 0 ? (int)CopenhagenPrediction.Left : (int)CopenhagenPrediction.Right] += 4;
        else if (Math.Abs(dy) >= 3)
            state.EyeDirectionVotes[dy < 0 ? (int)CopenhagenPrediction.Up : (int)CopenhagenPrediction.Down] += 4;
        state.EyeLastShipX = _shipX;
        state.EyeLastShipY = _shipY;
        state.EyePrediction = (CopenhagenPrediction)Enumerable.Range(0, state.EyeDirectionVotes.Length)
            .OrderByDescending(index => state.EyeDirectionVotes[index]).ThenBy(index => index).First();
    }

    private void StepCopenhagenEyeShots(CopenhagenWorldState state)
    {
        (double centerX, double centerY) = CopenhagenEyeCenter(state);
        for (int shotIndex = _shots.Count - 1; shotIndex >= 0; shotIndex--)
        {
            Shot shot = _shots[shotIndex];
            int hitLens = -1;
            if (state.EyePhase == 2)
            {
                for (int lens = 0; lens < state.EyeLensHealth.Length; lens++)
                {
                    if (state.EyeLensHealth[lens] <= 0) continue;
                    (double lensX, double lensY) = CopenhagenEyeLensPosition(state, lens, centerX, centerY);
                    if (DistanceSquared(shot.X, shot.Y, lensX, lensY) < 15 * 15)
                    {
                        hitLens = lens;
                        break;
                    }
                }
            }
            if (hitLens >= 0)
            {
                state.EyeLensHealth[hitLens] = Math.Max(0, state.EyeLensHealth[hitLens] - shot.Power);
                state.EyeLensHitFlash = 5;
                state.EyeLastHitLens = hitLens;
                _shots.RemoveAt(shotIndex);
                if (state.EyeLensHealth[hitLens] == 0)
                {
                    _score += 360;
                    _audio?.Trigger(StormaktSound.OresundCrownCoreBreak);
                }
                continue;
            }
            if (state.EyePhase == 2 || DistanceSquared(shot.X, shot.Y, centerX, centerY) >= 29 * 29) continue;
            state.EyeHealth = Math.Max(0, state.EyeHealth - shot.Power);
            state.EyeHitFlash = 5;
            _shots.RemoveAt(shotIndex);
        }
    }

    private void StepCopenhagenEyeWalls(CopenhagenWorldState state)
    {
        int interval = state.EyePhase == 3 ? 105 : 150;
        if (state.EyeAge > 105 && state.EyeAge % interval == 0)
        {
            bool vertical = state.EyePrediction is CopenhagenPrediction.Left or CopenhagenPrediction.Right;
            int futureX = Math.Clamp(_shipX + (state.EyePrediction == CopenhagenPrediction.Left ? -58 :
                state.EyePrediction == CopenhagenPrediction.Right ? 58 : 0), 34, _width - 34);
            int futureY = Math.Clamp(_shipY + (state.EyePrediction == CopenhagenPrediction.Up ? -54 :
                state.EyePrediction == CopenhagenPrediction.Down ? 54 : 0), 46, _height - 34);
            int gap = vertical
                ? Math.Clamp(futureY + (state.EyeWallSerial % 2 == 0 ? 42 : -42), 52, _height - 44)
                : Math.Clamp(futureX + (state.EyeWallSerial % 2 == 0 ? 52 : -52), 46, _width - 46);
            state.EyeWalls.Add(new CopenhagenTollWall(vertical, vertical ? futureX : futureY, gap, state.EyeWallSerial++));
            state.EyePredictedX = futureX;
            state.EyePredictedY = futureY;
            state.EyePredictionFlash = 45;
            _audio?.Trigger(StormaktSound.TitheCustomsGate);
        }
        foreach (CopenhagenTollWall wall in state.EyeWalls)
        {
            wall.Age++;
            if (wall.Age < 45 || wall.Age > 130 || wall.HitPlayer) continue;
            bool hit = wall.Vertical
                ? Math.Abs(_shipX - wall.Coordinate) < 6 && Math.Abs(_shipY - wall.Gap) > 31
                : Math.Abs(_shipY - wall.Coordinate) < 6 && Math.Abs(_shipX - wall.Gap) > 37;
            if (!hit) continue;
            wall.HitPlayer = true;
            DamageShip();
        }
        state.EyeWalls.RemoveAll(wall => wall.Age > 150);
    }

    private void StepCopenhagenEyeAttacks(CopenhagenWorldState state)
    {
        if (state.EyeAge < 90) return;
        (double centerX, double centerY) = CopenhagenEyeCenter(state);
        int aimedInterval = state.EyePhase == 3 ? 42 : 66;
        if (state.EyeAge % aimedInterval == 0)
            FireAimedCopenhagenShot(centerX, centerY + 12, state.EyePhase == 3 ? 2.55 : 2.15, 2);
        if (state.EyePhase != 2 || state.EyeAge % 105 != 0) return;
        for (int lens = 0; lens < state.EyeLensHealth.Length; lens++)
        {
            if (state.EyeLensHealth[lens] <= 0) continue;
            (double lensX, double lensY) = CopenhagenEyeLensPosition(state, lens, centerX, centerY);
            FireAimedCopenhagenShot(lensX, lensY, 2.0, 3);
        }
    }

    private (double X, double Y) CopenhagenEyeCenter(CopenhagenWorldState state)
    {
        double entry = Math.Min(1.0, state.EyeAge / 100.0);
        double eased = entry * entry * (3.0 - 2.0 * entry);
        double sway = state.EyeAge < 100 ? 0 : Math.Sin(state.EyeAge * 0.009) * 42;
        return (_width / 2.0 + sway, -52 + 126 * eased);
    }

    private static (double X, double Y) CopenhagenEyeLensPosition(
        CopenhagenWorldState state, int lens, double centerX, double centerY)
    {
        double angle = lens * Math.PI * 2.0 / 3.0 + state.EyeAge * 0.018;
        return (centerX + Math.Cos(angle) * 68.0, centerY + Math.Sin(angle) * 37.0);
    }

    private void BeginCopenhagenDannebrog(CopenhagenWorldState state, bool testFixture = false)
    {
        state.DannebrogActive = true;
        state.DannebrogTestFixture = testFixture;
        state.DannebrogAge = 0;
        state.DannebrogFormation = 0;
        state.DannebrogRotation = 0;
        state.DannebrogDeathAge = 0;
        state.DannebrogGapRadioPlayed = false;
        BeginCopenhagenDannebrogFormation(state);
        _enemyShots.Clear();
        _shots.Clear();
        if (testFixture) return;
        ActivateBossRadio(CopenhagenDannebrogRadio);
        _audio?.Trigger(StormaktSound.OresundFortressLock);
    }

    private void BeginCopenhagenDannebrogFormation(CopenhagenWorldState state)
    {
        state.DannebrogFormationAge = 0;
        state.DannebrogEscapeNode = -1;
        state.DannebrogBreakAge = 0;
        state.DannebrogChargeAge = 0;
        state.DannebrogHitFlash = 0;
        state.DannebrogHitPlayer = false;
        int health = state.DannebrogTestFixture ? 12 : CopenhagenDannebrogNodeHealth;
        for (int node = 0; node < state.DannebrogNodeHealth.Length; node++)
            state.DannebrogNodeHealth[node] = health;
    }

    private void StepCopenhagenDannebrog(CopenhagenWorldState state)
    {
        state.DannebrogAge++;
        state.DannebrogHitFlash = Math.Max(0, state.DannebrogHitFlash - 1);
        if (state.DannebrogDeathAge > 0)
        {
            _shots.Clear();
            int deathAge = state.DannebrogDeathAge++;
            if (deathAge == 1)
            {
                _enemyShots.Clear();
                _score += 4_500;
                ActivateBossRadio(CopenhagenDannebrogFallRadio);
                _audio?.Trigger(StormaktSound.Broadside);
            }
            if (deathAge is 34 or 82 or 138) _audio?.Trigger(StormaktSound.EnemyExplosion);
            if (deathAge < 240 || _bossRadioCard is not null) return;
            BeginCopenhagenDuo(state);
            return;
        }

        state.DannebrogFormationAge++;
        if (!state.DannebrogGapRadioPlayed && state.DannebrogAge >= 75 && _bossRadioCard is null)
        {
            state.DannebrogGapRadioPlayed = true;
            ActivateBossRadio(CopenhagenDannebrogGapRadio);
        }

        if (state.DannebrogChargeAge > 0)
        {
            state.DannebrogChargeAge++;
            StepCopenhagenDannebrogCollision(state);
            int chargeLimit = state.DannebrogTestFixture ? 115 : 150;
            if (state.DannebrogChargeAge <= chargeLimit) return;
            state.DannebrogFormation++;
            if (state.DannebrogFormation >= CopenhagenDannebrogFormationCount)
            {
                state.DannebrogDeathAge = 1;
                return;
            }
            state.DannebrogRotation = (state.DannebrogRotation + state.DannebrogEscapeNode + 1) & 7;
            BeginCopenhagenDannebrogFormation(state);
            _enemyShots.Clear();
            return;
        }

        StepCopenhagenDannebrogShots(state);
        if (state.DannebrogFormationAge >= 70 && state.DannebrogFormationAge % 58 == 0)
        {
            int start = state.DannebrogFormationAge / 58 + state.DannebrogFormation;
            for (int offset = 0; offset < state.DannebrogNodeHealth.Length; offset++)
            {
                int node = (start + offset) % state.DannebrogNodeHealth.Length;
                if (state.DannebrogNodeHealth[node] <= 0) continue;
                (double centerX, double centerY) = CopenhagenDannebrogCenter(state);
                (double nodeX, double nodeY) = CopenhagenDannebrogNodePosition(state, node, centerX, centerY);
                FireAimedCopenhagenShot(nodeX, nodeY, 2.15 + state.DannebrogFormation * 0.18, 3);
                break;
            }
        }

        if (state.DannebrogEscapeNode < 0 && state.DannebrogFormationAge >= 220)
        {
            state.DannebrogEscapeNode = (state.DannebrogRotation + state.DannebrogFormation) & 3;
            state.DannebrogNodeHealth[state.DannebrogEscapeNode] = 0;
            state.DannebrogBreakAge = state.DannebrogFormationAge;
            DamageShip();
        }
        if (state.DannebrogEscapeNode >= 0 &&
            (state.DannebrogFormationAge >= state.DannebrogBreakAge + 58 || state.DannebrogFormationAge >= 245))
        {
            state.DannebrogChargeAge = 1;
            _enemyShots.Clear();
            _audio?.Trigger(StormaktSound.Broadside);
        }
    }

    private void StepCopenhagenDannebrogShots(CopenhagenWorldState state)
    {
        (double centerX, double centerY) = CopenhagenDannebrogCenter(state);
        for (int shotIndex = _shots.Count - 1; shotIndex >= 0; shotIndex--)
        {
            Shot shot = _shots[shotIndex];
            int hitNode = -1;
            for (int node = 0; node < state.DannebrogNodeHealth.Length; node++)
            {
                if (state.DannebrogNodeHealth[node] <= 0) continue;
                (double nodeX, double nodeY) = CopenhagenDannebrogNodePosition(state, node, centerX, centerY);
                if (DistanceSquared(shot.X, shot.Y, nodeX, nodeY) < 15 * 15)
                {
                    hitNode = node;
                    break;
                }
            }
            if (hitNode < 0) continue;
            state.DannebrogNodeHealth[hitNode] = Math.Max(0, state.DannebrogNodeHealth[hitNode] - shot.Power);
            state.DannebrogHitFlash = 5;
            state.DannebrogLastHitNode = hitNode;
            _shots.RemoveAt(shotIndex);
            if (state.DannebrogNodeHealth[hitNode] != 0) continue;
            _score += state.DannebrogEscapeNode < 0 ? 540 : 240;
            if (state.DannebrogEscapeNode < 0)
            {
                state.DannebrogEscapeNode = hitNode;
                state.DannebrogBreakAge = state.DannebrogFormationAge;
            }
            _audio?.Trigger(StormaktSound.OresundSwitchBreak);
        }
    }

    private void StepCopenhagenDannebrogCollision(CopenhagenWorldState state)
    {
        if (state.DannebrogHitPlayer) return;
        (double centerX, double centerY) = CopenhagenDannebrogCenter(state);
        for (int node = 0; node < state.DannebrogNodeHealth.Length; node++)
        {
            if (state.DannebrogNodeHealth[node] <= 0) continue;
            (double nodeX, double nodeY) = CopenhagenDannebrogNodePosition(state, node, centerX, centerY);
            bool hit = DistancePointToSegmentSquared(_shipX, _shipY, centerX, centerY, nodeX, nodeY) < 9 * 9 ||
                DistanceSquared(_shipX, _shipY, nodeX, nodeY) < 15 * 15;
            if (!hit) continue;
            state.DannebrogHitPlayer = true;
            DamageShip();
            return;
        }
    }

    private (double X, double Y) CopenhagenDannebrogCenter(CopenhagenWorldState state)
    {
        if (state.DannebrogChargeAge > 0)
        {
            double speed = state.DannebrogTestFixture ? 3.0 : 2.25;
            return (_width / 2.0 + Math.Sin((state.DannebrogAge + state.DannebrogFormation * 71) * 0.013) * 18,
                72 + state.DannebrogChargeAge * speed);
        }
        double entry = Math.Min(1.0, state.DannebrogFormationAge / 60.0);
        double eased = entry * entry * (3.0 - 2.0 * entry);
        return (_width / 2.0 + Math.Sin((state.DannebrogAge + state.DannebrogFormation * 71) * 0.013) * 18,
            -58 + 130 * eased);
    }

    private static (double X, double Y) CopenhagenDannebrogNodePosition(
        CopenhagenWorldState state, int node, double centerX, double centerY)
    {
        double angle = Math.PI / 4.0 + state.DannebrogRotation * Math.PI / 8.0 + node * Math.PI / 2.0;
        return (centerX + Math.Cos(angle) * 72.0, centerY + Math.Sin(angle) * 48.0);
    }

    private void BeginCopenhagenDuo(CopenhagenWorldState state, bool testFixture = false)
    {
        state.DuoActive = true;
        state.DuoTestFixture = testFixture;
        state.DuoAge = 0;
        state.DuoCycleAge = 0;
        state.DuoDeathAge = 0;
        state.DuoWallRadioPlayed = false;
        state.DuoChargeRadioPlayed = false;
        state.DuoSupportApplied = false;
        state.DuoShieldWall = null;
        state.DuoElefantenChargeAge = 0;
        state.DuoElefantenChargeX = _width / 2;
        int health = testFixture ? 72 : CopenhagenDuoMaxHealth;
        state.DuoHealth[0] = health;
        state.DuoHealth[1] = health;
        int turretHealth = testFixture ? 12 : CopenhagenDuoTurretHealth;
        for (int turret = 0; turret < state.DuoTurretHealth.Length; turret++)
            state.DuoTurretHealth[turret] = turretHealth;
        Array.Clear(state.DuoShipFallAge);
        _enemyShots.Clear();
        _shots.Clear();
        if (testFixture) return;
        ActivateBossRadio(CopenhagenDuoRadio);
        _audio?.Trigger(StormaktSound.Deploy);
    }

    private void StepCopenhagenDuo(CopenhagenWorldState state)
    {
        state.DuoAge++;
        state.DuoCycleAge++;
        state.DuoHitFlash = Math.Max(0, state.DuoHitFlash - 1);
        state.DuoRepairFlash = Math.Max(0, state.DuoRepairFlash - 1);
        for (int ship = 0; ship < state.DuoShipFallAge.Length; ship++)
            if (state.DuoShipFallAge[ship] > 0) state.DuoShipFallAge[ship]++;

        if (state.DuoDeathAge > 0)
        {
            _shots.Clear();
            int deathAge = state.DuoDeathAge++;
            if (deathAge == 1)
            {
                _enemyShots.Clear();
                state.DuoShieldWall = null;
                _score += 8_000;
                ActivateBossRadio(CopenhagenDuoFallRadio);
                _audio?.Trigger(StormaktSound.Broadside);
            }
            if (deathAge is 28 or 66 or 112 or 174 or 226)
                _audio?.Trigger(StormaktSound.EnemyExplosion);
            if (deathAge < 270 || _bossRadioCard is not null) return;
            BeginCopenhagenSuperfrigate(state);
            return;
        }

        if (state.DuoCycleAge == 1 && state.DuoHealth[0] > 0)
            SpawnCopenhagenDuoWall(state);
        if (state.DuoShieldWall is CopenhagenShieldWall wall)
        {
            wall.Age++;
            if (wall.Age == 55 && state.SorenOathComplete && !wall.SorenBreakApplied)
            {
                wall.SorenBreakApplied = true;
                int supportNode = (wall.GapIndex + 2) % wall.Health.Length;
                wall.Health[supportNode] = 0;
                _score += 180;
                _audio?.Trigger(StormaktSound.OresundSwitchBreak);
            }
            if (wall.Age > 250) state.DuoShieldWall = null;
        }

        if (!state.DuoWallRadioPlayed && state.DuoAge >= 75 && _bossRadioCard is null)
        {
            state.DuoWallRadioPlayed = true;
            ActivateBossRadio(CopenhagenAbsalonWallRadio);
        }

        if (state.DuoCycleAge == 112 && state.DuoHealth[1] > 0)
        {
            CopenhagenShieldWall? activeWall = state.DuoShieldWall;
            state.DuoElefantenChargeX = activeWall is null
                ? Math.Clamp(_shipX, 38, _width - 38)
                : CopenhagenDuoWallNodeX(activeWall.GapIndex);
            state.DuoElefantenChargeAge = 1;
            state.DuoElefantenHitPlayer = false;
            _audio?.Trigger(StormaktSound.Broadside);
        }
        if (state.DuoElefantenChargeAge > 0)
        {
            state.DuoElefantenChargeAge++;
            (double chargeX, double chargeY) = CopenhagenDuoShipPosition(state, 1);
            if (!state.DuoElefantenHitPlayer &&
                DistanceSquared(_shipX, _shipY, chargeX, chargeY) < 25 * 25)
            {
                state.DuoElefantenHitPlayer = true;
                DamageShip();
            }
            if (chargeY > _height + 48) state.DuoElefantenChargeAge = 0;
        }
        if (!state.DuoChargeRadioPlayed && state.DuoElefantenChargeAge > 0 && _bossRadioCard is null)
        {
            state.DuoChargeRadioPlayed = true;
            ActivateBossRadio(CopenhagenElefantenChargeRadio);
        }

        StepCopenhagenDuoShots(state);
        StepCopenhagenDuoAttacks(state);
        StepCopenhagenDuoRepair(state);
        if (!state.DuoSupportApplied && state.DuoAge >= 100 && state.IncomingFreedShips > 0)
        {
            state.DuoSupportApplied = true;
            int supportHits = Math.Min(3, state.IncomingFreedShips);
            for (int hit = 0; hit < supportHits; hit++)
            {
                int turret = (hit * 3 + 1) % state.DuoTurretHealth.Length;
                state.DuoTurretHealth[turret] = Math.Max(0, state.DuoTurretHealth[turret] - 18);
            }
            state.DuoRepairFlash = 30;
            _audio?.Trigger(StormaktSound.TwinCannon);
        }
        if (state.DuoCycleAge >= 300) state.DuoCycleAge = 0;
    }

    private void SpawnCopenhagenDuoWall(CopenhagenWorldState state)
    {
        int gap = Math.Clamp((_shipX - 28) * 7 / Math.Max(1, _width - 56), 0, 6);
        int nodeHealth = state.DuoTestFixture ? 8 : CopenhagenDuoShieldHealth;
        state.DuoShieldWall = new CopenhagenShieldWall(gap, nodeHealth);
        _audio?.Trigger(StormaktSound.OresundFortressLock);
    }

    private void StepCopenhagenDuoShots(CopenhagenWorldState state)
    {
        for (int shotIndex = _shots.Count - 1; shotIndex >= 0; shotIndex--)
        {
            Shot shot = _shots[shotIndex];
            if (TryHitCopenhagenDuoWall(state, shot))
            {
                _shots.RemoveAt(shotIndex);
                continue;
            }

            bool consumed = false;
            for (int ship = 0; ship < state.DuoHealth.Length && !consumed; ship++)
            {
                if (state.DuoHealth[ship] <= 0) continue;
                (double shipX, double shipY) = CopenhagenDuoShipPosition(state, ship);
                for (int side = 0; side < 2; side++)
                {
                    int turret = ship * 2 + side;
                    if (state.DuoTurretHealth[turret] <= 0) continue;
                    (double turretX, double turretY) = CopenhagenDuoTurretPosition(shipX, shipY, side);
                    if (DistanceSquared(shot.X, shot.Y, turretX, turretY) >= 11 * 11) continue;
                    state.DuoTurretHealth[turret] = Math.Max(0, state.DuoTurretHealth[turret] - shot.Power);
                    state.DuoHitFlash = 5;
                    state.DuoLastHitShip = ship;
                    state.DuoLastHitTurret = turret;
                    consumed = true;
                    if (state.DuoTurretHealth[turret] == 0)
                    {
                        _score += 420;
                        _audio?.Trigger(StormaktSound.EnemyExplosion);
                    }
                    break;
                }
                if (consumed) break;
                double dx = (shot.X - shipX) / 43.0;
                double dy = (shot.Y - shipY) / 27.0;
                if (dx * dx + dy * dy >= 1.0) continue;
                state.DuoHealth[ship] = Math.Max(0, state.DuoHealth[ship] - shot.Power);
                state.DuoHitFlash = 5;
                state.DuoLastHitShip = ship;
                state.DuoLastHitTurret = -1;
                consumed = true;
                if (state.DuoHealth[ship] == 0) FallCopenhagenDuoShip(state, ship);
            }
            if (consumed) _shots.RemoveAt(shotIndex);
        }
    }

    private bool TryHitCopenhagenDuoWall(CopenhagenWorldState state, Shot shot)
    {
        if (state.DuoShieldWall is not CopenhagenShieldWall wall) return false;
        double wallY = CopenhagenDuoWallY(wall);
        for (int node = 0; node < wall.Health.Length; node++)
        {
            if (wall.Health[node] <= 0) continue;
            double nodeX = CopenhagenDuoWallNodeX(node);
            if (DistanceSquared(shot.X, shot.Y, nodeX, wallY) >= 13 * 13) continue;
            wall.Health[node] = Math.Max(0, wall.Health[node] - shot.Power);
            state.DuoHitFlash = 4;
            state.DuoLastHitShip = -1;
            if (wall.Health[node] == 0)
            {
                _score += 150;
                _audio?.Trigger(StormaktSound.OresundSwitchBreak);
            }
            return true;
        }
        return false;
    }

    private void StepCopenhagenDuoAttacks(CopenhagenWorldState state)
    {
        if (state.DuoCycleAge == 58 && state.DuoHealth[0] > 0)
            FireCopenhagenDuoBroadside(state, 0);
        if (state.DuoCycleAge == 228 && state.DuoHealth[1] > 0 && state.DuoElefantenChargeAge == 0)
            FireCopenhagenDuoBroadside(state, 1);
        if (state.DuoCycleAge == 168)
        {
            if (state.DuoHealth[0] <= 0 && state.DuoHealth[1] > 0) FireCopenhagenDuoBroadside(state, 1);
            else if (state.DuoHealth[1] <= 0 && state.DuoHealth[0] > 0) FireCopenhagenDuoBroadside(state, 0);
        }
    }

    private void FireCopenhagenDuoBroadside(CopenhagenWorldState state, int ship)
    {
        (double shipX, double shipY) = CopenhagenDuoShipPosition(state, ship);
        for (int side = 0; side < 2; side++)
        {
            int turret = ship * 2 + side;
            if (state.DuoTurretHealth[turret] <= 0) continue;
            (double turretX, double turretY) = CopenhagenDuoTurretPosition(shipX, shipY, side);
            for (int lane = -1; lane <= 1; lane++)
            {
                double targetX = _shipX + lane * 34;
                double targetY = _height + 12;
                double dx = targetX - turretX;
                double dy = targetY - turretY;
                double length = Math.Max(1.0, Math.Sqrt(dx * dx + dy * dy));
                _enemyShots.Add(new EnemyShot(turretX, turretY, dx / length * 2.25, dy / length * 2.25, 2));
            }
        }
        _audio?.Trigger(StormaktSound.Broadside);
    }

    private void StepCopenhagenDuoRepair(CopenhagenWorldState state)
    {
        int interval = 420 + Math.Max(0, state.SnapphaneAllies) * 90 + Math.Min(3, state.IncomingFreedShips) * 30;
        if (state.DuoAge == 0 || state.DuoAge % interval != 0) return;
        int maximum = state.DuoTestFixture ? 12 : CopenhagenDuoTurretHealth;
        for (int turret = 0; turret < state.DuoTurretHealth.Length; turret++)
        {
            int ship = turret / 2;
            if (state.DuoHealth[ship] <= 0 || state.DuoTurretHealth[turret] > 0) continue;
            state.DuoTurretHealth[turret] = Math.Max(1, maximum / 2);
            state.DuoRepairFlash = 75;
            state.DuoRepairTurret = turret;
            _audio?.Trigger(StormaktSound.TitheUpgradeInstall);
            return;
        }
    }

    private void FallCopenhagenDuoShip(CopenhagenWorldState state, int ship)
    {
        state.DuoShipFallAge[ship] = 1;
        state.DuoTurretHealth[ship * 2] = 0;
        state.DuoTurretHealth[ship * 2 + 1] = 0;
        if (ship == 0) state.DuoShieldWall = null;
        if (ship == 1) state.DuoElefantenChargeAge = 0;
        _score += 2_800;
        _enemyShots.Clear();
        _audio?.Trigger(StormaktSound.EnemyExplosion);
        if (state.DuoHealth.All(health => health <= 0)) state.DuoDeathAge = 1;
    }

    private (double X, double Y) CopenhagenDuoShipPosition(CopenhagenWorldState state, int ship)
    {
        if (ship == 1 && state.DuoElefantenChargeAge > 0)
            return (state.DuoElefantenChargeX, -38 + state.DuoElefantenChargeAge * 3.15);
        double entry = Math.Min(1.0, state.DuoAge / 90.0);
        double eased = entry * entry * (3.0 - 2.0 * entry);
        double baseX = _width / 2.0 + (ship == 0 ? -82 : 82);
        double sway = Math.Sin((state.DuoAge + ship * 95) * 0.012) * 13;
        return (baseX + sway, -52 + 118 * eased + Math.Sin((state.DuoAge + ship * 47) * 0.018) * 5);
    }

    private static (double X, double Y) CopenhagenDuoTurretPosition(double shipX, double shipY, int side) =>
        (shipX + (side == 0 ? -24 : 24), shipY + 9);

    private double CopenhagenDuoWallNodeX(int node) => 28 + node * (_width - 56) / 6.0;

    private static double CopenhagenDuoWallY(CopenhagenShieldWall wall)
    {
        double entry = Math.Min(1.0, wall.Age / 45.0);
        return -18 + 122 * entry;
    }

    private void BeginCopenhagenSuperfrigate(CopenhagenWorldState state, bool testFixture = false)
    {
        state.SuperActive = true;
        state.SuperTestFixture = testFixture;
        state.SuperAge = 0;
        state.SuperPhase = 1;
        state.SuperPhaseAge = 0;
        state.SuperDeathAge = 0;
        state.SuperHitFlash = 0;
        state.SuperLastHitSection = -1;
        state.SuperLockQuadrant = -1;
        state.SuperLockAge = 0;
        state.SuperMemoryOrder = 0;
        state.SuperMemoryHealth = testFixture ? 90 : CopenhagenSuperMemoryHealth;
        state.SuperBeamAge = 0;
        state.SuperBeamTargetX = _shipX;
        state.SuperBeamHitPlayer = false;
        state.SuperSupportShown = false;
        int sectionHealth = testFixture ? 36 : CopenhagenSuperSectionHealth;
        state.SuperSectionHealth[0] = sectionHealth;
        state.SuperSectionHealth[1] = sectionHealth;
        state.SuperSectionHealth[2] = sectionHealth;
        state.SuperSectionHealth[3] = testFixture ? 72 : CopenhagenSuperReactorHealth;
        Array.Clear(state.SuperCrossHealth);
        state.SuperDrones.Clear();
        _enemyShots.Clear();
        _shots.Clear();
        if (testFixture) return;
        ActivateBossRadio(CopenhagenSuperRadio);
        _audio?.SwitchMusic(StormaktMusicTrack.Boss);
        _audio?.Trigger(StormaktSound.OresundCrownCoreOpen);
    }

    private void StepCopenhagenSuperfrigate(CopenhagenWorldState state)
    {
        state.SuperAge++;
        state.SuperPhaseAge++;
        state.SuperHitFlash = Math.Max(0, state.SuperHitFlash - 1);
        state.SuperSectionBreakFlash = Math.Max(0, state.SuperSectionBreakFlash - 1);
        if (state.SuperDeathAge > 0)
        {
            _shots.Clear();
            int deathAge = state.SuperDeathAge++;
            if (deathAge == 1)
            {
                _enemyShots.Clear();
                state.SuperDrones.Clear();
                _score += 15_000;
                ActivateBossRadio(CopenhagenSuperFallRadio);
                _audio?.Trigger(StormaktSound.Broadside);
            }
            if (deathAge is 22 or 48 or 79 or 116 or 158 or 207 or 261)
                _audio?.Trigger(StormaktSound.EnemyExplosion);
            if (deathAge < 320 || _bossRadioCard is not null) return;
            BeginCopenhagenLanding(state);
            return;
        }

        StepCopenhagenSuperDrones(state);
        StepCopenhagenSuperShots(state);
        switch (state.SuperPhase)
        {
            case 1:
                StepCopenhagenSuperSections(state);
                break;
            case 2:
                StepCopenhagenSuperCross(state);
                break;
            case 3:
                StepCopenhagenSuperMemory(state);
                break;
            default:
                StepCopenhagenSuperReactor(state);
                break;
        }
    }

    private void StepCopenhagenSuperSections(CopenhagenWorldState state)
    {
        (double centerX, double centerY) = CopenhagenSuperCenter(state);
        if (state.SuperSectionHealth[0] > 0 && state.SuperPhaseAge % 145 == 40 && state.SuperDrones.Count < 7)
        {
            for (int drone = -1; drone <= 1; drone++)
                state.SuperDrones.Add(new CopenhagenRoyalDrone(centerX + drone * 18, centerY + 28,
                    drone * 0.32, 0.72, state.SuperTestFixture ? 6 : 24, state.SuperDroneSerial++));
            _audio?.Trigger(StormaktSound.Deploy);
        }
        if (state.SuperPhaseAge % 92 == 0)
        {
            if (state.SuperSectionHealth[1] > 0) FireCopenhagenSuperBroadside(centerX - 76, centerY + 12, -1);
            if (state.SuperSectionHealth[2] > 0) FireCopenhagenSuperBroadside(centerX + 76, centerY + 12, 1);
        }
        if (state.SuperSectionHealth.Take(3).Any(health => health > 0)) return;
        state.SuperPhase = 2;
        state.SuperPhaseAge = 0;
        int health = state.SuperTestFixture ? 12 : CopenhagenSuperCrossNodeHealth;
        for (int node = 0; node < state.SuperCrossHealth.Length; node++) state.SuperCrossHealth[node] = health;
        state.SuperDrones.Clear();
        _enemyShots.Clear();
        ActivateBossRadio(CopenhagenSuperCrossRadio);
        _audio?.Trigger(StormaktSound.OresundFortressLock);
    }

    private void StepCopenhagenSuperCross(CopenhagenWorldState state)
    {
        if (state.SuperLockAge > 0)
        {
            state.SuperLockAge++;
            if (state.SuperLockAge > 82)
            {
                state.SuperLockAge = 0;
                state.SuperLockQuadrant = -1;
            }
            else if (state.SuperLockAge >= 44 && !state.SuperLockHitPlayer &&
                CopenhagenSuperShipInsideQuadrant(state.SuperLockQuadrant))
            {
                state.SuperLockHitPlayer = true;
                DamageShip();
            }
        }
        if (state.SuperPhaseAge % 105 == 1)
        {
            int start = state.SuperPhaseAge / 105;
            state.SuperLockQuadrant = -1;
            for (int offset = 0; offset < state.SuperCrossHealth.Length; offset++)
            {
                int quadrant = (start + offset) % state.SuperCrossHealth.Length;
                if (state.SuperCrossHealth[quadrant] <= 0) continue;
                state.SuperLockQuadrant = quadrant;
                break;
            }
            if (state.SuperLockQuadrant >= 0)
            {
                state.SuperLockAge = 1;
                state.SuperLockHitPlayer = false;
                _audio?.Trigger(StormaktSound.TitheSealWall);
            }
        }
        if (state.SuperPhaseAge % 72 == 0)
        {
            (double centerX, double centerY) = CopenhagenSuperCenter(state);
            FireAimedCopenhagenShot(centerX, centerY + 23, 2.3, 2);
        }
        if (state.SuperCrossHealth.Any(health => health > 0)) return;
        state.SuperPhase = 3;
        state.SuperPhaseAge = 0;
        state.SuperLockAge = 0;
        state.SuperLockQuadrant = -1;
        _enemyShots.Clear();
        ActivateBossRadio(CopenhagenSuperMemoryRadio);
        _audio?.Trigger(StormaktSound.TitheBossPhaseBreak);
    }

    private void StepCopenhagenSuperMemory(CopenhagenWorldState state)
    {
        int maximum = state.SuperTestFixture ? 90 : CopenhagenSuperMemoryHealth;
        int order = Math.Clamp((maximum - state.SuperMemoryHealth) * 3 / Math.Max(1, maximum), 0, 2);
        if (order > state.SuperMemoryOrder)
        {
            state.SuperMemoryOrder = order;
            _enemyShots.Clear();
            _audio?.Trigger(StormaktSound.Broadside);
        }
        (double centerX, double centerY) = CopenhagenSuperCenter(state);
        if (state.SuperPhaseAge % 76 == 0)
        {
            int lanes = 3 + state.SuperMemoryOrder * 2;
            for (int lane = 0; lane < lanes; lane++)
            {
                double angle = Math.PI * (0.18 + 0.64 * lane / Math.Max(1, lanes - 1));
                _enemyShots.Add(new EnemyShot(centerX, centerY + 24,
                    Math.Cos(angle) * 2.1, Math.Sin(angle) * 2.1, 6));
            }
        }
        if (state.SuperMemoryOrder >= 1 && state.SuperPhaseAge % 58 == 18)
        {
            for (int rocket = -1; rocket <= 1; rocket++)
            {
                double originX = centerX + rocket * 42;
                double dx = _shipX + rocket * 18 - originX;
                double dy = _shipY - centerY;
                double length = Math.Max(1.0, Math.Sqrt(dx * dx + dy * dy));
                _enemyShots.Add(new EnemyShot(originX, centerY + 4, dx / length * 2.65, dy / length * 2.65, 4));
            }
        }
        if (state.SuperMemoryOrder >= 2) StepCopenhagenSuperBeam(state, 126);
        if (state.SuperMemoryHealth > 0) return;
        state.SuperPhase = 4;
        state.SuperPhaseAge = 0;
        state.SuperBeamAge = 0;
        _enemyShots.Clear();
        ActivateBossRadio(CopenhagenSuperHoldRadio);
        _audio?.Trigger(StormaktSound.OresundCrownCoreOpen);
    }

    private void StepCopenhagenSuperReactor(CopenhagenWorldState state)
    {
        int support = Math.Min(7, Math.Max(0, state.IncomingFreedShips) + Math.Max(0, state.SnapphaneAllies) +
            (state.SorenOathComplete ? 2 : 0));
        int aimedInterval = 48 + support * 5;
        (double centerX, double centerY) = CopenhagenSuperCenter(state);
        if (state.SuperPhaseAge % aimedInterval == 0)
        {
            FireAimedCopenhagenShot(centerX - 48, centerY + 18, 2.55, 2);
            FireAimedCopenhagenShot(centerX + 48, centerY + 18, 2.55, 2);
        }
        int droneInterval = 150 + support * 18;
        if (state.SuperPhaseAge % droneInterval == 35 && state.SuperDrones.Count < 5)
        {
            state.SuperDrones.Add(new CopenhagenRoyalDrone(centerX, centerY + 25, 0, 0.9,
                state.SuperTestFixture ? 6 : 24, state.SuperDroneSerial++));
        }
        StepCopenhagenSuperBeam(state, 138 + support * 4);
        if (!state.SuperSupportShown && state.SuperPhaseAge >= 90)
        {
            state.SuperSupportShown = true;
            state.SuperSupportFlash = 90;
            _audio?.Trigger(StormaktSound.TwinCannon);
        }
        state.SuperSupportFlash = Math.Max(0, state.SuperSupportFlash - 1);
        if (state.SuperSectionHealth[3] > 0) return;
        state.SuperDeathAge = 1;
    }

    private void StepCopenhagenSuperBeam(CopenhagenWorldState state, int interval)
    {
        if (state.SuperBeamAge > 0)
        {
            state.SuperBeamAge++;
            if (state.SuperBeamAge is >= 42 and <= 72 && !state.SuperBeamHitPlayer &&
                Math.Abs(_shipX - state.SuperBeamTargetX) < 10)
            {
                state.SuperBeamHitPlayer = true;
                DamageShip();
            }
            if (state.SuperBeamAge > 82) state.SuperBeamAge = 0;
        }
        if (state.SuperBeamAge == 0 && state.SuperPhaseAge % interval == 1)
        {
            state.SuperBeamAge = 1;
            state.SuperBeamTargetX = _shipX;
            state.SuperBeamHitPlayer = false;
            _audio?.Trigger(StormaktSound.OresundLaserRelay);
        }
    }

    private void StepCopenhagenSuperDrones(CopenhagenWorldState state)
    {
        for (int index = state.SuperDrones.Count - 1; index >= 0; index--)
        {
            CopenhagenRoyalDrone drone = state.SuperDrones[index];
            drone.Age++;
            drone.X += drone.Vx + Math.Sin((drone.Age + drone.Serial * 17) * 0.06) * 0.32;
            drone.Y += drone.Vy;
            if (drone.Age % 95 == 0) FireAimedCopenhagenShot(drone.X, drone.Y, 2.05, 3);
            if (DistanceSquared(drone.X, drone.Y, _shipX, _shipY) < 15 * 15)
            {
                state.SuperDrones.RemoveAt(index);
                DamageShip();
                continue;
            }
            if (drone.Y > _height + 24 || drone.X < -24 || drone.X > _width + 24)
                state.SuperDrones.RemoveAt(index);
        }
    }

    private void StepCopenhagenSuperShots(CopenhagenWorldState state)
    {
        (double centerX, double centerY) = CopenhagenSuperCenter(state);
        for (int shotIndex = _shots.Count - 1; shotIndex >= 0; shotIndex--)
        {
            Shot shot = _shots[shotIndex];
            CopenhagenRoyalDrone? drone = state.SuperDrones
                .FirstOrDefault(candidate => DistanceSquared(shot.X, shot.Y, candidate.X, candidate.Y) < 13 * 13);
            if (drone is not null)
            {
                drone.Health -= shot.Power;
                _shots.RemoveAt(shotIndex);
                if (drone.Health <= 0)
                {
                    state.SuperDrones.Remove(drone);
                    _score += 120;
                    _audio?.Trigger(StormaktSound.EnemyExplosion);
                }
                continue;
            }

            int target = -1;
            if (state.SuperPhase == 1)
            {
                for (int section = 0; section < 3; section++)
                {
                    if (state.SuperSectionHealth[section] <= 0) continue;
                    (double sectionX, double sectionY) = CopenhagenSuperSectionPosition(section, centerX, centerY);
                    if (DistanceSquared(shot.X, shot.Y, sectionX, sectionY) < (section == 0 ? 22 * 22 : 27 * 27))
                    {
                        target = section;
                        break;
                    }
                }
                if (target >= 0)
                    state.SuperSectionHealth[target] = Math.Max(0, state.SuperSectionHealth[target] - shot.Power);
            }
            else if (state.SuperPhase == 2)
            {
                for (int node = 0; node < state.SuperCrossHealth.Length; node++)
                {
                    if (state.SuperCrossHealth[node] <= 0) continue;
                    (double nodeX, double nodeY) = CopenhagenSuperCrossNodePosition(node, centerX, centerY);
                    if (DistanceSquared(shot.X, shot.Y, nodeX, nodeY) >= 14 * 14) continue;
                    state.SuperCrossHealth[node] = Math.Max(0, state.SuperCrossHealth[node] - shot.Power);
                    target = 10 + node;
                    break;
                }
            }
            else if (state.SuperPhase == 3 && state.SuperMemoryHealth > 0 &&
                DistanceSquared(shot.X, shot.Y, centerX, centerY - 4) < 25 * 25)
            {
                state.SuperMemoryHealth = Math.Max(0, state.SuperMemoryHealth - shot.Power);
                target = 20;
            }
            else if (state.SuperPhase == 4 && state.SuperSectionHealth[3] > 0 &&
                DistanceSquared(shot.X, shot.Y, centerX, centerY - 5) < 29 * 29)
            {
                state.SuperSectionHealth[3] = Math.Max(0, state.SuperSectionHealth[3] - shot.Power);
                target = 3;
            }
            if (target < 0) continue;
            _shots.RemoveAt(shotIndex);
            state.SuperHitFlash = 5;
            state.SuperLastHitSection = target;
            bool broken = target switch
            {
                >= 10 and < 14 => state.SuperCrossHealth[target - 10] == 0,
                20 => state.SuperMemoryHealth == 0,
                _ => state.SuperSectionHealth[target] == 0,
            };
            if (!broken) continue;
            state.SuperSectionBreakFlash = 20;
            _score += target >= 10 ? 480 : 900;
            _audio?.Trigger(StormaktSound.OresundCrownCoreBreak);
        }
    }

    private void FireCopenhagenSuperBroadside(double x, double y, int side)
    {
        for (int lane = -2; lane <= 2; lane++)
        {
            double targetX = _shipX + lane * 31 + side * 12;
            double dx = targetX - x;
            double dy = _height + 10 - y;
            double length = Math.Max(1.0, Math.Sqrt(dx * dx + dy * dy));
            _enemyShots.Add(new EnemyShot(x, y, dx / length * 2.3, dy / length * 2.3, 2));
        }
        _audio?.Trigger(StormaktSound.Broadside);
    }

    private bool CopenhagenSuperShipInsideQuadrant(int quadrant)
    {
        if (quadrant < 0) return false;
        int splitY = (_height + 52) / 2;
        bool right = _shipX >= _width / 2;
        bool bottom = _shipY >= splitY;
        return quadrant switch
        {
            0 => !right && !bottom,
            1 => right && !bottom,
            2 => right && bottom,
            _ => !right && bottom,
        };
    }

    private (double X, double Y) CopenhagenSuperCenter(CopenhagenWorldState state)
    {
        double entry = Math.Min(1.0, state.SuperAge / 110.0);
        double eased = entry * entry * (3.0 - 2.0 * entry);
        return (_width / 2.0 + Math.Sin(state.SuperAge * 0.006) * 18, -88 + 148 * eased);
    }

    private static (double X, double Y) CopenhagenSuperSectionPosition(int section, double centerX, double centerY) => section switch
    {
        0 => (centerX, centerY + 27),
        1 => (centerX - 77, centerY + 10),
        _ => (centerX + 77, centerY + 10),
    };

    private static (double X, double Y) CopenhagenSuperCrossNodePosition(int node, double centerX, double centerY)
    {
        double angle = Math.PI / 4.0 + node * Math.PI / 2.0;
        return (centerX + Math.Cos(angle) * 76.0, centerY + 32 + Math.Sin(angle) * 49.0);
    }

    private void BeginCopenhagenLanding(CopenhagenWorldState state, bool testFixture = false)
    {
        state.LandingActive = true;
        state.GroundActive = false;
        state.Ground = null;
        state.LandingTestFixture = testFixture;
        state.LandingAge = 0;
        state.LandingReleaseAge = 0;
        state.LandingHitFlash = 0;
        int health = testFixture ? 12 : CopenhagenLandingAnchorHealth;
        for (int anchor = 0; anchor < state.LandingAnchorHealth.Length; anchor++)
            state.LandingAnchorHealth[anchor] = health;
        _enemyShots.Clear();
        _shots.Clear();
        if (testFixture) return;
        ActivateBossRadio(CopenhagenLandingRadio);
        _audio?.SwitchMusic(StormaktMusicTrack.Relief);
        _audio?.Trigger(StormaktSound.OresundTrainRumble);
    }

    private void StepCopenhagenLanding(CopenhagenWorldState state)
    {
        state.LandingAge++;
        state.LandingHitFlash = Math.Max(0, state.LandingHitFlash - 1);
        for (int shotIndex = _shots.Count - 1; shotIndex >= 0; shotIndex--)
        {
            Shot shot = _shots[shotIndex];
            int hitAnchor = -1;
            for (int anchor = 0; anchor < state.LandingAnchorHealth.Length; anchor++)
            {
                if (state.LandingAnchorHealth[anchor] <= 0) continue;
                (double anchorX, double anchorY) = CopenhagenLandingAnchorPosition(anchor);
                if (DistanceSquared(shot.X, shot.Y, anchorX, anchorY) < 16 * 16)
                {
                    hitAnchor = anchor;
                    break;
                }
            }
            if (hitAnchor < 0) continue;
            state.LandingAnchorHealth[hitAnchor] = Math.Max(0, state.LandingAnchorHealth[hitAnchor] - shot.Power);
            state.LandingHitFlash = 5;
            state.LandingLastHitAnchor = hitAnchor;
            _shots.RemoveAt(shotIndex);
            if (state.LandingAnchorHealth[hitAnchor] == 0)
            {
                _score += 600;
                _audio?.Trigger(StormaktSound.TitheChainLockBreak);
            }
        }
        if (state.LandingAge > 75 && state.LandingAge % 84 == 0)
        {
            int anchor = state.LandingAge / 84 % state.LandingAnchorHealth.Length;
            if (state.LandingAnchorHealth[anchor] > 0)
            {
                (double anchorX, double anchorY) = CopenhagenLandingAnchorPosition(anchor);
                FireAimedCopenhagenShot(anchorX, anchorY + 7, 2.05, 4);
            }
        }
        if (state.LandingAnchorHealth.Any(health => health > 0)) return;
        if (state.LandingReleaseAge == 0)
        {
            state.LandingReleaseAge = 1;
            _enemyShots.Clear();
            ActivateBossRadio(CopenhagenLandingClearRadio);
            _audio?.Trigger(StormaktSound.OresundTrainCrash);
            return;
        }
        state.LandingReleaseAge++;
        if (state.LandingReleaseAge < 170 || _bossRadioCard is not null) return;
        BeginCopenhagenGround(state, testFixture: state.LandingTestFixture);
    }

    private (double X, double Y) CopenhagenLandingAnchorPosition(int anchor)
    {
        double x = (anchor + 1) * _width / 4.0;
        double y = 73 + anchor * 25 + Math.Sin((anchor + 1) * 1.7) * 5;
        return (x, y);
    }

    private void BeginCopenhagenGround(
        CopenhagenWorldState state, bool testFixture = false, bool suppressSave = false)
    {
        state.LandingActive = false;
        state.GroundActive = true;
        var ground = new CopenhagenGroundState
        {
            TestFixture = testFixture,
            SuppressSave = suppressSave,
            KarlX = _width / 2.0,
            KarlY = _height - 48,
            TargetX = _width / 2.0,
            TargetY = _height - 48,
            Health = 100,
            MaxHealth = 100,
            Potions = 1,
            FacingX = 0,
            FacingY = -1,
        };
        int enemyHealth = testFixture ? 12 : 42;
        (double X, double Y)[] positions =
        [
            (_width * 0.27, _height * 0.55),
            (_width * 0.73, _height * 0.51),
            (_width * 0.38, _height * 0.34),
            (_width * 0.64, _height * 0.29),
        ];
        for (int index = 0; index < positions.Length; index++)
            ground.Enemies.Add(new CopenhagenGroundEnemy(index, positions[index].X, positions[index].Y, enemyHealth));
        state.Ground = ground;
        _enemyShots.Clear();
        _shots.Clear();
        ClearBossRadio();
        if (!testFixture) ActivateBossRadio(CopenhagenGroundRadio);
        _audio?.SwitchMusic(StormaktMusicTrack.Dungeon);
        _audio?.Trigger(StormaktSound.DungeonSwordSlash);
        if (!testFixture && !suppressSave && !CopenhagenFixtureActive) WriteCopenhagenGroundSave(ground);
    }

    private void StepCopenhagenGround(
        CopenhagenWorldState state, uint buttons, RtsPointer pointer, ControllerInput controller)
    {
        CopenhagenGroundState? ground = state.Ground;
        if (ground is null) return;
        ground.Age++;
        ground.HitFlash = Math.Max(0, ground.HitFlash - 1);
        ground.AttackAge = Math.Max(0, ground.AttackAge - 1);
        ground.AttackCooldown = Math.Max(0, ground.AttackCooldown - 1);
        ground.PotionFlash = Math.Max(0, ground.PotionFlash - 1);
        ground.Moving = false;

        if (ground.Dead)
        {
            if (Pressed(buttons, Start))
            {
                if (!ground.TestFixture && !ground.SuppressSave &&
                    TryLoadCopenhagenGroundSave(out CopenhagenGroundSave save))
                    RestoreCopenhagenGround(state, save);
                else
                {
                    int restartRoom = ground.Room;
                    BeginCopenhagenGround(state, ground.TestFixture, ground.SuppressSave);
                    if (restartRoom >= 2 && state.Ground is CopenhagenGroundState restarted)
                    {
                        BeginCopenhagenRosenborgRoom(restarted);
                        if (restartRoom >= 3) BeginCopenhagenMemoryMachineRoom(restarted);
                        if (restartRoom >= 4) BeginCopenhagenSagaKingRoom(restarted);
                        if (restartRoom >= 5) BeginCopenhagenKorrektoriusRoom(restarted);
                        if (restartRoom >= 6) BeginCopenhagenWrathRoom(restarted);
                        if (restartRoom == 7) BeginCopenhagenCodexRoom(restarted);
                    }
                }
            }
            return;
        }
        if (ground.MarginalChoosing)
        {
            StepCopenhagenMarginalChoice(ground, buttons, pointer);
            return;
        }
        if (ground.MarginalCompileAge > 0)
        {
            StepCopenhagenMarginalCompile(ground);
            return;
        }
        if (ground.LegendChoosing)
        {
            StepCopenhagenLegendChoice(ground, buttons, pointer);
            return;
        }
        if (ground.LegendCompileAge > 0)
        {
            StepCopenhagenLegendCompile(ground);
            return;
        }
        if (ground.LocalLawChoosing)
        {
            StepCopenhagenLocalLawChoice(ground, buttons, pointer);
            return;
        }
        if (ground.LocalLawCompileAge > 0)
        {
            StepCopenhagenLocalLawCompile(ground);
            return;
        }
        if (ground.Room == 7 && ground.CodexOpened)
        {
            StepCopenhagenCodex(ground);
            return;
        }

        int speed = (buttons & Slow) != 0 ? 2 :
            ground.Room >= 5 && ground.LocalLaw == CopenhagenLocalLaw.SilverLighterThanGuilt ? 4 : 3;
        double previousKarlX = ground.KarlX;
        double previousKarlY = ground.KarlY;
        uint directions = Up | Down | Left | Right;
        uint controllerDirections = controller.Buttons & directions;
        uint keyboardDirections = (buttons & directions) & ~controllerDirections;
        int dx = ((keyboardDirections & Right) != 0 ? speed : 0) - ((keyboardDirections & Left) != 0 ? speed : 0);
        int dy = ((keyboardDirections & Down) != 0 ? speed : 0) - ((keyboardDirections & Up) != 0 ? speed : 0);
        (int analogX, int analogY, bool analogActive) = ControllerStickMovement(controller.LeftX, controller.LeftY, speed);
        if (analogActive)
        {
            dx += analogX;
            dy += analogY;
        }
        else
        {
            dx += ((controllerDirections & Right) != 0 ? 1 : 0) - ((controllerDirections & Left) != 0 ? 1 : 0);
            dy += ((controllerDirections & Down) != 0 ? 1 : 0) - ((controllerDirections & Up) != 0 ? 1 : 0);
        }
        if ((pointer.Buttons & 2) != 0 && pointer.Inside)
        {
            ground.TargetX = pointer.X;
            ground.TargetY = pointer.Y;
            ground.HasTarget = true;
        }
        if (dx != 0 || dy != 0)
        {
            ground.HasTarget = false;
            double length = Math.Max(1.0, Math.Sqrt(dx * dx + dy * dy));
            ground.FacingX = dx / length;
            ground.FacingY = dy / length;
            ground.KarlX += dx;
            ground.KarlY += dy;
        }
        else if (ground.HasTarget)
        {
            double targetDx = ground.TargetX - ground.KarlX;
            double targetDy = ground.TargetY - ground.KarlY;
            double length = Math.Sqrt(targetDx * targetDx + targetDy * targetDy);
            if (length <= speed) ground.HasTarget = false;
            else
            {
                ground.FacingX = targetDx / length;
                ground.FacingY = targetDy / length;
                ground.KarlX += ground.FacingX * speed;
                ground.KarlY += ground.FacingY * speed;
            }
        }
        ground.KarlX = Math.Clamp(ground.KarlX, 18, _width - 18);
        ground.KarlY = Math.Clamp(ground.KarlY, 47, _height - 17);
        double travelledX = ground.KarlX - previousKarlX;
        double travelledY = ground.KarlY - previousKarlY;
        double travelled = Math.Sqrt(travelledX * travelledX + travelledY * travelledY);
        ground.Moving = travelled > 0.01;
        ground.GaitDistance += travelled;

        if (ground.Room == 7)
        {
            StepCopenhagenCodex(ground);
            return;
        }

        bool pointerAttack = (pointer.Buttons & 1) != 0 && pointer.Inside;
        if (((buttons & Fire) != 0 || pointerAttack) && ground.AttackCooldown == 0)
        {
            if (pointerAttack)
            {
                double aimX = pointer.X - ground.KarlX;
                double aimY = pointer.Y - ground.KarlY;
                double length = Math.Max(1.0, Math.Sqrt(aimX * aimX + aimY * aimY));
                ground.FacingX = aimX / length;
                ground.FacingY = aimY / length;
            }
            AttackCopenhagenGround(ground);
        }
        if (Pressed(buttons, QuickPotion) && ground.Potions > 0 && ground.Health < ground.MaxHealth)
        {
            ground.Potions--;
            ground.Health = Math.Min(ground.MaxHealth, ground.Health + 45);
            ground.PotionFlash = 30;
            _audio?.Trigger(StormaktSound.Deploy);
        }
        StepCopenhagenGroundEnemies(ground);
        if (ground.Room == 1) StepCopenhagenArsenalCannon(ground);
        if (ground.Room >= 2) StepCopenhagenMaterialForm(ground);
        if (ground.Room == 2)
        {
            StepCopenhagenRosenborgCore(ground);
        }
        else if (ground.Room == 3) StepCopenhagenLegend(ground);
        else if (ground.Room == 4) StepCopenhagenSagaKing(ground);
        else if (ground.Room == 5) StepCopenhagenKorrektorius(ground);
        else if (ground.Room == 6) StepCopenhagenWrath(ground);
        bool threatsCleared = ground.Room != 7 && ground.Enemies.All(enemy => enemy.Health <= 0) &&
            (ground.Room != 1 || ground.ArsenalCannonHealth <= 0) &&
            (ground.Room != 2 || ground.RosenborgCoreHealth <= 0) &&
            (ground.Room != 4 || ground.SagaKingHealth <= 0) &&
            (ground.Room != 5 || ground.KorrektoriusHealth <= 0) &&
            (ground.Room != 6 || ground.WrathHealth <= 0);
        if (!ground.RoomClear && threatsCleared)
        {
            ground.RoomClear = true;
            ground.DoorReady = true;
            ActivateBossRadio(ground.Room switch
            {
                0 => CopenhagenGroundClearRadio,
                1 => CopenhagenArsenalClearRadio,
                2 => CopenhagenRosenborgClearRadio,
                3 => CopenhagenMemoryClearRadio,
                4 => CopenhagenSagaKingClearRadio,
                5 => CopenhagenKorrektoriusClearRadio,
                _ => CopenhagenWrathClearRadio,
            });
            _score += 2_400;
            _audio?.Trigger(StormaktSound.DungeonSilverShatter);
            if (!ground.TestFixture && !ground.SuppressSave && !CopenhagenFixtureActive)
                WriteCopenhagenGroundSave(ground);
        }
        bool atHeart = DistanceSquared(ground.KarlX, ground.KarlY, _width / 2.0, 43) < 29 * 29;
        bool atLectern = DistanceSquared(ground.KarlX, ground.KarlY, _width / 2.0, _height - 52) < 27 * 27;
        if (ground.Room == 0 && ground.DoorReady && atHeart && !ground.HeartPortOpen &&
            ((buttons & Fire) != 0 || pointerAttack))
        {
            ground.MarginalChoosing = true;
            ground.MarginalSelection = 0;
            ground.ChoicePointerSeen = false;
            ground.HasTarget = false;
            _audio?.Trigger(StormaktSound.Deploy);
        }
        else if (ground.Room == 0 && ground.HeartPortOpen && atHeart &&
            ((buttons & Up) != 0 || Pressed(buttons, Fire) || pointerAttack))
        {
            BeginCopenhagenArsenalRoom(ground);
        }
        else if (ground.Room == 1 && ground.DoorReady && atHeart &&
            ((buttons & Fire) != 0 || pointerAttack))
        {
            BeginCopenhagenRosenborgRoom(ground);
        }
        else if (ground.Room == 2 && atLectern && Pressed(buttons, AltFire))
        {
            ground.MarginalChoosing = true;
            ground.MarginalSelection = ground.ActiveMarginal == CopenhagenMarginalLaw.SilverIsBlade ? 1 : 0;
            ground.ChoicePointerSeen = false;
            ground.HasTarget = false;
            _audio?.Trigger(StormaktSound.Deploy);
        }
        else if (ground.Room == 2 && ground.DoorReady && atHeart &&
            ((buttons & Fire) != 0 || pointerAttack))
        {
            BeginCopenhagenMemoryMachineRoom(ground);
        }
        else if (ground.Room == 3 && ground.DoorReady && atHeart &&
            ((buttons & Fire) != 0 || pointerAttack))
        {
            BeginCopenhagenSagaKingRoom(ground);
        }
        else if (ground.Room == 4 && ground.DoorReady && atHeart &&
            ((buttons & Fire) != 0 || pointerAttack))
        {
            BeginCopenhagenKorrektoriusRoom(ground);
        }
        else if (ground.Room == 5 && atLectern && Pressed(buttons, AltFire) &&
            ground.KorrektoriusHealth > 0)
        {
            ground.LocalLawChoosing = true;
            ground.LocalLawSelection = Math.Max(0, (int)ground.LocalLaw - 1);
            ground.ChoicePointerSeen = false;
            ground.HasTarget = false;
            _audio?.Trigger(StormaktSound.Deploy);
        }
        else if (ground.Room == 5 && ground.DoorReady && atHeart &&
            ((buttons & Fire) != 0 || pointerAttack))
        {
            BeginCopenhagenWrathRoom(ground);
        }
        else if (ground.Room == 6 && CopenhagenWrathPhase(ground) == 0 && atLectern &&
            Pressed(buttons, AltFire) && ground.WrathHealth > 0)
        {
            ground.LocalLawChoosing = true;
            ground.LocalLawSelection = Math.Max(0, (int)ground.LocalLaw - 1);
            ground.ChoicePointerSeen = false;
            ground.HasTarget = false;
            _audio?.Trigger(StormaktSound.Deploy);
        }
        else if (ground.Room == 6 && ground.DoorReady && atHeart &&
            ((buttons & Fire) != 0 || pointerAttack))
        {
            BeginCopenhagenCodexRoom(ground);
        }
    }

    private void AttackCopenhagenGround(CopenhagenGroundState ground)
    {
        ground.AttackAge = 12;
        ground.AttackCooldown = 17;
        ground.AttackSerial++;
        foreach (CopenhagenGroundEnemy enemy in ground.Enemies)
        {
            if (enemy.Health <= 0) continue;
            double dx = enemy.X - ground.KarlX;
            double dy = enemy.Y - ground.KarlY;
            double distance = Math.Sqrt(dx * dx + dy * dy);
            if (distance > 39 || distance < 1) continue;
            double facing = dx / distance * ground.FacingX + dy / distance * ground.FacingY;
            if (facing < -0.05) continue;
            enemy.Health = Math.Max(0, enemy.Health - 18);
            enemy.HitFlash = 6;
            enemy.StaggerAge = 10;
            enemy.LastHitSerial = ground.AttackSerial;
            if (enemy.Health == 0)
            {
                enemy.DeathAge = 1;
                _score += 320;
                _audio?.Trigger(StormaktSound.DungeonSilverShatter);
            }
            else
            {
                _audio?.Trigger(StormaktSound.DungeonSwordHit);
            }
        }
        if (ground.Room == 1 && ground.ArsenalCannonHealth > 0)
        {
            (double cannonX, double cannonY) = CopenhagenArsenalCannonPosition();
            double dx = cannonX - ground.KarlX;
            double dy = cannonY - ground.KarlY;
            double distance = Math.Sqrt(dx * dx + dy * dy);
            if (distance <= 46 && distance >= 1 &&
                dx / distance * ground.FacingX + dy / distance * ground.FacingY >= -0.05)
            {
                ground.ArsenalCannonHealth = Math.Max(0, ground.ArsenalCannonHealth - 18);
                ground.ArsenalCannonHitFlash = 7;
                _audio?.Trigger(ground.ArsenalCannonHealth == 0
                    ? StormaktSound.DungeonSilverShatter : StormaktSound.DungeonSwordHit);
                if (ground.ArsenalCannonHealth == 0) _score += 700;
            }
        }
        if (ground.Room == 2 && ground.RosenborgCoreHealth > 0)
        {
            (double coreX, double coreY) = CopenhagenRosenborgCorePosition();
            double dx = coreX - ground.KarlX;
            double dy = coreY - ground.KarlY;
            double distance = Math.Sqrt(dx * dx + dy * dy);
            if (distance <= 49 && distance >= 1 &&
                dx / distance * ground.FacingX + dy / distance * ground.FacingY >= -0.05)
            {
                DamageCopenhagenRosenborgCore(ground, 18);
            }
        }
        if (ground.Room == 4 && ground.SagaKingHealth > 0)
        {
            (double bossX, double bossY) = CopenhagenSagaKingPosition(ground);
            double dx = bossX - ground.KarlX;
            double dy = bossY - ground.KarlY;
            double distance = Math.Sqrt(dx * dx + dy * dy);
            if (distance <= 55 && distance >= 1 &&
                dx / distance * ground.FacingX + dy / distance * ground.FacingY >= -0.05)
                DamageCopenhagenSagaKing(ground, 18);
        }
        if (ground.Room == 5 && ground.KorrektoriusHealth > 0)
        {
            int damage = ground.LocalLaw == CopenhagenLocalLaw.SilverLighterThanGuilt ? 21 : 18;
            int targetPen = Enumerable.Range(0, ground.KorrektoriusPenHealth.Length)
                .Where(pen => ground.KorrektoriusPenHealth[pen] > 0)
                .Where(pen =>
                {
                    (double penX, double penY) = CopenhagenKorrektoriusPenPosition(ground, pen);
                    double dx = penX - ground.KarlX;
                    double dy = penY - ground.KarlY;
                    double distance = Math.Sqrt(dx * dx + dy * dy);
                    return distance is >= 1 and <= 48 &&
                        dx / distance * ground.FacingX + dy / distance * ground.FacingY >= -0.05;
                })
                .OrderBy(pen =>
                {
                    (double penX, double penY) = CopenhagenKorrektoriusPenPosition(ground, pen);
                    return DistanceSquared(ground.KarlX, ground.KarlY, penX, penY);
                })
                .DefaultIfEmpty(-1).First();
            if (targetPen >= 0) DamageCopenhagenKorrektoriusPen(ground, targetPen, damage);
            else if (ground.KorrektoriusPenHealth.All(health => health <= 0))
            {
                (double bossX, double bossY) = CopenhagenKorrektoriusPosition(ground);
                double dx = bossX - ground.KarlX;
                double dy = bossY - ground.KarlY;
                double distance = Math.Sqrt(dx * dx + dy * dy);
                if (distance is >= 1 and <= 58 &&
                    dx / distance * ground.FacingX + dy / distance * ground.FacingY >= -0.05)
                    DamageCopenhagenKorrektorius(ground, damage);
            }
        }
        if (ground.Room == 6 && ground.WrathHealth > 0)
        {
            int damage = ground.LocalLaw == CopenhagenLocalLaw.SilverLighterThanGuilt ? 21 : 18;
            if (CopenhagenWrathPhase(ground) == 2)
            {
                int targetWord = Enumerable.Range(0, ground.WrathWordHealth.Length)
                    .Where(word => ground.WrathWordHealth[word] > 0)
                    .Where(word =>
                    {
                        (double wordX, double wordY) = CopenhagenWrathWordPosition(ground, word);
                        double dx = wordX - ground.KarlX;
                        double dy = wordY - ground.KarlY;
                        double distance = Math.Sqrt(dx * dx + dy * dy);
                        return distance is >= 1 and <= 48 &&
                            dx / distance * ground.FacingX + dy / distance * ground.FacingY >= -0.05;
                    })
                    .OrderBy(word =>
                    {
                        (double wordX, double wordY) = CopenhagenWrathWordPosition(ground, word);
                        return DistanceSquared(ground.KarlX, ground.KarlY, wordX, wordY);
                    })
                    .DefaultIfEmpty(-1).First();
                if (targetWord >= 0)
                {
                    DamageCopenhagenWrathWord(ground, targetWord, damage);
                    _audio?.Trigger(StormaktSound.DungeonSwordSlash);
                    return;
                }
            }
            if (CopenhagenWrathCanTakeDamage(ground))
            {
                (double bossX, double bossY) = CopenhagenWrathPosition(ground);
                double dx = bossX - ground.KarlX;
                double dy = bossY - ground.KarlY;
                double distance = Math.Sqrt(dx * dx + dy * dy);
                if (distance is >= 1 and <= 62 &&
                    dx / distance * ground.FacingX + dy / distance * ground.FacingY >= -0.05)
                    DamageCopenhagenWrath(ground, damage);
            }
        }
        _audio?.Trigger(StormaktSound.DungeonSwordSlash);
    }

    private void StepCopenhagenMarginalChoice(CopenhagenGroundState ground, uint buttons, RtsPointer pointer)
    {
        if (Pressed(buttons, Left) || Pressed(buttons, Up))
        {
            ground.MarginalSelection = 0;
            _audio?.Trigger(StormaktSound.Deploy);
        }
        if (Pressed(buttons, Right) || Pressed(buttons, Down))
        {
            ground.MarginalSelection = 1;
            _audio?.Trigger(StormaktSound.Deploy);
        }
        bool pointerMoved = ground.ChoicePointerSeen &&
            (pointer.X != ground.ChoicePointerX || pointer.Y != ground.ChoicePointerY);
        if (pointer.Inside && (pointerMoved || pointer.Buttons != 0))
            ground.MarginalSelection = pointer.X < _width / 2 ? 0 : 1;
        ground.ChoicePointerSeen = pointer.Inside;
        ground.ChoicePointerX = pointer.X;
        ground.ChoicePointerY = pointer.Y;
        if (Pressed(buttons, AltFire))
        {
            ground.MarginalChoosing = false;
            _audio?.Trigger(StormaktSound.Deploy);
            return;
        }
        bool pointerCompile = pointer.Inside && (pointer.Buttons & 1) != 0;
        if (!Pressed(buttons, Start) && !Pressed(buttons, Fire) && !pointerCompile) return;
        ground.MarginalChoosing = false;
        ground.ActiveMarginal = ground.Room == 2
            ? ground.MarginalSelection == 0
                ? CopenhagenMarginalLaw.SilverIsShield : CopenhagenMarginalLaw.SilverIsBlade
            : ground.MarginalSelection == 0
                ? CopenhagenMarginalLaw.HeartIsPort : CopenhagenMarginalLaw.HeartIsOpen;
        ground.MarginalCompileAge = 1;
        if (ground.Room == 0) ground.HeartPortOpen = false;
        _audio?.Trigger(StormaktSound.DungeonSilverShatter);
    }

    private void StepCopenhagenMarginalCompile(CopenhagenGroundState ground)
    {
        ground.MarginalCompileAge++;
        if (ground.ActiveMarginal is CopenhagenMarginalLaw.SilverIsShield or CopenhagenMarginalLaw.SilverIsBlade)
        {
            if (ground.MarginalCompileAge == 38)
            {
                ground.MaterialShieldCooldown = 0;
                ground.MaterialBladeAge = 0;
                _audio?.Trigger(StormaktSound.DungeonSilverWave);
            }
            if (ground.MarginalCompileAge >= 76)
            {
                ground.MarginalCompileAge = 0;
                if (!ground.TestFixture && !ground.SuppressSave && !CopenhagenFixtureActive)
                    WriteCopenhagenGroundSave(ground);
            }
            return;
        }
        if (ground.ActiveMarginal == CopenhagenMarginalLaw.HeartIsPort)
        {
            if (ground.MarginalCompileAge == 62)
            {
                ground.HeartPortOpen = true;
                _audio?.Trigger(StormaktSound.OresundCrownCoreOpen);
            }
            if (ground.MarginalCompileAge >= 112) ground.MarginalCompileAge = 0;
            return;
        }
        if (ground.ActiveMarginal != CopenhagenMarginalLaw.HeartIsOpen) return;
        if (ground.MarginalCompileAge == 54)
        {
            ground.HeartPortOpen = true;
            DamageCopenhagenGround(ground);
            ActivateBossRadio(CopenhagenMarginalFaultRadio);
            _audio?.Trigger(StormaktSound.OresundTrainCrash);
        }
        if (ground.MarginalCompileAge < 128) return;
        ground.MarginalCompileAge = 0;
        ground.ActiveMarginal = CopenhagenMarginalLaw.None;
        ground.HeartPortOpen = false;
        ground.MarginalChoosing = true;
        ground.MarginalSelection = 0;
        ground.ChoicePointerSeen = false;
    }

    private void BeginCopenhagenArsenalRoom(CopenhagenGroundState ground)
    {
        ground.Room = 1;
        ground.Age = 0;
        ground.KarlX = _width / 2.0;
        ground.KarlY = _height - 45;
        ground.TargetX = ground.KarlX;
        ground.TargetY = ground.KarlY;
        ground.HasTarget = false;
        ground.FacingX = 0;
        ground.FacingY = -1;
        ground.RoomClear = false;
        ground.DoorReady = false;
        ground.CheckpointReady = false;
        ground.ArsenalCannonAttackAge = 0;
        ground.ArsenalCannonHitFlash = 0;
        ground.ArsenalCannonHealth = ground.TestFixture ? 18 : CopenhagenArsenalCannonHealth;
        ground.Enemies.Clear();
        int enemyHealth = ground.TestFixture ? 12 : 42;
        (double X, double Y)[] positions =
        [
            (_width * 0.28, _height * 0.50),
            (_width * 0.72, _height * 0.46),
            (_width * 0.36, _height * 0.31),
        ];
        for (int index = 0; index < positions.Length; index++)
            ground.Enemies.Add(new CopenhagenGroundEnemy(10 + index, positions[index].X, positions[index].Y, enemyHealth));
        ClearBossRadio();
        ActivateBossRadio(CopenhagenArsenalRadio);
        _audio?.Trigger(StormaktSound.OresundTrainRumble);
        if (!ground.TestFixture && !ground.SuppressSave && !CopenhagenFixtureActive)
            WriteCopenhagenGroundSave(ground);
    }

    private (double X, double Y) CopenhagenArsenalCannonPosition() => (_width / 2.0, 115);

    private void StepCopenhagenArsenalCannon(CopenhagenGroundState ground)
    {
        ground.ArsenalCannonHitFlash = Math.Max(0, ground.ArsenalCannonHitFlash - 1);
        if (ground.ArsenalCannonHealth <= 0) return;
        ground.ArsenalCannonAttackAge++;
        int cycle = ground.ArsenalCannonAttackAge % 120;
        if (cycle != 72) return;
        (double cannonX, double cannonY) = CopenhagenArsenalCannonPosition();
        if (Math.Abs(ground.KarlX - cannonX) < 17 && ground.KarlY > cannonY)
            DamageCopenhagenGround(ground);
        _audio?.Trigger(StormaktSound.Broadside);
    }

    private void BeginCopenhagenRosenborgRoom(CopenhagenGroundState ground)
    {
        ground.Room = 2;
        ground.Age = 0;
        ground.KarlX = _width / 2.0;
        ground.KarlY = _height - 48;
        ground.TargetX = ground.KarlX;
        ground.TargetY = ground.KarlY;
        ground.HasTarget = false;
        ground.FacingX = 0;
        ground.FacingY = -1;
        ground.RoomClear = false;
        ground.DoorReady = false;
        ground.CheckpointReady = false;
        ground.HeartPortOpen = false;
        ground.ActiveMarginal = CopenhagenMarginalLaw.None;
        ground.MarginalChoosing = true;
        ground.MarginalSelection = 0;
        ground.ChoicePointerSeen = false;
        ground.MarginalCompileAge = 0;
        ground.RosenborgCoreHealth = ground.TestFixture ? 18 : CopenhagenRosenborgCoreHealth;
        ground.RosenborgCoreAttackAge = 0;
