    private void StepCopenhagenMaterialForm(CopenhagenGroundState ground)
    {
        ground.MaterialShieldCooldown = Math.Max(0, ground.MaterialShieldCooldown - 1);
        ground.MaterialBladeAge++;
        if (ground.ActiveMarginal != CopenhagenMarginalLaw.SilverIsBlade ||
            ground.MaterialBladeAge % 18 != 0) return;

        CopenhagenGroundEnemy? target = ground.Enemies
            .Where(enemy => enemy.Health > 0 && DistanceSquared(ground.KarlX, ground.KarlY, enemy.X, enemy.Y) <= 92 * 92)
            .OrderBy(enemy => DistanceSquared(ground.KarlX, ground.KarlY, enemy.X, enemy.Y))
            .ThenBy(enemy => enemy.Id)
            .FirstOrDefault();
        if (target is not null)
        {
            target.Health = Math.Max(0, target.Health - 9);
            target.HitFlash = 6;
            target.StaggerAge = 7;
            if (target.Health == 0)
            {
                target.DeathAge = 1;
                _score += 320;
                _audio?.Trigger(StormaktSound.DungeonSilverShatter);
            }
            else _audio?.Trigger(StormaktSound.DungeonSwordHit);
            return;
        }

        (double coreX, double coreY) = CopenhagenRosenborgCorePosition();
        if (ground.RosenborgCoreHealth > 0 &&
            DistanceSquared(ground.KarlX, ground.KarlY, coreX, coreY) <= 104 * 104)
            DamageCopenhagenRosenborgCore(ground, 9);
        else if (ground.Room == 4 && ground.SagaKingHealth > 0)
        {
            (double bossX, double bossY) = CopenhagenSagaKingPosition(ground);
            if (DistanceSquared(ground.KarlX, ground.KarlY, bossX, bossY) <= 112 * 112)
                DamageCopenhagenSagaKing(ground, 9);
        }
        else if (ground.Room == 5 && ground.KorrektoriusHealth > 0)
        {
            int targetPen = Enumerable.Range(0, ground.KorrektoriusPenHealth.Length)
                .Where(pen => ground.KorrektoriusPenHealth[pen] > 0)
                .Where(pen =>
                {
                    (double penX, double penY) = CopenhagenKorrektoriusPenPosition(ground, pen);
                    return DistanceSquared(ground.KarlX, ground.KarlY, penX, penY) <= 112 * 112;
                })
                .OrderBy(pen => ground.KorrektoriusPenHealth[pen])
                .ThenBy(pen => pen)
                .DefaultIfEmpty(-1).First();
            if (targetPen >= 0) DamageCopenhagenKorrektoriusPen(ground, targetPen, 9);
            else if (ground.KorrektoriusPenHealth.All(health => health <= 0))
            {
                (double bossX, double bossY) = CopenhagenKorrektoriusPosition(ground);
                if (DistanceSquared(ground.KarlX, ground.KarlY, bossX, bossY) <= 118 * 118)
                    DamageCopenhagenKorrektorius(ground, 9);
            }
        }
        else if (ground.Room == 6 && ground.WrathHealth > 0)
        {
            if (CopenhagenWrathPhase(ground) == 2)
            {
                int targetWord = Enumerable.Range(0, ground.WrathWordHealth.Length)
                    .Where(word => ground.WrathWordHealth[word] > 0)
                    .Where(word =>
                    {
                        (double wordX, double wordY) = CopenhagenWrathWordPosition(ground, word);
                        return DistanceSquared(ground.KarlX, ground.KarlY, wordX, wordY) <= 112 * 112;
                    })
                    .OrderBy(word => ground.WrathWordHealth[word]).ThenBy(word => word)
                    .DefaultIfEmpty(-1).First();
                if (targetWord >= 0)
                {
                    DamageCopenhagenWrathWord(ground, targetWord, 9);
                    return;
                }
            }
            if (CopenhagenWrathCanTakeDamage(ground))
            {
                (double bossX, double bossY) = CopenhagenWrathPosition(ground);
                if (DistanceSquared(ground.KarlX, ground.KarlY, bossX, bossY) <= 122 * 122)
                    DamageCopenhagenWrath(ground, 9);
            }
        }
    }

    private void StepCopenhagenRosenborgCore(CopenhagenGroundState ground)
    {
        ground.RosenborgCoreHitFlash = Math.Max(0, ground.RosenborgCoreHitFlash - 1);
        if (ground.RosenborgCoreHealth <= 0) return;
        ground.RosenborgCoreAttackAge++;
        int cycle = ground.RosenborgCoreAttackAge % 120;
        if (cycle != 70) return;
        (double coreX, double coreY) = CopenhagenRosenborgCorePosition();
        if (Math.Abs(ground.KarlX - coreX) < 23 || Math.Abs(ground.KarlY - coreY) < 17)
            DamageCopenhagenGround(ground);
