    {
        target.Health = Math.Max(0, target.Health - damage);
        target.HitFlash = 7;
        target.StaggerAge = 8;
        ground.LegendHitFlash = 6;
        if (target.Health == 0)
        {
            target.DeathAge = 1;
            _score += 320;
            _audio?.Trigger(StormaktSound.DungeonSilverShatter);
        }
        else _audio?.Trigger(StormaktSound.DungeonSwordHit);
    }

