            122 + Math.Sin(angle) * 55);
    }

    private void StepCopenhagenKorrektorius(CopenhagenGroundState ground)
    {
        ground.KorrektoriusHitFlash = Math.Max(0, ground.KorrektoriusHitFlash - 1);
        for (int pen = 0; pen < ground.KorrektoriusPenHitFlash.Length; pen++)
            ground.KorrektoriusPenHitFlash[pen] = Math.Max(0, ground.KorrektoriusPenHitFlash[pen] - 1);
        if (ground.KorrektoriusCorruptionAge > 0)
        {
            ground.KorrektoriusCorruptionAge--;
            if (ground.KorrektoriusCorruptionAge == 0)
                ground.KorrektoriusCorruption = CopenhagenCorruption.None;
        }
        if (ground.KorrektoriusHealth <= 0) return;
        ground.KorrektoriusAge++;

        List<int> livingPens = Enumerable.Range(0, ground.KorrektoriusPenHealth.Length)
            .Where(pen => ground.KorrektoriusPenHealth[pen] > 0).ToList();
        if (livingPens.Count == 0)
        {
            int exposedCycle = ground.KorrektoriusAge % 82;
            if (exposedCycle == 18)
            {
                ground.KorrektoriusTargetX = ground.KarlX;
                ground.KorrektoriusTargetY = ground.KarlY;
            }
            if (exposedCycle == 52)
            {
                if (Math.Abs(ground.KarlX - ground.KorrektoriusTargetX) < 18 ||
                    Math.Abs(ground.KarlY - ground.KorrektoriusTargetY) < 15)
                    DamageCopenhagenGround(ground);
                _audio?.Trigger(StormaktSound.Broadside);
            }
            return;
        }

        int period = ground.LocalLaw switch
        {
            CopenhagenLocalLaw.NoDanishWorkMayFly => 198,
            CopenhagenLocalLaw.SilverLighterThanGuilt => 180,
            _ => 168,
        };
        int cycle = ground.KorrektoriusAge % period;
        if (cycle == 18)
        {
            ground.KorrektoriusActivePen = livingPens[ground.KorrektoriusOrderSerial % livingPens.Count];
            ground.KorrektoriusOrderSerial++;
            ground.KorrektoriusCorruption = (CopenhagenCorruption)
                (1 + (ground.KorrektoriusOrderSerial - 1) % 4);
            ground.KorrektoriusTargetX = ground.KarlX;
            ground.KorrektoriusTargetY = ground.KarlY;
        }
        if (cycle == 52 && ground.LocalLaw == CopenhagenLocalLaw.NoDanishWorkMayFly &&
            ground.KorrektoriusActivePen is >= 0 and < 4 &&
            ground.KorrektoriusPenHealth[ground.KorrektoriusActivePen] > 0)
            DamageCopenhagenKorrektoriusPen(ground, ground.KorrektoriusActivePen, 6);
        if (cycle != 102 || ground.KorrektoriusActivePen is < 0 or >= 4) return;
        if (ground.KorrektoriusPenHealth[ground.KorrektoriusActivePen] <= 0)
        {
            ground.KorrektoriusCorruption = CopenhagenCorruption.None;
            ground.KorrektoriusCorruptionAge = 0;
            _audio?.Trigger(StormaktSound.DungeonSilverWave);
            return;
        }

        ground.KorrektoriusCorruptionAge = 108;
        bool hit = ground.KorrektoriusCorruption switch
        {
            CopenhagenCorruption.Negation => DistanceSquared(ground.KarlX, ground.KarlY,
                ground.KorrektoriusTargetX, ground.KorrektoriusTargetY) < 38 * 38,
            CopenhagenCorruption.NationSwap =>
                Math.Abs(ground.KarlX - ground.KorrektoriusTargetX) < 17 ||
                Math.Abs(ground.KarlY - ground.KorrektoriusTargetY) < 14,
            CopenhagenCorruption.Punctuation =>
                (ground.KarlX < _width / 2.0) == (ground.KorrektoriusTargetX < _width / 2.0),
            _ => Enumerable.Range(-1, 3).Any(offset => DistanceSquared(
                ground.KarlX, ground.KarlY, ground.KorrektoriusTargetX + offset * 48,
                ground.KorrektoriusTargetY + Math.Abs(offset) * 13) < 20 * 20),
        };
        if (hit) DamageCopenhagenGround(ground);
        _audio?.Trigger(ground.KorrektoriusCorruption == CopenhagenCorruption.WeightSwap
            ? StormaktSound.OresundTrainCrash : StormaktSound.Broadside);
    }

    private void DamageCopenhagenKorrektoriusPen(
        CopenhagenGroundState ground, int pen, int damage)
    {
        if (pen is < 0 or >= 4 || ground.KorrektoriusPenHealth[pen] <= 0) return;
        ground.KorrektoriusPenHealth[pen] = Math.Max(0, ground.KorrektoriusPenHealth[pen] - damage);
        ground.KorrektoriusPenHitFlash[pen] = 7;
        if (ground.KorrektoriusPenHealth[pen] == 0)
        {
            _score += 540;
            if (pen == ground.KorrektoriusActivePen)
            {
                ground.KorrektoriusCorruption = CopenhagenCorruption.None;
                ground.KorrektoriusCorruptionAge = 0;
            }
            if (ground.LocalLaw == CopenhagenLocalLaw.CrownOwnsOnlyWhatItCarries)
                DamageCopenhagenKorrektorius(ground, 18);
            _audio?.Trigger(StormaktSound.DungeonSilverShatter);
        }
        else _audio?.Trigger(StormaktSound.DungeonSwordHit);
    }

    private void DamageCopenhagenKorrektorius(CopenhagenGroundState ground, int damage)
    {
        if (ground.KorrektoriusHealth <= 0) return;
        ground.KorrektoriusHealth = Math.Max(0, ground.KorrektoriusHealth - damage);
        ground.KorrektoriusHitFlash = 7;
        if (ground.KorrektoriusHealth == 0)
        {
            ground.KorrektoriusCorruption = CopenhagenCorruption.None;
            ground.KorrektoriusCorruptionAge = 0;
            _score += 4_800;
            _audio?.Trigger(StormaktSound.DungeonSilverShatter);
        }
        else _audio?.Trigger(StormaktSound.DungeonSwordHit);
    }

    private void BeginCopenhagenWrathRoom(CopenhagenGroundState ground)
    {
        ground.Room = 6;
        ground.Age = 0;
        ground.KarlX = _width / 2.0;
        ground.KarlY = _height - 48;
        ground.TargetX = ground.KarlX;
        ground.TargetY = ground.KarlY;
        ground.HasTarget = false;
        ground.FacingX = 0;
        ground.FacingY = -1;
        ground.RoomClear = false;
        ground.DoorReady = false;
        ground.CheckpointReady = false;
        ground.Enemies.Clear();
        if (ground.LocalLaw == CopenhagenLocalLaw.None)
            ground.LocalLaw = CopenhagenLocalLaw.NoDanishWorkMayFly;
        ground.LocalLawChoosing = false;
        ground.LocalLawCompileAge = 0;
        ground.WrathHealth = ground.TestFixture ? 240 : CopenhagenWrathHealth;
        ground.WrathAge = 0;
        ground.WrathHitFlash = 0;
        ground.WrathRoyalLaw = CopenhagenRoyalLaw.FlightClaim;
        ground.WrathOrderSerial = 0;
        ground.WrathTargetX = _width / 2.0;
        ground.WrathTargetY = _height / 2.0;
        ground.WrathCircuitStandAge = 0;
        int wordHealth = ground.TestFixture ? 18 : CopenhagenWrathWordHealth;
        for (int word = 0; word < ground.WrathWordHealth.Length; word++)
        {
            ground.WrathWordHealth[word] = wordHealth;
            ground.WrathWordHitFlash[word] = 0;
        }
        ClearBossRadio();
        ActivateBossRadio(CopenhagenWrathRadio);
        _audio?.SwitchMusic(StormaktMusicTrack.Boss);
        _audio?.Trigger(StormaktSound.OresundCrownCoreOpen);
        if (!ground.TestFixture && !ground.SuppressSave && !CopenhagenFixtureActive)
            WriteCopenhagenGroundSave(ground);
    }

    private void BeginCopenhagenCodexRoom(CopenhagenGroundState ground)
    {
        ground.Room = 7;
        ground.Age = 0;
        ground.KarlX = _width / 2.0;
        ground.KarlY = _height - 48;
        ground.TargetX = ground.KarlX;
        ground.TargetY = ground.KarlY;
        ground.HasTarget = false;
        ground.FacingX = 0;
        ground.FacingY = -1;
        ground.RoomClear = false;
        ground.DoorReady = false;
        ground.CheckpointReady = false;
        ground.Dead = false;
        ground.CodexOpened = false;
        ground.CodexAge = 0;
        ground.Enemies.Clear();
        ClearBossRadio();
        _audio?.SwitchMusic(StormaktMusicTrack.Codex);
        _audio?.Trigger(StormaktSound.OresundCrownCoreOpen);
        if (!ground.TestFixture && !ground.SuppressSave && !CopenhagenFixtureActive)
            WriteCopenhagenGroundSave(ground);
    }

    private void StepCopenhagenCodex(CopenhagenGroundState ground)
    {
        if (!ground.CodexOpened)
        {
            double bookY = _height <= 224 ? 78 : 91;
            if (DistanceSquared(ground.KarlX, ground.KarlY, _width / 2.0, bookY) > 55 * 55) return;
            ground.CodexOpened = true;
            ground.CodexAge = 1;
            ground.HasTarget = false;
            ground.FacingX = 0;
            ground.FacingY = -1;
            _audio?.Trigger(StormaktSound.DungeonSilverWave);
            if (!ground.TestFixture && !ground.SuppressSave && !CopenhagenFixtureActive)
                WriteCopenhagenGroundSave(ground);
            return;
        }

        ground.CodexAge++;
        if (ground.CodexAge is 72 or 156 or 246)
            _audio?.Trigger(StormaktSound.OresundCrownCoreOpen);
        else if (ground.CodexAge is 330 or 438)
            _audio?.Trigger(StormaktSound.DungeonSilverWave);
        if (ground.CodexAge is 156 or 330 && !ground.TestFixture && !ground.SuppressSave && !CopenhagenFixtureActive)
            WriteCopenhagenGroundSave(ground);
    }

    private int CopenhagenWrathPhase(CopenhagenGroundState ground)
    {
        int maximum = ground.TestFixture ? 240 : CopenhagenWrathHealth;
        return Math.Clamp((maximum - ground.WrathHealth) * 4 / Math.Max(1, maximum), 0, 3);
    }

    private bool CopenhagenWrathLawMatched(CopenhagenGroundState ground) =>
        ground.WrathRoyalLaw switch
        {
            CopenhagenRoyalLaw.FlightClaim => ground.LocalLaw == CopenhagenLocalLaw.NoDanishWorkMayFly,
            CopenhagenRoyalLaw.GuiltClaim => ground.LocalLaw == CopenhagenLocalLaw.SilverLighterThanGuilt,
            _ => ground.LocalLaw == CopenhagenLocalLaw.CrownOwnsOnlyWhatItCarries,
        };

    private (double X, double Y) CopenhagenWrathPosition(CopenhagenGroundState ground)
    {
        int phase = CopenhagenWrathPhase(ground);
        if (phase == 3)
        {
            int maximum = ground.TestFixture ? 240 : CopenhagenWrathHealth;
            int quarter = Math.Max(1, maximum / 4);
            double guilt = Math.Clamp((quarter - ground.WrathHealth) / (double)quarter, 0, 1);
            return (_width / 2.0 + Math.Sin(ground.WrathAge * 0.018) * 18, 135 + guilt * 42);
        }
        return (_width / 2.0 + Math.Sin(ground.WrathAge * 0.021) * 46, 87);
    }

    private (double X, double Y) CopenhagenWrathWordPosition(CopenhagenGroundState ground, int word)
    {
        double angle = ground.WrathAge * 0.016 + word * Math.PI * 2 / 3;
        return (_width / 2.0 + Math.Cos(angle) * (_width <= 320 ? 70 : 88),
            126 + Math.Sin(angle) * 53);
    }

    private bool CopenhagenWrathCanTakeDamage(CopenhagenGroundState ground) =>
        CopenhagenWrathPhase(ground) switch
        {
            0 => CopenhagenWrathLawMatched(ground),
            1 => true,
            2 => ground.WrathWordHealth.All(health => health <= 0),
            _ => ground.WrathCircuitStandAge >= 24,
        };

    private void StepCopenhagenWrath(CopenhagenGroundState ground)
    {
        ground.WrathHitFlash = Math.Max(0, ground.WrathHitFlash - 1);
        for (int word = 0; word < ground.WrathWordHitFlash.Length; word++)
            ground.WrathWordHitFlash[word] = Math.Max(0, ground.WrathWordHitFlash[word] - 1);
        if (ground.WrathHealth <= 0) return;
        ground.WrathAge++;
        int phase = CopenhagenWrathPhase(ground);

        if (phase == 3)
        {
            double circuitX = _width / 2.0;
            double circuitY = _height - 82;
            if (DistanceSquared(ground.KarlX, ground.KarlY, circuitX, circuitY) < 58 * 58)
                ground.WrathCircuitStandAge = Math.Min(90, ground.WrathCircuitStandAge + 1);
            else ground.WrathCircuitStandAge = Math.Max(0, ground.WrathCircuitStandAge - 2);
            int cycle = ground.WrathAge % 112;
            if (cycle == 20)
            {
                ground.WrathTargetX = ground.KarlX;
                ground.WrathTargetY = ground.KarlY;
            }
            if (cycle == 78)
            {
                if (DistanceSquared(ground.KarlX, ground.KarlY, circuitX, circuitY) >= 58 * 58)
                    DamageCopenhagenGround(ground);
                _audio?.Trigger(StormaktSound.DungeonSilverWave);
            }
            return;
        }

        if (phase == 0)
        {
            int lawCycle = ground.WrathAge % 220;
            if (lawCycle == 1)
            {
                ground.WrathRoyalLaw = (CopenhagenRoyalLaw)(ground.WrathOrderSerial % 3);
                ground.WrathOrderSerial++;
            }
            if (lawCycle == 28)
            {
                ground.WrathTargetX = ground.KarlX;
                ground.WrathTargetY = ground.KarlY;
            }
            if (lawCycle == 104 && !CopenhagenWrathLawMatched(ground))
            {
                bool hit = ground.WrathRoyalLaw switch
                {
                    CopenhagenRoyalLaw.FlightClaim => DistanceSquared(ground.KarlX, ground.KarlY,
                        ground.WrathTargetX, ground.WrathTargetY) < 42 * 42,
                    CopenhagenRoyalLaw.GuiltClaim =>
                        Math.Abs(ground.KarlX - ground.WrathTargetX) < 18 ||
                        Math.Abs(ground.KarlY - ground.WrathTargetY) < 15,
                    _ => Math.Abs(ground.KarlY - ground.WrathTargetY) < 19,
                };
                if (hit) DamageCopenhagenGround(ground);
                _audio?.Trigger(StormaktSound.Broadside);
            }
            return;
        }

        if (phase == 1)
        {
            int cycle = ground.WrathAge % 174;
            if (cycle == 22)
            {
                ground.WrathOrderSerial++;
                ground.WrathTargetX = ground.KarlX;
                ground.WrathTargetY = ground.KarlY;
            }
            if (cycle == 92)
            {
                int memory = ground.WrathOrderSerial % 3;
                bool hit = memory switch
                {
                    0 => Enumerable.Range(-1, 3).Any(offset =>
                        Math.Abs(ground.KarlX - (ground.WrathTargetX + offset * 58)) < 14),
                    1 => Math.Abs(ground.KarlX - ground.WrathTargetX) < 17 ||
                        Math.Abs(ground.KarlY - ground.WrathTargetY) < 14,
                    _ => Enumerable.Range(-1, 3).Any(offset => DistanceSquared(
                        ground.KarlX, ground.KarlY, ground.WrathTargetX + offset * 52,
                        ground.WrathTargetY + Math.Abs(offset) * 13) < 22 * 22),
                };
                if (hit) DamageCopenhagenGround(ground);
                _audio?.Trigger(memory == 2 ? StormaktSound.OresundTrainCrash : StormaktSound.Broadside);
            }
            return;
        }

        int wordCycle = ground.WrathAge % 106;
        if (wordCycle == 18)
        {
            ground.WrathOrderSerial++;
            ground.WrathTargetX = ground.KarlX;
            ground.WrathTargetY = ground.KarlY;
        }
        if (wordCycle == 70)
        {
            int word = ground.WrathOrderSerial % 3;
            if (ground.WrathWordHealth[word] > 0)
            {
                (double wordX, double wordY) = CopenhagenWrathWordPosition(ground, word);
                if (Math.Abs(ground.KarlX - wordX) < 17 || Math.Abs(ground.KarlY - wordY) < 14)
                    DamageCopenhagenGround(ground);
                _audio?.Trigger(StormaktSound.DungeonSilverWave);
            }
        }
    }

    private void DamageCopenhagenWrathWord(CopenhagenGroundState ground, int word, int damage)
    {
        if (word is < 0 or >= 3 || ground.WrathWordHealth[word] <= 0) return;
        ground.WrathWordHealth[word] = Math.Max(0, ground.WrathWordHealth[word] - damage);
        ground.WrathWordHitFlash[word] = 7;
        if (ground.WrathWordHealth[word] == 0)
        {
            _score += 720;
            _audio?.Trigger(StormaktSound.DungeonSilverShatter);
        }
        else _audio?.Trigger(StormaktSound.DungeonSwordHit);
    }

    private void DamageCopenhagenWrath(CopenhagenGroundState ground, int damage)
    {
        if (ground.WrathHealth <= 0) return;
        ground.WrathHealth = Math.Max(0, ground.WrathHealth - damage);
        ground.WrathHitFlash = 7;
        if (ground.WrathHealth == 0)
        {
            _score += 7_200;
            _audio?.Trigger(StormaktSound.DungeonSilverShatter);
        }
        else _audio?.Trigger(StormaktSound.DungeonSwordHit);
    }

    private void StepCopenhagenGroundEnemies(CopenhagenGroundState ground)
    {
        foreach (CopenhagenGroundEnemy enemy in ground.Enemies)
        {
            enemy.HitFlash = Math.Max(0, enemy.HitFlash - 1);
            enemy.Moving = false;
            if (enemy.Health <= 0)
            {
                enemy.DeathAge++;
                continue;
            }
            if (enemy.StaggerAge > 0)
            {
                enemy.StaggerAge--;
                continue;
            }
            double dx = ground.KarlX - enemy.X;
            double dy = ground.KarlY - enemy.Y;
            double distance = Math.Max(1.0, Math.Sqrt(dx * dx + dy * dy));
            enemy.FacingLeft = dx < 0;
            if (distance > 34)
            {
                double speed = 0.68 + enemy.Id * 0.05;
                enemy.X += dx / distance * speed;
                enemy.Y += dy / distance * speed;
                enemy.Moving = true;
                enemy.AttackAge = 0;
            }
            else
            {
                enemy.AttackAge++;
                if (enemy.AttackAge == 28 && distance < 42)
                    DamageCopenhagenGround(ground);
                if (enemy.AttackAge > 54) enemy.AttackAge = 0;
            }
        }
    }

    private void DamageCopenhagenGround(CopenhagenGroundState ground)
    {
        if (ground.Room >= 2 && ground.ActiveMarginal == CopenhagenMarginalLaw.SilverIsShield &&
            ground.MaterialShieldCooldown == 0)
        {
            ground.MaterialShieldCooldown = 90;
            _audio?.Trigger(StormaktSound.DungeonSilverWave);
            return;
        }
        ground.HitFlash = 12;
        if (_developerMode && _levelId == 6) return;
        ground.Health = Math.Max(0, ground.Health - 20);
        _audio?.Trigger(StormaktSound.HullHit);
        if (ground.Health == 0) ground.Dead = true;
    }

    private void StepCopenhagenGateShots(CopenhagenWorldState state)
    {
        if (state.GateFallAge > 0) return;
        (double centerX, double centerY) = CopenhagenGateCenter(state);
        for (int shotIndex = _shots.Count - 1; shotIndex >= 0; shotIndex--)
        {
            Shot shot = _shots[shotIndex];
            int hitNode = -1;
            for (int node = 0; node < state.GateHealth.Length; node++)
            {
                if (state.GateHealth[node] <= 0) continue;
                (double nodeX, double nodeY) = CopenhagenGateNodePosition(state, node, centerX, centerY);
                if (DistanceSquared(shot.X, shot.Y, nodeX, nodeY) < 18 * 18)
                {
                    hitNode = node;
                    break;
                }
            }
            if (hitNode < 0) continue;

            state.GateHealth[hitNode] = Math.Max(0, state.GateHealth[hitNode] - shot.Power);
            state.HitFlash = 5;
            _shots.RemoveAt(shotIndex);
            if (state.GateHealth[hitNode] == 0)
            {
                state.DestroyedOrder.Add(hitNode);
                _score += 450;
                _audio?.Trigger(StormaktSound.EnemyExplosion);
            }
        }
    }

    private void StepCopenhagenGateAttacks(CopenhagenWorldState state)
    {
        if (state.GateFallAge > 0 || state.GateIntroAge < 90) return;
        (double centerX, double centerY) = CopenhagenGateCenter(state);
        int attackAge = state.GateIntroAge - 90;

        if (state.GateHealth[1] > 0 && attackAge % 54 == 0)
        {
            (double x, double y) = CopenhagenGateNodePosition(state, 1, centerX, centerY);
            double baseAngle = attackAge * 0.027;
            for (int ray = 0; ray < 4; ray++)
            {
                double angle = baseAngle + ray * Math.PI / 2.0;
                _enemyShots.Add(new EnemyShot(x, y, Math.Cos(angle) * 1.75, Math.Sin(angle) * 1.75, 3));
            }
            _audio?.Trigger(StormaktSound.TwinCannon);
        }

        if (state.GateHealth[0] > 0 && attackAge % 180 == 36 && state.BarrierAge == 0)
        {
            state.BarrierAge = 1;
            state.BarrierY = centerY + 20;
            int span = Math.Max(72, _width - 150);
            state.BarrierGapX = 75 + Math.Abs((attackAge * 37 + state.DestroyedOrder.Count * 53) % span);
            state.BarrierFlash = 12;
            _audio?.Trigger(StormaktSound.Deploy);
        }

        if (state.GateHealth[2] > 0 && attackAge > 0 && attackAge % 150 == 0)
        {
            int target = Enumerable.Range(0, state.GateHealth.Length)
                .Where(index => index != 2 && state.GateHealth[index] > 0)
                .OrderBy(index => state.GateHealth[index])
                .FirstOrDefault(-1);
            if (target >= 0)
            {
                state.GateHealth[target] = Math.Min(CopenhagenGateNodeMaxHealth, state.GateHealth[target] + 18);
                state.RepairTarget = target;
                state.RepairFlash = 30;
                _audio?.Trigger(StormaktSound.TitheUpgradeInstall);
            }
        }
    }

    private void StepCopenhagenBarrier(CopenhagenWorldState state)
    {
        if (state.BarrierAge == 0) return;
        state.BarrierAge++;
        state.BarrierY += 1.45;
        const int gapWidth = 66;
        if (!state.BarrierHitPlayer && Math.Abs(_shipY - state.BarrierY) < 7 &&
            Math.Abs(_shipX - state.BarrierGapX) > gapWidth / 2)
        {
            state.BarrierHitPlayer = true;
            DamageShip();
        }
        if (state.BarrierY <= _height + 12) return;
        state.BarrierAge = 0;
        state.BarrierHitPlayer = false;
    }

    private (double X, double Y) CopenhagenGateCenter(CopenhagenWorldState state)
    {
        double entry = Math.Min(1.0, state.GateIntroAge / 90.0);
        double eased = entry * entry * (3.0 - 2.0 * entry);
        return (_width / 2.0, -58 + (126 * eased));
    }

    private static (double X, double Y) CopenhagenGateNodePosition(
        CopenhagenWorldState state, int node, double centerX, double centerY)
    {
        double angle = -Math.PI / 2.0 + node * Math.PI * 2.0 / 3.0 + state.GateIntroAge * 0.004;
        return (centerX + Math.Cos(angle) * 65.0, centerY + Math.Sin(angle) * 34.0);
    }

    private void ResetSnapphaneWorld(SnapphaneWorldState state)
    {
        state.Age = 0;
        state.WreckSerial = 18;
        for (int index = 0; index < 18; index++)
        {
            int layer = index % 3;
            int margin = layer == 2 ? 34 : 12;
            double x = margin + _random.Next(Math.Max(1, _width - margin * 2));
            int fieldHeight = layer == 2 ? Math.Max(1, _height - 112) : Math.Max(1, _height - 34);
            double y = 20 + _random.Next(fieldHeight);
            double speed = layer switch { 0 => 0.12, 1 => 0.28, _ => 0.58 } + _random.NextDouble() * 0.12;
            state.Wrecks.Add(new SnapphaneWreck(x, y, speed, layer, index % 4, index * 17));
        }
    }

    private void StepSnapphaneWorld()
    {
        if (_snapphaneWorld is not SnapphaneWorldState state || _stageClear) return;

        state.Age++;
        foreach (SnapphaneWreck wreck in state.Wrecks)
        {
            if (wreck.BurstAge > 0)
            {
                wreck.BurstAge++;
                if (wreck.BurstAge < 42) continue;
                ResetSnapphaneWreck(state, wreck);
                continue;
            }
            wreck.X += wreck.Vx;
            wreck.Vx *= 0.992;
            wreck.Y += wreck.Speed;
            if (wreck.Physical && DistanceSquared(wreck.X, wreck.Y, _shipX, _shipY) < 20 * 20) DamageShip();
            if (wreck.Y > _height + 38 || wreck.X < -48 || wreck.X > _width + 48)
                ResetSnapphaneWreck(state, wreck);
        }

        if (!state.RouteStarted)
        {
            if (state.Age is 90 or 1_050 or 2_010) SpawnSnapphaneBeaconWave(state);
            if (state.Age is 420 or 780 or 1_260 or 1_740 or 2_220 or 2_700 or 3_180)
                SpawnSnapphaneScentMine(state);
            if (state.Age == 3_300) BeginSorenDuel(state);
        }

        StepSnapphaneBeacons(state);
        StepSnapphaneMines(state);
        StepSnapphaneHunters(state);
        StepSnapphaneHuntShots(state);
        StepSorenDuel(state);
        StepSnapphaneRoute(state);
        if (state.RouteComplete) StepDepartingSnapphaneRescues(state);
        StepRedHoundsBoss(state);
        StepSnapphanePlayerShots(state);

        if (state.Duel is { Phase: 3, OathAge: >= 720 } && !state.RouteStarted && _bossRadioCard is null)
            BeginSnapphaneRouteChoice(state);
        if (state.RouteComplete && state.RedHounds is null && !state.RedHoundsDefeated)
        {
            state.PostRouteAge++;
            if (state.PostRouteAge == 180) BeginRedHoundsBoss(state);
        }
        if (!state.RedHoundsDefeated || _bossRadioCard is not null) return;

        _stageClear = true;
        _stageClearAge = 0;
        _shots.Clear();
        _enemyShots.Clear();
        _enemies.Clear();
        state.HuntShots.Clear();
        _audio?.Trigger(StormaktSound.Deploy);
    }

    private bool IsSnapphaneRescueChanneling()
    {
        if (_snapphaneWorld is not { Route: SnapphaneRoute.Kaparleden, RouteComplete: false } state) return false;
        return state.Rescues.Any(rescue => !rescue.Rescued && rescue.Y > 35 &&
            DistanceSquared(_shipX, _shipY, rescue.X, rescue.Y) < 31 * 31);
    }

    private void BeginSnapphaneRouteChoice(SnapphaneWorldState state)
    {
        state.RouteStarted = true;
        state.RouteChoiceActive = true;
        state.RouteChoiceAge = 0;
        state.Route = SnapphaneRoute.None;
        state.SnapphaneAllies = 0;
        state.RouteTargetsDestroyed = 0;
        state.Beacons.Clear();
        state.ScentMines.Clear();
        state.Hunters.Clear();
        state.HuntShots.Clear();
        _shots.Clear();
        ActivateBossRadio(SnapphaneRouteOpenRadio);
        _audio?.Trigger(StormaktSound.Deploy);
    }

    private void StepSnapphaneRoute(SnapphaneWorldState state)
    {
        if (!state.RouteStarted || state.RouteComplete) return;
        if (state.RouteChoiceActive)
        {
            state.RouteChoiceAge++;
            if (state.RouteChoiceAge < 90 || _bossRadioCard is not null) return;
            int deadZone = Math.Max(22, _width / 13);
            if (_shipX < _width / 2.0 - deadZone) LockSnapphaneRoute(state, SnapphaneRoute.Kaparleden);
            else if (_shipX > _width / 2.0 + deadZone) LockSnapphaneRoute(state, SnapphaneRoute.Krutrannan);
            return;
        }

        state.RouteAge++;
        if (state.Route == SnapphaneRoute.Kaparleden) StepSnapphaneKaparRoute(state);
        else if (state.Route == SnapphaneRoute.Krutrannan) StepSnapphaneKrutRoute(state);
    }

    private void LockSnapphaneRoute(SnapphaneWorldState state, SnapphaneRoute route)
    {
        state.Route = route;
        state.RouteChoiceActive = false;
        state.RouteAge = 0;
        if (route == SnapphaneRoute.Kaparleden)
        {
            double laneX = Math.Max(48, _width * 0.28);
            state.Rescues.Add(new SnapphaneRescueShip(laneX - 8, 72, 0));
            state.Rescues.Add(new SnapphaneRescueShip(laneX + 13, 126, 1));
            state.Rescues.Add(new SnapphaneRescueShip(laneX - 3, Math.Min(_height - 42, 180), 2));
            ActivateBossRadio(SnapphaneKaparRouteRadio);
        }
        else
        {
            ActivateBossRadio(SnapphaneKrutRouteRadio);
        }
        WriteCampaignSave(state.IncomingFreedShips);
        _audio?.Trigger(StormaktSound.Deploy);
    }

    private void StepSnapphaneKaparRoute(SnapphaneWorldState state)
    {
        if (state.RouteAge is 45 or 145 or 255 or 375 or 510 or 670 or 850 or 1_060 or 1_300 or 1_580 or 1_860)
            SpawnSnapphaneRescueHunter(state);
        if (state.RouteAge is 210 or 500 or 820 or 1_180)
            SpawnSnapphaneScentMine(state);

        for (int index = 0; index < state.Rescues.Count; index++)
        {
            SnapphaneRescueShip rescue = state.Rescues[index];
            if (rescue.Rescued)
            {
                rescue.FreedAge++;
                rescue.X -= 0.34 + index * 0.04;
                rescue.Y -= 0.22;
                continue;
            }
            int arrivalAge = index * 180;
            if (state.RouteAge < arrivalAge) continue;
            rescue.Y += (rescue.TargetY - rescue.Y) * 0.045;
            bool channeling = DistanceSquared(_shipX, _shipY, rescue.X, rescue.Y) < 31 * 31;
            if (channeling) rescue.Progress = Math.Min(SnapphaneRescueShip.RequiredProgress, rescue.Progress + 1);
            else rescue.Progress = Math.Max(0, rescue.Progress - 1);
            if (rescue.Progress < SnapphaneRescueShip.RequiredProgress) continue;
            rescue.Rescued = true;
            rescue.FreedAge = 1;
            state.SnapphaneAllies++;
            _score += 900;
            WriteCampaignSave(state.IncomingFreedShips);
            _audio?.Trigger(StormaktSound.TitheChainLockBreak);
        }

        if ((state.Rescues.Count > 0 && state.Rescues.All(rescue => rescue.Rescued)) || state.RouteAge >= 2_100)
            CompleteSnapphaneRoute(state);
    }

    private void SpawnSnapphaneRescueHunter(SnapphaneWorldState state)
    {
        int serial = 2_000 + state.RescueAttackSerial++;
        bool right = (serial & 1) == 0;
        state.Hunters.Add(new SnapphaneHunter(right ? _width - 54 : 54, -28, serial)
        {
            Health = serial % 5 == 0 ? 52 : 30,
            Elite = serial % 5 == 0,
        });
    }

    private void StepSnapphaneKrutRoute(SnapphaneWorldState state)
    {
        if (state.RouteAge is 90 or 390 or 690 or 990)
        {
            int serial = state.RouteAge / 300;
            double gapX = serial switch
            {
                0 => _width * 0.69,
                1 => _width * 0.43,
                2 => _width * 0.72,
                _ => _width * 0.52,
            };
            state.Presses.Add(new SnapphaneWreckPress(gapX, serial));
        }
        if (state.RouteAge is 170 or 520 or 870)
        {
            int serial = state.RouteAge / 350;
            state.Beacons.Add(new SnapphaneBeacon(_width * (serial % 2 == 0 ? 0.68 : 0.42), -22,
                false, 70 + serial));
        }
        if (state.RouteAge is 260 or 760)
        {
            int serial = 700 + state.RouteAge;
            state.Hunters.Add(new SnapphaneHunter(state.RouteAge == 260 ? _width - 62 : 62, -26, serial)
            {
                Health = 74,
                Elite = true,
            });
        }
        if (state.RouteAge is 330 or 630 or 930 or 1_230) SpawnSnapphaneScentMine(state);

        for (int index = state.Presses.Count - 1; index >= 0; index--)
        {
            SnapphaneWreckPress press = state.Presses[index];
            press.Age++;
            press.Y += 1.08;
            press.GapX += Math.Sin((press.Age + press.Serial * 41) * 0.025) * 0.32;
            double gapWidth = _width <= 320 ? 62 : 76;
            if (!press.HitPlayer && Math.Abs(_shipY - press.Y) < 17 && Math.Abs(_shipX - press.GapX) > gapWidth / 2)
            {
                press.HitPlayer = true;
                DamageShip();
            }
            if (press.Y > _height + 48) state.Presses.RemoveAt(index);
        }

        if (state.RouteAge >= 1_520) CompleteSnapphaneRoute(state);
    }

    private void CompleteSnapphaneRoute(SnapphaneWorldState state)
    {
        if (state.RouteComplete) return;
        state.RouteComplete = true;
        if (state.Route == SnapphaneRoute.Krutrannan)
        {
            int bonus = 900 + state.RouteTargetsDestroyed * 300;
            state.KrutBonus = bonus;
            _score += bonus;
        }
        WriteCampaignSave(state.IncomingFreedShips);
        _shots.Clear();
        state.Beacons.Clear();
        state.ScentMines.Clear();
        state.Hunters.Clear();
        state.HuntShots.Clear();
        state.Presses.Clear();
        _audio?.Trigger(StormaktSound.Deploy);
    }

    private void StepDepartingSnapphaneRescues(SnapphaneWorldState state)
    {
        for (int index = state.Rescues.Count - 1; index >= 0; index--)
        {
            SnapphaneRescueShip rescue = state.Rescues[index];
            rescue.FreedAge++;
            if (rescue.Rescued)
            {
                rescue.X += (rescue.Serial - 1) * 0.18;
                rescue.Y -= Math.Min(2.05, 0.82 + rescue.FreedAge * 0.009);
            }
            else
            {
                rescue.X += rescue.Serial == 1 ? 0.12 : -0.12;
                rescue.Y += 0.78;
            }
            if (rescue.Y < -54 || rescue.Y > _height + 54 || rescue.X < -54 || rescue.X > _width + 54)
                state.Rescues.RemoveAt(index);
        }
    }

    private void BeginRedHoundsBoss(SnapphaneWorldState state)
    {
        _shots.Clear();
        state.HuntShots.Clear();
        state.Rescues.Clear();
        foreach (SnapphaneWreck wreck in state.Wrecks.Where(wreck => wreck.Physical))
            ResetSnapphaneWreck(state, wreck);
        RedHoundsBossState boss = CreateRedHoundsBossState();
        state.RedHounds = boss;
        ActivateBossRadio(RedHoundsAgneteRadio);
        ActivateBossRadio(RedHoundsBodilRadio);
        ActivateBossRadio(RedHoundsDagmarRadio);
        ActivateBossRadio(RedHoundsTripletsRadio);
        _audio?.SwitchMusic(StormaktMusicTrack.RedHoundsBoss);
        _audio?.Trigger(StormaktSound.Deploy);
    }

    private RedHoundsBossState CreateRedHoundsBossState()
    {
        var boss = new RedHoundsBossState
        {
            Health = RedHoundsBossState.MaxHealth,
            Phase = 1,
        };
        boss.Ships.Add(new RedHoundShip(RedHoundKind.Sporet, _width * 0.22, -82, _width * 0.22, 62));
        boss.Ships.Add(new RedHoundShip(RedHoundKind.Biddet, _width * 0.78, -104, _width * 0.78, 76));
        boss.Ships.Add(new RedHoundShip(RedHoundKind.Koblet, _width * 0.50, -132, _width * 0.50, 50));
        return boss;
    }

    private void StepRedHoundsBoss(SnapphaneWorldState state)
    {
        if (state.RedHounds is not RedHoundsBossState boss) return;
        boss.Age++;
        boss.PhaseAge++;
        boss.HitFlash = Math.Max(0, boss.HitFlash - 1);
        StepRedHoundShots(boss);
        StepRedHoundSupportBolts(boss);
        foreach (RedHoundChain chain in boss.Chains)
            if (chain.Broken) chain.BreakAge++;

        if (boss.Phase == 4)
        {
            boss.DeathAge++;
            if (boss.DeathAge == 1) _shots.Clear();
            for (int index = 0; index < boss.Ships.Count; index++)
            {
                RedHoundShip ship = boss.Ships[index];
                ship.Y += 0.10 + index * 0.035;
                ship.X += (index - 1) * 0.08;
            }
            if (boss.DeathAge is 1 or 70 or 140 or 220 or 310)
                _audio?.Trigger(boss.DeathAge is 220 or 310 ? StormaktSound.Broadside : StormaktSound.EnemyExplosion);
            if (boss.DeathAge == 210) ActivateBossRadio(RedHoundsVictoryRadio);
            if (boss.DeathAge >= 570 && _bossRadioCard is null)
            {
                state.RedHoundsDefeated = true;
                state.RedHounds = null;
                WriteCampaignSave(state.IncomingFreedShips);
            }
            return;
        }

        MoveRedHoundFleet(boss);
        if (boss.Phase == 1)
        {
            StepRedHoundSearchLock(boss);
            FireRedHoundFleet(boss, 82);
            StepRedHoundSupport(state, boss);
            if (boss.PhaseAge >= 760 && (boss.Health <= 700 || boss.PhaseAge >= 1_050))
                BeginRedHoundsChains(boss);
        }
        else if (boss.Phase == 2)
        {
            FireRedHoundFleet(boss, 98);
            StepRedHoundSupport(state, boss);
            if (boss.PhaseAge >= 400 && boss.Chains.Count == 2 && boss.Chains.All(chain => chain.Broken))
                BeginRedHoundsMask(boss);
        }
        else
        {
            boss.MaskOpen = boss.PhaseAge >= 400;
            bool desperation = boss.MaskOpen && boss.VentHealth.All(health => health <= 0);
            FireRedHoundFleet(boss, desperation ? 58 : 68);
            StepRedHoundMegaWeapon(boss);
            StepRedHoundFrenzy(boss);
            StepRedHoundSupport(state, boss);
        }
    }

    private void StepRedHoundFrenzy(RedHoundsBossState boss)
    {
        if (!boss.MaskOpen) return;
        bool desperation = boss.VentHealth.All(health => health <= 0);
        if (!desperation)
        {
            if (boss.PhaseAge % 88 != 38) return;
            for (int index = 0; index < 2; index++)
            {
                RedHoundShip ship = boss.Ships[index];
                if (ship.CannonHealth <= 0) continue;
                FireRedHoundAimedFan(boss, ship, index, 3, 0.17, 2.48, 1);
            }
            _audio?.Trigger(StormaktSound.Broadside);
            return;
        }

        boss.DesperationAge++;
        RedHoundShip leader = boss.Ships[2];
        if (boss.DesperationAge % 44 == 8)
        {
            FireRedHoundAimedFan(boss, leader, 2, 5, 0.14, 2.78, 1);
            _audio?.Trigger(StormaktSound.Broadside);
        }
        if (boss.DesperationAge % 86 == 30)
        {
            int gap = boss.DesperationAge / 86 % 7;
            double originY = leader.Y + 24;
            for (int lane = 0; lane < 7; lane++)
            {
                if (lane == gap) continue;
                double targetX = 24 + lane * (_width - 48) / 6.0;
                double dx = targetX - leader.X;
                double dy = _height + 18 - originY;
                double length = Math.Max(1, Math.Sqrt(dx * dx + dy * dy));
                boss.Shots.Add(new RedHoundShot(leader.X, originY,
                    dx / length * 2.62, dy / length * 2.62, 2, 2));
            }
            _audio?.Trigger(StormaktSound.Broadside);
        }
        if (boss.DesperationAge % 72 == 52)
        {
            int shipIndex = boss.DesperationAge / 72 & 1;
            RedHoundShip ship = boss.Ships[shipIndex];
            if (ship.CannonHealth > 0)
                FireRedHoundAimedFan(boss, ship, shipIndex, 3, 0.11, 2.88, 1);
        }
    }

    private void FireRedHoundAimedFan(RedHoundsBossState boss, RedHoundShip ship, int source,
        int count, double spread, double speed, int style)
    {
        double baseAngle = Math.Atan2(_shipY - ship.Y, _shipX - ship.X);
        for (int index = 0; index < count; index++)
        {
            double angle = baseAngle + (index - (count - 1) / 2.0) * spread;
            boss.Shots.Add(new RedHoundShot(ship.X, ship.Y + 17,
                Math.Cos(angle) * speed, Math.Sin(angle) * speed, source, style));
        }
    }

    private void StepRedHoundMegaWeapon(RedHoundsBossState boss)
    {
        if (!boss.MaskOpen || boss.VentHealth.All(health => health <= 0)) return;
        int cycle = (boss.PhaseAge - 400) % 270;
        if (cycle == 0)
        {
            boss.MegaTargetX = _shipX;
            boss.MegaHit = false;
            if (!boss.MegaRadioPlayed)
            {
                boss.MegaRadioPlayed = true;
                ActivateBossRadio(RedHoundsMegaRadio);
            }
            _audio?.Trigger(StormaktSound.Deploy);
        }
        if (cycle == 108)
        {
            RedHoundShip leader = boss.Ships[2];
            double originY = leader.Y + 24;
            for (int lane = -2; lane <= 2; lane++)
            {
                double targetX = boss.MegaTargetX + lane * 34;
                double dx = targetX - leader.X;
                double dy = _height + 20 - originY;
                double length = Math.Max(1, Math.Sqrt(dx * dx + dy * dy));
                boss.Shots.Add(new RedHoundShot(leader.X, originY,
                    dx / length * 2.75, dy / length * 2.75, 2));
            }
            _audio?.Trigger(StormaktSound.Broadside);
        }
        if (cycle is >= 108 and < 154 && !boss.MegaHit)
        {
            RedHoundShip leader = boss.Ships[2];
            double distance = DistancePointToSegmentSquared(_shipX, _shipY,
                leader.X, leader.Y + 22, boss.MegaTargetX, _height + 8);
            if (distance < 14 * 14)
            {
                boss.MegaHit = true;
                DamageShip();
            }
        }
    }

    private void MoveRedHoundFleet(RedHoundsBossState boss)
    {
        for (int index = 0; index < boss.Ships.Count; index++)
        {
            RedHoundShip ship = boss.Ships[index];
            if (boss.Phase == 1)
            {
                ship.TargetX = (index + 1) * _width / 4.0 + Math.Sin((boss.Age + index * 71) * 0.018) * 24;
                ship.TargetY = index == 2 ? 49 : 66 + index * 8;
            }
            else if (boss.Phase == 2)
            {
                ship.TargetX = index switch { 0 => _width * 0.24, 1 => _width * 0.76, _ => _width * 0.50 };
                ship.TargetY = index == 2 ? 94 : 55;
            }
            else
            {
                ship.TargetX = index switch { 0 => 48, 1 => _width - 48, _ => _width * 0.50 };
                ship.TargetY = index == 2 ? 54 : 88;
                if (boss.DesperationAge > 0)
                {
                    double sweep = index == 2 ? _width * 0.14 : 24;
                    ship.TargetX += Math.Sin((boss.DesperationAge + index * 47) * 0.045) * sweep;
                    ship.TargetY += Math.Cos((boss.DesperationAge + index * 31) * 0.037) * (index == 2 ? 13 : 8);
                }
            }
            ship.X += (ship.TargetX - ship.X) * 0.035;
            ship.Y += (ship.TargetY - ship.Y) * 0.035;
        }
    }

    private void StepRedHoundSearchLock(RedHoundsBossState boss)
    {
        int cycle = boss.PhaseAge % 240;
        if (cycle == 1)
        {
            boss.SearchShip = boss.PhaseAge / 240 % boss.Ships.Count;
            boss.SearchTargetX = _shipX;
            boss.SearchHit = false;
        }
        if (cycle == 126 && !boss.SearchHit && Math.Abs(_shipX - boss.SearchTargetX) < 25)
        {
            boss.SearchHit = true;
            DamageShip();
        }
    }

    private void FireRedHoundFleet(RedHoundsBossState boss, int interval)
    {
        for (int index = 0; index < boss.Ships.Count; index++)
        {
            RedHoundShip ship = boss.Ships[index];
            if (ship.CannonHealth <= 0 || (boss.PhaseAge + index * 29) % interval != 24) continue;
            double dx = _shipX - ship.X;
            double dy = _shipY - ship.Y;
            double length = Math.Max(1, Math.Sqrt(dx * dx + dy * dy));
            double speed = boss.Phase == 3 ? 2.35 : 1.95;
            boss.Shots.Add(new RedHoundShot(ship.X - 9, ship.Y + 15,
                dx / length * speed - 0.18, dy / length * speed, index));
            boss.Shots.Add(new RedHoundShot(ship.X + 9, ship.Y + 15,
                dx / length * speed + 0.18, dy / length * speed, index));
            _audio?.Trigger(StormaktSound.Broadside);
        }
    }

    private void StepRedHoundShots(RedHoundsBossState boss)
    {
        for (int index = boss.Shots.Count - 1; index >= 0; index--)
        {
            RedHoundShot shot = boss.Shots[index];
            shot.Age++;
            shot.X += shot.Vx;
            shot.Y += shot.Vy;
            if (DistanceSquared(shot.X, shot.Y, _shipX, _shipY) < 7 * 7)
            {
                DamageShip();
                boss.Shots.RemoveAt(index);
            }
            else if (shot.Age > 240 || shot.X < -18 || shot.X > _width + 18 || shot.Y > _height + 18)
                boss.Shots.RemoveAt(index);
        }
    }

    private void StepRedHoundSupport(SnapphaneWorldState state, RedHoundsBossState boss)
    {
        if (boss.Age % 126 == 30)
        {
            if (boss.Phase == 2)
            {
                RedHoundChain? target = boss.Chains.Where(chain => !chain.Broken)
                    .OrderByDescending(chain => chain.Health).ThenBy(chain => chain.LeftShip).FirstOrDefault();
                if (target is not null)
                {
                    target.Health -= 14;
                    if (target.Health <= 0) BreakRedHoundChain(target);
                    AddRedHoundSupportBolt(state, boss, ChainMidpoint(boss, target), true);
                }
            }
            else if (boss.Phase == 1)
            {
                RedHoundShip target = boss.Ships.OrderByDescending(ship => ship.CannonHealth)
                    .ThenBy(ship => ship.Kind).First();
                target.CannonHealth = Math.Max(0, target.CannonHealth - 10);
                AddRedHoundSupportBolt(state, boss, (target.X, target.Y + 12), true);
            }
            else if (boss.MaskOpen && boss.VentHealth.All(health => health <= 0) && boss.Health > 20)
            {
                RedHoundShip leader = boss.Ships[2];
                boss.Health = Math.Max(20, boss.Health - 8);
                AddRedHoundSupportBolt(state, boss, (leader.X, leader.Y + 12), true);
            }
        }

        int allies = Math.Min(3, state.SnapphaneAllies);
        if (allies > 0 && boss.Age % 150 == 74)
        {
            for (int index = 0; index < allies; index++)
            {
                RedHoundShip target = boss.Ships.OrderByDescending(ship => ship.CannonHealth)
                    .ThenBy(ship => ship.Kind).First();
                if (target.CannonHealth <= 0) break;
                target.CannonHealth = Math.Max(0, target.CannonHealth - 5);
                double sourceX = 34 + index * 22;
                double sourceY = _height - 42 - index * 5;
                boss.SupportBolts.Add(new RedHoundSupportBolt(sourceX, sourceY, target.X, target.Y + 12, false));
            }
        }
    }

    private void AddRedHoundSupportBolt(SnapphaneWorldState state, RedHoundsBossState boss,
        (double X, double Y) target, bool soren)
    {
        double sourceX = state.Duel?.X ?? _shipX + 62;
        double sourceY = state.Duel?.Y ?? _shipY - 36;
        boss.SupportBolts.Add(new RedHoundSupportBolt(sourceX, sourceY, target.X, target.Y, soren));
    }

    private static void StepRedHoundSupportBolts(RedHoundsBossState boss)
    {
        for (int index = boss.SupportBolts.Count - 1; index >= 0; index--)
            if (++boss.SupportBolts[index].Age > 26) boss.SupportBolts.RemoveAt(index);
    }

    private void BeginRedHoundsChains(RedHoundsBossState boss)
    {
        boss.Phase = 2;
        boss.PhaseAge = 0;
        boss.Health = Math.Min(boss.Health, 700);
        boss.Chains.Clear();
        boss.Chains.Add(new RedHoundChain(0, 2));
        boss.Chains.Add(new RedHoundChain(2, 1));
        boss.Shots.Clear();
        ActivateBossRadio(RedHoundsChainTripletsRadio);
        ActivateBossRadio(RedHoundsChainRadio);
        _audio?.Trigger(StormaktSound.TitheChainCanister);
    }

    private void BeginRedHoundsMask(RedHoundsBossState boss)
    {
        boss.Phase = 3;
        boss.PhaseAge = 0;
        boss.Health = Math.Min(boss.Health, 420);
        boss.Shots.Clear();
        boss.MaskOpen = false;
        ActivateBossRadio(RedHoundsDagmarMaskRadio);
        ActivateBossRadio(RedHoundsMaskRadio);
        _audio?.Trigger(StormaktSound.Deploy);
    }

    private static (double X, double Y) ChainMidpoint(RedHoundsBossState boss, RedHoundChain chain)
    {
        RedHoundShip left = boss.Ships[chain.LeftShip];
        RedHoundShip right = boss.Ships[chain.RightShip];
        return ((left.X + right.X) / 2, (left.Y + right.Y) / 2);
    }

    private void BreakRedHoundChain(RedHoundChain chain)
    {
        if (chain.Broken) return;
        chain.Broken = true;
        chain.BreakAge = 1;
        _score += 500;
        _audio?.Trigger(StormaktSound.TitheChainLockBreak);
    }

    private void BeginRedHoundsDeath(RedHoundsBossState boss)
    {
        if (boss.Phase == 4) return;
        boss.Phase = 4;
        boss.PhaseAge = 0;
        boss.DeathAge = 0;
        boss.Health = 0;
        boss.Shots.Clear();
        _audio?.DuckMusic(2_400);
        _audio?.SwitchMusic(StormaktMusicTrack.SnapphaneVictory);
    }

    private void BeginSorenDuel(SnapphaneWorldState state)
    {
        state.Beacons.Clear();
        state.ScentMines.Clear();
        state.Hunters.Clear();
        state.HuntShots.Clear();
        _enemyShots.Clear();
        state.Duel = new SorenDuelState
        {
            X = _width / 2.0,
            TargetX = _width / 2.0,
        };
        foreach (SnapphaneWreck wreck in state.Wrecks.Where(wreck => wreck.Physical))
            ResetSnapphaneWreck(state, wreck);
        ActivateBossRadio(SnapphaneDuelChallengeRadio);
        _audio?.SwitchMusic(StormaktMusicTrack.Snapphane);
        _audio?.Trigger(StormaktSound.Deploy);
    }

    private void StepSorenDuel(SnapphaneWorldState state)
    {
        if (state.Duel is not SorenDuelState duel) return;
        duel.Age++;
        duel.PhaseAge++;
        duel.HitFlash = Math.Max(0, duel.HitFlash - 1);
        for (int index = duel.Afterimages.Count - 1; index >= 0; index--)
        {
            if (++duel.Afterimages[index].Age > 44) duel.Afterimages.RemoveAt(index);
        }

        if (duel.Phase == 3)
        {
            duel.OathAge++;
            if (state.Route == SnapphaneRoute.Kaparleden && state.RouteStarted && !state.RouteComplete)
                StepSorenRescueCombat(state, duel);
            else
            {
                double oathX = Math.Clamp(_shipX + (_shipX < _width / 2 ? 68 : -68), 42, _width - 42);
                double oathY = Math.Clamp(_shipY - 42, 54, _height - 70);
                duel.X += (oathX - duel.X) * 0.035;
                duel.Y += (oathY - duel.Y) * 0.035;
                duel.Shots.Clear();
            }
            if (duel.OathAge == 180) state.SorenOathComplete = true;
            return;
        }

        duel.Y += (66 - duel.Y) * 0.025;
        if (duel.Phase == 1)
        {
            if (duel.PhaseAge % 145 == 1)
            {
                duel.DashAge = 32;
                duel.TargetX = Math.Clamp(_shipX + (_shipX < _width / 2 ? 92 : -92), 48, _width - 48);
            }
            if (duel.DashAge > 0)
            {
                duel.DashAge--;
                if ((duel.DashAge & 5) == 0) duel.Afterimages.Add(new SorenAfterimage(duel.X, duel.Y));
                duel.X += (duel.TargetX - duel.X) * 0.18;
            }
            else
            {
                duel.X += Math.Sin(duel.Age * 0.035) * 0.42;
            }
            if (duel.PhaseAge % 92 == 28) FireSorenCopperSalvo(duel, 3);
            if (duel.Honor <= SorenDuelState.MaxHonor / 2 || duel.PhaseAge >= 720)
            {
                duel.Phase = 2;
                duel.PhaseAge = 0;
                duel.DashAge = 0;
                ActivateBossRadio(SnapphaneDuelHooksRadio);
                _audio?.Trigger(StormaktSound.Deploy);
            }
        }
        else
        {
            double patrolX = _width / 2.0 + Math.Sin(duel.Age * 0.021) * (_width * 0.28);
            duel.X += (patrolX - duel.X) * 0.055;
            if (duel.PhaseAge % 170 == 34) LaunchSorenHook(duel);
            if (duel.PhaseAge % 108 == 54) FireSorenCopperSalvo(duel, 2);
            if (duel.Honor <= 0 || duel.PhaseAge >= 780)
                BreakSorenDuel(state, duel);
        }

        StepSorenCopperShots(duel);
        StepSorenHooks(duel);
        if (DistanceSquared(duel.X, duel.Y, _shipX, _shipY) < 24 * 24) DamageShip();
    }

    private void StepSorenRescueCombat(SnapphaneWorldState state, SorenDuelState duel)
    {
        SnapphaneRescueShip? activeRescue = state.Rescues
            .Where(rescue => !rescue.Rescued && state.RouteAge >= rescue.Serial * 180)
            .OrderBy(rescue => rescue.Serial)
            .FirstOrDefault();
        double guardX = activeRescue is null
            ? Math.Clamp(_shipX + (_shipX < _width / 2 ? 76 : -76), 44, _width - 44)
            : Math.Clamp(activeRescue.X + 92 + Math.Sin(state.RouteAge * 0.055) * 34, 44, _width - 44);
        double guardY = activeRescue is null
            ? Math.Clamp(_shipY - 48, 50, _height - 64)
            : Math.Clamp(activeRescue.Y - 32 + Math.Cos(state.RouteAge * 0.041) * 22, 50, _height - 64);
        duel.X += (guardX - duel.X) * 0.095;
        duel.Y += (guardY - duel.Y) * 0.095;
        duel.DashAge = Math.Max(0, duel.DashAge - 1);
        if (state.RouteAge % 96 == 18)
        {
            duel.DashAge = 28;
            duel.Afterimages.Add(new SorenAfterimage(duel.X, duel.Y));
        }

        SnapphaneHunter? target = state.Hunters
            .Where(hunter => hunter.BurstAge == 0)
            .OrderBy(hunter => DistanceSquared(duel.X, duel.Y, hunter.X, hunter.Y))
            .FirstOrDefault();
        if (target is not null && state.RouteAge % 46 == 12)
        {
            double baseAngle = Math.Atan2(target.Y - duel.Y, target.X - duel.X);
            for (int index = 0; index < 2; index++)
            {
                double angle = baseAngle + (index == 0 ? -0.08 : 0.08);
                duel.Shots.Add(new SorenCopperShot(duel.X, duel.Y - 12,
                    Math.Cos(angle) * 2.9, Math.Sin(angle) * 2.9));
            }
            _audio?.Trigger(StormaktSound.Broadside);
        }

        for (int index = duel.Shots.Count - 1; index >= 0; index--)
        {
            SorenCopperShot shot = duel.Shots[index];
            shot.Age++;
            SnapphaneHunter? shotTarget = state.Hunters
                .Where(hunter => hunter.BurstAge == 0)
                .OrderBy(hunter => DistanceSquared(shot.X, shot.Y, hunter.X, hunter.Y))
                .FirstOrDefault();
            if (shotTarget is null)
            {
                duel.Shots.RemoveAt(index);
                continue;
            }
            double dx = shotTarget.X - shot.X;
            double dy = shotTarget.Y - shot.Y;
            double length = Math.Max(1, Math.Sqrt(dx * dx + dy * dy));
            shot.Vx = shot.Vx * 0.91 + dx / length * 0.34;
            shot.Vy = shot.Vy * 0.91 + dy / length * 0.34;
            shot.X += shot.Vx;
            shot.Y += shot.Vy;
            if (DistanceSquared(shot.X, shot.Y, shotTarget.X, shotTarget.Y) < 10 * 10)
            {
                shotTarget.Health -= 16;
                if (shotTarget.Health <= 0) shotTarget.BurstAge = 1;
                duel.Shots.RemoveAt(index);
            }
            else if (shot.Age > 180 || shot.X < -18 || shot.X > _width + 18 || shot.Y < -18 || shot.Y > _height + 18)
            {
                duel.Shots.RemoveAt(index);
            }
        }
    }

    private void FireSorenCopperSalvo(SorenDuelState duel, int count)
    {
        double dx = _shipX - duel.X;
        double dy = _shipY - duel.Y;
        double baseAngle = Math.Atan2(dy, dx);
        for (int index = 0; index < count; index++)
        {
            double spread = (index - (count - 1) / 2.0) * 0.16;
            double angle = baseAngle + spread;
            duel.Shots.Add(new SorenCopperShot(duel.X, duel.Y + 12,
                Math.Cos(angle) * 2.35, Math.Sin(angle) * 2.35));
        }
        _audio?.Trigger(StormaktSound.Broadside);
    }

    private void LaunchSorenHook(SorenDuelState duel)
    {
        int serial = duel.HookSerial++;
        double startX = duel.X + ((serial & 1) == 0 ? -22 : 22);
        double targetX = _shipX + ((serial & 1) == 0 ? -28 : 28);
        double dx = targetX - startX;
        double dy = _shipY - duel.Y;
        double length = Math.Max(1, Math.Sqrt(dx * dx + dy * dy));
        duel.Hooks.Add(new SorenChainHook(startX, duel.Y + 10, dx / length * 2.25, dy / length * 2.25, serial));
        _audio?.Trigger(StormaktSound.TitheChainCanister);
    }

    private void StepSorenCopperShots(SorenDuelState duel)
    {
        for (int index = duel.Shots.Count - 1; index >= 0; index--)
        {
            SorenCopperShot shot = duel.Shots[index];
            shot.Age++;
            shot.X += shot.Vx;
            shot.Y += shot.Vy;
            if (DistanceSquared(shot.X, shot.Y, _shipX, _shipY) < 7 * 7)
            {
                DamageShip();
                duel.Shots.RemoveAt(index);
            }
            else if (shot.Age > 220 || shot.X < -16 || shot.X > _width + 16 || shot.Y > _height + 16)
            {
                duel.Shots.RemoveAt(index);
            }
        }
    }

    private void StepSorenHooks(SorenDuelState duel)
    {
        for (int index = duel.Hooks.Count - 1; index >= 0; index--)
        {
            SorenChainHook hook = duel.Hooks[index];
            hook.Age++;
            if (hook.BrokenAge > 0)
            {
                if (++hook.BrokenAge > 30) duel.Hooks.RemoveAt(index);
                continue;
            }
            hook.X += hook.Vx;
            hook.Y += hook.Vy;
            if (DistanceSquared(hook.X, hook.Y, _shipX, _shipY) < 11 * 11)
            {
                DamageShip();
                hook.BrokenAge = 1;
            }
            else if (hook.Y > _height + 28 || hook.X < -28 || hook.X > _width + 28)
            {
                duel.Hooks.RemoveAt(index);
            }
        }
    }

    private void BreakSorenDuel(SnapphaneWorldState state, SorenDuelState duel)
    {
        duel.Phase = 3;
        duel.PhaseAge = 0;
        duel.OathAge = 1;
        duel.Honor = 0;
        duel.Hooks.Clear();
        duel.Shots.Clear();
        duel.Afterimages.Clear();
        _shots.Clear();
        ActivateBossRadio(SnapphaneOathRadio);
        ActivateBossRadio(SnapphaneEbbaOathRadio);
        _audio?.SwitchMusic(StormaktMusicTrack.Snapphane);
        _audio?.Trigger(StormaktSound.Deploy);
    }

    private void ResetSnapphaneWreck(SnapphaneWorldState state, SnapphaneWreck wreck)
    {
        int serial = state.WreckSerial++;
        wreck.Y = -28 - (serial % 5) * 13;
        wreck.X = 18 + Math.Abs(serial * 73 + wreck.Kind * 41) % Math.Max(1, _width - 36);
        wreck.Kind = (wreck.Kind + 1 + serial) % 3;
        wreck.Phase = serial * 19;
        wreck.Vx = 0;
        wreck.Health = wreck.Physical ? 30 : 999;
        wreck.BurstAge = 0;
    }

    private void SpawnSnapphaneBeaconWave(SnapphaneWorldState state)
    {
        int group = state.BeaconWave++;
        int trueIndex = group switch { 0 => 1, 1 => 2, _ => 0 };
        for (int index = 0; index < 3; index++)
        {
            double x = (index + 1) * _width / 4.0 + (group - 1) * 7;
            state.Beacons.Add(new SnapphaneBeacon(x, -28 - index * 5, index == trueIndex, group));
        }
    }

    private void SpawnSnapphaneScentMine(SnapphaneWorldState state)
    {
        int serial = state.ScentMines.Count + state.Age / 30;
        bool left = (serial & 1) == 0;
        state.ScentMines.Add(new SnapphaneScentMine(left ? 30 : _width - 30, -18, serial)
        {
            Vx = left ? 0.22 : -0.22,
        });
    }

    private void StepSnapphaneBeacons(SnapphaneWorldState state)
    {
        for (int index = state.Beacons.Count - 1; index >= 0; index--)
        {
            SnapphaneBeacon beacon = state.Beacons[index];
            beacon.Age++;
            beacon.Y += beacon.State == SnapphaneBeaconState.Destroyed ? 0.48 : 0.24;
            if (beacon.State is not (SnapphaneBeaconState.Revealed or SnapphaneBeaconState.Destroyed))
            {
                int pulse = beacon.Age % 90;
                bool lit = beacon.TrueSignal
                    ? pulse < 8 || pulse is >= 18 and < 26
                    : pulse < 24;
                beacon.State = lit ? SnapphaneBeaconState.Signal : SnapphaneBeaconState.Off;
            }
            if (beacon.Y > _height + 42 || beacon.State == SnapphaneBeaconState.Destroyed && beacon.Age > 360)
                state.Beacons.RemoveAt(index);
        }
    }

    private void StepSnapphaneMines(SnapphaneWorldState state)
    {
        for (int index = state.ScentMines.Count - 1; index >= 0; index--)
        {
            SnapphaneScentMine mine = state.ScentMines[index];
            mine.Age++;
            if (mine.BurstAge > 0)
            {
                if (++mine.BurstAge > 34) state.ScentMines.RemoveAt(index);
                continue;
            }
            if (mine.Turned)
            {
                mine.Vy = Math.Max(0.12, mine.Vy - 0.01);
            }
            else
            {
                double dx = _shipX - mine.X;
                mine.Vx = Math.Clamp(mine.Vx + Math.Sign(dx) * 0.008, -0.72, 0.72);
                mine.Vy = Math.Min(1.25, mine.Vy + 0.006);
            }
            mine.X += mine.Vx;
            mine.Y += mine.Vy;
            if (!mine.Turned && DistanceSquared(mine.X, mine.Y, _shipX, _shipY) < 15 * 15)
            {
                mine.BurstAge = 1;
                DamageShip();
            }
            if (mine.Y < -42 || mine.Y > _height + 42 || mine.X < -42 || mine.X > _width + 42)
                state.ScentMines.RemoveAt(index);
        }
    }

    private void StepSnapphaneHunters(SnapphaneWorldState state)
    {
        for (int index = state.Hunters.Count - 1; index >= 0; index--)
        {
            SnapphaneHunter hunter = state.Hunters[index];
            hunter.Age++;
            if (hunter.BurstAge > 0)
            {
                if (++hunter.BurstAge > 38) state.Hunters.RemoveAt(index);
                continue;
            }
            hunter.Y += hunter.Y < 58 + hunter.Serial % 32 ? 0.72 : 0.08;
            hunter.X += Math.Sin((hunter.Age + hunter.Serial * 13) * 0.035) * 0.34;
            int firingInterval = hunter.Elite ? 72 : 105;
            if (hunter.Age % firingInterval == 42)
            {
                bool targetsSoren = state.Route == SnapphaneRoute.Kaparleden && !state.RouteComplete &&
                    state.Duel is { Phase: 3 } && hunter.Serial % 3 != 0;
                double targetX = targetsSoren ? state.Duel!.X : _shipX;
                double targetY = targetsSoren ? state.Duel!.Y : _shipY;
                double dx = targetX - hunter.X;
                double dy = targetY - hunter.Y;
                double length = Math.Max(1, Math.Sqrt(dx * dx + dy * dy));
                state.HuntShots.Add(new SnapphaneHuntShot(hunter.X, hunter.Y + 10,
                    dx / length * 1.8, dy / length * 1.8, hunter.Serial) { TargetsSoren = targetsSoren });
                if (hunter.Elite)
                    state.HuntShots.Add(new SnapphaneHuntShot(hunter.X, hunter.Y + 10,
                        dx / length * 1.65 + 0.32, dy / length * 1.65, hunter.Serial) { TargetsSoren = targetsSoren });
            }
            if (DistanceSquared(hunter.X, hunter.Y, _shipX, _shipY) < 18 * 18) DamageShip();
        }
    }

    private void StepSnapphaneHuntShots(SnapphaneWorldState state)
    {
        for (int index = state.HuntShots.Count - 1; index >= 0; index--)
        {
            SnapphaneHuntShot shot = state.HuntShots[index];
            shot.Age++;
            SnapphaneScentMine? lure = state.ScentMines
                .Where(mine => mine.Turned && mine.BurstAge == 0)
                .OrderBy(mine => DistanceSquared(shot.X, shot.Y, mine.X, mine.Y))
                .FirstOrDefault();
            bool targetsSoren = lure is null && shot.TargetsSoren &&
                state.Route == SnapphaneRoute.Kaparleden && !state.RouteComplete && state.Duel is { Phase: 3 };
            double targetX = lure?.X ?? (targetsSoren ? state.Duel!.X : _shipX);
            double targetY = lure?.Y ?? (targetsSoren ? state.Duel!.Y : _shipY);
            double dx = targetX - shot.X;
            double dy = targetY - shot.Y;
            double length = Math.Max(1, Math.Sqrt(dx * dx + dy * dy));
            shot.Vx = shot.Vx * 0.94 + dx / length * 0.16;
            shot.Vy = shot.Vy * 0.94 + dy / length * 0.16;
            shot.X += shot.Vx;
            shot.Y += shot.Vy;

            if (lure is not null && DistanceSquared(shot.X, shot.Y, lure.X, lure.Y) < 9 * 9)
            {
                BurstSnapphaneMine(state, lure);
                state.HuntShots.RemoveAt(index);
                continue;
            }
            if (TrySnapphaneHuntShotEnvironmentHit(state, shot))
            {
                state.HuntShots.RemoveAt(index);
                continue;
            }
            if (targetsSoren && DistanceSquared(shot.X, shot.Y, state.Duel!.X, state.Duel.Y) < 9 * 9)
            {
                state.Duel.HitFlash = 8;
                state.Duel.DashAge = Math.Max(state.Duel.DashAge, 18);
                state.Duel.Afterimages.Add(new SorenAfterimage(state.Duel.X, state.Duel.Y));
                state.HuntShots.RemoveAt(index);
                continue;
            }
            if (!targetsSoren && lure is null && DistanceSquared(shot.X, shot.Y, _shipX, _shipY) < 7 * 7)
            {
                DamageShip();
                state.HuntShots.RemoveAt(index);
                continue;
            }
            if (shot.Age > 300 || shot.X < -16 || shot.X > _width + 16 || shot.Y < -16 || shot.Y > _height + 16)
                state.HuntShots.RemoveAt(index);
        }
    }

    private bool TrySnapphaneHuntShotEnvironmentHit(SnapphaneWorldState state, SnapphaneHuntShot shot)
    {
        foreach (SnapphaneWreck wreck in state.Wrecks)
        {
            if (!wreck.Physical || wreck.BurstAge > 0 || DistanceSquared(shot.X, shot.Y, wreck.X, wreck.Y) >= 15 * 15)
                continue;
            DamageSnapphaneWreck(wreck, 12, shot.Serial);
            state.EnvironmentKills++;
            return true;
        }
        foreach (SnapphaneBeacon beacon in state.Beacons)
        {
            if (beacon.TrueSignal || beacon.State == SnapphaneBeaconState.Destroyed ||
                DistanceSquared(shot.X, shot.Y, beacon.X, beacon.Y) >= 14 * 14) continue;
            DamageSnapphaneBeacon(state, beacon, 12);
            state.EnvironmentKills++;
            return true;
        }
        foreach (SnapphaneHunter hunter in state.Hunters)
        {
            if (hunter.Serial == shot.Serial || hunter.BurstAge > 0 ||
                DistanceSquared(shot.X, shot.Y, hunter.X, hunter.Y) >= 14 * 14) continue;
            hunter.Health -= 14;
            if (hunter.Health <= 0) hunter.BurstAge = 1;
            state.EnvironmentKills++;
            return true;
        }
        return false;
    }

    private void StepSnapphanePlayerShots(SnapphaneWorldState state)
    {
        for (int shotIndex = _shots.Count - 1; shotIndex >= 0; shotIndex--)
        {
            Shot shot = _shots[shotIndex];
            bool consumed = false;
            if (state.Duel is SorenDuelState { Phase: < 3 } duel)
            {
                foreach (SorenChainHook hook in duel.Hooks)
                {
                    if (hook.BrokenAge > 0 || DistanceSquared(shot.X, shot.Y, hook.X, hook.Y) >= 13 * 13) continue;
                    hook.Health -= shot.Kind == TitheShotChainShot ? shot.Power * 2 : shot.Power;
                    if (hook.Health <= 0)
                    {
                        hook.BrokenAge = 1;
                        _score += 90;
                    }
                    consumed = true;
                    break;
                }
                if (!consumed && DistanceSquared(shot.X, shot.Y, duel.X, duel.Y) < 23 * 23)
                {
                    duel.Honor = Math.Max(0, duel.Honor - shot.Power);
                    duel.HitFlash = 7;
                    _score += shot.Power * 2;
                    consumed = true;
                }
            }
            if (!consumed && state.RedHounds is RedHoundsBossState redHounds)
                consumed = DamageRedHoundsWithShot(redHounds, shot);
            foreach (SnapphaneScentMine mine in state.ScentMines)
            {
                if (consumed) break;
                if (mine.BurstAge > 0 || DistanceSquared(shot.X, shot.Y, mine.X, mine.Y) >= 13 * 13) continue;
                if (shot.Kind == TitheShotMagnetRing)
                {
                    mine.Turned = true;
                    mine.Vy = Math.Min(mine.Vy, 0.28);
                    _score += 75;
                }
                else
                {
                    mine.Health -= shot.Kind == TitheShotChainShot ? shot.Power * 2 : shot.Power;
                    if (mine.Health <= 0) mine.BurstAge = 1;
                }
                consumed = true;
                break;
            }
            if (!consumed)
            {
                foreach (SnapphaneBeacon beacon in state.Beacons)
                {
                    if (beacon.State == SnapphaneBeaconState.Destroyed ||
                        DistanceSquared(shot.X, shot.Y, beacon.X, beacon.Y) >= 15 * 15) continue;
                    if (!beacon.TrueSignal) DamageSnapphaneBeacon(state, beacon, shot.Power);
                    consumed = true;
                    break;
                }
            }
            if (!consumed)
            {
                foreach (SnapphaneHunter hunter in state.Hunters)
                {
                    if (hunter.BurstAge > 0 || DistanceSquared(shot.X, shot.Y, hunter.X, hunter.Y) >= 15 * 15) continue;
                    hunter.Health -= shot.Power;
                    if (hunter.Health <= 0)
                    {
                        hunter.BurstAge = 1;
                        _score += 180;
                    }
                    consumed = true;
                    break;
                }
            }
            if (!consumed)
            {
                foreach (SnapphaneWreck wreck in state.Wrecks)
                {
                    if (!wreck.Physical || wreck.BurstAge > 0 ||
                        DistanceSquared(shot.X, shot.Y, wreck.X, wreck.Y) >= 17 * 17) continue;
                    DamageSnapphaneWreck(wreck, shot.Power, shot.X + shot.Kind);
                    consumed = true;
                    break;
                }
            }
            if (consumed) _shots.RemoveAt(shotIndex);
        }
    }

    private bool DamageRedHoundsWithShot(RedHoundsBossState boss, Shot shot)
    {
        if (boss.Phase == 4) return false;
        if (boss.Phase == 2)
        {
            foreach (RedHoundChain chain in boss.Chains)
            {
                if (chain.Broken) continue;
                RedHoundShip left = boss.Ships[chain.LeftShip];
                RedHoundShip right = boss.Ships[chain.RightShip];
                double radius = shot.Kind == TitheShotChainShot ? 18 : 9;
                if (DistancePointToSegmentSquared(shot.X, shot.Y, left.X, left.Y, right.X, right.Y) >= radius * radius)
                    continue;
                int multiplier = shot.Kind is TitheShotChainShot or TitheShotDrillBolt ? 2 : 1;
                chain.Health -= shot.Power * multiplier;
                boss.HitFlash = 5;
                if (chain.Health <= 0) BreakRedHoundChain(chain);
                return shot.Kind != TitheShotDrillBolt;
            }
        }

        RedHoundShip leader = boss.Ships[2];
        if (boss.Phase == 3)
        {
            if (!boss.MaskOpen) return DistanceSquared(shot.X, shot.Y, leader.X, leader.Y) < 34 * 34;
            for (int index = 0; index < boss.VentHealth.Length; index++)
            {
                if (boss.VentHealth[index] <= 0) continue;
                (double ventX, double ventY) = RedHoundVentPosition(leader, index);
                if (DistanceSquared(shot.X, shot.Y, ventX, ventY) >= 11 * 11) continue;
                boss.VentHealth[index] = Math.Max(0, boss.VentHealth[index] - shot.Power);
                boss.HitFlash = 6;
                if (boss.VentHealth[index] == 0)
                {
                    _score += 350;
                    _audio?.Trigger(StormaktSound.TitheChainLockBreak);
                }
                return true;
            }
            if (boss.VentHealth.Any(health => health > 0))
            {
                if (DistanceSquared(shot.X, shot.Y, leader.X, leader.Y + 10) >= 36 * 36) return false;
                int nearestVent = Enumerable.Range(0, boss.VentHealth.Length)
                    .Where(index => boss.VentHealth[index] > 0)
                    .OrderBy(index =>
                    {
                        (double vx, double vy) = RedHoundVentPosition(leader, index);
                        return DistanceSquared(shot.X, shot.Y, vx, vy);
                    })
                    .First();
                boss.VentHealth[nearestVent] = Math.Max(0, boss.VentHealth[nearestVent] - shot.Power);
                boss.HitFlash = 6;
                if (boss.VentHealth[nearestVent] == 0)
                {
                    _score += 350;
                    _audio?.Trigger(StormaktSound.TitheChainLockBreak);
                }
                return true;
            }
            if (DistanceSquared(shot.X, shot.Y, leader.X, leader.Y + 8) < 31 * 31)
            {
                DamageRedHoundsCore(boss, shot.Power);
                return true;
            }
        }

        foreach (RedHoundShip ship in boss.Ships.OrderBy(ship => DistanceSquared(shot.X, shot.Y, ship.X, ship.Y)))
        {
            if (DistanceSquared(shot.X, shot.Y, ship.X, ship.Y) >= 32 * 32) continue;
            bool cannonHit = ship.CannonHealth > 0 && Math.Abs(shot.X - ship.X) >= 11 &&
                Math.Abs(shot.Y - (ship.Y + 10)) < 23;
            if (cannonHit)
            {
                ship.CannonHealth = Math.Max(0, ship.CannonHealth - shot.Power);
                if (ship.CannonHealth == 0) _score += 300;
            }
            else if (boss.Phase < 3)
                DamageRedHoundsCore(boss, shot.Power);
            boss.HitFlash = 5;
            return true;
        }
        return false;
    }

    private void DamageRedHoundsCore(RedHoundsBossState boss, int damage)
    {
        boss.Health = Math.Max(0, boss.Health - damage);
        boss.HitFlash = 6;
        _score += damage * 3;
        if (boss.Health == 0) BeginRedHoundsDeath(boss);
    }

    private static (double X, double Y) RedHoundVentPosition(RedHoundShip leader, int index) => index switch
    {
        0 => (leader.X, leader.Y + 3),
        1 => (leader.X - 17, leader.Y + 20),
        _ => (leader.X + 17, leader.Y + 20),
    };

    private void DamageSnapphaneBeacon(SnapphaneWorldState state, SnapphaneBeacon beacon, int damage)
    {
        if (beacon.TrueSignal) return;
        beacon.State = SnapphaneBeaconState.Revealed;
        beacon.Health -= damage;
        if (!beacon.HunterReleased)
        {
            beacon.HunterReleased = true;
            state.Hunters.Add(new SnapphaneHunter(beacon.X, beacon.Y - 12, beacon.Group * 10 + state.Hunters.Count));
        }
        if (beacon.Health <= 0)
        {
            beacon.State = SnapphaneBeaconState.Destroyed;
            beacon.Age = 0;
            _score += 125;
            if (beacon.Group >= 70) state.RouteTargetsDestroyed++;
        }
    }

    private static void DamageSnapphaneWreck(SnapphaneWreck wreck, int damage, int impulseSeed)
    {
        wreck.Health -= damage;
        if (damage >= 7) wreck.Vx += ((impulseSeed & 1) == 0 ? -1 : 1) * Math.Min(0.8, damage * 0.045);
        if (wreck.Health <= 0) wreck.BurstAge = 1;
    }

    private void BurstSnapphaneMine(SnapphaneWorldState state, SnapphaneScentMine mine)
    {
        mine.BurstAge = 1;
        foreach (SnapphaneWreck wreck in state.Wrecks)
            if (wreck.Physical && wreck.BurstAge == 0 && DistanceSquared(mine.X, mine.Y, wreck.X, wreck.Y) < 58 * 58)
                DamageSnapphaneWreck(wreck, 24, mine.Serial);
        foreach (SnapphaneBeacon beacon in state.Beacons)
            if (!beacon.TrueSignal && beacon.State != SnapphaneBeaconState.Destroyed &&
                DistanceSquared(mine.X, mine.Y, beacon.X, beacon.Y) < 58 * 58)
                DamageSnapphaneBeacon(state, beacon, 24);
        foreach (SnapphaneHunter hunter in state.Hunters)
        {
            if (hunter.BurstAge > 0 || DistanceSquared(mine.X, mine.Y, hunter.X, hunter.Y) >= 58 * 58) continue;
            hunter.Health -= 24;
            if (hunter.Health <= 0) hunter.BurstAge = 1;
        }
        state.EnvironmentKills++;
        _score += 220;
    }

    private void StepTitheWorld()
    {
        if (_levelId != 4 || _titheWorld is not TitheWorldState state || state.ChoosingUpgrade || _stageClear)
            return;

        state.Age++;
        if (state.Age == 80) state.Chains.Add(new TitheChainTarget(_width / 2 - 74, 76, 0));
        if (state.Age == 370) state.Chains.Add(new TitheChainTarget(_width / 2 + 82, 60, 1));
        if (state.Age is 220 or 520 or 1_080)
        {
            int side = state.Age / 220 & 1;
            _enemies.Add(new Enemy(side == 0 ? 62 : _width - 62, -18, 1, 10, 9,
                0xff8f2635, 7, state.Age * 0.013, state.Age, 0, false));
        }

        for (int index = state.Chains.Count - 1; index >= 0; index--)
        {
            TitheChainTarget chain = state.Chains[index];
            chain.Age++;
            if (chain.Freed)
            {
                chain.FreedAge++;
                chain.X += chain.Kind == 0 ? -1.35 : 1.35;
                chain.Y -= 0.42;
                if (chain.FreedAge > 150) state.Chains.RemoveAt(index);
                continue;
            }

            chain.Y += 0.16;
            int lockY = (int)Math.Round(chain.Y) - 31;
            for (int shotIndex = _shots.Count - 1; shotIndex >= 0; shotIndex--)
            {
                Shot shot = _shots[shotIndex];
                if (Math.Abs(shot.X - chain.X) > 13 || Math.Abs(shot.Y - lockY) > 15) continue;
                chain.Health -= shot.Power;
                _shots.RemoveAt(shotIndex);
                if (chain.Health <= 0)
                {
                    chain.Freed = true;
                    chain.FreedAge = 0;
                    state.FreedShips++;
                    _score += 1_200;
                    _audio?.Trigger(StormaktSound.TitheChainLockBreak);
                }
                break;
            }
        }

        if (state.Age == 850 && !state.UpgradeOffered)
        {
            state.UpgradeOffered = true;
            state.UpgradeChoice = TitheUpgradeChoice.Primary;
            state.ChoosingUpgrade = true;
            state.UpgradeSelection = 0;
            _shots.Clear();
            _enemyShots.Clear();
            _enemies.Clear();
            _audio?.Trigger(StormaktSound.Deploy);
        }
        if (state.UpgradeInstalled)
        {
            StepTitheCustomsCorridor(state);
            StepTitheCoinMines(state);
            StepTitheRegisterRoute(state);
            StepTitheInterestWorks(state);
            StepTitheBoss(state);
        }
    }

    private void StepTitheBoss(TitheWorldState state)
    {
        if (!state.ShipUpgradeInstalled) return;
        if (state.Age == 5_700 && state.Boss is null)
        {
            state.SealWalls.Clear();
            state.Mines.Clear();
            _shots.Clear();
            _enemyShots.Clear();
            _enemies.Clear();
            state.Boss = new TitheBossState
            {
                X = _width / 2.0,
                Y = -112,
                Health = TitheBossState.MaxHealth,
                LeftArmor = TitheBossState.ArmorHealth,
                RightArmor = TitheBossState.ArmorHealth,
                LeftLedger = TitheBossState.LedgerHealth,
                RightLedger = TitheBossState.LedgerHealth,
                Phase = 1,
            };
            ActivateBossRadio(RigsregnskabetIntroRadio);
            _audio?.SwitchMusic(StormaktMusicTrack.TitheBoss);
            _audio?.Trigger(StormaktSound.Deploy);
        }
        if (state.Boss is not TitheBossState boss) return;

        boss.Age++;
        boss.PhaseAge++;
        if (boss.Phase == 4)
        {
            boss.Y += 0.12;
            if (boss.PhaseAge % 32 == 1) _audio?.Trigger(StormaktSound.EnemyExplosion);
            if (boss.PhaseAge >= 480 && _bossRadioCard is null)
            {
                state.Boss = null;
                WriteCampaignSave(state.FreedShips);
                _stageClear = true;
                _stageClearAge = 0;
                _shots.Clear();
                _enemyShots.Clear();
                state.Mines.Clear();
                state.SealWalls.Clear();
                _audio?.SwitchMusic(StormaktMusicTrack.Combat);
            }
            return;
        }

        if (boss.Age <= 150)
        {
            double t = boss.Age / 150.0;
            double eased = t * t * (3.0 - 2.0 * t);
            boss.Y = -112 + (92 + 112) * eased;
        }
        else
        {
            boss.X = _width / 2.0 + Math.Sin(boss.Age * 0.018) * (_width <= 320 ? 22 : 30);
            boss.Y = 92 + Math.Sin(boss.Age * 0.026) * 5;
        }

        int bossX = (int)Math.Round(boss.X);
        int bossY = (int)Math.Round(boss.Y);
        for (int shotIndex = _shots.Count - 1; shotIndex >= 0; shotIndex--)
        {
            Shot shot = _shots[shotIndex];
            bool hit = false;
            if (boss.Phase == 1 && boss.LeftArmor > 0 &&
                Math.Abs(shot.X - (bossX - 66)) <= 35 && Math.Abs(shot.Y - (bossY + 2)) <= 48)
            {
                boss.LeftArmor -= shot.Power;
                hit = true;
            }
            else if (boss.Phase == 1 && boss.RightArmor > 0 &&
                Math.Abs(shot.X - (bossX + 66)) <= 35 && Math.Abs(shot.Y - (bossY + 2)) <= 48)
            {
                boss.RightArmor -= shot.Power;
                hit = true;
            }
            else if (boss.Phase == 2 && Math.Abs(shot.X - bossX) <= 34 && Math.Abs(shot.Y - (bossY + 12)) <= 44)
            {
                boss.Health -= shot.Power;
                hit = true;
            }
            else if (boss.Phase == 3 && boss.LeftLedger > 0 &&
                Math.Abs(shot.X - (bossX - 58)) <= 19 && Math.Abs(shot.Y - (bossY + 18)) <= 28)
            {
                int priorHealth = boss.LeftLedger;
                boss.LeftLedger -= shot.Power;
                if (priorHealth > 0 && boss.LeftLedger <= 0)
                    _audio?.Trigger(StormaktSound.TitheLedgerShatter);
                hit = true;
            }
            else if (boss.Phase == 3 && boss.RightLedger > 0 &&
                Math.Abs(shot.X - (bossX + 58)) <= 19 && Math.Abs(shot.Y - (bossY + 18)) <= 28)
            {
                int priorHealth = boss.RightLedger;
                boss.RightLedger -= shot.Power;
                if (priorHealth > 0 && boss.RightLedger <= 0)
                    _audio?.Trigger(StormaktSound.TitheLedgerShatter);
                hit = true;
            }
            else if (boss.Phase == 3 && boss.LeftLedger <= 0 && boss.RightLedger <= 0 &&
                Math.Abs(shot.X - bossX) <= 32 && Math.Abs(shot.Y - (bossY + 12)) <= 42)
            {
                boss.Health -= shot.Power;
                hit = true;
            }
            if (hit) _shots.RemoveAt(shotIndex);
        }

        if (boss.Phase == 1 && boss.LeftArmor <= 0 && boss.RightArmor <= 0)
        {
            boss.Phase = 2;
            boss.PhaseAge = 0;
            boss.Health = Math.Max(boss.Health, TitheBossState.PhaseThreeHealth);
            _shots.Clear();
            _enemyShots.Clear();
            ActivateBossRadio(RigsregnskabetInterestRadio);
            _audio?.Trigger(StormaktSound.TitheBossPhaseBreak);
        }
        else if (boss.Phase == 2 && boss.Health <= TitheBossState.PhaseThreeHealth)
        {
            boss.Health = TitheBossState.PhaseThreeHealth;
            boss.Phase = 3;
            boss.PhaseAge = 0;
            state.Mines.Clear();
            state.SealWalls.Clear();
            _shots.Clear();
            _enemyShots.Clear();
            ActivateBossRadio(RigsregnskabetCoreRadio);
            _audio?.Trigger(StormaktSound.TitheBossPhaseBreak);
        }
        else if (boss.Phase == 3 && boss.Health <= 0)
        {
            boss.Health = 0;
            boss.Phase = 4;
            boss.PhaseAge = 0;
            _shots.Clear();
            _enemyShots.Clear();
            state.Mines.Clear();
            state.SealWalls.Clear();
            _score += 8_000;
            ActivateBossRadio(RigsregnskabetDeathRadio);
            _audio?.Trigger(StormaktSound.EnemyExplosion);
        }

        if (boss.Age <= 170) return;
        if (boss.Phase == 1 && boss.PhaseAge % 72 == 0)
        {
            FireTitheBossFan(bossX - 66, bossY + 22, 7, 3);
            FireTitheBossFan(bossX + 66, bossY + 22, 7, 3);
        }
        else if (boss.Phase == 2)
        {
            if (boss.PhaseAge % 105 == 1)
                state.Mines.Add(new TitheCoinMine(bossX + (boss.PhaseAge / 105 % 3 - 1) * 58, bossY + 32));
            if (boss.PhaseAge % 210 == 80)
                state.SealWalls.Add(new TitheSealWall((boss.PhaseAge / 210 * 2 + 1) % TitheSealWall.SegmentCount));
        }
        else if (boss.Phase == 3 && boss.PhaseAge % 58 == 0)
        {
            FireTitheBossFan(bossX, bossY + 30, 6, 5);
        }
    }

    private void FireTitheBossFan(int x, int y, int kind, int count)
    {
        for (int index = 0; index < count; index++)
        {
            double vx = (index - (count - 1) / 2.0) * 0.75;
            _enemyShots.Add(new EnemyShot(x, y, vx, 2.0 + Math.Abs(vx) * 0.18, kind));
        }
        _audio?.Trigger(StormaktSound.TwinCannon);
    }

    private void StepTitheInterestWorks(TitheWorldState state)
    {
        if (state.Age == 3_140)
        {
            state.InterestWorksActive = true;
            state.Chains.Clear();
            _enemies.Clear();
            _enemyShots.Clear();
        }
        if (!state.InterestWorksActive) return;

        if (state.Age is 3_200 or 3_400 or 3_600 or 4_150 or 4_350 or 4_980 or 5_230)
        {
            int ordinal = state.SealWallsSpawned++;
            int gap = (ordinal * 3 + 2) % TitheSealWall.SegmentCount;
            state.SealWalls.Add(new TitheSealWall(gap));
            _audio?.Trigger(StormaktSound.TitheSealWall);
        }

        for (int wallIndex = state.SealWalls.Count - 1; wallIndex >= 0; wallIndex--)
        {
            TitheSealWall wall = state.SealWalls[wallIndex];
            wall.Age++;
            wall.Y += _height <= 224 ? 0.72 : 0.86;
            int segmentWidth = (_width + TitheSealWall.SegmentCount - 1) / TitheSealWall.SegmentCount;
            for (int shotIndex = _shots.Count - 1; shotIndex >= 0; shotIndex--)
            {
                Shot shot = _shots[shotIndex];
                if (Math.Abs(shot.Y - wall.Y) > 10) continue;
                int segment = Math.Clamp(shot.X / segmentWidth, 0, TitheSealWall.SegmentCount - 1);
                if (wall.Health[segment] <= 0) continue;
                wall.Health[segment] -= shot.Power;
                _shots.RemoveAt(shotIndex);
                if (wall.Health[segment] <= 0)
                {
                    wall.Health[segment] = 0;
                    _score += 110;
                    _audio?.Trigger(StormaktSound.EnemyExplosion);
                }
            }
            if (!wall.HitPlayer && Math.Abs(_shipY - wall.Y) < 9)
            {
                int segment = Math.Clamp(_shipX / segmentWidth, 0, TitheSealWall.SegmentCount - 1);
                if (wall.Health[segment] > 0)
                {
                    wall.HitPlayer = true;
                    DamageShip();
                }
            }
            if (wall.Y > _height + 25) state.SealWalls.RemoveAt(wallIndex);
        }

        if (state.Age is 3_285 or 3_485 or 3_685 or 4_240 or 4_440)
        {
            double x = (state.Age / 200 & 1) == 0 ? 36 : _width - 36;
            double dx = _shipX - x;
            double dy = _shipY - 46;
            double length = Math.Max(1, Math.Sqrt(dx * dx + dy * dy));
            _enemyShots.Add(new EnemyShot(x, 46, dx / length * 2.0, dy / length * 2.0, 7));
        }

        if (state.Age == 3_820 && !state.BroadsideUpgradeOffered)
        {
            state.BroadsideUpgradeOffered = true;
            state.UpgradeChoice = TitheUpgradeChoice.Broadside;
            state.ChoosingUpgrade = true;
            state.UpgradeSelection = 0;
            state.SealWalls.Clear();
            _shots.Clear();
            _enemyShots.Clear();
            _enemies.Clear();
            _audio?.Trigger(StormaktSound.Deploy);
        }
        if (state.Age == 4_650 && !state.ShipUpgradeOffered)
        {
            state.ShipUpgradeOffered = true;
            state.UpgradeChoice = TitheUpgradeChoice.Ship;
            state.ChoosingUpgrade = true;
            state.UpgradeSelection = 0;
            state.SealWalls.Clear();
            _shots.Clear();
            _enemyShots.Clear();
            _enemies.Clear();
            _audio?.Trigger(StormaktSound.Deploy);
        }
    }

    private void ReflectTitheLightShots()
    {
        if (_levelId != 4) return;
        for (int index = _enemyShots.Count - 1; index >= 0; index--)
        {
            EnemyShot hostile = _enemyShots[index];
            if (hostile.Kind == 6 || hostile.Kind >= 8 ||
                DistanceSquared(hostile.X, hostile.Y, _shipX, _shipY) > 105 * 105) continue;
            _enemyShots.RemoveAt(index);
            _shots.Add(new Shot((int)Math.Round(hostile.X), (int)Math.Round(hostile.Y),
                (int)Math.Clamp(Math.Round(-hostile.Vx), -3, 3), -6, 0xffbdf8ff, 4));
            _score += 25;
        }
    }

    private void StepTitheRegisterRoute(TitheWorldState state)
    {
        if (state.Age == 2_175)
        {
            state.Gates.Clear();
            state.Mines.Clear();
            _enemyShots.Clear();
            _enemies.Clear();
        }
        if (state.Age == 2_200)
        {
            state.RouteChoiceActive = true;
            state.RouteNoticeAge = 0;
            _audio?.Trigger(StormaktSound.Deploy);
        }
        if (state.RouteChoiceActive && state.Age == 2_380)
        {
            state.RouteChoiceActive = false;
            state.Route = _shipX < _width / 2 ? TitheRegisterRoute.Revision : TitheRegisterRoute.ChainHall;
            state.RouteNoticeAge = 150;
            if (state.Route == TitheRegisterRoute.Revision)
            {
                _score += 1_500;
            }
            else
            {
                state.Chains.Add(new TitheChainTarget(68, 58, 1));
                state.Chains.Add(new TitheChainTarget(_width / 2, 43, 0));
                state.Chains.Add(new TitheChainTarget(_width - 68, 67, 1));
            }
            _audio?.Trigger(StormaktSound.TitheRegisterSwitch);
        }
        if (state.RouteNoticeAge > 0) state.RouteNoticeAge--;

        if (state.Route == TitheRegisterRoute.Revision && state.Age is 2_470 or 2_620 or 2_770)
        {
            int side = state.Age / 150 & 1;
            _enemies.Add(new Enemy(side == 0 ? 52 : _width - 52, -18, 1, 14, 10,
                0xff8f2635, 7, state.Age * 0.017, state.Age, 0, false));
        }
        else if (state.Route == TitheRegisterRoute.ChainHall && state.Age == 2_700)
        {
            _enemies.Add(new Enemy(_width / 2, -18, 1, 10, 9,
                0xff8f2635, 7, state.Age * 0.017, state.Age, 0, false));
        }
    }

    private void StepTitheCustomsCorridor(TitheWorldState state)
    {
        if (state.Age is 1_000 or 1_300 or 1_600 or 1_900)
        {
            int passage = state.Age / 300 & 1;
            state.Gates.Add(new TitheCustomsGate(passage == 0 ? _width / 3 : _width * 2 / 3));
            _audio?.Trigger(StormaktSound.TitheCustomsGate);
        }

        for (int index = state.Gates.Count - 1; index >= 0; index--)
        {
            TitheCustomsGate gate = state.Gates[index];
            gate.Age++;
            if (gate.Age > TitheCustomsGate.WarningFrames) gate.Y += _height <= 224 ? 1.25 : 1.55;

            int openingHalf = _width <= 320 ? 34 : 42;
            for (int shotIndex = _shots.Count - 1; shotIndex >= 0; shotIndex--)
            {
                Shot shot = _shots[shotIndex];
                if (Math.Abs(shot.Y - gate.Y) > 6 || Math.Abs(shot.X - gate.OpeningX) <= openingHalf) continue;
                _shots.RemoveAt(shotIndex);
            }
            if (!gate.HitPlayer && gate.Age > TitheCustomsGate.WarningFrames &&
                Math.Abs(_shipY - gate.Y) < 8 && Math.Abs(_shipX - gate.OpeningX) > openingHalf - 5)
            {
                gate.HitPlayer = true;
                DamageShip();
            }
            if (gate.Y > _height + 24) state.Gates.RemoveAt(index);
        }
    }

    private void StepTitheCoinMines(TitheWorldState state)
    {
        if (state.Age is 1_075 or 1_190 or 1_420 or 1_535 or 1_775 or 2_025)
        {
            int ordinal = state.MinesSpawned++;
            double x = 38 + (ordinal * 83 + 47) % Math.Max(80, _width - 76);
            state.Mines.Add(new TitheCoinMine(x, 24));
        }

        for (int index = state.Mines.Count - 1; index >= 0; index--)
        {
            TitheCoinMine mine = state.Mines[index];
            mine.Age++;
            if (mine.Reflected)
            {
                mine.X += mine.Vx;
                mine.Y += mine.Vy;
                mine.Vy = Math.Max(-4.4, mine.Vy - 0.035);
                for (int enemyIndex = _enemies.Count - 1; enemyIndex >= 0; enemyIndex--)
                {
                    Enemy enemy = _enemies[enemyIndex];
                    if (DistanceSquared(mine.X, mine.Y, enemy.X, enemy.Y) > 18 * 18) continue;
                    _enemies.RemoveAt(enemyIndex);
                    state.Mines.RemoveAt(index);
                    _score += 650;
                    _audio?.Trigger(StormaktSound.EnemyExplosion);
                    goto NextMine;
                }
            }
            else
            {
                double dx = _shipX - mine.X;
                double dy = _shipY - mine.Y;
                double length = Math.Max(1, Math.Sqrt(dx * dx + dy * dy));
                mine.Vx = Math.Clamp(mine.Vx + dx / length * 0.035, -1.8, 1.8);
                mine.Vy = Math.Clamp(mine.Vy + dy / length * 0.027, 0.45, 1.65);
                mine.X += mine.Vx;
                mine.Y += mine.Vy;
                if (length < 70 || mine.Age > 185)
                {
                    if (mine.ChargeAge == 0) _audio?.Trigger(StormaktSound.TitheCoinMineCharge);
                    mine.ChargeAge++;
                }
            }

            for (int shotIndex = _shots.Count - 1; shotIndex >= 0; shotIndex--)
            {
                Shot shot = _shots[shotIndex];
                bool broadsideCatch = !mine.Reflected && shot.Power >= 5 &&
                    Math.Abs(mine.X - shot.X) <= 90 && Math.Abs(mine.Y - shot.Y) <= 85;
                if (!broadsideCatch && DistanceSquared(mine.X, mine.Y, shot.X, shot.Y) > 13 * 13) continue;
                _shots.RemoveAt(shotIndex);
                if (!mine.Reflected && shot.Power >= 5)
                {
                    mine.Reflected = true;
                    mine.ChargeAge = 0;
                    mine.Vx = Math.Clamp((mine.X - _shipX) * 0.035, -2.6, 2.6);
                    mine.Vy = -2.7;
                    _score += 120;
                    _audio?.Trigger(StormaktSound.Broadside);
                }
                else
                {
                    mine.Health -= shot.Power;
                    if (mine.Health <= 0)
                    {
                        state.Mines.RemoveAt(index);
                        _score += 280;
                        _audio?.Trigger(StormaktSound.TitheCoinMineBreak);
                        goto NextMine;
                    }
                }
                break;
            }

            if (!mine.Reflected && mine.ChargeAge >= TitheCoinMine.FuseFrames)
            {
                if (DistanceSquared(mine.X, mine.Y, _shipX, _shipY) < 42 * 42) DamageShip();
                state.Mines.RemoveAt(index);
                _audio?.Trigger(StormaktSound.TitheCoinMineBreak);
                goto NextMine;
            }
            if (mine.Y < -28 || mine.Y > _height + 28 || mine.X < -28 || mine.X > _width + 28)
                state.Mines.RemoveAt(index);

        NextMine:;
        }
    }

    private void StepTitheUpgradeChoice(TitheWorldState state, uint buttons)
    {
        if (_activeLoadout is not StormaktLoadout loadout) return;
        if (Pressed(buttons, Left) || Pressed(buttons, Right))
        {
            state.UpgradeSelection = 1 - state.UpgradeSelection;
            _audio?.Trigger(StormaktSound.Deploy);
        }
        if (Pressed(buttons, AltFire))
        {
            state.ShowUpgradeDetails = !state.ShowUpgradeDetails;
            _audio?.Trigger(StormaktSound.Deploy);
        }
        if (Pressed(buttons, Fire) || Pressed(buttons, Start))
        {
            if (state.UpgradeChoice == TitheUpgradeChoice.Ship)
            {
                loadout.ShipModule = state.UpgradeSelection == 0
                    ? TitheShipModule.SilverCooler
                    : TitheShipModule.SeizureArmor;
                loadout.ArmorCharge = loadout.ShipModule == TitheShipModule.SeizureArmor ? 1 : 0;
                state.ShipUpgradeInstalled = true;
                WriteCampaignSave(state.FreedShips);
            }
            else if (state.UpgradeChoice == TitheUpgradeChoice.Broadside)
            {
                loadout.BroadsideModule = state.UpgradeSelection == 0
                    ? TitheBroadsideModule.MagnetBroadside
                    : TitheBroadsideModule.ChainCanister;
                state.BroadsideUpgradeInstalled = true;
                WriteCampaignSave(state.FreedShips);
            }
            else
            {
                loadout.PrimaryModule = state.UpgradeSelection == 0
                    ? TithePrimaryModule.CrownDrill
                    : TithePrimaryModule.VolleyDirector;
                state.UpgradeInstalled = true;
                WriteCampaignSave(state.FreedShips);
            }
            state.ChoosingUpgrade = false;
            _cooldown = 0;
            _heat = Math.Min(_heat, 45);
            _audio?.Trigger(StormaktSound.TitheUpgradeInstall);
        }
    }

    private void BeginOresundBridgeSection(BridgeSectionState section)
    {
        section.Mode = BridgeSectionMode.Carriage;
        section.Active = true;
        section.Age = 0;
        section.Powered = true;
        section.TrackLockedLeft = false;
        section.ControlHealth = 12;
        section.CarriageHealth = OresundServiceCarriageHealth;
        section.CarriageHitAge = 0;
        section.CouplingHealth = 6;
        section.CouplingBroken = false;
        section.ControlX = _width <= 320 ? 48 : 62;
        section.LaserX = _width - section.ControlX;
        section.CarriageX = _width / 2;
        section.ControlY = -34;
        section.LaserY = -34;
        section.CarriageY = -18;
        section.Outcome = BridgeSectionOutcome.None;
        section.LastEvent = "SECTION START";
        section.Notice = "BROSEKTION 01";
        section.NoticeAge = 90;
        section.LocalChanges = 0;
    }

    private void BeginOresundFlapSection(BridgeSectionState section)
    {
        section.Mode = BridgeSectionMode.Flaps;
        section.Active = true;
        section.Age = 0;
        section.Powered = true;
        section.FlapInset = 0;
        section.FlapY = _height <= 700 ? 150 : 188;
        section.FlapHealth = 3;
        section.FirstFlapOpened = false;
        section.SecondFlapOpened = false;
        section.FlapCoverScored = false;
        section.Outcome = BridgeSectionOutcome.None;
        section.LastEvent = "FLAPS ARMED";
        section.Notice = "BROKLAFFAR";
        section.NoticeAge = 90;
    }

    private void BeginOresundTrainSection(BridgeSectionState section)
    {
        section.Mode = BridgeSectionMode.Train;
        section.Active = true;
        section.Age = 0;
        section.TrainX = _width / 2;
        section.TrainY = -96;
        section.TrainCannonFrontHealth = OresundTrainCannonHealth;
        section.TrainCannonRearHealth = OresundTrainCannonHealth;
        section.TrainCouplingHealth = 6;
        section.TrainSwitchHealth = 9;
        section.TrainCouplingBroken = false;
        section.TrainTrackDiverted = false;
        section.TrainCrashAge = 0;
        section.Outcome = BridgeSectionOutcome.None;
        section.LastEvent = "ARMORED TRAIN IN";
        section.Notice = "PANSARTÅG";
        section.NoticeAge = 100;
    }

    private void BeginOresundSoren(BridgeSectionState section)
    {
        OresundSorenTarget target = section.Outcome switch
        {
            BridgeSectionOutcome.TrainDisarmed => OresundSorenTarget.TrackSwitch,
            BridgeSectionOutcome.TrainCrashed => OresundSorenTarget.LaserRelay,
            _ => OresundSorenTarget.RearCannon,
        };
        int targetX = target switch
        {
            OresundSorenTarget.TrackSwitch => _width <= 320 ? 52 : 64,
            OresundSorenTarget.LaserRelay => _width - (_width <= 320 ? 52 : 64),
            _ => _width / 2,
        };
        _oresundSoren = new OresundSorenState
        {
            Target = target,
            TargetX = targetX,
            TargetY = target == OresundSorenTarget.RearCannon ? 124 : 102,
            X = targetX < _width / 2 ? _width + 48 : -48,
            Y = 58,
            FromRight = targetX < _width / 2,
        };
    }

    private void BeginOresundFortressBoss()
    {
        _oresundBoss = new OresundFortressBossState
        {
            Health = OresundBossMaxHealth,
            LeftIntegrity = 540,
            RightIntegrity = 540,
            Phase = 1,
            LeftX = -74,
            RightX = _width + 74,
            Y = 78,
            LastEvent = "TWIN FORTRESS IN",
        };
        _enemies.Clear();
        _enemyShots.Clear();
        _shots.Clear();
        _audio?.SwitchMusic(StormaktMusicTrack.Boss);
        _audio?.Trigger(StormaktSound.Deploy);
    }

    private void StepOresundBridgeSection()
    {
        if (_levelId != 2 || _bridgeSection is not BridgeSectionState section) return;
        section.NoticeAge = Math.Max(0, section.NoticeAge - 1);
        if (!section.Active) return;

        if (section.Mode == BridgeSectionMode.Flaps)
        {
            StepOresundFlaps(section);
            return;
        }
        if (section.Mode == BridgeSectionMode.Train)
        {
            StepOresundTrain(section);
            return;
        }

        section.Age++;
        section.CarriageHitAge = Math.Max(0, section.CarriageHitAge - 1);
        int entry = Math.Min(0, section.Age - 126);
        section.ControlY = 82 + entry;
        section.LaserY = 82 + entry;
        section.CarriageY = 112 + entry;

        if (section.Age == 390 && section.Powered)
            _audio?.Trigger(StormaktSound.OresundLaserRelay);

        if (section.Outcome == BridgeSectionOutcome.None)
        {
            ResolveOresundBridgeShots(section);
        }

        if (section.TrackLockedLeft)
        {
            section.CarriageX = Math.Max(-30, section.CarriageX - 3);
        }
        else if (section.CouplingBroken)
        {
            section.CarriageX = Math.Min(section.LaserX, section.CarriageX + 2);
        }

        bool laserFiring = section.Age is >= 420 and < 480 && section.Powered;
        if (laserFiring && section.Outcome == BridgeSectionOutcome.None && section.CouplingBroken &&
            Math.Abs(section.CarriageX - section.LaserX) <= 5)
        {
            CompleteOresundBridgeSection(section, BridgeSectionOutcome.LaserDestroyedCarriage,
                "LIST x2", "LASER HIT CARRIAGE", 800);
        }
        else if (laserFiring && section.Outcome == BridgeSectionOutcome.None &&
            Math.Abs(_shipX - section.LaserX) < 7 && _shipY > section.LaserY)
        {
            DamageShip();
        }

        if (section.Age == 650 && section.Outcome == BridgeSectionOutcome.None)
        {
            CompleteOresundBridgeSection(section, BridgeSectionOutcome.Passed,
                "BRON PASSERAD", "SECTION PASSED", 0);
        }
        if (section.Age >= 720) section.Active = false;
    }

    private void StepOresundFlaps(BridgeSectionState section)
    {
        section.Age++;
        int firstTarget = _width - (_width <= 320 ? 72 : 88);
        int pairTarget = (_width - (_width <= 320 ? 64 : 78)) / 2;
        bool firstSequence = section.Age is >= 60 and < 360;
        bool secondSequence = section.Age is >= 400 and < 700;
        section.FlapPair = secondSequence;

        if (section.Age == 60)
        {
            section.Notice = "KLAFF VÄNSTER";
            section.NoticeAge = 80;
            section.LastEvent = "FIRST TELEGRAPH";
        }
        if (section.Age is 120 or 460)
            _audio?.Trigger(StormaktSound.OresundFlapMotor);
        if (section.Age == 520)
            _audio?.Trigger(StormaktSound.OresundLaserRelay);
        if (section.Age == 400)
        {
            section.FlapHealth = 6;
            section.Notice = "DUBBELKLAFF + LASER";
            section.NoticeAge = 100;
            section.LastEvent = "SECOND TELEGRAPH";
        }

        if (firstSequence)
        {
            section.FlapInset = section.FirstFlapOpened ? Math.Max(0, section.FlapInset - 8) :
                section.Age switch
                {
                    < 120 => 0,
                    < 150 => firstTarget * (section.Age - 120) / 30,
                    < 300 => firstTarget,
                    _ => Math.Max(0, firstTarget * (360 - section.Age) / 60),
                };
        }
        else if (secondSequence)
        {
            section.FlapInset = section.SecondFlapOpened ? Math.Max(0, section.FlapInset - 8) :
                section.Age switch
                {
                    < 460 => 0,
                    < 490 => pairTarget * (section.Age - 460) / 30,
                    < 650 => pairTarget,
                    _ => Math.Max(0, pairTarget * (700 - section.Age) / 50),
                };
        }
        else
        {
            section.FlapInset = Math.Max(0, section.FlapInset - 8);
        }

        ResolveOresundFlapShots(section);

        if (section.FlapInset > 8 && ShipTouchesOresundFlap(section)) DamageShip();

        if (section.Age is 205 or 235 or 525 or 585)
        {
            _enemyShots.Add(new EnemyShot(_shipX, section.FlapY - 32, 0, 2.6, 0));
        }

        bool laserWarning = section.Age is >= 490 and < 550;
        bool laserFiring = section.Age is >= 550 and < 610;
        section.FlapLaserActive = laserWarning || laserFiring;
        if (laserFiring && Math.Abs(_shipX - _width / 2) < 7 && _shipY > section.FlapY - 30)
        {
            DamageShip();
        }

        if (section.Age >= 720)
        {
            section.Active = false;
            section.Notice = section.FlapCoverScored ? "KLAFFSEKTION KLAR" : "BRON PASSERAD";
            section.NoticeAge = 100;
        }
    }

    private void ResolveOresundFlapShots(BridgeSectionState section)
    {
        if (section.FlapInset <= 4) return;
        int nodeY = section.FlapY;
        int leftNodeX = section.FlapInset - 8;
        int rightNodeX = _width - section.FlapInset + 8;
        for (int index = _shots.Count - 1; index >= 0; index--)
        {
            Shot shot = _shots[index];
            bool nodeHit = Math.Abs(shot.Y - nodeY) <= 10 &&
                (Math.Abs(shot.X - leftNodeX) <= 9 ||
                 (section.FlapPair && Math.Abs(shot.X - rightNodeX) <= 9));
            if (nodeHit)
            {
                section.FlapHealth -= shot.Power;
                _shots.RemoveAt(index);
                if (section.FlapHealth <= 0)
                {
                    if (section.FlapPair) section.SecondFlapOpened = true;
                    else section.FirstFlapOpened = true;
                    section.LastEvent = "EARLY OPEN";
                    section.Notice = "KLAFF ÖPPNAD";
                    section.NoticeAge = 90;
                    _score += 200;
                    _audio?.Trigger(StormaktSound.Deploy);
                    return;
                }
                continue;
            }
            if (PointInsideOresundFlap(section, shot.X, shot.Y)) _shots.RemoveAt(index);
        }
    }

    private bool ShipTouchesOresundFlap(BridgeSectionState section) =>
        PointInsideOresundFlap(section, _shipX - 6, _shipY) ||
        PointInsideOresundFlap(section, _shipX + 6, _shipY);

    private bool PointInsideOresundFlap(BridgeSectionState section, double x, double y)
    {
        if (Math.Abs(y - section.FlapY) > 18 || section.FlapInset <= 0) return false;
        return x <= section.FlapInset || (section.FlapPair && x >= _width - section.FlapInset);
    }

    private void StepOresundTrain(BridgeSectionState section)
    {
        section.Age++;
        if (section.Age == 18)
            _audio?.Trigger(StormaktSound.OresundTrainRumble);
        int settledTrainY = _width <= 320 ? -12 : 26;
        section.TrainY = -96 + Math.Min(settledTrainY + 96, section.Age * 2);
        ResolveOresundTrainShots(section);

        if (section.TrainTrackDiverted && section.Outcome == BridgeSectionOutcome.None)
        {
            section.TrainX = Math.Max(_width <= 320 ? 58 : 70, section.TrainX - 3);
            if (section.TrainX <= (_width <= 320 ? 58 : 70))
            {
                CompleteOresundTrain(section, BridgeSectionOutcome.TrainCrashed,
                    "LIST x3", "TRAIN BUFFER CRASH", 750);
                _audio?.Trigger(StormaktSound.OresundTrainCrash);
                section.TrainCrashAge = 1;
                if (_shipX < 105 && Math.Abs(_shipY - (section.TrainY + 135)) < 70) DamageShip();
            }
        }
        if (section.TrainCrashAge > 0) section.TrainCrashAge++;

        if (!section.TrainTrackDiverted && section.Age is >= 170 and < 650)
        {
            if (section.TrainCannonRearHealth > 0 && section.Age % 72 == 18)
                FireEnemyShot(section.TrainX, section.TrainY + 165, 3, 2.35);
            if (section.TrainCannonFrontHealth > 0 && section.Age % 84 == 42)
                FireEnemyShot(section.TrainX, section.TrainY + 105, 3, 2.2);
        }

        if (section.Age >= 820)
        {
            if (section.Outcome == BridgeSectionOutcome.None)
            {
                section.Notice = "TÅGET PASSERADE";
                section.NoticeAge = 90;
                section.LastEvent = "TRAIN PASSED";
            }
            section.Active = false;
        }
    }

    private void ResolveOresundTrainShots(BridgeSectionState section)
    {
        if (section.Age < 100 || section.Age >= 700 || section.Outcome != BridgeSectionOutcome.None) return;
        int frontY = section.TrainY + 105;
        int rearY = section.TrainY + 165;
        int couplingX = section.TrainX + 30;
        int couplingY = section.TrainY + 136;
        int switchX = _width <= 320 ? 52 : 64;
        int switchY = 104;

        for (int index = _shots.Count - 1; index >= 0; index--)
        {
            Shot shot = _shots[index];
            if (!section.TrainCouplingBroken && Math.Abs(shot.X - couplingX) <= 7 &&
                Math.Abs(shot.Y - couplingY) <= 9)
            {
                section.TrainCouplingHealth -= shot.Power;
                _shots.RemoveAt(index);
                if (section.TrainCouplingHealth <= 0)
                {
                    section.TrainCouplingBroken = true;
                    section.LastEvent = "MASTER COUPLING BROKEN";
                    section.Notice = "HUVUDKOPPLING BRUTEN";
                    section.NoticeAge = 90;
                    _score += 100;
                    _audio?.Trigger(StormaktSound.Broadside);
                }
                continue;
            }
            if (section.TrainCouplingBroken && !section.TrainTrackDiverted &&
                Math.Abs(shot.X - switchX) <= 13 && Math.Abs(shot.Y - switchY) <= 13)
            {
                section.TrainSwitchHealth -= shot.Power;
                _shots.RemoveAt(index);
                if (section.TrainSwitchHealth <= 0)
                {
                    section.TrainTrackDiverted = true;
                    section.LastEvent = "TRACK DIVERTED";
                    section.Notice = "VÄXEL MOT BUFFERT";
                    section.NoticeAge = 100;
                    _score += 150;
                    _audio?.Trigger(StormaktSound.Deploy);
                }
                continue;
            }
            if (section.TrainCannonRearHealth > 0 && Math.Abs(shot.X - section.TrainX) <= 22 &&
                Math.Abs(shot.Y - rearY) <= 27)
            {
                section.TrainCannonRearHealth -= shot.Power;
                _shots.RemoveAt(index);
                if (section.TrainCannonRearHealth <= 0)
                {
                    section.LastEvent = "REAR CANNON DESTROYED";
                    section.Notice = "BAKRE KANON TYST";
                    section.NoticeAge = 70;
                    _score += 300;
                }
                continue;
            }
            if (section.TrainCannonFrontHealth > 0 && Math.Abs(shot.X - section.TrainX) <= 22 &&
                Math.Abs(shot.Y - frontY) <= 27)
            {
                section.TrainCannonFrontHealth -= shot.Power;
                _shots.RemoveAt(index);
                if (section.TrainCannonFrontHealth <= 0)
                {
                    section.LastEvent = "FRONT CANNON DESTROYED";
                    section.Notice = "FRÄMRE KANON TYST";
                    section.NoticeAge = 70;
                    _score += 300;
                }
            }
        }

        if (section.TrainCannonFrontHealth <= 0 && section.TrainCannonRearHealth <= 0)
            CompleteOresundTrain(section, BridgeSectionOutcome.TrainDisarmed,
                "TÅGET AVVÄPNAT", "TRAIN DISARMED", 0);
    }

    private void CompleteOresundTrain(BridgeSectionState section, BridgeSectionOutcome outcome,
        string notice, string eventName, int score)
    {
        if (section.Outcome != BridgeSectionOutcome.None) return;
        section.Outcome = outcome;
        section.Notice = notice;
        section.NoticeAge = 120;
        section.LastEvent = eventName;
        _score += score;
        if (outcome != BridgeSectionOutcome.TrainCrashed)
            _audio?.Trigger(StormaktSound.EnemyExplosion);
    }

    private void ResolveOresundBridgeShots(BridgeSectionState section)
    {
        if (section.Age < 110 || section.Age >= 560) return;
        for (int index = _shots.Count - 1; index >= 0; index--)
        {
            Shot shot = _shots[index];
            if (!section.TrackLockedLeft && Math.Abs(shot.X - section.ControlX) <= 13 &&
                Math.Abs(shot.Y - section.ControlY) <= 12)
            {
                section.ControlHealth -= shot.Power;
                _shots.RemoveAt(index);
                if (section.ControlHealth <= 0)
                {
                    section.TrackLockedLeft = true;
                    section.LocalChanges = Math.Min(2, section.LocalChanges + 1);
                    CompleteOresundBridgeSection(section, BridgeSectionOutcome.SafeReroute,
                        "VÄXEL LÅST", "CONTROL DESTROYED", 250);
                    return;
                }
                continue;
            }

            int couplingX = section.CarriageX + 18;
            if (!section.CouplingBroken && Math.Abs(shot.X - couplingX) <= 5 &&
                Math.Abs(shot.Y - section.CarriageY) <= 7)
            {
                section.CouplingHealth -= shot.Power;
                _shots.RemoveAt(index);
                if (section.CouplingHealth <= 0)
                {
                    section.CouplingBroken = true;
                    section.LocalChanges = Math.Min(2, section.LocalChanges + 1);
                    section.LastEvent = "COUPLING BROKEN";
                    section.Notice = "KOPPLING BRUTEN";
                    section.NoticeAge = 90;
                    _score += 100;
                    _audio?.Trigger(StormaktSound.Broadside);
                }
                continue;
            }

            if (Math.Abs(shot.X - section.CarriageX) <= 20 &&
                Math.Abs(shot.Y - section.CarriageY) <= 14)
            {
                section.CarriageHealth -= shot.Power;
                section.CarriageHitAge = 8;
                _shots.RemoveAt(index);
                if (section.Age % 12 < 6)
                    _audio?.Trigger(StormaktSound.HullHit);
                if (section.CarriageHealth <= 0)
                {
                    CompleteOresundBridgeSection(section, BridgeSectionOutcome.DirectDestroyed,
                        "VAGN FÖRSTÖRD", "CARRIAGE DESTROYED", 400);
                    return;
                }
            }
        }
    }

    private void CompleteOresundBridgeSection(BridgeSectionState section, BridgeSectionOutcome outcome,
        string notice, string eventName, int score)
    {
        if (section.Outcome != BridgeSectionOutcome.None) return;
        section.Outcome = outcome;
        section.LastEvent = eventName;
        section.Notice = notice;
        section.NoticeAge = 120;
        _score += score;
        _audio?.Trigger(outcome == BridgeSectionOutcome.SafeReroute
            ? StormaktSound.OresundSwitchBreak : StormaktSound.EnemyExplosion);
    }

    private void StepShots()
    {
        for (int i = _shots.Count - 1; i >= 0; i--)
        {
            Shot shot = _shots[i];
            shot.X += shot.Vx;
            shot.Y += shot.Vy;
            if (shot.Y < -8 || shot.X < -8 || shot.X >= _width + 8)
            {
                _shots.RemoveAt(i);
            }
            else
            {
                _shots[i] = shot;
            }
        }
    }

    private void StepEnemyShots()
    {
        for (int index = _enemyShots.Count - 1; index >= 0; index--)
        {
            EnemyShot shot = _enemyShots[index];
            shot.X += shot.Vx;
            shot.Y += shot.Vy;
            if (shot.Y < -10 || shot.Y > _height + 10 || shot.X < -10 || shot.X > _width + 10)
            {
                _enemyShots.RemoveAt(index);
                continue;
            }
            if (_bridgeSection is BridgeSectionState { Active: true, Mode: BridgeSectionMode.Flaps } section &&
                PointInsideOresundFlap(section, shot.X, shot.Y))
            {
                _enemyShots.RemoveAt(index);
                if (!section.FlapCoverScored)
                {
                    section.FlapCoverScored = true;
                    section.LastEvent = "FLAP COVER";
                    section.Notice = "KLAFFSKYDD";
                    section.NoticeAge = 75;
                    _score += 150;
                }
                continue;
            }
            if (Math.Abs(_shipX - shot.X) < 7 && Math.Abs(_shipY - shot.Y) < 7)
            {
                _enemyShots.RemoveAt(index);
                DamageShip();
                continue;
            }
            _enemyShots[index] = shot;
        }
    }

    private void StepGroundTargets()
    {
        for (int index = _groundTargets.Count - 1; index >= 0; index--)
        {
            GroundTarget target = _groundTargets[index];
            target.Y++;
            target.Age++;

            if (target.CollapseFrames > 0)
            {
                target.Y += 2;
                target.CollapseFrames--;
                if (target.CollapseFrames == 0 || target.Y > _height + 42)
                {
                    _groundTargets.RemoveAt(index);
                }
                else
                {
                    _groundTargets[index] = target;
                }
                continue;
            }

            if (target.Type == GroundTargetType.Turret && target.Enabled && target.Y > 24 && target.Y < _height - 50)
            {
                int cycle = target.Age % 180;
                if (cycle is 88 or 96 or 104)
                {
                    FireGroundShot(target.X, target.Y);
                }
            }

            bool destroyed = false;
            int halfWidth = target.Type == GroundTargetType.BridgeSpan ? 42 : 10;
            int halfHeight = target.Type == GroundTargetType.BridgeSpan ? 9 : 11;
            for (int shotIndex = _shots.Count - 1; shotIndex >= 0; shotIndex--)
            {
                Shot shot = _shots[shotIndex];
                if (Math.Abs(shot.X - target.X) <= halfWidth && Math.Abs(shot.Y - target.Y) <= halfHeight)
                {
                    target.Health -= shot.Power;
                    _shots.RemoveAt(shotIndex);
                    if (target.Health <= 0)
                    {
                        destroyed = true;
                    }
                    break;
                }
            }

            if (destroyed)
            {
                _score += target.Type switch
                {
                    GroundTargetType.Turret => 450,
                    GroundTargetType.EnergyNode => 250,
                    GroundTargetType.SignalBeacon => 300,
                    _ => 180,
                };
                if (target.Type == GroundTargetType.BridgeSpan)
                {
                    CollapseBridgeGroup(target.Group);
                    _audio?.Trigger(StormaktSound.Broadside);
                    continue;
                }
                if (target.Type == GroundTargetType.EnergyNode)
                {
                    DisableLinkedTurret(target.Group);
                }
                _groundTargets.RemoveAt(index);
                _audio?.Trigger(StormaktSound.EnemyExplosion);
                continue;
            }
            if (target.Y > _height + 42)
            {
                _groundTargets.RemoveAt(index);
                continue;
            }
            _groundTargets[index] = target;
        }
    }

    private void CollapseBridgeGroup(int group)
    {
        for (int index = 0; index < _groundTargets.Count; index++)
        {
            GroundTarget target = _groundTargets[index];
            if (target.Group == group)
            {
                _groundTargets[index] = target with { Enabled = false, CollapseFrames = 45 };
            }
        }
    }

    private void FireGroundShot(int x, int y)
    {
        double dx = _shipX - x;
        double dy = _shipY - y;
        double length = Math.Max(1.0, Math.Sqrt(dx * dx + dy * dy));
        _enemyShots.Add(new EnemyShot(x, y + 7, dx / length * 2.15, dy / length * 2.15, 0));
        _audio?.Trigger(StormaktSound.TwinCannon);
    }

    private void DisableLinkedTurret(int group)
    {
        for (int index = 0; index < _groundTargets.Count; index++)
        {
            GroundTarget target = _groundTargets[index];
            if (target.Group == group && target.Type == GroundTargetType.Turret)
            {
                _groundTargets[index] = target with { Enabled = false };
            }
        }
    }

    private void DamageShip()
    {
        if (_developerMode && _levelId is 5 or 6)
        {
            _heat = Math.Max(_heat, 40);
            _invulnerabilityFrames = Math.Max(_invulnerabilityFrames, 8);
            return;
        }
        if (_activeLoadout is StormaktLoadout { ShipModule: TitheShipModule.SeizureArmor, ArmorCharge: > 0 } armor)
        {
            armor.ArmorCharge--;
            _heat = Math.Max(_heat, 90);
            _invulnerabilityFrames = 90;
            _audio?.Trigger(StormaktSound.HullHit);
            return;
        }
        if (_invincibleTestMode)
        {
            _heat = Math.Max(_heat, 40);
            return;
        }
        if (_invulnerabilityFrames > 0)
        {
            return;
        }
        _lives--;
        _heat = 120;
        _invulnerabilityFrames = 90;
        _audio?.Trigger(StormaktSound.HullHit);
        if (_lives <= 0)
        {
            _gameOver = true;
        }
    }

    private void SpawnBoss()
    {
        if (_levelId == 1)
        {
            if (_missionFrame == 3_600 && _glimminge is null)
            {
                _glimminge = new GlimmingeState
                {
                    X = _width / 2.0,
                    Y = -72.0,
                    Health = GlimmingeMaxHealth,
                    Phase = 1,
                };
                _enemyShots.Clear();
                _audio?.SwitchMusic(StormaktMusicTrack.Boss);
                _audio?.Trigger(StormaktSound.Deploy);
            }
            return;
        }
        if (_levelId != 0)
        {
            return;
        }
        if (_missionFrame == BossArrivalFrame && _boss is null)
        {
            _boss = new BossState
            {
                X = _width / 2.0,
                Y = -58.0,
                Health = BossPhaseOneHealth,
                LeftCannonHealth = 70,
                RightCannonHealth = 70,
                Phase = 1,
            };
            _audio?.Trigger(StormaktSound.Deploy);
            _audio?.SwitchMusic(StormaktMusicTrack.Boss);
        }
    }

    private void StepSorenRival()
    {
        if (_sorenRival is not SorenRivalState rival)
        {
            return;
        }
        rival.Age++;
        if (rival.Interrupted)
        {
            rival.InterruptAge++;
            rival.X += 5.5;
            rival.Y -= 0.8;
            if (rival.InterruptAge >= 90 || rival.X > _width + 48)
            {
                _sorenRival = null;
            }
            return;
        }

        bool decoyPhase = rival.Age >= 330 || rival.Health <= 82;
        if (!decoyPhase)
        {
            int dashSide = (rival.Age / 90 & 1) == 0 ? 1 : -1;
            double targetX = _width / 2.0 + dashSide * (_width / 3.2);
            rival.X += Math.Clamp(targetX - rival.X, -5.2, 5.2);
            rival.Y = 67 + Math.Sin(rival.Age * 0.055) * 9.0;
            if (rival.Age % 72 == 48)
            {
                FireEnemyShot((int)rival.X, (int)rival.Y + 12, 3, 2.55);
            }
        }
        else
        {
            rival.X = _width / 2.0 + Math.Sin(rival.Age * 0.052) * (_width / 3.4);
            rival.Y = 70 + Math.Cos(rival.Age * 0.037) * 14.0;
            if (rival.Age % 54 == 32)
            {
                FireEnemyShot((int)rival.X - 8, (int)rival.Y + 10, 3, 2.35);
                FireEnemyShot((int)rival.X + 8, (int)rival.Y + 10, 3, 2.35);
            }
        }

        for (int shotIndex = _shots.Count - 1; shotIndex >= 0; shotIndex--)
        {
            Shot shot = _shots[shotIndex];
            if (Math.Abs(shot.X - rival.X) <= 22 && Math.Abs(shot.Y - rival.Y) <= 18)
            {
                rival.Health -= shot.Power;
                _shots.RemoveAt(shotIndex);
            }
        }
        if (rival.Health <= 49 || _missionFrame >= 3_420)
        {
            rival.Interrupted = true;
            rival.InterruptAge = 0;
            _enemyShots.Clear();
            _audio?.Trigger(StormaktSound.Broadside);
        }
    }

    private void StepOresundSoren()
    {
        if (_levelId != 2 || _oresundSoren is not OresundSorenState intervention) return;
        intervention.Age++;

        if (!intervention.RadioQueued &&
            (_bridgeSection is not BridgeSectionState section || section.NoticeAge == 0))
        {
            intervention.RadioQueued = true;
            ActivateBossRadio(OresundSorenStrikeRadio);
            ActivateBossRadio(OresundEbbaSorenRadio);
        }

        double stagingX = intervention.TargetX + (intervention.FromRight ? 74 : -74);
        if (intervention.Age < 150)
        {
            intervention.X += Math.Clamp(stagingX - intervention.X, -5.0, 5.0);
            intervention.Y = 58 + Math.Sin(intervention.Age * 0.055) * 10.0;
        }
        else if (intervention.Age < 220)
        {
            intervention.X += Math.Clamp(stagingX - intervention.X, -2.0, 2.0);
            intervention.Y = 64 + Math.Sin(intervention.Age * 0.09) * 5.0;
            if (intervention.Age == 180)
            {
                intervention.ShotFired = true;
                _audio?.Trigger(StormaktSound.Broadside);
            }
            if (intervention.Age == 210)
            {
                intervention.TargetDestroyed = true;
                if (_bridgeSection is BridgeSectionState resultSection)
                {
                    resultSection.LastEvent = $"SOREN {intervention.Target}";
                    resultSection.Notice = intervention.Target switch
                    {
                        OresundSorenTarget.TrackSwitch => "SÖREN TAR VÄXELN",
                        OresundSorenTarget.LaserRelay => "SÖREN TAR FYREN",
                        _ => "SÖREN TAR TÅGET",
                    };
                    resultSection.NoticeAge = 100;
                }
                _audio?.Trigger(StormaktSound.EnemyExplosion);
            }
        }
        else
        {
            intervention.X += intervention.FromRight ? -6.0 : 6.0;
            intervention.Y -= 0.45;
        }

        if (intervention.Age >= 720) _oresundSoren = null;
    }

    private void StepGlimminge()
    {
        if (_glimminge is not GlimmingeState boss)
        {
            return;
        }
        boss.Age++;
        boss.PhaseAge++;
        if (boss.BurningTransitionAge is > 0 and < 60)
        {
            boss.BurningTransitionAge++;
        }
        if (boss.Phase == 3)
        {
            if (boss.PhaseAge is 1 or 35 or 70 or 110 or 155 or 210 or 270)
            {
                _audio?.Trigger(boss.PhaseAge >= 155 ? StormaktSound.Broadside : StormaktSound.EnemyExplosion);
            }
            if (boss.PhaseAge >= 300)
            {
                _glimminge = null;
                _stageClear = true;
                _stageClearAge = 0;
                _enemyShots.Clear();
                _crystalSpears.Clear();
            }
            return;
        }

        if (boss.Age <= 150)
        {
            boss.Y = Math.Min(64.0, boss.Y + 0.92);
            return;
        }
        double sweep = _width <= 320 ? 42.0 : 55.0;
        if (boss.Phase == 1)
        {
            boss.X = _width / 2.0 + Math.Sin((boss.Age - 150) * 0.011) * sweep;
        }
        else
        {
            double phaseTwoX = _width / 2.0 + Math.Sin(boss.PhaseAge * 0.018) * sweep;
            if (boss.PhaseAge < 60)
            {
                double t = boss.PhaseAge / 60.0;
                double eased = t * t * (3.0 - 2.0 * t);
                boss.X = boss.PhaseTransitionX + (phaseTwoX - boss.PhaseTransitionX) * eased;
            }
            else
            {
                boss.X = phaseTwoX;
            }
        }
        bool shieldBraced = boss.Phase == 1 && boss.PhaseAge % 84 is >= 24 and <= 58;

        for (int shotIndex = _shots.Count - 1; shotIndex >= 0; shotIndex--)
        {
            Shot shot = _shots[shotIndex];
            if (Math.Abs(shot.X - boss.X) <= 56 && Math.Abs(shot.Y - boss.Y) <= 32)
            {
                if (shieldBraced)
                {
                    _shots.RemoveAt(shotIndex);
                    continue;
                }
                int previousHealth = boss.Health;
                boss.Health -= shot.Power;
                _shots.RemoveAt(shotIndex);
                if (boss.Phase == 2 && previousHealth > GlimmingeBurningHealth && boss.Health <= GlimmingeBurningHealth)
                {
                    boss.BurningTransitionAge = 1;
                }
                if (boss.Phase == 1 && boss.Health <= GlimmingePhaseTwoHealth)
                {
                    boss.Health = GlimmingePhaseTwoHealth;
                    boss.Phase = 2;
                    boss.PhaseAge = 0;
                    boss.PhaseTransitionX = boss.X;
                    _enemyShots.Clear();
                    ActivateBossRadio(BirgittePhaseTwoRadio);
                    _audio?.Trigger(StormaktSound.Broadside);
                }
                else if (boss.Phase == 2 && boss.Health <= 0)
                {
                    boss.Health = 0;
                    boss.Phase = 3;
                    boss.PhaseAge = 0;
                    _score += 7_500;
                    _shots.Clear();
                    _enemyShots.Clear();
                    _enemies.Clear();
                    _crystalSpears.Clear();
                    ActivateBossRadio(BirgitteDeathRadio);
                    _audio?.Trigger(StormaktSound.Broadside);
                    break;
                }
            }
        }

        if (boss.Phase == 1 && boss.PhaseAge % 84 == 42)
        {
            FireGlimmingeWall(boss);
        }
        if (boss.Phase == 1 && boss.PhaseAge % 240 == 120)
        {
            SpawnGlimmingeEscorts(boss, 2);
        }
        else if (boss.Phase == 2)
        {
            bool burningStage = boss.Health <= GlimmingeBurningHealth;
            int drillInterval = burningStage ? 42 : 66;
            int spearInterval = burningStage ? 90 : 150;
            if (boss.PhaseAge % drillInterval == 24)
            {
                FireEnemyShot((int)boss.X - 38, (int)boss.Y + 25, 4, 2.05);
                FireEnemyShot((int)boss.X + 38, (int)boss.Y + 25, 4, 2.05);
            }
            if (boss.PhaseAge % spearInterval == 60)
            {
                int span = Math.Max(1, _width - 96);
                int spearX = 48 + ((boss.PhaseAge / spearInterval * 97 + 41) % span);
                _crystalSpears.Add(new CrystalSpear(spearX, 0));
            }
            if (burningStage && boss.PhaseAge % 72 == 12)
            {
                FireGlimmingeEmbers(boss);
            }
            int escortInterval = burningStage ? 120 : 180;
            if (boss.PhaseAge % escortInterval == 80)
            {
                SpawnGlimmingeEscorts(boss, burningStage ? 3 : 2);
            }
        }
    }

    private void SpawnGlimmingeEscorts(GlimmingeState boss, int count)
    {
        for (int index = 0; index < count; index++)
        {
            int side = (index & 1) == 0 ? -1 : 1;
            int spread = count == 3 && index == 2 ? 0 : side * 58;
            _enemies.Add(new Enemy(
                Math.Clamp((int)Math.Round(boss.X) + spread, 20, _width - 20),
                (int)Math.Round(boss.Y) + 25 - index * 8,
                1,
                11,
                12,
                0xff3a3030,
                6,
                index * 1.7,
                boss.PhaseAge + index * 37,
                spread,
                false));
        }
        _audio?.Trigger(StormaktSound.Deploy);
    }

    private void FireGlimmingeWall(GlimmingeState boss)
    {
        int gap = 1 + (boss.PhaseAge / 84) % 5;
        for (int column = 0; column < 7; column++)
        {
            if (column == gap || column == gap + 1)
            {
                continue;
            }
            double x = 28 + column * ((_width - 56) / 6.0);
            _enemyShots.Add(new EnemyShot(x, boss.Y + 24, 0, 1.65, 6));
        }
        _audio?.Trigger(StormaktSound.Broadside);
    }

    private void FireGlimmingeEmbers(GlimmingeState boss)
    {
        int x = (int)Math.Round(boss.X);
        int y = (int)Math.Round(boss.Y) + 15;
        for (int index = 0; index < 8; index++)
        {
            double angle = Math.PI / 8.0 + index * Math.PI / 4.0;
            _enemyShots.Add(new EnemyShot(x, y, Math.Cos(angle) * 1.45, Math.Sin(angle) * 1.45, 4));
        }
        _audio?.Trigger(StormaktSound.EnemyExplosion);
    }

    private void StepCrystalSpears()
    {
        for (int index = _crystalSpears.Count - 1; index >= 0; index--)
        {
            CrystalSpear spear = _crystalSpears[index];
            spear.Age++;
            if (spear.Age >= 48)
            {
                int y = 18 + (spear.Age - 48) * 5;
                if (Math.Abs(_shipX - spear.X) < 11 && Math.Abs(_shipY - y) < 22)
                {
                    DamageShip();
                }
                if (y > _height + 30)
                {
                    _crystalSpears.RemoveAt(index);
                    continue;
                }
            }
            _crystalSpears[index] = spear;
        }
    }

    private void StepBoss()
    {
        if (_levelId == 2)
        {
            StepOresundFortressBoss();
            return;
        }
        BossState? boss = _boss;
        if (boss is null)
        {
            return;
        }

        boss.Age++;
        boss.PhaseAge++;
        if (boss.Age <= 180)
        {
            boss.Y = Math.Min(58.0, boss.Y + 0.66);
        }
        else if (boss.Phase == 3)
        {
            StepBossPhaseThreeMovement(boss);
        }
        else if (boss.Phase == 4)
        {
            boss.Y = 58.0;
        }
        else
        {
            double sweep = _width <= 320 ? 54.0 : 68.0;
            boss.X = (_width / 2.0) + Math.Sin((boss.Age - 180) * 0.012) * sweep;
        }

        for (int shotIndex = _shots.Count - 1; shotIndex >= 0; shotIndex--)
        {
            Shot shot = _shots[shotIndex];
            int bossX = (int)Math.Round(boss.X);
            int bossY = (int)Math.Round(boss.Y);
            bool hit = false;
            if (boss.Phase < 4 && boss.Age >= 500 && boss.LeftCannonHealth > 0 && Math.Abs(shot.X - (bossX - BossCannonOffset)) <= 13 && Math.Abs(shot.Y - (bossY + 7)) <= 14)
            {
                boss.LeftCannonHealth -= shot.Power;
                hit = true;
                if (boss.LeftCannonHealth <= 0)
                {
                    _score += 1_200;
                    _audio?.Trigger(StormaktSound.EnemyExplosion);
                }
            }
            else if (boss.Phase < 4 && boss.Age >= 500 && boss.RightCannonHealth > 0 && Math.Abs(shot.X - (bossX + BossCannonOffset)) <= 13 && Math.Abs(shot.Y - (bossY + 7)) <= 14)
            {
                boss.RightCannonHealth -= shot.Power;
                hit = true;
                if (boss.RightCannonHealth <= 0)
                {
                    _score += 1_200;
                    _audio?.Trigger(StormaktSound.EnemyExplosion);
                }
            }
            else if (boss.Age >= 500 && boss.Phase == 1 && Math.Abs(shot.X - bossX) <= 52 && Math.Abs(shot.Y - bossY) <= 29)
            {
                boss.Health -= shot.Power;
                hit = true;
                if (boss.Health <= BossPhaseTwoThreshold)
                {
                    boss.Health = BossPhaseTwoThreshold;
                    boss.Phase = 2;
                    boss.PhaseAge = 0;
                    boss.LeftDockHealth = 50;
                    boss.RightDockHealth = 50;
                    _enemyShots.Clear();
                    _anchorHazards.Clear();
                    ActivateBossRadio(RasmusPhaseTwoRadio);
                    _audio?.Trigger(StormaktSound.Broadside);
                }
            }
            else if (boss.Phase == 2 && boss.LeftDockHealth > 0 &&
                Math.Abs(shot.X - (bossX - BossDockOffset)) <= 11 && Math.Abs(shot.Y - (bossY + 17)) <= 13)
            {
                boss.LeftDockHealth -= shot.Power;
                hit = true;
                if (boss.LeftDockHealth <= 0)
                {
                    _score += 900;
                    _audio?.Trigger(StormaktSound.EnemyExplosion);
                }
            }
            else if (boss.Phase == 2 && boss.RightDockHealth > 0 &&
                Math.Abs(shot.X - (bossX + BossDockOffset)) <= 11 && Math.Abs(shot.Y - (bossY + 17)) <= 13)
            {
                boss.RightDockHealth -= shot.Power;
                hit = true;
                if (boss.RightDockHealth <= 0)
                {
                    _score += 900;
                    _audio?.Trigger(StormaktSound.EnemyExplosion);
                }
            }
            else if (boss.Phase == 2 && Math.Abs(shot.X - bossX) <= 28 && Math.Abs(shot.Y - (bossY + 12)) <= 24)
            {
                hit = true;
                if (IsBossCoreVulnerable(boss))
                {
                    boss.Health -= shot.Power;
                    if (boss.Health <= BossPhaseThreeThreshold)
                    {
                        boss.Health = BossPhaseThreeThreshold;
                        boss.Phase = 3;
                        boss.PhaseAge = 0;
                        boss.PhaseTransitionX = boss.X;
                        boss.PhaseTransitionY = boss.Y;
                        boss.RushX = boss.X;
                        _enemyShots.Clear();
                        _anchorHazards.Clear();
                        ActivateBossRadio(RasmusPhaseThreeRadio);
                        _audio?.Trigger(StormaktSound.Broadside);
                    }
                }
            }
            else if (boss.Phase == 3 && boss.PhaseAge >= 180 &&
                Math.Abs(shot.X - bossX) <= 46 && Math.Abs(shot.Y - bossY) <= 30)
            {
                boss.Health -= Math.Max(1, (shot.Power + 1) / 2);
                hit = true;
                if (boss.Health <= 0)
                {
                    boss.Health = 0;
                    boss.Phase = 4;
                    boss.PhaseAge = 0;
                    _score += 5_000;
                    _shots.Clear();
                    _enemyShots.Clear();
                    _anchorHazards.Clear();
                    ActivateBossRadio(RasmusDeathRadio);
                    _audio?.Trigger(StormaktSound.Broadside);
                    break;
                }
            }
            if (hit)
            {
                _shots.RemoveAt(shotIndex);
            }
        }

        if (boss.Phase == 1 && boss.Age >= 520)
        {
            int attackFrame = boss.Age - 520;
            if (attackFrame % 90 == 0)
            {
                FireBossFans(boss);
            }
            if (attackFrame % 240 == 30)
            {
                int anchorIndex = attackFrame / 240;
                int span = Math.Max(1, _width - 144);
                _anchorHazards.Add(new AnchorHazard(72 + ((anchorIndex * 83) % span), 0));
            }
        }
        else if (boss.Phase == 2 && boss.PhaseAge >= 180)
        {
            StepBossPhaseTwoAttacks(boss);
        }
        else if (boss.Phase == 3 && boss.PhaseAge >= 180)
        {
            StepBossPhaseThreeAttacks(boss);
        }
        else if (boss.Phase == 4)
        {
            StepBossDeath(boss);
        }
    }

    private void StepOresundFortressBoss()
    {
        if (_oresundBoss is not OresundFortressBossState boss) return;
        boss.Age++;
        boss.PhaseAge++;

        if (boss.Phase == 4)
        {
            double separationSpeed = boss.PhaseAge < 120 ? 0.18 : 0.78;
            boss.LeftX -= separationSpeed;
            boss.RightX += separationSpeed;
            boss.Y += boss.PhaseAge < 120 ? 0.04 : 0.12;
            if (boss.PhaseAge % 38 == 1) _audio?.Trigger(StormaktSound.EnemyExplosion);
            if (boss.PhaseAge >= 330)
            {
                _oresundBoss = null;
                _stageClear = true;
                _stageClearAge = 0;
                _enemyShots.Clear();
                _shots.Clear();
                _audio?.SwitchMusic(StormaktMusicTrack.Oresund);
            }
            return;
        }

        int baseInset = _width <= 320 ? 58 : 72;
        if (boss.Age <= 150)
        {
            double t = boss.Age / 150.0;
            double eased = t * t * (3.0 - 2.0 * t);
            boss.LeftX = -74 + (baseInset + 74) * eased;
            boss.RightX = _width + 74 - (baseInset + 74) * eased;
        }
        else if (boss.Phase == 1)
        {
            boss.LeftX = baseInset;
            boss.RightX = _width - baseInset;
        }
        else if (boss.Phase == 2)
        {
            int closedInset = _width <= 320 ? 86 : 112;
            double t = Math.Min(1.0, boss.PhaseAge / 90.0);
            double eased = t * t * (3.0 - 2.0 * t);
            boss.LeftX = baseInset + (closedInset - baseInset) * eased;
            boss.RightX = _width - boss.LeftX;
        }
        else
        {
            double pulse = Math.Sin(boss.PhaseAge * 0.025) * (_width <= 320 ? 8 : 12);
            int closedInset = _width <= 320 ? 86 : 112;
            double t = Math.Min(1.0, boss.PhaseAge / 90.0);
            double eased = t * t * (3.0 - 2.0 * t);
            boss.LeftX = closedInset + (baseInset + pulse - closedInset) * eased;
            boss.RightX = _width - boss.LeftX;
            if (boss.PhaseAge == 120) boss.SorenStrikeAge = 1;
            if (boss.SorenStrikeAge > 0)
            {
                boss.SorenStrikeAge++;
                if (boss.SorenStrikeAge == 45)
                {
                    boss.CrossLockBroken = true;
                    boss.LastEvent = "SOREN BREAKS CROSSLOCK";
                    _audio?.Trigger(StormaktSound.Broadside);
                }
            }
        }

        if (boss.Age == 170 && !boss.IntroRadioStarted)
        {
            boss.IntroRadioStarted = true;
            ActivateBossRadio(OresundBossIntroRadio);
        }
        if (boss.Age < 320) return;

        ResolveOresundFortressShots(boss);
        if (boss.Phase == 4) return;
        if (boss.Phase == 1) StepOresundBossPhaseOne(boss);
        else if (boss.Phase == 2) StepOresundBossPhaseTwo(boss);
        else StepOresundBossPhaseThree(boss);
    }

    private void ResolveOresundFortressShots(OresundFortressBossState boss)
    {
        bool attackLeft = (boss.PhaseAge / 180 & 1) == 0;
        for (int index = _shots.Count - 1; index >= 0; index--)
        {
            Shot shot = _shots[index];
            if (boss.Phase == 3)
            {
                int coreY = 96;
                if (Math.Abs(shot.X - _width / 2) <= 24 && Math.Abs(shot.Y - coreY) <= 24)
                {
                    boss.Health -= shot.Power;
                    _shots.RemoveAt(index);
                    if (boss.Health <= 0)
                    {
                        BeginOresundBossDeath(boss);
                        return;
                    }
                }
                continue;
            }

            bool hitLeft = boss.LeftIntegrity > 0 && Math.Abs(shot.X - boss.LeftX) <= 50 &&
                Math.Abs(shot.Y - boss.Y) <= 46;
            bool hitRight = boss.RightIntegrity > 0 && Math.Abs(shot.X - boss.RightX) <= 50 &&
                Math.Abs(shot.Y - boss.Y) <= 46;
            if (!hitLeft && !hitRight) continue;

            bool shielded = boss.Phase == 1 && (hitLeft ? !attackLeft : attackLeft);
            _shots.RemoveAt(index);
            if (shielded)
            {
                boss.LastEvent = hitLeft ? "HELSINGOR SHIELD" : "HELSINGBORG SHIELD";
                continue;
            }

            if (hitLeft)
            {
                boss.LeftIntegrity -= shot.Power;
                if (boss.LeftIntegrity <= 0)
                {
                    boss.LeftIntegrity = 0;
                    boss.LastEvent = "HELSINGOR DISABLED";
                    _score += 1_500;
                    _audio?.Trigger(StormaktSound.EnemyExplosion);
                }
            }
            else
            {
                boss.RightIntegrity -= shot.Power;
                if (boss.RightIntegrity <= 0)
                {
                    boss.RightIntegrity = 0;
                    boss.LastEvent = "HELSINGBORG DISABLED";
                    _score += 1_500;
                    _audio?.Trigger(StormaktSound.EnemyExplosion);
                }
            }
            boss.Health -= shot.Power;
            if (boss.Phase == 1 && boss.Health <= OresundBossPhaseTwoHealth)
            {
                boss.Health = OresundBossPhaseTwoHealth;
                boss.Phase = 2;
                boss.PhaseAge = 0;
                boss.LastEvent = "CROSS POWER";
                _enemyShots.Clear();
                ActivateBossRadio(OresundBossCrossfireRadio);
                _audio?.Trigger(StormaktSound.OresundFortressLock);
                return;
            }
            if (boss.Phase == 2 && boss.Health <= OresundBossCoreHealth)
            {
                boss.Health = OresundBossCoreHealth;
                boss.Phase = 3;
                boss.PhaseAge = 0;
                boss.LastEvent = "CROWN CORE EXPOSED";
                _enemyShots.Clear();
                ActivateBossRadio(OresundBossCoreRadio);
                _audio?.Trigger(StormaktSound.OresundCrownCoreOpen);
                return;
            }
        }
    }

    private void StepOresundBossPhaseOne(OresundFortressBossState boss)
    {
        int cycle = boss.PhaseAge % 180;
        bool attackLeft = (boss.PhaseAge / 180 & 1) == 0;
        if (cycle is 52 or 126)
        {
            double x = attackLeft ? boss.LeftX : boss.RightX;
            int integrity = attackLeft ? boss.LeftIntegrity : boss.RightIntegrity;
            if (integrity <= 0)
            {
                x = attackLeft ? boss.RightX : boss.LeftX;
                integrity = attackLeft ? boss.RightIntegrity : boss.LeftIntegrity;
            }
            if (integrity > 0)
            {
                FireEnemyShot((int)x - 12, (int)boss.Y + 28, 3, 2.25);
                FireEnemyShot((int)x + 12, (int)boss.Y + 28, 3, 2.25);
            }
        }
    }

    private void StepOresundBossPhaseTwo(OresundFortressBossState boss)
    {
        int cycle = boss.PhaseAge % 150;
        bool leftBeam = (boss.PhaseAge / 150 & 1) == 0;
        double beamX = leftBeam ? boss.LeftX : boss.RightX;
        if (cycle is >= 50 and < 88 && Math.Abs(_shipX - beamX) < 8 && _shipY > boss.Y)
            DamageShip();
        if (cycle == 108)
        {
            double x = leftBeam ? boss.RightX : boss.LeftX;
            int integrity = leftBeam ? boss.RightIntegrity : boss.LeftIntegrity;
            if (integrity > 0) FireEnemyShot((int)x, (int)boss.Y + 30, 4, 2.45);
        }
    }

    private void StepOresundBossPhaseThree(OresundFortressBossState boss)
    {
        if (boss.PhaseAge < 105 || boss.PhaseAge % 60 != 45) return;
        int coreX = _width / 2;
        int coreY = 96;
        double offset = (boss.PhaseAge / 60 & 1) == 0 ? 0.0 : Math.PI / 10.0;
        for (int index = 0; index < 10; index++)
        {
            double angle = offset + index * Math.PI / 5.0;
            _enemyShots.Add(new EnemyShot(coreX, coreY,
                Math.Cos(angle) * 1.82, Math.Sin(angle) * 1.82, 4));
        }
        _audio?.Trigger(StormaktSound.Broadside);
    }

    private void BeginOresundBossDeath(OresundFortressBossState boss)
    {
        if (boss.Phase == 4) return;
        boss.Health = 0;
        boss.Phase = 4;
        boss.PhaseAge = 0;
        boss.LastEvent = "IRON CROWN BROKEN";
        _score += 10_000;
        _shots.Clear();
        _enemyShots.Clear();
        _enemies.Clear();
        ActivateBossRadio(OresundBossFallRadio);
        _audio?.Trigger(StormaktSound.OresundCrownCoreBreak);
    }

    private static bool IsBossCoreVulnerable(BossState boss)
    {
        if (boss.Phase != 2 || boss.PhaseAge < 180)
        {
            return false;
        }
        int cycle = (boss.PhaseAge - 180) % 300;
        bool docksDestroyed = boss.LeftDockHealth <= 0 && boss.RightDockHealth <= 0;
        return docksDestroyed ? cycle is >= 105 and < 265 : cycle is >= 165 and < 225;
    }

    private void FireBossFans(BossState boss)
    {
        int y = (int)Math.Round(boss.Y) + 13;
        if (boss.LeftCannonHealth > 0)
        {
            FireBossFan((int)Math.Round(boss.X) - BossCannonOffset, y, -0.22);
        }
        if (boss.RightCannonHealth > 0)
        {
            FireBossFan((int)Math.Round(boss.X) + BossCannonOffset, y, 0.22);
        }
        _audio?.Trigger(StormaktSound.Broadside);
    }

    private void FireBossFan(int x, int y, double bias)
    {
        for (int index = -2; index <= 2; index++)
        {
            double vx = bias + index * 0.48;
            double vy = 1.72 + (2 - Math.Abs(index)) * 0.16;
            _enemyShots.Add(new EnemyShot(x, y, vx, vy, 0));
        }
    }

    private void StepBossPhaseTwoAttacks(BossState boss)
    {
        int attackFrame = boss.PhaseAge - 180;
        int cycle = attackFrame % 300;
        if (cycle is 0 or 18 or 36)
        {
            FireSealRing(boss, cycle / 18, attackFrame / 300);
            if (cycle == 0)
            {
                _audio?.Trigger(StormaktSound.Broadside);
            }
        }
        if (cycle is 90 or 102 or 114)
        {
            if (boss.LeftCannonHealth > 0)
            {
                FireAimedBossShot((int)Math.Round(boss.X) - BossCannonOffset, (int)Math.Round(boss.Y) + 13, -0.12);
            }
            if (boss.RightCannonHealth > 0)
            {
                FireAimedBossShot((int)Math.Round(boss.X) + BossCannonOffset, (int)Math.Round(boss.Y) + 13, 0.12);
            }
            _audio?.Trigger(StormaktSound.TwinCannon);
        }
    }

    private void FireSealRing(BossState boss, int ringIndex, int volley)
    {
        double gapAngle = Math.PI / 2.0 + ((volley % 3) - 1) * 0.58;
        double speed = 1.05 + ringIndex * 0.28;
        int x = (int)Math.Round(boss.X);
        int y = (int)Math.Round(boss.Y) + 15;
        for (int index = 0; index < 28; index++)
        {
            double angle = index * Math.PI * 2.0 / 28.0;
            double difference = Math.Abs(Math.Atan2(Math.Sin(angle - gapAngle), Math.Cos(angle - gapAngle)));
            if (difference < 0.40)
            {
                continue;
            }
            _enemyShots.Add(new EnemyShot(x, y, Math.Cos(angle) * speed, Math.Sin(angle) * speed, 1));
        }
    }

    private void FireAimedBossShot(int x, int y, double spread)
    {
        double dx = _shipX - x;
        double dy = _shipY - y;
        double length = Math.Max(1.0, Math.Sqrt(dx * dx + dy * dy));
        double vx = dx / length;
        double vy = dy / length;
        _enemyShots.Add(new EnemyShot(x, y, (vx - vy * spread) * 2.45, (vy + vx * spread) * 2.45, 2));
    }

    private void StepBossPhaseThreeMovement(BossState boss)
    {
        const double homeY = 58.0;
        const int retreatFrames = 90;
        double rushY = _height - 74.0;
        double rushDistance = rushY - homeY;
        if (boss.PhaseAge < retreatFrames)
        {
            double t = boss.PhaseAge / (double)retreatFrames;
            double eased = t * t * (3.0 - 2.0 * t);
            boss.X = boss.PhaseTransitionX + ((_width / 2.0) - boss.PhaseTransitionX) * eased;
            boss.Y = boss.PhaseTransitionY + (homeY - boss.PhaseTransitionY) * eased;
            boss.RushX = boss.X;
            return;
        }
        if (boss.PhaseAge < 180)
        {
            boss.X = _width / 2.0;
            boss.Y = homeY;
            boss.RushX = boss.X;
            return;
        }

        int attackFrame = boss.PhaseAge - 180;
        if (attackFrame is 0 or 130)
        {
            boss.RushX = boss.X;
        }
        boss.X = boss.RushX;
        if (attackFrame is >= 48 and < 82)
        {
            boss.Y = homeY + (attackFrame - 48) * (rushDistance / 34.0);
        }
        else if (attackFrame is >= 82 and < 120)
        {
            boss.Y = rushY - (attackFrame - 82) * (rushDistance / 38.0);
        }
        else if (attackFrame is >= 178 and < 212)
        {
            boss.Y = homeY + (attackFrame - 178) * (rushDistance / 34.0);
        }
        else if (attackFrame is >= 212 and < 250)
        {
            boss.Y = rushY - (attackFrame - 212) * (rushDistance / 38.0);
        }
        else
        {
            boss.Y = homeY;
            if (attackFrame > 250)
            {
                boss.X = (_width / 2.0) + Math.Sin((attackFrame - 250) * 0.018) * 34.0;
                boss.RushX = boss.X;
            }
        }

        if (boss.Y > 95 && Math.Abs(_shipX - boss.X) < 48 && Math.Abs(_shipY - boss.Y) < 34)
        {
            DamageShip();
        }
    }

    private void StepBossPhaseThreeAttacks(BossState boss)
    {
        int attackFrame = boss.PhaseAge - 180;
        if (attackFrame % 8 == 0)
        {
            double angle = attackFrame * 0.115;
            int x = (int)Math.Round(boss.X);
            int y = (int)Math.Round(boss.Y) + 16;
            _enemyShots.Add(new EnemyShot(x, y, Math.Cos(angle) * 1.32, Math.Sin(angle) * 1.32, 4));
            _enemyShots.Add(new EnemyShot(x, y, -Math.Cos(angle) * 1.32, -Math.Sin(angle) * 1.32, 4));
        }
        if (attackFrame is 48 or 178)
        {
            _audio?.Trigger(StormaktSound.Broadside);
        }
        bool rushing = attackFrame is >= 48 and < 120 or >= 178 and < 250;
        if (rushing && attackFrame % 10 == 0)
        {
            int x = (int)Math.Round(boss.X);
            int y = (int)Math.Round(boss.Y) + 18;
            _enemyShots.Add(new EnemyShot(x - 46, y, -0.75, 2.15, 3));
            _enemyShots.Add(new EnemyShot(x + 46, y, 0.75, 2.15, 3));
        }
    }

    private void StepBossDeath(BossState boss)
    {
        if (boss.PhaseAge == 300)
        {
            ActivateBossRadio(RasmusDeathOathRadio);
        }
        if (boss.PhaseAge is 1 or 30 or 60 or 90 or 120 or 155 or 210 or 270 or 330 or 390 or 480 or 540 or 600)
        {
            bool heavy = boss.PhaseAge is 155 or 330 or 390 or 600;
            _audio?.Trigger(heavy ? StormaktSound.Broadside : StormaktSound.EnemyExplosion);
            if (boss.PhaseAge == 600)
            {
                _audio?.DuckMusic(2_600);
            }
        }
        if (boss.PhaseAge < 660)
        {
            return;
        }
        _boss = null;
        _stageClear = true;
        _stageClearAge = 0;
        _enemyShots.Clear();
        _shots.Clear();
    }

    private void StepAnchorHazards()
    {
        for (int index = _anchorHazards.Count - 1; index >= 0; index--)
        {
            AnchorHazard anchor = _anchorHazards[index];
            anchor.Age++;
            if (anchor.Age >= 48)
            {
                double y = _height - 15 - (anchor.Age - 48) * 4.2;
                if (Math.Abs(_shipX - anchor.X) < 10 && Math.Abs(_shipY - y) < 15)
                {
                    DamageShip();
                }
                if (y < -24)
                {
                    _anchorHazards.RemoveAt(index);
                    continue;
                }
            }
            _anchorHazards[index] = anchor;
        }
    }

    private void StepEnemies()
    {
        for (int i = _enemies.Count - 1; i >= 0; i--)
        {
            Enemy enemy = _enemies[i];
            if (enemy.Kind == 3)
            {
                GroundTarget? bridge = FindActiveBridge(enemy.BridgeGroup);
                if (bridge is GroundTarget cover)
                {
                    int desiredX = cover.X + enemy.EscortOffset;
                    int desiredY = cover.Y - 27 - Math.Abs(enemy.EscortOffset) / 5;
                    enemy.X += Math.Clamp(desiredX - enemy.X, -2, 2);
                    enemy.Y += Math.Clamp(desiredY - enemy.Y, -2, 2);
                }
                else
                {
                    enemy.Breakaway = true;
                    enemy.Y += 2;
                    enemy.X += enemy.EscortOffset < 0 ? -2 : 2;
                }
            }
            else
            {
                enemy.Y += enemy.Speed;
                enemy.Phase += 0.08;
                int wobble = (int)(Math.Sin(enemy.Phase) * 2.0);
                enemy.X += wobble;
            }

            if (enemy.Kind is 4 or 5 or 6 or 7 && enemy.Y > 24 && enemy.Y < _height - 64)
            {
                int attackPeriod = enemy.Kind switch { 4 => 150, 5 => 210, 7 => 165, _ => 120 };
                int fireFrame = enemy.Kind switch { 4 => 96, 5 => 132, 7 => 102, _ => 64 };
                int attackCycle = (_missionFrame + enemy.BridgeGroup) % attackPeriod;
                if (attackCycle == fireFrame)
                {
                    int shotKind = enemy.Kind switch { 4 => 5, 5 => 7, 6 => 6, 7 => 2, _ => 0 };
                    double shotSpeed = enemy.Kind switch { 4 => 2.35, 6 => 2.55, 7 => 2.15, _ => 1.85 };
                    FireEnemyShot(enemy.X, enemy.Y + enemy.Radius, shotKind, shotSpeed);
                }
            }

            bool removed = false;
            for (int s = _shots.Count - 1; s >= 0; s--)
            {
                Shot shot = _shots[s];
                if (Math.Abs(shot.X - enemy.X) <= enemy.Radius + 3 && Math.Abs(shot.Y - enemy.Y) <= enemy.Radius + 3)
                {
                    enemy.Health -= shot.Power;
                    _shots.RemoveAt(s);
                    if (enemy.Health <= 0)
                    {
                        _score += enemy.Radius * 10;
                        _enemies.RemoveAt(i);
                        _audio?.Trigger(StormaktSound.EnemyExplosion);
                        removed = true;
                    }
                    break;
                }
            }
            if (removed)
            {
                continue;
            }

            if (Math.Abs(_shipX - enemy.X) < enemy.Radius + 8 && Math.Abs(_shipY - enemy.Y) < enemy.Radius + 8)
            {
                _enemies.RemoveAt(i);
                DamageShip();
                continue;
            }

            if (enemy.Y > _height + 20)
            {
                _enemies.RemoveAt(i);
            }
            else
            {
                _enemies[i] = enemy;
            }
        }
    }

    private GroundTarget? FindActiveBridge(int group)
    {
        foreach (GroundTarget target in _groundTargets)
        {
            if (target.Group == group && target.Type == GroundTargetType.BridgeSpan && target.CollapseFrames == 0)
            {
                return target;
            }
        }
        return null;
    }

    private void SpawnEnemies()
    {
        if (_levelId == 4) return;
        int endFrame = _levelId switch { 1 => 2_700, 2 => FlythroughFrames, _ => BossArrivalFrame };
        if (_missionFrame >= endFrame)
        {
            return;
        }
        int timelineFrame = _missionFrame;
        ReadOnlySpan<EnemyWave> waves = _levelId switch
        {
            1 => SkanskaEnemyWaves,
            2 => OresundEnemyWaves,
            _ => EnemyWaves,
        };
        foreach (EnemyWave wave in waves)
        {
            if (timelineFrame < wave.StartFrame || timelineFrame >= wave.EndFrame ||
                (timelineFrame - wave.StartFrame) % wave.IntervalFrames != 0)
            {
                continue;
            }

            int volley = (timelineFrame - wave.StartFrame) / wave.IntervalFrames;
            SpawnFormation(wave, volley);
        }
    }

    private void SpawnFormation(EnemyWave wave, int volley)
    {
        int centerSpan = Math.Max(1, _width - 124);
        int center = 62 + ((volley * 71 + wave.Kind * 43) % centerSpan);
        int radius = wave.Kind == 2 ? 12 : wave.Kind is 1 or 5 or 7 ? 10 : 8;
        int speed = wave.Kind is 2 or 5 ? 1 : 2;
        int health = wave.Kind == 2 ? 8 : wave.Kind is 1 or 5 or 7 ? 6 : 4;
        uint color = wave.Kind switch
        {
            0 => 0xffa71930,
            1 => 0xffc51f35,
            4 => 0xff2e4939,
            5 => 0xff6f4a32,
            7 => 0xff8f2635,
            _ => 0xff7f1727,
        };
        for (int index = 0; index < wave.Count; index++)
        {
            int offset = (index - ((wave.Count - 1) / 2)) * 28;
            int y = -radius - (Math.Abs(index - wave.Count / 2) * 12);
            double phase = ((volley * 17 + index * 29 + wave.Kind * 11) % 100) * Math.PI / 50.0;
            _enemies.Add(new Enemy(
                Math.Clamp(center + offset, 20, _width - 20), y, speed, radius, health, color, wave.Kind, phase,
                wave.Kind is 4 or 5 or 7 ? volley * 31 + index * 47 : 0, 0, false));
        }
    }

    private void FireEnemyShot(int x, int y, int kind, double speed)
    {
        double dx = _shipX - x;
        double dy = _shipY - y;
        double length = Math.Max(1.0, Math.Sqrt(dx * dx + dy * dy));
        _enemyShots.Add(new EnemyShot(x, y, dx / length * speed, dy / length * speed, kind));
        _audio?.Trigger(_levelId == 2 && kind == 2
            ? StormaktSound.OresundGuardShot
            : StormaktSound.TwinCannon);
    }

    private void SpawnGroundEncounters()
    {
        if (_levelId == 1)
        {
            if (_missionFrame is 900 or 2_100 or 3_000)
            {
                int margin = Math.Min(64, Math.Max(28, _width / 5));
                int x = _missionFrame == 2_100 ? _width - margin : margin;
                _groundTargets.Add(new GroundTarget(
                    x, -24, GroundTargetType.SignalBeacon, 10, _missionFrame, 0, true, 0));
            }
            return;
        }
        if (_levelId != 0)
        {
            return;
        }
        if (_missionFrame >= BossArrivalFrame)
        {
            return;
        }
        int timelineFrame = _missionFrame;
        if (timelineFrame is not (720 or 1_920 or 2_760))
        {
            return;
        }

        bool left = timelineFrame != 1_920;
        int group = _missionFrame * 2;
        SpawnBridgeGroup(left ? 52 : _width - 52, left, group);
        if (timelineFrame == 2_760)
        {
            SpawnBridgeGroup(_width - 52, false, group + 1);
        }
    }

    private void SpawnBridgeGroup(int x, bool left, int group)
    {
        _groundTargets.Add(new GroundTarget(x, -22, GroundTargetType.BridgeSpan, 24, group, 0, true, 0));
        _groundTargets.Add(new GroundTarget(x, -29, GroundTargetType.Turret, 16, group, -48, true, 0));
        _groundTargets.Add(new GroundTarget(x + (left ? 25 : -25), -13, GroundTargetType.EnergyNode, 7, group, 0, true, 0));
        _enemies.Add(new Enemy(x - 19, -54, 0, 11, 8, 0xff7f1727, 3, 0.0, group, -19, false));
        _enemies.Add(new Enemy(x + 19, -58, 0, 11, 8, 0xff7f1727, 3, Math.PI, group, 19, false));
    }

    private void StepStars()
    {
        for (int i = 0; i < _stars.Length; i++)
        {
            Star star = _stars[i];
            star = star with { Y = star.Y + star.Speed };
            if (star.Y >= _height)
            {
                star = star with { X = _random.Next(_width), Y = 0, Speed = 1 + _random.Next(3), Brightness = _random.Next(50, 180) };
            }
            _stars[i] = star;
        }
    }

    private void DrawDungeon(uint[] frame)
    {
        DungeonState dungeon = _dungeon!;
        if (dungeon.EpilogueAge > 0)
        {
            DrawDungeonEpilogue(frame, dungeon);
            return;
        }
        DrawRect(frame, 0, 0, _width, _height, 0xff080b0a);
        string floorName = dungeon.Depth == 4 ? "dungeon_temple_floor" :
            dungeon.Depth >= 3 ? "dungeon_cursed_floor" : "dungeon_floor_wet";
        if (_sprites?.TryGet(floorName, out Sprite floor) == true)
        {
            int startX = -(dungeon.CameraX % floor.Width);
            int startY = 18 - (dungeon.CameraY % floor.Height);
            for (int y = startY; y < _height; y += floor.Height)
            for (int x = startX; x < _width; x += floor.Width)
                DrawSprite(frame, floor, x, y);
        }
        if (dungeon.Depth == 1)
        {
            DrawDungeonSprite(frame, dungeon, "dungeon_wall_timber", 105, 67);
            DrawDungeonSprite(frame, dungeon, "dungeon_wall_timber", 205, 67);
            DrawDungeonSprite(frame, dungeon, "dungeon_wall_corner", 280, 144);
            string doorSprite = dungeon.DoorReady ? "dungeon_wood_door_broken" :
                dungeon.DoorHealth <= 1 ? "dungeon_wood_door_damaged" : "dungeon_wood_door";
            DrawDungeonSprite(frame, dungeon, doorSprite, 650, 218);
            DrawDungeonSprite(frame, dungeon, "dungeon_rails", 380, 360);
            DrawDungeonSprite(frame, dungeon, "dungeon_chain_lift", 88, 228);
            DrawDungeonSprite(frame, dungeon, "dungeon_supply", 470, 300);
            DrawDungeonSprite(frame, dungeon, "dungeon_descent_pit", 598, 126);
            foreach (DungeonChest chest in dungeon.Chests.Where(chest => chest.Depth == 1))
            {
                int chestY = (int)Math.Round(chest.Y) - (chest.OpenAge is > 0 and < 12 ? chest.OpenAge % 3 : 0);
                DrawDungeonSprite(frame, dungeon, chest.Open ? "dungeon_chest_open" : "dungeon_chest_closed",
                    (int)Math.Round(chest.X), chestY);
            }
        }
        else if (dungeon.Depth == 2)
        {
            DrawDungeonSprite(frame, dungeon, "dungeon_wood_door_broken", 60, 410);
            foreach ((int x, int y) in new[] { (285, 175), (285, 245), (535, 470), (535, 610),
                (795, 165), (795, 310), (1030, 545), (1030, 675) })
                DrawDungeonSprite(frame, dungeon, "dungeon_wall_timber", x, y);
            for (int index = 0; index < DungeonSilverVents.Length; index++)
            {
                (int x, int y) = DungeonSilverVents[index];
                DrawDungeonSprite(frame, dungeon, "dungeon_silver_vent", x, y);
                int cycle = (dungeon.Age + index * 43) % 180;
                if (_sprites?.TryGet("dungeon_silver_mist", out Sprite vapor) == true && cycle is >= 30 and < 102)
                {
                    int alpha = cycle < 54 ? 70 + (cycle - 30) * 5 : cycle < 84 ? 210 : 210 - (cycle - 84) * 11;
                    DrawSpriteAlpha(frame, vapor, x - dungeon.CameraX - vapor.Width / 2,
                        y - dungeon.CameraY - vapor.Height / 2 - 7, (uint)Math.Clamp(alpha, 40, 220));
                }
            }
            foreach ((int x, int y) in new[] { (355, 555), (680, 180), (910, 520), (1180, 315) })
                DrawDungeonSprite(frame, dungeon, "dungeon_silver_mist", x, y);
            foreach (DungeonChest chest in dungeon.Chests.Where(chest => chest.Depth == 2))
            {
                int chestY = (int)Math.Round(chest.Y) - (chest.OpenAge is > 0 and < 12 ? chest.OpenAge % 3 : 0);
                DrawDungeonSprite(frame, dungeon, chest.Open ? "dungeon_chest_open" : "dungeon_chest_closed",
                    (int)Math.Round(chest.X), chestY);
            }
            DrawDungeonSprite(frame, dungeon,
                dungeon.DepthThreeOpen ? "dungeon_gruva3_portal" : "dungeon_gruva3_wall", 1190, 390);
        }
        else if (dungeon.Depth == 3)
        {
            DrawDungeonSprite(frame, dungeon, "dungeon_gruva3_portal", 60, 240);
            foreach ((int x, int y) in DungeonBlackWaters) DrawDungeonSprite(frame, dungeon, "dungeon_black_water", x, y);
            foreach ((int x, int y) in DungeonHolyShrines) DrawDungeonSprite(frame, dungeon, "dungeon_holy_shrine", x, y);
            foreach ((int x, int y) in new[] { (300, 120), (610, 410), (850, 180), (1080, 650) })
                DrawDungeonSprite(frame, dungeon, "dungeon_runic_arch", x, y);
            foreach ((int x, int y) in new[] { (260, 650), (700, 250), (1010, 580), (1220, 210) })
                DrawDungeonSprite(frame, dungeon, "dungeon_twisted_silver", x, y);
            foreach ((int x, int y) in new[] { (450, 720), (820, 120), (1140, 730) })
                DrawDungeonSprite(frame, dungeon, "dungeon_side_chamber", x, y);
            foreach ((int x, int y) in new[] { (390, 520), (930, 430), (1180, 120) })
                DrawDungeonSprite(frame, dungeon, "dungeon_lore_stele", x, y);
            foreach (DungeonChest chest in dungeon.Chests.Where(chest => chest.Depth == 3))
                DrawDungeonSprite(frame, dungeon, chest.Open ? "dungeon_chest_open" : "dungeon_cursed_chest",
                    (int)chest.X, (int)chest.Y);
            if (dungeon.TempleOpen)
            {
                DrawDungeonSprite(frame, dungeon, "dungeon_temple_stairs", 1320, 450);
                int templeX = 1320 - dungeon.CameraX;
                int templeY = 450 - dungeon.CameraY;
                DrawCircleOutline(frame, templeX, templeY + 8, 42 + dungeon.Age / 10 % 3,
                    dungeon.Age / 8 % 2 == 0 ? 0xff73b8d0 : 0xffffd66b);
                DrawText(frame, Math.Clamp(templeX - 39, 4, _width - 82),
                    Math.Max(52, templeY - 58), "TEMPELINGÅNG", 0xffffd66b);
            }
        }
        else
        {
            DrawDungeonSprite(frame, dungeon, "dungeon_temple_stairs", 60, 250);
            foreach ((int x, int y) in DungeonTempleWaters)
                DrawDungeonSprite(frame, dungeon, "dungeon_black_water", x, y);
            foreach ((int x, int y) in DungeonTempleShrines)
                DrawDungeonSprite(frame, dungeon,
                    x >= 1500 ? "dungeon_temple_altar" : "dungeon_holy_shrine", x, y);
            foreach ((int x, int y) in new[] { (455, 360), (810, 500), (1050, 275) })
                DrawDungeonSprite(frame, dungeon, "dungeon_runic_arch", x, y);
            foreach ((int x, int y) in new[] { (300, 650), (700, 110), (1110, 600) })
                DrawDungeonSprite(frame, dungeon, "dungeon_twisted_silver", x, y);
            foreach ((int x, int y) in new[] { (520, 680), (900, 105) })
                DrawDungeonSprite(frame, dungeon, "dungeon_side_chamber", x, y);
            foreach ((int x, int y) in DungeonTempleGuardianStatues)
                DrawDungeonSprite(frame, dungeon, "dungeon_temple_guardian", x, y);
            foreach ((int x, int y) in DungeonTempleClosedSarcophagi)
                DrawDungeonSprite(frame, dungeon, "dungeon_temple_sarc_closed", x, y);
            foreach ((int x, int y) in DungeonTempleOpenSarcophagi)
                DrawDungeonSprite(frame, dungeon, "dungeon_temple_sarc_open", x, y);
            int secondRuneProgress = DungeonSecondRuneProgress(dungeon);
            for (int index = 0; index < DungeonSecondTempleRunes.Length; index++)
            {
                (int x, int y) = DungeonSecondTempleRunes[index];
                DrawDungeonSprite(frame, dungeon, "dungeon_temple_guardian", x, y);
                DrawSecondTempleRuneMarker(frame, dungeon, x, y, index, index < secondRuneProgress);
            }
            int thirdVerseProgress = DungeonThirdVerseProgress(dungeon);
            for (int index = 0; index < DungeonThirdTempleSteles.Length; index++)
            {
                (int x, int y) = DungeonThirdTempleSteles[index];
                DrawDungeonSprite(frame, dungeon, "dungeon_lore_stele", x, y);
                DrawThirdTempleVerseMarker(frame, dungeon, x, y, index, index < thirdVerseProgress);
            }
            bool fogdeRescued = (dungeon.LoreMask & DungeonFogdeRescuedMask) != 0;
            if (!fogdeRescued)
                DrawDungeonSprite(frame, dungeon, "dk_silver_fogde_death", 1850, 185);
            else if (_sprites?.TryGet("dk_silver_fogde_idle", out Sprite rescuedFogde) == true)
            {
                int fogdeWidth = rescuedFogde.Width * 4 / 5;
                int fogdeHeight = rescuedFogde.Height * 4 / 5;
                int fogdeX = 1905 - dungeon.CameraX;
                int fogdeY = 220 - dungeon.CameraY;
                DrawSpriteScaled(frame, rescuedFogde, fogdeX - fogdeWidth / 2, fogdeY - fogdeHeight / 2,
                    fogdeWidth, fogdeHeight);
                DrawText(frame, fogdeX - 17, fogdeY - fogdeHeight / 2 - 9, "FOGDE", 0xff9bd4dc);
            }
            foreach (DungeonChest chest in dungeon.Chests.Where(chest => chest.Depth == 4))
                DrawDungeonSprite(frame, dungeon, chest.Open ? "dungeon_chest_open" : "dungeon_cursed_chest",
                    (int)chest.X, (int)chest.Y);
            bool shadowDefeated = dungeon.Enemies.Any(enemy => enemy.Depth == 4 &&
                enemy.Type == DungeonEnemyType.LemminkainenShadow && enemy.State == DungeonEnemyState.Dead);
            DrawDungeonSprite(frame, dungeon, shadowDefeated ? "dungeon_temple_gate_open" : "dungeon_temple_gate_closed",
                1140, 380);
            bool firstSigilActive = (dungeon.LoreMask & DungeonFirstSigilMask) != 0;
            DrawDungeonSprite(frame, dungeon, firstSigilActive ? "dungeon_temple_gate_open" : "dungeon_temple_gate_closed",
                1705, 380);
            bool secondSigilActive = (dungeon.LoreMask & DungeonSecondSigilMask) != 0;
            DrawDungeonSprite(frame, dungeon, secondSigilActive ? "dungeon_temple_gate_open" : "dungeon_temple_gate_closed",
                2385, 380);
            bool thirdSigilActive = (dungeon.LoreMask & DungeonThirdSigilMask) != 0;
            DrawDungeonSprite(frame, dungeon, thirdSigilActive ? "dungeon_temple_gate_open" : "dungeon_temple_gate_closed",
                3150, 380);
            bool swanDefeated = (dungeon.LoreMask & DungeonSwanDefeatedMask) != 0;
            bool louhiStarted = (dungeon.LoreMask & DungeonLouhiStartedMask) != 0;
            bool louhiDefeated = (dungeon.LoreMask & DungeonLouhiPhaseThreeMask) != 0;
            bool louhiGateSealed = louhiStarted && !louhiDefeated && dungeon.KarlX >= 3990;
            DrawDungeonSprite(frame, dungeon, swanDefeated ? "dungeon_temple_gate_open" : "dungeon_temple_gate_closed", 3550, 380);
            if (!firstSigilActive) DrawDungeonTempleSeal(frame, dungeon, 1705, "FÖRSTA SIGILLET");
            if (!secondSigilActive) DrawDungeonTempleSeal(frame, dungeon, 2385, "ANDRA SIGILLET");
            if (!thirdSigilActive) DrawDungeonTempleSeal(frame, dungeon, 3150, "TREDJE SIGILLET");
            if (!swanDefeated) DrawDungeonTempleSeal(frame, dungeon, 3550, "SVANENS SIGILL");
            int sigilX = 1580 - dungeon.CameraX;
            int sigilY = 380 - dungeon.CameraY;
            DrawCircleOutline(frame, sigilX, sigilY, firstSigilActive ? 34 : 27,
                firstSigilActive ? 0xffffd66b : 0xff73b8d0);
            int secondSigilX = 2280 - dungeon.CameraX;
            int secondSigilY = 380 - dungeon.CameraY;
            DrawCircleOutline(frame, secondSigilX, secondSigilY, secondSigilActive ? 34 : 27,
                secondSigilActive ? 0xffffd66b : secondRuneProgress >= 3 ? 0xffdce8f2 : 0xff5e7180);
            int thirdSigilX = 3030 - dungeon.CameraX;
            int thirdSigilY = 380 - dungeon.CameraY;
            DrawCircleOutline(frame, thirdSigilX, thirdSigilY, thirdSigilActive ? 34 : 27,
                thirdSigilActive ? 0xffffd66b : thirdVerseProgress >= 3 ? 0xffdce8f2 : 0xff5e7180);
            bool swanRevealed = (dungeon.LoreMask & DungeonSwanRevealedMask) != 0;
            DrawDungeonSwanEncounter(frame, dungeon, swanRevealed, swanDefeated);
            foreach ((int x, int y) in DungeonLouhiProcessionStatues)
                DrawDungeonSprite(frame, dungeon, "dungeon_temple_guardian", x, y);
            foreach ((int x, int y) in DungeonLouhiProcessionSarcophagi)
                DrawDungeonSprite(frame, dungeon, "dungeon_temple_sarc_closed", x, y);
            DrawDungeonSprite(frame, dungeon, "dungeon_runic_arch", 3890, 380);
            DrawDungeonSprite(frame, dungeon,
                louhiGateSealed ? "dungeon_temple_gate_closed" : "dungeon_temple_gate_open", 3970, 380);
            DrawDungeonSprite(frame, dungeon, "louhi_silver_altar", 4170, 380);
            if ((dungeon.LoreMask & DungeonLouhiPhaseThreeMask) != 0)
            {
                DrawDungeonSprite(frame, dungeon, "dungeon_chain_lift", 4380, 380);
                int liftX = 4380 - dungeon.CameraX;
                int liftY = 380 - dungeon.CameraY;
                DrawCircleOutline(frame, liftX, liftY + 20, 30 + dungeon.Age / 10 % 3,
                    dungeon.Age / 8 % 2 == 0 ? 0xff65c58a : 0xffb55c55);
            }
            DrawDungeonLouhiEncounter(frame, dungeon);
            if (!shadowDefeated)
            {
                int barrierX = 1165 - dungeon.CameraX;
                for (int worldY = 65; worldY < dungeon.RoomHeight - 35; worldY += 18)
                {
                    int y = worldY - dungeon.CameraY;
                    DrawLine(frame, barrierX, y, barrierX, y + 10,
                        (dungeon.Age / 6 + worldY / 18) % 2 == 0 ? 0xff73b8d0 : 0xffdce8f2);
                }
            }
        }

        foreach (DungeonSilverWave wave in dungeon.SilverWaves)
        {
            int waveX = (int)Math.Round(wave.X) - dungeon.CameraX;
            int waveY = (int)Math.Round(wave.Y) - dungeon.CameraY;
            uint color = wave.Age / 3 % 2 == 0 ? 0xffdce8f2 : 0xff73b8d0;
            DrawLine(frame, waveX - 7, waveY + 3, waveX, waveY - 5, color);
            DrawLine(frame, waveX, waveY - 5, waveX + 7, waveY + 3, color);
        }

        foreach (DungeonItem item in dungeon.Items.Where(candidate => candidate.OnGround))
        {
            DungeonItemDefinition definition = DungeonItemDefinitions[item.Definition];
            int itemX = (int)Math.Round(item.WorldX) - dungeon.CameraX;
            int itemY = (int)Math.Round(item.WorldY) - dungeon.CameraY;
            DrawCircleOutline(frame, itemX, itemY, 9, DungeonRarityColor(item.Rarity));
            if (_sprites?.TryGet(definition.Sprite, out Sprite icon) == true)
                DrawSprite(frame, icon, itemX - icon.Width / 2, itemY - icon.Height / 2);
        }

        foreach (DungeonEnemy enemy in dungeon.Enemies.Where(enemy => enemy.Depth == dungeon.Depth &&
            enemy.Type != DungeonEnemyType.TuonelaSwan &&
            enemy.Type != DungeonEnemyType.Louhi &&
            (enemy.Type != DungeonEnemyType.LemminkainenShadow || enemy.Phase != 0)).OrderBy(enemy => enemy.Y))
        {
            int enemyX = (int)Math.Round(enemy.X) - dungeon.CameraX;
            bool stepping = enemy.State == DungeonEnemyState.Approach && Math.Abs(enemy.VelocityX) + Math.Abs(enemy.VelocityY) > 0.08;
            int foot = (int)(enemy.GaitDistance / 5.5) & 3;
            int enemyY = (int)Math.Round(enemy.Y) - dungeon.CameraY - (stepping && foot is 1 or 3 ? 1 : 0);
            string prefix = enemy.Type switch
            {
                DungeonEnemyType.Pikeman => "dk_pikeman",
                DungeonEnemyType.SilverFogde => "dk_silver_fogde",
                DungeonEnemyType.UndeadMiner => "undead_miner",
                DungeonEnemyType.TuonelaGuard => "tuonela_guard",
                DungeonEnemyType.BlindShepherd => "blind_shepherd",
                DungeonEnemyType.LemminkainenShadow => "lemminkainen_shadow",
                _ => "dk_stormer",
            };
            string enemyName = enemy.State switch
            {
                DungeonEnemyState.Dead when enemy.Type == DungeonEnemyType.SilverFogde => "dk_silver_fogde_death",
                DungeonEnemyState.Dead when enemy.Type == DungeonEnemyType.BlindShepherd => "blind_shepherd_death",
                DungeonEnemyState.Dead when enemy.Type == DungeonEnemyType.LemminkainenShadow => "lemminkainen_shadow_hit",
                DungeonEnemyState.Telegraph when enemy.Type == DungeonEnemyType.LemminkainenShadow => "lemminkainen_shadow_split",
                DungeonEnemyState.Attack when enemy.Type == DungeonEnemyType.SilverFogde && enemy.SpecialKind > 0 => "dk_silver_fogde_slam",
                DungeonEnemyState.Attack or DungeonEnemyState.Telegraph => prefix + "_attack",
                DungeonEnemyState.Stagger or DungeonEnemyState.Dead => prefix + "_hit",
                DungeonEnemyState.Approach when enemy.Type == DungeonEnemyType.BlindShepherd => "blind_shepherd_idle",
                DungeonEnemyState.Approach => stepping && foot is 1 or 2 ? prefix + "_walk" : prefix + "_idle",
                _ => prefix + "_idle",
            };
            if (enemy.State == DungeonEnemyState.Telegraph)
                DrawCircleOutline(frame, enemyX, enemyY - 4,
                    enemy.Type switch { DungeonEnemyType.Pikeman => 22, DungeonEnemyType.SilverFogde => 29, _ => 17 },
                    enemy.StateAge / 4 % 2 == 0 ? 0xffffc45c : 0xffb92f3f);
            if (_sprites?.TryGet(enemyName, out Sprite enemySprite) == true)
            {
                int drawX = enemyX - enemySprite.Width / 2;
                int drawY = enemyY - enemySprite.Height + 10;
                if (enemy.FacingLeft) DrawSpriteFlippedX(frame, enemySprite, drawX, drawY);
                else DrawSprite(frame, enemySprite, drawX, drawY);
            }
            if (enemy.Health > 0 && enemy.Health < enemy.MaxHealth)
            {
                DrawRect(frame, enemyX - 15, enemyY - 36, 30, 3, 0xff26161a);
                DrawRect(frame, enemyX - 15, enemyY - 36, 30 * enemy.Health / enemy.MaxHealth, 2, 0xffbf3348);
            }
        }

        DungeonEnemy? fogde = dungeon.Depth == 2
            ? dungeon.Enemies.FirstOrDefault(enemy => enemy.Type == DungeonEnemyType.SilverFogde &&
                enemy.State != DungeonEnemyState.Dead && DungeonZone(dungeon) == 3)
            : null;
        DungeonEnemy? shepherd = dungeon.Depth == 3
            ? dungeon.Enemies.FirstOrDefault(enemy => enemy.Type == DungeonEnemyType.BlindShepherd &&
                enemy.State != DungeonEnemyState.Dead && DungeonZone(dungeon) == 34)
            : null;
        DungeonEnemy? shadow = dungeon.Depth == 4
            ? dungeon.Enemies.FirstOrDefault(enemy => enemy.Type == DungeonEnemyType.LemminkainenShadow &&
                enemy.State != DungeonEnemyState.Dead && enemy.Phase != 0 && DungeonZone(dungeon) == 43)
            : null;
        DungeonEnemy? swanBoss = dungeon.Depth == 4
            ? dungeon.Enemies.FirstOrDefault(enemy => enemy.Type == DungeonEnemyType.TuonelaSwan &&
                enemy.State != DungeonEnemyState.Dead && DungeonZone(dungeon) == 48)
            : null;
        DungeonEnemy? louhiBoss = dungeon.Depth == 4
            ? dungeon.Enemies.FirstOrDefault(enemy => enemy.Type == DungeonEnemyType.Louhi &&
                enemy.Phase is 1 or 2 or 3 && enemy.State != DungeonEnemyState.Dead && DungeonZone(dungeon) == 49)
            : null;
        DungeonEnemy? activeBoss = fogde ?? shepherd ?? shadow ?? swanBoss ?? louhiBoss;
        if (activeBoss is not null)
        {
            int barWidth = Math.Min(220, _width - 100);
            int barX = (_width - barWidth) / 2;
            DrawRect(frame, barX, 20, barWidth, 27, 0xee0b0d10);
            string bossName = fogde is not null ? "DEN FÖRSILVRADE GRUVFOGDEN" :
                shepherd is not null ? "DEN BLINDE HERDEN" : shadow is not null ?
                "LEMMINKÄINENS SKUGGA" : swanBoss is not null ? "SVANEN I TUONELA" :
                louhiBoss?.Phase == 3 ? "TEMPLETS MALMMODER" :
                louhiBoss?.Phase == 2 ? "JÄRNFÅGELN" : "LOUHI AV POHJOLA";
            DrawText(frame, barX + 8, 24, bossName, 0xffdce8f2);
            DrawRect(frame, barX + 2, 37, barWidth - 4, 7, 0xff20171d);
            DrawRect(frame, barX + 3, 38, (barWidth - 6) * activeBoss.Health / activeBoss.MaxHealth, 5, 0xffb7c7d6);
        }

        int karlX = (int)Math.Round(dungeon.KarlX) - dungeon.CameraX;
        int karlY = (int)Math.Round(dungeon.KarlY) - dungeon.CameraY;
        string karlName;
        // Drive the cycle from travelled world distance so speed changes do
        // not slide the feet. Roughly 34 px per full cycle matches Karl's
        // long, deliberate Carolean stride at both normal and Slow speed.
        int gait = (int)(dungeon.GaitDistance / 8.5) & 3;
        bool hammer = dungeon.Items.Any(item => item.Equipped == DungeonEquipmentSlot.MainHand && item.Definition == 3);
        string hammerDirection = dungeon.Facing switch
        {
            DungeonFacing.North => "n",
            DungeonFacing.East or DungeonFacing.West => "e",
            _ => "s",
        };
        string hammerIdle = $"karl_hammer_{hammerDirection}_idle";
        if (dungeon.HurtAge > 0) karlName = hammer ? hammerIdle : "karl_hit";
        else if (dungeon.Guarding) karlName = hammer ? hammerIdle :
            dungeon.Facing == DungeonFacing.North ? "karl_parry_n" : "karl_parry";
        else if (dungeon.AttackAge > 0 && hammer)
        {
            string phase = dungeon.AttackAge < 10 ? "windup" : dungeon.AttackAge < 19 ? "contact" : "recover";
            karlName = $"karl_hammer_{hammerDirection}_{phase}";
        }
        else if (dungeon.AttackAge > 0 && dungeon.Facing is DungeonFacing.East or DungeonFacing.West)
            karlName = dungeon.AttackAge < 9 ? "karl_slash_e_windup" : "karl_slash_e_contact";
        else if (dungeon.AttackAge > 0 && dungeon.Facing == DungeonFacing.North)
            karlName = dungeon.AttackAge switch
            {
                < 8 => "karl_slash_n_windup", < 13 => "karl_slash_n_contact", _ => "karl_slash_n_follow",
            };
        else if (dungeon.AttackAge > 0) karlName = dungeon.AttackAge switch
        {
            < 8 => "karl_slash_windup", < 13 => "karl_slash_contact", _ => "karl_slash_follow",
        };
        else if (dungeon.Age < 150) karlName = dungeon.Age < 95 ? "dungeon_karl_kneel" : "dungeon_karl_s_idle";
        else if (hammer && !dungeon.Moving) karlName = hammerIdle;
        else if (hammer) karlName = gait is 0 or 2 ? hammerIdle : gait == 1
            ? $"karl_hammer_{hammerDirection}_walk_a"
            : $"karl_hammer_{hammerDirection}_walk_b";
        else if (dungeon.Facing == DungeonFacing.North) karlName = dungeon.Moving && gait is 1 or 3 ? "dungeon_karl_n_walk" : "dungeon_karl_n_idle";
        else if (dungeon.Facing is DungeonFacing.East or DungeonFacing.West) karlName = dungeon.Moving && gait is 1 or 3 ? "dungeon_karl_e_walk" : "dungeon_karl_e_idle";
        else karlName = !dungeon.Moving || gait is 0 or 2 ? "dungeon_karl_s_idle" :
            gait == 1 ? "dungeon_karl_s_walk_a" : "dungeon_karl_s_walk_b";
        if (_sprites?.TryGet(karlName, out Sprite karl) == true)
        {
            int drawX = karlX - karl.Width / 2;
            // Combat cells include weapon arcs and impact debris below or
            // around the body. Anchor the boots, not the alpha bounds, so
            // Karl stays planted while his coat is free to flare in the pose.
            int footAnchor = karlName switch
            {
                "karl_slash_windup" or "karl_slash_contact" or "karl_slash_follow" or "karl_parry" => 20,
                "karl_slash_e_windup" or "karl_slash_e_contact" => 22,
                "karl_slash_n_windup" or "karl_slash_n_contact" or "karl_slash_n_follow" or "karl_parry_n" => 16,
                "karl_hammer_s_contact" or "karl_hammer_n_contact" or "karl_hammer_e_contact" => 19,
                "karl_hit" => 25,
                _ => 12,
            };
            int drawY = karlY - karl.Height + footAnchor;
            if (dungeon.Facing == DungeonFacing.West) DrawSpriteFlippedX(frame, karl, drawX, drawY);
            else DrawSprite(frame, karl, drawX, drawY);
        }

        if (dungeon.CollapseAge > 0) DrawDungeonCollapseOverlay(frame, dungeon.CollapseAge);
        DrawRect(frame, 0, 0, _width, 18, 0xee080d12);
        DrawText(frame, 6, 5, dungeon.Depth switch
        {
            1 => "GRUVA I  ÖVERGIVNA ORTEN",
            2 => "GRUVA II  SILVERÅNGORNA",
            3 => "GRUVA III  DEN FÖRBANNADE GRUVAN",
            _ => "GRUVA IV  LEMMINKÄINENS TEMPEL",
        }, 0xffffd66b);
        DrawText(frame, _width - 78, 5, "AUTOSPAR", 0xff65c58a);
        DrawDungeonHealth(frame, dungeon);
        DrawDungeonPotionBelt(frame, dungeon);
        if (dungeon.Depth == 3)
        {
            int curseY = _bossRadioCard is not null ? 92 : activeBoss is null ? 22 : 52;
            DrawText(frame, 108, curseY, "FÖRBANNELSE", 0xffc589ff);
            DrawRect(frame, 108, curseY + 10, 84, 6, 0xff17111d);
            DrawRect(frame, 110, curseY + 12, 80 * dungeon.Curse / 100, 2,
                dungeon.Curse >= 80 ? 0xffff6b62 : 0xff9867c5);
        }
        int experienceY = activeBoss is null ? 22 : 49;
        int experienceX = _width - 104;
        DrawText(frame, experienceX, experienceY, $"NIVÅ {dungeon.Level:00}", 0xffffd66b);
        DrawRect(frame, experienceX + 47, experienceY + 1, 52, 5, 0xff121923);
        DrawRect(frame, experienceX + 48, experienceY + 2,
            50 * dungeon.Experience / Math.Max(1, dungeon.Level * 100), 3, 0xff73b8d0);
        DrawRect(frame, 0, _height - 14, _width, 14, 0xee080d12);
        string objective = dungeon.Age < 150 ? "KARL SÄNKS NER" : "HÖGERKLICK HUGG  SLOW PARERA";
        if (dungeon.RoomClear)
            objective = dungeon.Depth == 1
                ? dungeon.DoorReady
                    ? _bossRadioCard is null ? "KLICKA PÅ GÅNGEN ELLER FIRE FÖR ATT GÅ NER" : "LYSSNA PÅ EBBA"
                    : "HUGG SÖNDER TRÄPORTEN I ÖSTER"
                : "GRUVA II SÄKRAD  SÖK I KISTORNA";
        if (dungeon.Depth == 3 && dungeon.TempleOpen) objective = "GÅ IN I DEN LYSANDE STENPORTEN I ÖSTER";
        if (dungeon.Depth == 4)
        {
            bool shadowDefeated = dungeon.Enemies.Any(enemy => enemy.Depth == 4 &&
                enemy.Type == DungeonEnemyType.LemminkainenShadow && enemy.State == DungeonEnemyState.Dead);
            bool shadowAwake = dungeon.Enemies.Any(enemy => enemy.Depth == 4 &&
                enemy.Type == DungeonEnemyType.LemminkainenShadow && enemy.Phase != 0 && enemy.State != DungeonEnemyState.Dead);
            bool courtyardClear = dungeon.Enemies.Where(enemy => enemy.Depth == 4 && enemy.Zone == 44)
                .All(enemy => enemy.State == DungeonEnemyState.Dead);
            bool firstSigilActive = (dungeon.LoreMask & DungeonFirstSigilMask) != 0;
            bool fogdeRescued = (dungeon.LoreMask & DungeonFogdeRescuedMask) != 0;
            bool fogdeSpoken = (dungeon.LoreMask & DungeonFogdeSpokenMask) != 0;
            bool secondCourtyardClear = DungeonSecondCourtyardClear(dungeon);
            int secondRuneProgress = DungeonSecondRuneProgress(dungeon);
            bool secondSigilActive = (dungeon.LoreMask & DungeonSecondSigilMask) != 0;
            int thirdVerseProgress = DungeonThirdVerseProgress(dungeon);
            bool thirdSigilActive = (dungeon.LoreMask & DungeonThirdSigilMask) != 0;
            bool swanRevealed = (dungeon.LoreMask & DungeonSwanRevealedMask) != 0;
            bool swanDefeated = (dungeon.LoreMask & DungeonSwanDefeatedMask) != 0;
            bool louhiStarted = (dungeon.LoreMask & DungeonLouhiStartedMask) != 0;
            bool louhiPhaseOne = (dungeon.LoreMask & DungeonLouhiPhaseOneMask) != 0;
            bool louhiPhaseTwo = (dungeon.LoreMask & DungeonLouhiPhaseTwoMask) != 0;
            bool louhiPhaseThree = (dungeon.LoreMask & DungeonLouhiPhaseThreeMask) != 0;
            bool louhiRelic = (dungeon.LoreMask & DungeonLouhiRelicMask) != 0;
            int collapseSeconds = Math.Max(0, (1500 - dungeon.CollapseAge) / 60);
            DungeonEnemy? louhi = dungeon.Enemies.FirstOrDefault(enemy =>
                enemy.Depth == 4 && enemy.Type == DungeonEnemyType.Louhi);
            DungeonEnemy? swan = dungeon.Enemies.FirstOrDefault(enemy =>
                enemy.Depth == 4 && enemy.Type == DungeonEnemyType.TuonelaSwan);
            bool heartOpen = swan is not null && swan.Phase == 3 && DungeonSwanVulnerable(swan);
            objective = louhiRelic ? $"TEMPLET RASAR  TILL HISSEN I ÖSTER  {collapseSeconds:00}" :
                louhiPhaseThree ? $"TEMPLET RASAR  TA RUNRINGEN  {collapseSeconds:00}" :
                louhiPhaseTwo && louhi?.SpecialAge > 0 ? "HJÄRTAT ÖPPET  BYT TILL VÄRJA" :
                louhiPhaseTwo ? "LYSSNA PÅ GRUVFOGDEN  KROSSA RÄTT HJÄRTA MED HAMMAREN" :
                louhiPhaseOne ? "JÄRNFÅGELN  PARERA VINGEN OCH DYKEN" :
                louhiStarted && dungeon.LouhiGreedAge > 0 ? "GIRIGHET  PARERA ELLER VÄNTA  ANFALL INTE" :
                louhiStarted ? "LÄS RUNORNA  PARERA STAVEN  BRYT LOUHI" :
                swanDefeated ? "FÖLJ PROCESSIONSGÅNGEN TILL SILVERALTARET" :
                swan?.State == DungeonEnemyState.Dead ? "SVANEN SJUNKER UNDER SVART VATTEN" :
                heartOpen ? "SILVERHJÄRTAT ÄR ÖPPET  SLÅ NU" :
                swan is { Phase: 3 } ? "UNDVIK DÖDSVÅGORNA  VÄNTA PÅ HJÄRTAT" :
                swanRevealed ? "BRYT SVANENS SILVERBAND" :
                thirdSigilActive ? "TREDJE SIGILLET VÄCKT  SVANENS PORT ÄR ÖPPEN" :
                secondSigilActive && dungeon.KarlX < 2440 ? "SLUTPORTEN ÄR ÖPPEN  LÄS DEN SISTA SIDAN" :
                secondSigilActive && thirdVerseProgress < 3 ?
                    $"VERSER SOL > SILVER > HJÄRTA  {thirdVerseProgress}/3" :
                secondSigilActive ? "STIG IN I TREDJE SIGILLET" :
                firstSigilActive && dungeon.KarlX < 1740 ? "ÖSTPORTEN ÄR ÖPPEN  SÖK FOGDEN" :
                firstSigilActive && !fogdeRescued ? "FRIGÖR GRUVFOGDEN UR SARKOFAGEN" :
                firstSigilActive && !fogdeSpoken ? "TALA MED GRUVFOGDEN" :
                firstSigilActive && !secondCourtyardClear ? "FÄLL VÄKTARNA FÖRE NÄSTA RUNA" :
                firstSigilActive && secondRuneProgress < 3 ?
                    $"RUNOR SOL > SVAN > KRONA  {secondRuneProgress}/3" :
                firstSigilActive ? "STIG IN I ANDRA SIGILLET" :
                shadowDefeated && dungeon.KarlX < 1200 ? "GÅ GENOM RUNPORTEN" :
                shadowDefeated && !courtyardClear ? "BRYT VAKTEN KRING FÖRSTA SIGILLET" :
                shadowDefeated ? "STIG IN I SIGILLET" :
                shadowAwake ? "ÖVERLEV LEMMINKÄINENS SKUGGA" : "FÖLJ RUNORNA MOT DEN FÖRSEGLADE PORTEN";
        }
        DrawText(frame, 7, _height - 10, objective, 0xffdce8f2);
        if (dungeon.PickupNoticeAge > 0)
        {
            int noticeWidth = dungeon.PickupNotice.Length * 6 + 10;
            int noticeX = Math.Max(4, (_width - noticeWidth) / 2);
            DrawRect(frame, noticeX, _height - 29, Math.Min(noticeWidth, _width - noticeX - 4), 13, 0xee201319);
            DrawText(frame, noticeX + 5, _height - 26, dungeon.PickupNotice, 0xffff9c8f);
        }
        if (_bossRadioCard is RadioCard radio && _bossRadioAge < radio.DurationFrames)
        {
            DrawRadioCard(frame, radio, _bossRadioAge);
        }
        if (dungeon.InventoryOpen) DrawDungeonInventory(frame, dungeon);
        if (dungeon.DeveloperNoticeAge > 0)
        {
            int noticeWidth = dungeon.DeveloperNotice.Length * 6 + 10;
            int noticeX = Math.Max(4, (_width - noticeWidth) / 2);
            DrawRect(frame, noticeX, 43, Math.Min(noticeWidth, _width - noticeX - 4), 13, 0xee0a1b24);
            DrawText(frame, noticeX + 5, 46, dungeon.DeveloperNotice, 0xff73b8d0);
        }
        if (dungeon.LevelPulse > 0 && dungeon.LevelPulse / 8 % 2 == 0)
            DrawText(frame, (_width - 72) / 2, 48, "NY NIVÅ!", 0xffffd66b);
        if (dungeon.DeathAge > 0)
        {
            int alpha = Math.Clamp(dungeon.DeathAge * 3, 40, 210);
            DrawRect(frame, 0, 18, _width, _height - 32, ((uint)alpha << 24) | 0x0026070c);
            DrawText(frame, (_width - 66) / 2, _height / 2, "KARL FALLER", 0xffffc4c4);
        }
    }

    private void DrawDungeonCollapseOverlay(uint[] frame, int age)
    {
        for (int index = 0; index < 9; index++)
        {
            int x = (index * 73 + age * (2 + index % 3)) % (_width + 30) - 15;
            int y = (index * 41 + age * (3 + index % 2)) % (_height + 50) - 25;
            int size = 2 + (index + age / 18) % 5;
            DrawRect(frame, x, y, size, size + 2, index % 3 == 0 ? 0xff8d4b43 : 0xff59635f);
        }
        for (int crack = 0; crack < 5; crack++)
        {
            int seed = age / 24 + crack * 37;
            int x = (seed * 53) % Math.Max(1, _width - 20) + 10;
            int y = (seed * 29) % Math.Max(1, _height - 70) + 34;
            uint color = crack % 2 == 0 ? 0xff8d4b43 : 0xff65a77c;
            DrawLine(frame, x, y, x + (crack % 2 == 0 ? 11 : -9), y + 13, color);
            DrawLine(frame, x + (crack % 2 == 0 ? 11 : -9), y + 13,
                x + (crack % 2 == 0 ? 4 : -15), y + 25, 0xff68736f);
        }
        if (age / 6 % 19 == 0) DrawRect(frame, 0, 18, _width, _height - 32, 0x552b1614);
    }

    private void DrawDungeonEpilogue(uint[] frame, DungeonState dungeon)
    {
        int age = dungeon.EpilogueAge;
        DrawRect(frame, 0, 0, _width, _height, 0xff080b0a);
        if (age < 150)
        {
            if (_sprites?.TryGet("dungeon_temple_floor", out Sprite stone) == true)
            {
                int drift = age * 2 % stone.Height;
                for (int y = -stone.Height + drift; y < _height; y += stone.Height)
                for (int x = 0; x < _width; x += stone.Width) DrawSprite(frame, stone, x, y);
            }
            DrawEpilogueSprite(frame, "dungeon_chain_lift", _width / 2, _height / 2 + 10);
            // Karl's boots stay on the platform instead of hanging below its
            // front edge while the shaft races past.
            DrawEpilogueSprite(frame, "dungeon_karl_s_idle", _width / 2, _height / 2 + 3);
            DrawLine(frame, _width / 2 - 30, 18, _width / 2 - 30, _height - 18, 0xff6f7775);
            DrawLine(frame, _width / 2 + 30, 18, _width / 2 + 30, _height - 18, 0xff6f7775);
            DrawText(frame, Math.Max(6, (_width - 126) / 2), 24, "GRUVHISSEN STIGER", 0xff9fd6a4);
            DrawDungeonCollapseOverlay(frame, age + 500);
            return;
        }

        if (_sprites?.TryGet("rts_forest_floor", out Sprite forest) == true)
        {
            for (int y = 18; y < _height; y += forest.Height)
            for (int x = 0; x < _width; x += forest.Width) DrawSprite(frame, forest, x, y);
        }
        DrawRect(frame, 0, 0, _width, 36, 0xff101923);
        DrawText(frame, 8, 8, age < 430 ? "SILVERKROPPENS YTA" : "MOT KARL CCLV", 0xffffd66b);
        // Stop the world scroll before the dismount. The moose then brakes at
        // a fixed world anchor instead of continuing to slide like scenery.
        int travel = Math.Max(0, Math.Min(age, 590) - 260) * 3;
        string[] trees = ["rts_spruce_tall", "rts_spruce_bent", "rts_pine_dead"];
        for (int index = 0; index < 7; index++)
        {
            int treeX = ((index * 79 - travel / 2) % (_width + 90) + _width + 90) % (_width + 90) - 45;
            DrawEpilogueSprite(frame, trees[index % trees.Length], treeX, 82 + index % 2 * 13);
        }

        if (age < 330)
        {
            int incomingMooseX = Math.Min(_width / 2 - 35, -55 + (age - 150) * 3);
            DrawEpilogueSprite(frame, DungeonEpilogueGallopFrame(age),
                incomingMooseX, _height - 56 + DungeonEpilogueGallopBob(age));
            DrawText(frame, 8, _height - 16, age < 225 ? "ÄLGEN MINNS VÄGEN" : "KARL HÅLLER FAST", 0xffdce8f2);
            DrawDungeonCollapseOverlay(frame, age + 700);
            return;
        }

        // The ship is already parked at the clearing. The moose crosses the
        // remaining ground to it; the ship must never slide over the rider.
        int shipX = _width - 50;
        int cruisingMooseX = _width / 2 - 35;
        int parkedMooseX = _width - 125;
        if (age < 620)
        {
            string rideSprite = age < 590 ? DungeonEpilogueGallopFrame(age) : "epilogue_karl_moose_ready";
            int rideBob = age < 590 ? DungeonEpilogueGallopBob(age) : 0;
            double approach = Math.Clamp((age - 430) / 160.0, 0.0, 1.0);
            approach = approach * approach * (3.0 - 2.0 * approach);
            int rideX = cruisingMooseX + (int)Math.Round((parkedMooseX - cruisingMooseX) * approach);
            if (age >= 430) DrawEpilogueShip(frame, shipX, _height - 82, 0);
            DrawEpilogueSprite(frame, rideSprite, rideX, _height - 56 + rideBob);
            DrawText(frame, 8, _height - 16, "RASET FÖLJER EFTER", 0xffdce8f2);
            if (age < 470) DrawDungeonCollapseOverlay(frame, age + 900);
            return;
        }

        int mooseX = parkedMooseX;
        int groundY = _height - 56;
        int lift = Math.Max(0, age - 790);
        string mooseSprite = age < 630 ? "epilogue_karl_moose_ready" : "epilogue_moose_riderless";
        DrawEpilogueShip(frame, shipX, _height - 82 - lift, lift);
        DrawEpilogueSprite(frame, mooseSprite, mooseX, groundY);
        if (age >= 630 && age < 790)
        {
            int dismountAge = age - 630;
            int karlX;
            int karlFootY;
            string karlSprite;
            if (dismountAge < 24)
            {
                double t = dismountAge / 23.0;
                karlX = mooseX + 3 + (int)Math.Round(t * 30);
                karlFootY = groundY - 28 + (int)Math.Round(t * 28 - Math.Sin(t * Math.PI) * 13);
                karlSprite = "dungeon_karl_e_idle";
            }
            else
            {
                int walkAge = dismountAge - 24;
                karlX = Math.Min(shipX - 30, mooseX + 33 + walkAge * 2);
                karlFootY = groundY;
                karlSprite = walkAge / 8 % 2 == 0 ? "dungeon_karl_e_idle" : "dungeon_karl_e_walk";
            }
            if (karlX < shipX - 32)
                DrawEpilogueSprite(frame, karlSprite, karlX, karlFootY);
        }
        if (age < 630)
            DrawText(frame, 8, _height - 16, "SKEPPET VÄNTAR", 0xffffd66b);
        else if (age < 670)
            DrawText(frame, 8, _height - 16, "KARL HOPPAR AV", 0xffffd66b);
        else if (age < 790)
            DrawText(frame, 8, _height - 16, "OMBORD PÅ KARL CCLV", 0xffffd66b);
        else if (age < 900)
            DrawText(frame, 8, _height - 16, "KURS MOT NÄSTA STORM", 0xff9bd4dc);
        else
        {
            DrawRect(frame, 20, _height / 2 - 37, _width - 40, 74, 0xe6080d12);
            DrawText(frame, Math.Max(26, (_width - 168) / 2), _height / 2 - 24,
                "LEMMINKÄINENS TEMPEL", 0xffffd66b);
            DrawText(frame, Math.Max(26, (_width - 126) / 2), _height / 2 - 6,
                "MALMMODERNS RING", 0xff9fd6a4);
            DrawText(frame, Math.Max(26, (_width - 90) / 2), _height / 2 + 16,
                "ELD FORTSÄTT", 0xffdce8f2);
        }
        if (age < 700) DrawDungeonCollapseOverlay(frame, age + 1100);
    }

    private static string DungeonEpilogueGallopFrame(int age) => (age / 6 % 3) switch
    {
        0 => "epilogue_karl_moose_gallop_a",
        1 => "epilogue_karl_moose_gallop_b",
        _ => "epilogue_karl_moose_gallop_c",
    };

    private static int DungeonEpilogueGallopBob(int age) => age / 6 % 3 == 1 ? -2 : 0;

    private void DrawEpilogueSprite(uint[] frame, string name, int centerX, int footY)
    {
        if (_sprites?.TryGet(name, out Sprite sprite) != true) return;
        DrawSprite(frame, sprite, centerX - sprite.Width / 2, footY - sprite.Height);
    }

    private void DrawEpilogueShip(uint[] frame, int centerX, int centerY, int thrust)
    {
        if (_sprites?.TryGet("player", out Sprite ship) == true)
            DrawSpriteScaled(frame, ship, centerX - 36, centerY - 44, 72, 88);
        if (thrust <= 0) return;
        int flame = 12 + thrust / 12 % 10;
        DrawLine(frame, centerX - 12, centerY + 36, centerX - 12, centerY + 36 + flame, 0xff73b8d0);
        DrawLine(frame, centerX + 12, centerY + 36, centerX + 12, centerY + 36 + flame, 0xffffd66b);
    }

