            DrawText(frame, panelX + 20, 98, "BROFOGDENS VREDE", 0xffff6b62);
        }
        else if (boss.Phase == 3 && boss.PhaseAge is >= 90 and < 180)
        {
            int panelX = (_width - 162) / 2;
            DrawRect(frame, panelX, 88, 162, 27, 0xff160b0e);
            DrawText(frame, panelX + 31, 98, "TIONDET BRISTER", 0xffff8a4a);
        }
    }

    private void DrawCopenhagenWorld(uint[] frame)
    {
        Clear(frame, 0xff03080f);
        CopenhagenWorldState? state = _copenhagenWorld;
        if (state is { GroundActive: true })
        {
            DrawCopenhagenGroundWorld(frame, state);
            return;
        }
        int age = state?.Age ?? 0;
        DrawCopenhagenBackground(frame, age);
        if (state is not null)
        {
            DrawCopenhagenBarrier(frame, state);
            DrawCopenhagenEyeWalls(frame, state);
            if (state.LandingActive) DrawCopenhagenLanding(frame, state);
            else if (state.SuperActive) DrawCopenhagenSuperfrigate(frame, state);
            else if (state.DuoActive) DrawCopenhagenDuo(frame, state);
            else if (state.DannebrogActive) DrawCopenhagenDannebrog(frame, state);
            else if (state.EyeActive) DrawCopenhagenEye(frame, state);
            else if (state.FrederikActive) DrawCopenhagenFrederik(frame, state);
            else if (state.AdmiraltyActive) DrawCopenhagenAdmiralty(frame, state);
            else if (state.GateActive) DrawCopenhagenGate(frame, state);
        }
        DrawShots(frame);
        DrawEnemyShots(frame);
        DrawShip(frame);
        DrawBorder(frame);
        DrawHud(frame);
        DrawLoadoutHud(frame);
        if (state is not null)
        {
            DrawCopenhagenGateHud(frame, state);
            DrawCopenhagenAdmiraltyHud(frame, state);
            DrawCopenhagenFrederikHud(frame, state);
            DrawCopenhagenEyeHud(frame, state);
            DrawCopenhagenDannebrogHud(frame, state);
            DrawCopenhagenDuoHud(frame, state);
            DrawCopenhagenSuperHud(frame, state);
            DrawCopenhagenLandingHud(frame, state);
            DrawCopenhagenCheckpointBanner(frame, state);
        }
        DrawCopenhagenMissionTitle(frame, age);
        DrawRadio(frame);
        DrawStageClear(frame);
        DrawPause(frame);
        if (_gameOver)
        {
            int x = (_width - 168) / 2;
            int y = (_height - 42) / 2;
            DrawRect(frame, x, y, 168, 42, 0xdd090b10);
            DrawText(frame, x + 16, y + 10, "FLOTTAN FÖLL", 0xffff6b7f);
            DrawText(frame, x + 22, y + 26, "START ÅTERKALLAR", 0xffffd66b);
        }
    }

    private void DrawCopenhagenBackground(uint[] frame, int age)
    {
        string backgroundName = _width <= 320 ? "copenhagen_background" : "copenhagen_background_wide";
        if (_sprites?.TryGet(backgroundName, out Sprite background) == true)
        {
            int scroll = (age / 3) % background.Height;
            DrawSprite(frame, background, 0, scroll - background.Height);
            DrawSprite(frame, background, 0, scroll);
            return;
        }
        for (int y = 17; y < _height - 12; y++)
        {
            int depth = y * 24 / Math.Max(1, _height);
            uint color = 0xff000000u | ((uint)(3 + depth / 5) << 16) |
                ((uint)(9 + depth / 2) << 8) | (uint)(16 + depth);
            DrawLine(frame, 0, y, _width - 1, y, color);
        }
        DrawStars(frame);

        int farScroll = age / 5;
        int horizon = 42 + farScroll % 74;
        for (int index = 0; index < 9; index++)
        {
            int x = index * (_width + 40) / 8 - 20;
            int height = 15 + Math.Abs(index * 17 + 9) % 28;
            int y = horizon - height / 2;
            DrawRect(frame, x - 8, y, 17, height, 0xff101923);
            FillTriangle(frame, x, y - 18, x - 7, y + 1, x + 7, y + 1, 0xff17212a);
            DrawLine(frame, x, y - 17, x, y + height, 0xff6b552f);
            if ((index & 1) == 0) PutPixel(frame, x + 3, y + 6, 0xffffd66b);
        }

        int ringY = 74 + age / 2 % Math.Max(80, _height + 70) - 70;
        DrawCircleOutline(frame, _width / 2, ringY, Math.Max(82, _width / 3), 0xff493c29);
        DrawCircleOutline(frame, _width / 2, ringY, Math.Max(75, _width / 3 - 7), 0xff1e3441);
        for (int spoke = 0; spoke < 8; spoke++)
        {
            double angle = spoke * Math.PI / 4.0 + age * 0.002;
            int x1 = _width / 2 + (int)Math.Round(Math.Cos(angle) * 75);
            int y1 = ringY + (int)Math.Round(Math.Sin(angle) * 35);
            int x2 = _width / 2 + (int)Math.Round(Math.Cos(angle) * 112);
            int y2 = ringY + (int)Math.Round(Math.Sin(angle) * 53);
            DrawLine(frame, x1, y1, x2, y2, spoke % 2 == 0 ? 0xff8a6b38 : 0xff344d5c);
        }

        int sealScroll = age % 96;
        for (int lane = 0; lane < 5; lane++)
        {
            int x = 24 + lane * Math.Max(1, (_width - 48) / 4);
            int y = (lane * 53 + sealScroll) % (_height + 50) - 25;
            DrawLine(frame, x - 13, y, x + 13, y, 0xff263744);
            DrawLine(frame, x, y - 7, x, y + 7, 0xff765139);
            PutPixel(frame, x, y, 0xff9bd4dc);
        }
    }

    private void DrawCopenhagenGate(uint[] frame, CopenhagenWorldState state)
    {
        (double centerXD, double centerYD) = CopenhagenGateCenter(state);
        int centerX = (int)Math.Round(centerXD);
        int centerY = (int)Math.Round(centerYD);
        uint ring = state.GateFallAge > 0 ? 0xff8f2635 : state.HitFlash > 0 ? 0xffffec9a : 0xffd6b25e;
        string ringName = state.GateFallAge > 0 ? "copenhagen_gate_ring_broken" : "copenhagen_gate_ring";
        Sprite gateRing = default;
        bool packedRing = _sprites is not null && _sprites.TryGet(ringName, out gateRing);
        if (packedRing)
        {
            DrawSprite(frame, gateRing, centerX - gateRing.Width / 2, centerY - gateRing.Height / 2);
            if (state.HitFlash > 0) DrawCircleOutline(frame, centerX, centerY, 72, ring);
        }
        else
        {
            DrawCircleOutline(frame, centerX, centerY, 72, ring);
            DrawCircleOutline(frame, centerX, centerY, 61, 0xff344d5c);
        }
        for (int node = 0; node < state.GateHealth.Length; node++)
        {
            (double nodeXD, double nodeYD) = CopenhagenGateNodePosition(state, node, centerXD, centerYD);
            int x = (int)Math.Round(nodeXD);
            int y = (int)Math.Round(nodeYD);
            DrawLine(frame, centerX, centerY, x, y, state.GateHealth[node] > 0 ? 0xff765139 : 0xff3b2026);
            if (state.GateHealth[node] <= 0)
            {
                DrawLine(frame, x - 10, y - 10, x + 10, y + 10, 0xff8f2635);
                DrawLine(frame, x + 10, y - 10, x - 10, y + 10, 0xff8f2635);
                continue;
            }
            uint crownColor = node switch { 0 => 0xff7fc7ff, 1 => 0xffff6b62, _ => 0xff77e6a0 };
            string nodeName = node switch
            {
                0 => "copenhagen_gate_node_blue",
                1 => "copenhagen_gate_node_red",
                _ => "copenhagen_gate_node_green",
            };
            if (_sprites?.TryGet(nodeName, out Sprite crownNode) == true)
                DrawSprite(frame, crownNode, x - crownNode.Width / 2, y - crownNode.Height / 2);
            else
            {
                FillCircle(frame, x, y, 13, 0xff17212a);
                DrawCircleOutline(frame, x, y, 14, crownColor);
                DrawCrown(frame, x - 4, y - 3, crownColor);
            }
            int healthWidth = 22 * state.GateHealth[node] / CopenhagenGateNodeMaxHealth;
            DrawRect(frame, x - 11, y + 17, 22, 3, 0xff291b20);
            DrawRect(frame, x - 11, y + 17, healthWidth, 3, crownColor);
            if (state.RepairFlash > 0 && state.RepairTarget == node)
            {
                DrawCircleOutline(frame, x, y, 18 + state.RepairFlash % 5, 0xffbdf8ff);
                DrawLine(frame, centerX, centerY, x, y, 0xff77e6a0);
            }
        }
        if (_sprites?.TryGet("copenhagen_gate_core", out Sprite gateCore) == true)
            DrawSprite(frame, gateCore, centerX - gateCore.Width / 2, centerY - gateCore.Height / 2);
        else
        {
            FillCircle(frame, centerX, centerY, 9, 0xff101820);
            DrawCrown(frame, centerX - 4, centerY - 3, 0xffffd66b);
        }
        if (state.GateFallAge > 0)
        {
            int burst = Math.Min(45, state.GateFallAge / 2);
            DrawCircleOutline(frame, centerX, centerY, 12 + burst, 0xffff8a4a);
            DrawCircleOutline(frame, centerX, centerY, 6 + burst * 2, 0xff8f2635);
        }
    }

    private void DrawCopenhagenBarrier(uint[] frame, CopenhagenWorldState state)
    {
        if (state.BarrierAge == 0) return;
        int y = (int)Math.Round(state.BarrierY);
        const int gapWidth = 66;
        uint edge = state.BarrierFlash > 0 ? 0xffffec9a : 0xff7fc7ff;
        DrawRect(frame, 0, y - 3, Math.Max(0, state.BarrierGapX - gapWidth / 2), 7, 0xff1b3448);
        DrawRect(frame, state.BarrierGapX + gapWidth / 2, y - 3,
            Math.Max(0, _width - state.BarrierGapX - gapWidth / 2), 7, 0xff1b3448);
        DrawLine(frame, 0, y - 4, state.BarrierGapX - gapWidth / 2, y - 4, edge);
        DrawLine(frame, state.BarrierGapX + gapWidth / 2, y - 4, _width - 1, y - 4, edge);
        DrawCrown(frame, state.BarrierGapX - gapWidth / 2 - 5, y - 3, 0xffffd66b);
        DrawCrown(frame, state.BarrierGapX + gapWidth / 2 + 1, y - 3, 0xffffd66b);
    }

    private void DrawCopenhagenGateHud(uint[] frame, CopenhagenWorldState state)
    {
        if (!state.GateActive || state.GateIntroAge < 45 || state.GateFallAge > 0) return;
        int alive = state.GateHealth.Count(health => health > 0);
        int total = state.GateHealth.Sum();
        int barWidth = Math.Min(184, _width - 96);
        int x = (_width - barWidth) / 2;
        DrawRect(frame, x, 21, barWidth, 13, 0xdd080d12);
        DrawRect(frame, x + 2, 23, (barWidth - 4) * total / (CopenhagenGateNodeMaxHealth * 3), 4, 0xffffd66b);
        DrawText(frame, x + 4, 28, $"TREKRONERS LÅS  {alive}/3", 0xffbdf8ff);
    }

    private void DrawCopenhagenAdmiralty(uint[] frame, CopenhagenWorldState state)
    {
        (double centerXD, double centerYD) = CopenhagenAdmiraltyCenter(state);
        int centerX = (int)Math.Round(centerXD);
        int centerY = (int)Math.Round(centerYD);
        uint outer = state.NoonFlash > 0 && (state.NoonFlash / 4 & 1) == 0 ? 0xffff6b62 : 0xffd6b25e;
        string clockName = state.AdmiraltyDeathAge > 0
            ? "cph_admiralty_clock_broken"
            : "cph_admiralty_clock";
        Sprite clock = default;
        bool packedClock = _sprites is not null && _sprites.TryGet(clockName, out clock);
        if (packedClock)
        {
            DrawSprite(frame, clock, centerX - clock.Width / 2, centerY - clock.Height / 2);
            if (state.NoonFlash > 0) DrawCircleOutline(frame, centerX, centerY, 104, outer);
        }
        else
        {
            DrawCircleOutline(frame, centerX, centerY, 108, outer);
            DrawCircleOutline(frame, centerX, centerY, 94, 0xff344d5c);
        }
        for (int hour = 0; hour < state.HourHealth.Length; hour++)
        {
            (double hourXD, double hourYD) = CopenhagenHourPosition(hour, centerXD, centerYD);
            int x = (int)Math.Round(hourXD);
            int y = (int)Math.Round(hourYD);
            bool broken = state.HourHealth[hour] <= 0;
            bool current = hour == state.CurrentHour;
            bool hit = state.HourHitFlash > 0 && state.LastHitHour == hour;
            uint color = broken ? 0xff263744 : hit ? 0xffffffff : current ? 0xffff8a4a :
                state.HourArmed[hour] ? 0xffff6b62 : 0xff9bd4dc;
            if (!packedClock) DrawLine(frame, centerX, centerY, x, y, broken ? 0xff202b33 : 0xff493c29);
            if (broken)
            {
                DrawLine(frame, x - 5, y - 5, x + 5, y + 5, 0xff315b42);
                DrawLine(frame, x + 5, y - 5, x - 5, y + 5, 0xff315b42);
            }
            else
            {
                FillCircle(frame, x, y, current ? 7 : 5, 0xff101820);
                DrawCircleOutline(frame, x, y, current ? 8 : 6, color);
                PutPixel(frame, x, y, color);
            }
        }

        int handHour = state.CurrentHour;
        (double handX, double handY) = CopenhagenHourPosition(handHour, centerXD, centerYD);
        DrawLine(frame, centerX, centerY, (int)Math.Round(handX), (int)Math.Round(handY), 0xffffd66b);
        double minuteAngle = -Math.PI / 2.0 + (state.AdmiraltyAge % 90) * Math.PI * 2.0 / 90.0;
        DrawLine(frame, centerX, centerY, centerX + (int)Math.Round(Math.Cos(minuteAngle) * 61),
            centerY + (int)Math.Round(Math.Sin(minuteAngle) * 30), 0xff7fc7ff);

        if (packedClock)
        {
            if (state.AdmiraltyHitFlash > 0)
                DrawCircleOutline(frame, centerX, centerY, 25 + state.AdmiraltyHitFlash % 3, 0xffffec9a);
        }
        else
        {
            uint core = state.AdmiraltyDeathAge > 0 ? 0xff8f2635 :
                state.AdmiraltyHitFlash > 0 ? 0xffffec9a : 0xff172536;
            FillCircle(frame, centerX, centerY, 22, core);
            DrawCircleOutline(frame, centerX, centerY, 24, 0xffffd66b);
            DrawCrown(frame, centerX - 4, centerY - 4, 0xffff8a4a);
            DrawLine(frame, centerX - 13, centerY + 9, centerX + 13, centerY + 9, 0xff9bd4dc);
        }
        if (state.AdmiraltyDeathAge > 0)
        {
            int burst = Math.Min(70, state.AdmiraltyDeathAge / 2);
            DrawCircleOutline(frame, centerX, centerY, 26 + burst, 0xffff8a4a);
            for (int hour = 0; hour < 12; hour += 2)
            {
                (double x, double y) = CopenhagenHourPosition(hour, centerXD, centerYD);
                DrawLine(frame, centerX, centerY, (int)x, (int)y, 0xff8f2635);
            }
        }
    }

    private void DrawCopenhagenAdmiraltyHud(uint[] frame, CopenhagenWorldState state)
    {
        if (!state.AdmiraltyActive || state.AdmiraltyAge < 45 || state.AdmiraltyDeathAge > 0) return;
        int barWidth = Math.Min(196, _width - 90);
        int x = (_width - barWidth) / 2;
        int safeHours = state.HourHealth.Count(health => health <= 0);
        DrawRect(frame, x, 21, barWidth, 14, 0xdd080d12);
        DrawRect(frame, x + 2, 23, (barWidth - 4) * state.AdmiraltyHealth / CopenhagenAdmiraltyMaxHealth, 4, 0xffff8a4a);
        DrawText(frame, x + 4, 28, $"AMIRALITETET  {state.CurrentHour + 1:00}  LUCKOR {safeHours}", 0xffbdf8ff);
    }

    private void DrawCopenhagenFrederik(uint[] frame, CopenhagenWorldState state)
    {
        (double centerXD, double centerYD) = CopenhagenFrederikCenter(state);
        int centerX = (int)Math.Round(centerXD);
        int centerY = (int)Math.Round(centerYD);
        int supportCount = Math.Clamp(Math.Max(1, state.IncomingFreedShips), 1, 3);
        if (state.FrederikPhase == 1)
        {
            for (int support = 0; support < supportCount; support++)
            {
                (double supportXD, double supportYD) = CopenhagenFrederikSupportPosition(support, supportCount);
                int supportX = (int)Math.Round(supportXD);
                int supportY = (int)Math.Round(supportYD);
                bool seized = (state.FrederikSeizedMask & (1 << support)) != 0;
                string supportName = seized ? "cph_detail_ally_seized" : "cph_detail_ally";
                if (_sprites?.TryGet(supportName, out Sprite supportShip) == true)
                    DrawSprite(frame, supportShip, supportX - supportShip.Width / 2, supportY - supportShip.Height / 2);
                else
                {
                    FillTriangle(frame, supportX, supportY - 10, supportX - 12, supportY + 8,
                        supportX + 12, supportY + 8, seized ? 0xff8f2635 : 0xff315b42);
                    DrawLine(frame, supportX - 9, supportY + 5, supportX + 9, supportY + 5,
                        seized ? 0xffff6b62 : 0xff77e6a0);
                    if (seized) DrawCrown(frame, supportX - 4, supportY - 1, 0xffffd66b);
                }
            }
            foreach (CopenhagenSeizureChain chain in state.FrederikChains)
            {
                if (chain.Health <= 0) continue;
                int tipX = (int)Math.Round(CopenhagenFrederikChainTipX(state, chain, centerXD));
                int tipY = (int)Math.Round(CopenhagenFrederikChainTipY(state, chain, centerYD));
                uint chainColor = chain.Completed ? 0xffff6b62 : 0xffd6b25e;
                if (_sprites?.TryGet("cph_fx_orange_link", out _) == true)
                    DrawCopenhagenEffectLink(frame, "cph_fx_orange_link", centerX, centerY + 22, tipX, tipY, chainColor);
                else
                {
                    DrawLine(frame, centerX, centerY + 22, tipX, tipY, chainColor);
                    for (int link = 1; link < 5; link++)
                    {
                        int x = centerX + (tipX - centerX) * link / 5;
                        int y = centerY + 22 + (tipY - centerY - 22) * link / 5;
                        FillCircle(frame, x, y, 2, chainColor);
                    }
                }
                if (!chain.Completed) DrawCircleOutline(frame, tipX, tipY, 8, 0xffbdf8ff);
            }
        }

        uint hull = state.FrederikDeathAge > 0 ? 0xff8f2635 :
            state.FrederikHitFlash > 0 ? 0xffffec9a : 0xff29343a;
        string frederikName = state.FrederikDeathAge > 0 ? "cph_frederik_broken" :
            state.FrederikPhase == 3 ? "cph_frederik_p3" : "cph_frederik_p1";
        Sprite frederik = default;
        bool packedFrederik = _sprites is not null && _sprites.TryGet(frederikName, out frederik);
        if (packedFrederik)
        {
            DrawSprite(frame, frederik, centerX - frederik.Width / 2, centerY - frederik.Height / 2);
            if (state.FrederikHitFlash > 0)
                DrawCircleOutline(frame, centerX, centerY, 47 + state.FrederikHitFlash % 3, hull);
        }
        else
        {
            FillTriangle(frame, centerX, centerY - 42, centerX - 78, centerY + 36, centerX + 78, centerY + 36, hull);
            DrawLine(frame, centerX - 74, centerY + 33, centerX + 74, centerY + 33, 0xffd6b25e);
            DrawLine(frame, centerX - 58, centerY + 18, centerX + 58, centerY + 18, 0xff765139);
            DrawRect(frame, centerX - 24, centerY - 22, 48, 36,
                state.FrederikPhase == 1 ? 0xff4b2530 : 0xff1b242b);
            FillTriangle(frame, centerX, centerY - 48, centerX - 20, centerY - 13,
                centerX + 20, centerY - 13, 0xff6b3a31);
            DrawCrown(frame, centerX - 4, centerY - 25, 0xffffd66b);
            for (int receipt = 0; receipt < 5; receipt++)
            {
                int x = centerX - 54 + receipt * 27;
                DrawRect(frame, x, centerY + 21, 13, 8, 0xffd8d1b9);
                DrawLine(frame, x + 2, centerY + 24, x + 10, centerY + 24, 0xff765139);
            }
        }

        if (state.FrederikPhase == 2)
        {
            DrawCopenhagenFrederikBlade(frame, state, false, centerXD, centerYD);
            DrawCopenhagenFrederikBlade(frame, state, true, centerXD, centerYD);
            DrawLine(frame, centerX - 22, centerY - 20, centerX + 22, centerY + 13, 0xff8f2635);
            DrawLine(frame, centerX + 22, centerY - 20, centerX - 22, centerY + 13, 0xff8f2635);
        }
        else if (state.FrederikPhase == 3)
        {
            for (int node = 0; node < state.FrederikRepairHealth.Length; node++)
            {
                int x = centerX + (node - 1) * 54;
                int y = centerY + 40;
                bool active = node == state.FrederikActiveRepairNode;
                bool broken = state.FrederikRepairHealth[node] <= 0;
                uint color = broken ? 0xff263744 : active ? 0xff77e6a0 : 0xff8f2635;
                if (!broken && _sprites?.TryGet("cph_detail_repair_node", out Sprite repairNode) == true)
                    DrawSprite(frame, repairNode, x - repairNode.Width / 2, y - repairNode.Height / 2);
                else
                {
                    FillCircle(frame, x, y, 9, 0xff101820);
                    DrawCircleOutline(frame, x, y, 11, color);
                    DrawText(frame, x - 3, y - 3, $"{node}", color);
                }
                if (active && !broken)
                {
                    int cycle = state.FrederikPhaseAge % 240;
                    DrawCircleOutline(frame, x, y, 14 + cycle / 30 % 5,
                        state.FrederikRepairFlash > 0 ? 0xffffffff : 0xffbdf8ff);
                    DrawLine(frame, x, y - 12, centerX, centerY, 0xff77e6a0);
                }
            }
        }

        if (state.FrederikDeathAge > 0)
        {
            int burst = Math.Min(92, state.FrederikDeathAge / 2);
            DrawCircleOutline(frame, centerX, centerY, 38 + burst, 0xffff8a4a);
            DrawCircleOutline(frame, centerX, centerY, 18 + burst / 2, 0xff8f2635);
        }
    }

    private void DrawCopenhagenFrederikBlade(
        uint[] frame, CopenhagenWorldState state, bool right, double centerX, double centerY)
    {
        int health = right ? state.FrederikRightBladeHealth : state.FrederikLeftBladeHealth;
        (double xD, double yD) = CopenhagenFrederikBladePosition(state, right, centerX, centerY);
        int x = (int)Math.Round(xD);
        int y = (int)Math.Round(yD);
        if (health <= 0)
        {
            DrawLine(frame, x - 13, y - 13, x + 13, y + 13, 0xff8f2635);
            return;
        }
        if (_sprites?.TryGet("cph_detail_blade", out Sprite blade) == true)
        {
            if (right) DrawSprite(frame, blade, x - blade.Width / 2, y - blade.Height / 2);
            else DrawSpriteFlippedX(frame, blade, x - blade.Width / 2, y - blade.Height / 2);
        }
        else
        {
            double side = right ? 1 : -1;
            FillTriangle(frame, x, y + 24, x - (int)(side * 10) - 7, y - 20,
                x - (int)(side * 10) + 7, y - 20, 0xffb7c7d6);
            DrawLine(frame, x, y + 23, x - (int)(side * 10), y - 20, 0xffffd66b);
        }
        DrawRect(frame, x - 10, y + 27, 20 * health / CopenhagenFrederikBladeHealth, 3, 0xffff8a4a);
    }

    private void DrawCopenhagenFrederikHud(uint[] frame, CopenhagenWorldState state)
    {
        if (!state.FrederikActive || state.FrederikAge < 45 || state.FrederikDeathAge > 0) return;
        int maximum = state.FrederikTestFixture ? 180 : CopenhagenFrederikMaxHealth;
        int barWidth = Math.Min(204, _width - 86);
        int x = (_width - barWidth) / 2;
        string phase = state.FrederikPhase switch { 1 => "BESLAG", 2 => "REGISTERBLAD", _ => "NOLLSTÄLLNING" };
        DrawRect(frame, x, 21, barWidth, 14, 0xdd080d12);
        DrawRect(frame, x + 2, 23, (barWidth - 4) * state.FrederikHealth / maximum, 4, 0xffff8a4a);
        DrawText(frame, x + 4, 28, $"FREDERIK NULL  {phase}", 0xffbdf8ff);
    }

    private void DrawCopenhagenEyeWalls(uint[] frame, CopenhagenWorldState state)
    {
        if (!state.EyeActive) return;
        foreach (CopenhagenTollWall wall in state.EyeWalls)
        {
            bool telegraph = wall.Age < 45;
            bool active = wall.Age is >= 45 and <= 130;
            if (!telegraph && !active) continue;
            uint color = telegraph ? ((wall.Age / 5 & 1) == 0 ? 0xff493c29 : 0xff765139) :
                wall.HitPlayer ? 0xff8f2635 : 0xff7fc7ff;
            if (wall.Vertical)
            {
                DrawLine(frame, wall.Coordinate, 17, wall.Coordinate, wall.Gap - 31, color);
                DrawLine(frame, wall.Coordinate, wall.Gap + 31, wall.Coordinate, _height - 13, color);
                if (active)
                {
                    DrawLine(frame, wall.Coordinate - 2, 17, wall.Coordinate - 2, wall.Gap - 31, 0xff1b3448);
                    DrawLine(frame, wall.Coordinate - 2, wall.Gap + 31, wall.Coordinate - 2, _height - 13, 0xff1b3448);
                }
            }
            else
            {
                DrawLine(frame, 0, wall.Coordinate, wall.Gap - 37, wall.Coordinate, color);
                DrawLine(frame, wall.Gap + 37, wall.Coordinate, _width - 1, wall.Coordinate, color);
                if (active)
                {
                    DrawLine(frame, 0, wall.Coordinate - 2, wall.Gap - 37, wall.Coordinate - 2, 0xff1b3448);
                    DrawLine(frame, wall.Gap + 37, wall.Coordinate - 2, _width - 1, wall.Coordinate - 2, 0xff1b3448);
                }
            }
        }
        if (state.EyePredictionFlash > 0)
        {
            int radius = 8 + state.EyePredictionFlash / 6;
            uint color = (state.EyePredictionFlash / 4 & 1) == 0 ? 0xffff6b62 : 0xffffd66b;
            DrawCircleOutline(frame, state.EyePredictedX, state.EyePredictedY, radius, color);
            DrawLine(frame, state.EyePredictedX - radius - 4, state.EyePredictedY,
                state.EyePredictedX + radius + 4, state.EyePredictedY, color);
            DrawLine(frame, state.EyePredictedX, state.EyePredictedY - radius - 4,
                state.EyePredictedX, state.EyePredictedY + radius + 4, color);
        }
    }

    private void DrawCopenhagenEye(uint[] frame, CopenhagenWorldState state)
    {
        (double centerXD, double centerYD) = CopenhagenEyeCenter(state);
        int centerX = (int)Math.Round(centerXD);
        int centerY = (int)Math.Round(centerYD);
        uint shell = state.EyeDeathAge > 0 ? 0xff8f2635 : state.EyeHitFlash > 0 ? 0xffffec9a : 0xff29343a;
        string eyeName = state.EyeDeathAge > 0 ? "cph_eye_broken" :
            state.EyePhase == 3 ? "cph_eye_p3" : "cph_eye_p1";
        Sprite eye = default;
        bool packedEye = _sprites is not null && _sprites.TryGet(eyeName, out eye);
        if (packedEye)
        {
            DrawSprite(frame, eye, centerX - eye.Width / 2, centerY - eye.Height / 2);
            if (state.EyeHitFlash > 0) DrawCircleOutline(frame, centerX, centerY, 35, shell);
        }
        else
        {
            FillTriangle(frame, centerX, centerY - 48, centerX - 88, centerY + 4, centerX, centerY + 50, shell);
            FillTriangle(frame, centerX, centerY - 48, centerX + 88, centerY + 4, centerX, centerY + 50, shell);
            DrawLine(frame, centerX - 84, centerY + 3, centerX, centerY - 45, 0xffd6b25e);
            DrawLine(frame, centerX, centerY - 45, centerX + 84, centerY + 3, 0xffd6b25e);
            DrawLine(frame, centerX - 84, centerY + 3, centerX, centerY + 47, 0xff765139);
            DrawLine(frame, centerX, centerY + 47, centerX + 84, centerY + 3, 0xff765139);
            FillCircle(frame, centerX, centerY, 31, 0xff101820);
            DrawCircleOutline(frame, centerX, centerY, 33, 0xff9bd4dc);
            DrawCircleOutline(frame, centerX, centerY, 25, 0xffd6b25e);
        }
        double dx = state.EyePredictedX - centerXD;
        double dy = state.EyePredictedY - centerYD;
        double length = Math.Max(1.0, Math.Sqrt(dx * dx + dy * dy));
        int pupilX = centerX + (int)Math.Round(dx / length * 10);
        int pupilY = centerY + (int)Math.Round(dy / length * 7);
        if (!packedEye)
        {
            FillCircle(frame, pupilX, pupilY, 9, state.EyePhase == 3 ? 0xffff6b62 : 0xff7fc7ff);
            FillCircle(frame, pupilX, pupilY, 4, 0xff03080f);
            PutPixel(frame, pupilX - 2, pupilY - 2, 0xffffffff);
        }

        if (state.EyePhase == 2)
        {
            for (int lens = 0; lens < state.EyeLensHealth.Length; lens++)
            {
                (double lensXD, double lensYD) = CopenhagenEyeLensPosition(state, lens, centerXD, centerYD);
                int x = (int)Math.Round(lensXD);
                int y = (int)Math.Round(lensYD);
                bool broken = state.EyeLensHealth[lens] <= 0;
                bool hit = state.EyeLensHitFlash > 0 && state.EyeLastHitLens == lens;
                uint color = broken ? 0xff315b42 : hit ? 0xffffffff : 0xffff8a4a;
                DrawCopenhagenEffectLink(frame, broken ? "cph_fx_orange_link" : "cph_fx_white_link",
                    centerX, centerY, x, y, broken ? 0xff263744 : 0xff765139);
                string lensName = broken ? "cph_detail_eye_lens_broken" : "cph_detail_eye_lens";
                if (_sprites?.TryGet(lensName, out Sprite eyeLens) == true)
                {
                    DrawSprite(frame, eyeLens, x - eyeLens.Width / 2, y - eyeLens.Height / 2);
                    if (hit) DrawCircleOutline(frame, x, y, 14, 0xffffffff);
                }
                else if (broken)
                {
                    DrawLine(frame, x - 7, y - 7, x + 7, y + 7, color);
                    DrawLine(frame, x + 7, y - 7, x - 7, y + 7, color);
                }
                else
                {
                    FillCircle(frame, x, y, 10, 0xff101820);
                    DrawCircleOutline(frame, x, y, 12, color);
                    FillCircle(frame, x, y, 3, 0xff7fc7ff);
                }
            }
        }
        if (state.EyeDeathAge > 0)
        {
            int burst = Math.Min(96, state.EyeDeathAge / 2);
            DrawCircleOutline(frame, centerX, centerY, 35 + burst, 0xffff8a4a);
            DrawCircleOutline(frame, centerX, centerY, 18 + burst / 2, 0xff8f2635);
        }
    }

    private void DrawCopenhagenEyeHud(uint[] frame, CopenhagenWorldState state)
    {
        if (!state.EyeActive || state.EyeAge < 45 || state.EyeDeathAge > 0) return;
        int maximum = state.EyeTestFixture ? 180 : CopenhagenEyeMaxHealth;
        int barWidth = Math.Min(210, _width - 80);
        int x = (_width - barWidth) / 2;
        string prediction = state.EyePrediction switch
        {
            CopenhagenPrediction.Up => "UPP",
            CopenhagenPrediction.Down => "NED",
            CopenhagenPrediction.Left => "VÄNSTER",
            _ => "HÖGER",
        };
        DrawRect(frame, x, 21, barWidth, 14, 0xdd080d12);
        DrawRect(frame, x + 2, 23, (barWidth - 4) * state.EyeHealth / maximum, 4, 0xff7fc7ff);
        DrawText(frame, x + 4, 28, $"ØRESUNDS ØJE  PROGNOS {prediction}", 0xffbdf8ff);
    }

    private void DrawCopenhagenDannebrog(uint[] frame, CopenhagenWorldState state)
    {
        int portalX = _width / 2;
        int portalY = 67;
        int pulse = state.DannebrogAge / 5 % 7;
        Sprite portal = default;
        bool packedPortal = _sprites is not null && _sprites.TryGet("cph_dannebrog_portal", out portal);
        if (packedPortal)
            DrawSprite(frame, portal, portalX - portal.Width / 2, portalY - portal.Height / 2);
        else
        {
            DrawCircleOutline(frame, portalX, portalY, 88 + pulse, 0xff765139);
            DrawCircleOutline(frame, portalX, portalY, 76 - pulse / 2, 0xffd6b25e);
        }
        for (int ray = 0; ray < 8; ray++)
        {
            double angle = ray * Math.PI / 4.0 + state.DannebrogAge * 0.004;
            int innerX = portalX + (int)Math.Round(Math.Cos(angle) * 77);
            int innerY = portalY + (int)Math.Round(Math.Sin(angle) * 48);
            int outerX = portalX + (int)Math.Round(Math.Cos(angle) * 94);
            int outerY = portalY + (int)Math.Round(Math.Sin(angle) * 59);
            DrawLine(frame, innerX, innerY, outerX, outerY, ray % 2 == 0 ? 0xff8f2635 : 0xffd8d1b9);
        }

        if (state.DannebrogDeathAge > 0)
        {
            int burst = Math.Min(110, state.DannebrogDeathAge / 2);
            DrawCircleOutline(frame, portalX, portalY, 28 + burst, 0xffff8a4a);
            DrawCircleOutline(frame, portalX, portalY, 12 + burst / 2, 0xfff2eee4);
            for (int wing = 0; wing < 4; wing++)
            {
                int dx = (wing % 2 == 0 ? -1 : 1) * (20 + burst);
                int dy = (wing < 2 ? -1 : 1) * (12 + burst / 2);
                DrawLine(frame, portalX + dx - 8, portalY + dy - 5,
                    portalX + dx + 8, portalY + dy + 5, wing % 2 == 0 ? 0xff8f2635 : 0xffd8d1b9);
            }
            return;
        }

        (double centerXD, double centerYD) = CopenhagenDannebrogCenter(state);
        int centerX = (int)Math.Round(centerXD);
        int centerY = (int)Math.Round(centerYD);
        FillCircle(frame, centerX, centerY, 10, 0xff101820);
        DrawCircleOutline(frame, centerX, centerY, 12, 0xffffd66b);
        DrawCrown(frame, centerX - 4, centerY - 4, 0xffffd66b);
        for (int node = 0; node < state.DannebrogNodeHealth.Length; node++)
        {
            (double nodeXD, double nodeYD) = CopenhagenDannebrogNodePosition(state, node, centerXD, centerYD);
            int nodeX = (int)Math.Round(nodeXD);
            int nodeY = (int)Math.Round(nodeYD);
            bool broken = state.DannebrogNodeHealth[node] <= 0;
            bool hit = state.DannebrogHitFlash > 0 && state.DannebrogLastHitNode == node;
            if (broken)
            {
                uint scar = node == state.DannebrogEscapeNode ? 0xff7fc7ff : 0xff315b42;
                DrawLine(frame, centerX + (nodeX - centerX) / 3, centerY + (nodeY - centerY) / 3,
                    nodeX, nodeY, scar);
                DrawLine(frame, nodeX - 7, nodeY - 7, nodeX + 7, nodeY + 7, scar);
                DrawLine(frame, nodeX + 7, nodeY - 7, nodeX - 7, nodeY + 7, scar);
                continue;
            }
            uint stripe = (node + state.DannebrogFormation) % 2 == 0 ? 0xff8f2635 : 0xffd8d1b9;
            DrawCopenhagenEffectLink(frame, "cph_fx_white_link", centerX, centerY, nodeX, nodeY, 0xfff2eee4);
            DrawCopenhagenEffectLink(frame, "cph_fx_orange_link", centerX + 2, centerY, nodeX + 2, nodeY, 0xff8f2635);
            if (_sprites?.TryGet("cph_dannebrog_node", out Sprite dannebrogNode) == true)
            {
                DrawSprite(frame, dannebrogNode, nodeX - dannebrogNode.Width / 2, nodeY - dannebrogNode.Height / 2);
                if (hit) DrawCircleOutline(frame, nodeX, nodeY, 15, 0xffffffff);
            }
            else
            {
                FillTriangle(frame, nodeX, nodeY - 11, nodeX - 14, nodeY + 8, nodeX + 14, nodeY + 8,
                    hit ? 0xffffffff : stripe);
                DrawLine(frame, nodeX - 10, nodeY + 2, nodeX + 10, nodeY + 2,
                    stripe == 0xff8f2635 ? 0xfff2eee4 : 0xff8f2635);
                FillCircle(frame, nodeX, nodeY, 4, 0xffffd66b);
            }
            int maximum = state.DannebrogTestFixture ? 12 : CopenhagenDannebrogNodeHealth;
            DrawRect(frame, nodeX - 12, nodeY + 12, 24, 3, 0xff101820);
            DrawRect(frame, nodeX - 12, nodeY + 12, 24 * state.DannebrogNodeHealth[node] / maximum, 3, 0xffff8a4a);
        }
        if (state.DannebrogChargeAge > 0)
        {
            int trail = Math.Min(70, state.DannebrogChargeAge);
            DrawLine(frame, centerX - 4, centerY - trail, centerX - 4, centerY - 14, 0xff8f2635);
            DrawLine(frame, centerX + 4, centerY - trail, centerX + 4, centerY - 14, 0xfff2eee4);
        }
        if (state.DannebrogAge < 180)
        {
            int width = Math.Min(250, _width - 30);
            int x = (_width - width) / 2;
            int y = _height <= 224 ? 128 : 159;
            DrawRect(frame, x, y, width, 29, 0xdd080d12);
            DrawLine(frame, x, y, x + width - 1, y, 0xff8f2635);
            DrawText(frame, x + (width - 150) / 2, y + 10, "SUPERARMADAN KOMPILERAS", 0xffffd66b);
        }
    }

    private void DrawCopenhagenDannebrogHud(uint[] frame, CopenhagenWorldState state)
    {
        if (!state.DannebrogActive || state.DannebrogAge < 35 || state.DannebrogDeathAge > 0) return;
        int width = Math.Min(214, _width - 82);
        int x = (_width - width) / 2;
        string task = state.DannebrogChargeAge > 0 ? "FLYG GENOM ÄRRET" :
            state.DannebrogEscapeNode >= 0 ? $"ÄRR {state.DannebrogEscapeNode + 1} ÖPPET" : "BRYT ETT HÖRN";
        DrawRect(frame, x, 21, width, 14, 0xdd080d12);
        int progress = state.DannebrogFormation * 4 + state.DannebrogNodeHealth.Count(health => health <= 0);
        DrawRect(frame, x + 2, 23, (width - 4) * Math.Min(12, progress) / 12, 4, 0xff8f2635);
        DrawText(frame, x + 4, 28,
            $"DANNEBROG {state.DannebrogFormation + 1}/{CopenhagenDannebrogFormationCount}  {task}", 0xffbdf8ff);
    }

    private void DrawCopenhagenDuo(uint[] frame, CopenhagenWorldState state)
    {
        if (state.DuoShieldWall is CopenhagenShieldWall wall)
        {
            int wallY = (int)Math.Round(CopenhagenDuoWallY(wall));
            for (int node = 0; node < wall.Health.Length; node++)
            {
                int nodeX = (int)Math.Round(CopenhagenDuoWallNodeX(node));
                if (wall.Health[node] <= 0)
                {
                    uint gap = node == wall.GapIndex ? 0xff7fc7ff : 0xff315b42;
                    DrawLine(frame, nodeX - 8, wallY - 6, nodeX + 8, wallY + 6, gap);
                    DrawLine(frame, nodeX + 8, wallY - 6, nodeX - 8, wallY + 6, gap);
                    continue;
                }
                if (node > 0 && wall.Health[node - 1] > 0)
                {
                    int linkX = (int)Math.Round(CopenhagenDuoWallNodeX(node - 1)) + 11;
                    if (_sprites?.TryGet("cph_fx_white_link", out Sprite wallLink) == true)
                        DrawSpriteScaled(frame, wallLink, linkX, wallY - 5, Math.Max(1, nodeX - 11 - linkX), 10);
                    else DrawLine(frame, linkX, wallY, nodeX - 11, wallY, 0xff9bd4dc);
                }
                if (_sprites?.TryGet("cph_detail_shield_node", out Sprite shieldNode) == true)
                    DrawSprite(frame, shieldNode, nodeX - shieldNode.Width / 2, wallY - shieldNode.Height / 2);
                else
                {
                    FillCircle(frame, nodeX, wallY, 9, 0xff172734);
                    DrawCircleOutline(frame, nodeX, wallY, 11, node % 2 == 0 ? 0xfff2eee4 : 0xff8f2635);
                    DrawLine(frame, nodeX - 6, wallY, nodeX + 6, wallY, 0xffd6b25e);
                }
                int maximum = state.DuoTestFixture ? 8 : CopenhagenDuoShieldHealth;
                DrawRect(frame, nodeX - 9, wallY + 13, 18 * wall.Health[node] / maximum, 2, 0xff7fc7ff);
            }
        }

        int chargeX = (int)Math.Round(state.DuoShieldWall is CopenhagenShieldWall activeWall
            ? CopenhagenDuoWallNodeX(activeWall.GapIndex)
            : state.DuoElefantenChargeX);
        bool chargeWarning = state.DuoCycleAge is >= 82 and < 112 && state.DuoHealth[1] > 0;
        if (chargeWarning || state.DuoElefantenChargeAge > 0)
        {
            uint warning = chargeWarning && (state.DuoCycleAge / 5 & 1) == 0 ? 0xffffd66b : 0xff8f2635;
            DrawLine(frame, chargeX - 20, 18, chargeX - 20, _height - 13, warning);
            DrawLine(frame, chargeX + 20, 18, chargeX + 20, _height - 13, warning);
            if (chargeWarning) DrawText(frame, chargeX - 15, _height - 33, "FLYT", warning);
        }

        DrawCopenhagenDuoShip(frame, state, 0);
        DrawCopenhagenDuoShip(frame, state, 1);
        if (state.DuoRepairFlash > 0 && state.DuoRepairTurret >= 0)
        {
            int ship = state.DuoRepairTurret / 2;
            int side = state.DuoRepairTurret % 2;
            if (state.DuoHealth[ship] > 0)
            {
                (double shipX, double shipY) = CopenhagenDuoShipPosition(state, ship);
                (double turretX, double turretY) = CopenhagenDuoTurretPosition(shipX, shipY, side);
                int droneX = (int)Math.Round(turretX + Math.Sin(state.DuoAge * 0.08) * 18);
                int droneY = (int)Math.Round(turretY - 24);
                if (_sprites?.TryGet("cph_detail_repair_drone", out Sprite repairDrone) == true)
                    DrawSprite(frame, repairDrone, droneX - repairDrone.Width / 2, droneY - repairDrone.Height / 2);
                else FillCircle(frame, droneX, droneY, 4, 0xff77e6a0);
                DrawLine(frame, droneX, droneY, (int)Math.Round(turretX), (int)Math.Round(turretY), 0xff77e6a0);
            }
        }
        if (state.DuoAge < 180)
        {
            int width = Math.Min(244, _width - 30);
            int x = (_width - width) / 2;
            int y = _height <= 224 ? 132 : 164;
            DrawRect(frame, x, y, width, 29, 0xdd080d12);
            DrawLine(frame, x, y, x + width - 1, y, 0xffd6b25e);
            DrawText(frame, x + (width - 126) / 2, y + 10, "ABSALON · ELEFANTEN", 0xffffd66b);
        }
    }

    private void DrawCopenhagenDuoShip(uint[] frame, CopenhagenWorldState state, int ship)
    {
        (double shipXD, double shipYD) = CopenhagenDuoShipPosition(state, ship);
        int x = (int)Math.Round(shipXD);
        int y = (int)Math.Round(shipYD);
        bool dead = state.DuoHealth[ship] <= 0;
        int fall = state.DuoShipFallAge[ship];
        if (dead) y += Math.Min(95, fall / 2);
        bool hit = state.DuoHitFlash > 0 && state.DuoLastHitShip == ship && state.DuoLastHitTurret < 0;
        uint hull = dead ? 0xff592531 : hit ? 0xffffffff : ship == 0 ? 0xff263744 : 0xff4b3030;
        uint trim = ship == 0 ? 0xff9bd4dc : 0xffff8a4a;
        string duoName = ship == 0
            ? dead ? "cph_absalon_broken" : "cph_absalon"
            : dead ? "cph_elefant_broken" : "cph_elefant";
        Sprite duoShip = default;
        bool packedDuo = _sprites is not null && _sprites.TryGet(duoName, out duoShip);
        if (packedDuo)
        {
            DrawSprite(frame, duoShip, x - duoShip.Width / 2, y - duoShip.Height / 2);
            if (hit) DrawCircleOutline(frame, x, y, ship == 0 ? 35 : 31, 0xffffffff);
        }
        else if (ship == 0)
        {
            FillTriangle(frame, x, y - 29, x - 45, y + 22, x + 45, y + 22, hull);
            DrawLine(frame, x - 39, y + 18, x + 39, y + 18, trim);
            DrawLine(frame, x - 31, y + 4, x + 31, y + 4, 0xfff2eee4);
            DrawCircleOutline(frame, x, y - 2, 13, 0xff7fc7ff);
        }
        else
        {
            FillTriangle(frame, x, y + 31, x - 39, y - 21, x + 39, y - 21, hull);
            FillTriangle(frame, x, y - 30, x - 15, y + 7, x + 15, y + 7, 0xff765139);
            DrawLine(frame, x - 34, y - 17, x + 34, y - 17, trim);
            FillCircle(frame, x, y - 5, 8, 0xffffd66b);
        }
        if (!packedDuo)
            DrawText(frame, x - (ship == 0 ? 21 : 27), y + 27, ship == 0 ? "ABSALON" : "ELEFANTEN", trim);
        for (int side = 0; side < 2; side++)
        {
            int turret = ship * 2 + side;
            (double turretXD, double turretYD) = CopenhagenDuoTurretPosition(x, y, side);
            int turretX = (int)Math.Round(turretXD);
            int turretY = (int)Math.Round(turretYD);
            bool turretHit = state.DuoHitFlash > 0 && state.DuoLastHitTurret == turret;
            if (state.DuoTurretHealth[turret] <= 0)
            {
                DrawLine(frame, turretX - 6, turretY - 5, turretX + 6, turretY + 5, 0xff8f2635);
                continue;
            }
            if (_sprites?.TryGet("cph_detail_turret", out Sprite turretSprite) == true)
            {
                DrawSprite(frame, turretSprite, turretX - turretSprite.Width / 2, turretY - turretSprite.Height / 2);
                if (turretHit) DrawCircleOutline(frame, turretX, turretY, 9, 0xffffffff);
            }
            else
            {
                FillCircle(frame, turretX, turretY, 6, 0xff101820);
                DrawCircleOutline(frame, turretX, turretY, 7, turretHit ? 0xffffffff : 0xffffd66b);
                DrawLine(frame, turretX, turretY, turretX, turretY + 11, trim);
            }
        }
        if (dead)
        {
            int burst = Math.Min(58, fall / 2);
            DrawCircleOutline(frame, x, y, 18 + burst, 0xffff8a4a);
        }
    }

    private void DrawCopenhagenDuoHud(uint[] frame, CopenhagenWorldState state)
    {
        if (!state.DuoActive || state.DuoAge < 35 || state.DuoDeathAge > 0) return;
        int width = Math.Min(220, _width - 74);
        int x = (_width - width) / 2;
        int maximum = state.DuoTestFixture ? 72 : CopenhagenDuoMaxHealth;
        DrawRect(frame, x, 20, width, 25, 0xdd080d12);
        DrawRect(frame, x + 2, 22, (width - 4) * state.DuoHealth[0] / maximum, 4, 0xff7fc7ff);
        DrawText(frame, x + 4, 28, "ABSALON", state.DuoHealth[0] > 0 ? 0xffbdf8ff : 0xff8f2635);
        DrawRect(frame, x + 2, 35, (width - 4) * state.DuoHealth[1] / maximum, 4, 0xffff8a4a);
        DrawText(frame, x + width - 58, 41, "ELEFANTEN", state.DuoHealth[1] > 0 ? 0xffffd66b : 0xff8f2635);
    }

    private void DrawCopenhagenSuperfrigate(uint[] frame, CopenhagenWorldState state)
    {
        if (state.SuperLockQuadrant >= 0 && state.SuperLockAge > 0)
            DrawCopenhagenSuperQuadrantLock(frame, state);
        if (state.SuperBeamAge > 0)
        {
            bool active = state.SuperBeamAge is >= 42 and <= 72;
            uint color = active ? 0xffffffff : (state.SuperBeamAge / 5 & 1) == 0 ? 0xff7fc7ff : 0xffd6b25e;
            int radius = active ? 7 : 2;
            for (int offset = -radius; offset <= radius; offset += Math.Max(1, radius))
                DrawLine(frame, state.SuperBeamTargetX + offset, 16, state.SuperBeamTargetX + offset, _height - 13, color);
        }

        (double centerXD, double centerYD) = CopenhagenSuperCenter(state);
        int centerX = (int)Math.Round(centerXD);
        int centerY = (int)Math.Round(centerYD);
        uint hull = state.SuperDeathAge > 0 ? 0xff692834 : state.SuperHitFlash > 0 ? 0xff4b5358 : 0xff202b34;
        string superName = state.SuperDeathAge > 0 ? "cph_superfrigate_broken" : "cph_superfrigate";
        Sprite superfrigate = default;
        bool packedSuper = _sprites is not null && _sprites.TryGet(superName, out superfrigate);
        if (packedSuper)
        {
            DrawSprite(frame, superfrigate, centerX - superfrigate.Width / 2, centerY - superfrigate.Height / 2);
            if (state.SuperHitFlash > 0)
            {
                if (_sprites?.TryGet("cph_fx_hit_ring", out Sprite hitRing) == true)
                    DrawSpriteScaled(frame, hitRing, centerX - 28, centerY - 28, 56, 56);
                else DrawCircleOutline(frame, centerX, centerY, 55, 0xffffffff);
            }
        }
        else
        {
            FillTriangle(frame, centerX, centerY - 55, centerX - 128, centerY + 48, centerX + 128, centerY + 48, hull);
            FillTriangle(frame, centerX, centerY - 39, centerX - 105, centerY + 34, centerX + 105, centerY + 34, 0xff29343a);
            DrawLine(frame, centerX - 123, centerY + 44, centerX + 123, centerY + 44, 0xffd6b25e);
            DrawLine(frame, centerX - 101, centerY + 31, centerX + 101, centerY + 31, 0xff8f2635);
            DrawCrown(frame, centerX - 4, centerY - 41, 0xffffd66b);
        }

        for (int section = 0; section < 3; section++)
        {
            (double sectionXD, double sectionYD) = CopenhagenSuperSectionPosition(section, centerXD, centerYD);
            int x = (int)Math.Round(sectionXD);
            int y = (int)Math.Round(sectionYD);
            bool broken = state.SuperSectionHealth[section] <= 0;
            bool hit = state.SuperHitFlash > 0 && state.SuperLastHitSection == section;
            uint color = broken ? 0xff592531 : hit ? 0xffffffff : section == 0 ? 0xff765139 : 0xff8f2635;
            if (packedSuper)
            {
                if (hit) DrawCircleOutline(frame, x, y, 18, 0xffffffff);
            }
            else if (section == 0)
            {
                DrawRect(frame, x - 25, y - 12, 50, 23, 0xff101820);
                DrawCircleOutline(frame, x, y, 17, color);
                for (int hatch = -16; hatch <= 16; hatch += 8)
                    DrawLine(frame, x + hatch, y - 8, x + hatch + 5, y + 8, color);
            }
            else
            {
                FillTriangle(frame, x, y - 18, x - 28, y + 14, x + 28, y + 14, color);
                DrawLine(frame, x - 20, y + 6, x + 20, y + 6, 0xfff2eee4);
                for (int gun = -1; gun <= 1; gun++) FillCircle(frame, x + gun * 10, y + 11, 3, 0xffffd66b);
            }
            if (broken)
            {
                if (_sprites?.TryGet("cph_fx_fracture", out Sprite brokenFracture) == true)
                    DrawSpriteScaled(frame, brokenFracture, x - 18, y - 18, 36, 36);
                else
                {
                    DrawLine(frame, x - 17, y - 13, x + 17, y + 13, 0xffff8a4a);
                    DrawLine(frame, x + 17, y - 13, x - 17, y + 13, 0xffff8a4a);
                }
            }
            if (state.SuperSectionBreakFlash > 0 && state.SuperLastHitSection == section &&
                _sprites?.TryGet("cph_fx_fracture", out Sprite fracture) == true)
                DrawSprite(frame, fracture, x - fracture.Width / 2, y - fracture.Height / 2);
        }

        if (state.SuperPhase == 2)
        {
            for (int node = 0; node < state.SuperCrossHealth.Length; node++)
            {
                (double nodeXD, double nodeYD) = CopenhagenSuperCrossNodePosition(node, centerXD, centerYD);
                int x = (int)Math.Round(nodeXD);
                int y = (int)Math.Round(nodeYD);
                bool broken = state.SuperCrossHealth[node] <= 0;
                DrawCopenhagenEffectLink(frame, broken ? "cph_fx_orange_link" : "cph_fx_white_link",
                    centerX, centerY + 12, x, y, broken ? 0xff315b42 : 0xfff2eee4);
                if (broken)
                {
                    if (_sprites?.TryGet("cph_fx_fracture", out Sprite nodeFracture) == true)
                        DrawSpriteScaled(frame, nodeFracture, x - 11, y - 11, 22, 22);
                    else
                    {
                        DrawLine(frame, x - 7, y - 7, x + 7, y + 7, 0xff7fc7ff);
                        DrawLine(frame, x + 7, y - 7, x - 7, y + 7, 0xff7fc7ff);
                    }
                }
                else
                {
                    if (_sprites?.TryGet("cph_detail_cross_node", out Sprite crossNode) == true)
                    {
                        DrawSprite(frame, crossNode, x - crossNode.Width / 2, y - crossNode.Height / 2);
                        if (state.SuperLockQuadrant == node) DrawCircleOutline(frame, x, y, 12, 0xffff6b62);
                    }
                    else
                    {
                        FillCircle(frame, x, y, 8, 0xff101820);
                        DrawCircleOutline(frame, x, y, 10,
                            state.SuperLockQuadrant == node ? 0xffff6b62 : 0xfff2eee4);
                        FillCircle(frame, x, y, 3, 0xff7fc7ff);
                    }
                }
            }
        }

        if (state.SuperPhase >= 3)
        {
            bool reactor = state.SuperPhase == 4;
            uint core = reactor ? 0xffffec9a : state.SuperMemoryOrder switch
            {
                0 => 0xffd6b25e,
                1 => 0xffff8a4a,
                _ => 0xffbdf8ff,
            };
            FillCircle(frame, centerX, centerY - 4, reactor ? 24 : 20, 0xff101820);
            DrawCircleOutline(frame, centerX, centerY - 4, reactor ? 27 : 23, core);
            DrawCircleOutline(frame, centerX, centerY - 4, reactor ? 17 : 13, 0xff8f2635);
            FillCircle(frame, centerX, centerY - 4, reactor ? 9 : 6, core);
            if (reactor)
            {
                int pulse = state.SuperPhaseAge / 5 % 8;
                DrawCircleOutline(frame, centerX, centerY - 4, 31 + pulse, 0xff7fc7ff);
            }
        }

        foreach (CopenhagenRoyalDrone drone in state.SuperDrones)
        {
            int x = (int)Math.Round(drone.X);
            int y = (int)Math.Round(drone.Y);
            if (_sprites?.TryGet("cph_detail_royal_drone", out Sprite royalDrone) == true)
            {
                if ((drone.Serial & 1) == 0)
                    DrawSprite(frame, royalDrone, x - royalDrone.Width / 2, y - royalDrone.Height / 2);
                else DrawSpriteFlippedX(frame, royalDrone, x - royalDrone.Width / 2, y - royalDrone.Height / 2);
            }
            else
            {
                FillTriangle(frame, x, y - 8, x - 10, y + 7, x + 10, y + 7,
                    drone.Serial % 2 == 0 ? 0xff8f2635 : 0xffd8d1b9);
                FillCircle(frame, x, y, 3, 0xffffd66b);
            }
        }
        if (state.SuperPhase == 4 && state.SuperSupportShown)
            DrawCopenhagenSuperSupport(frame, state);
        if (state.SuperDeathAge > 0)
        {
            int burst = Math.Min(135, state.SuperDeathAge / 2);
            DrawCircleOutline(frame, centerX, centerY, 36 + burst, 0xffff8a4a);
            DrawCircleOutline(frame, centerX, centerY, 18 + burst / 2, 0xffffffff);
            DrawLine(frame, centerX - burst, centerY - 35, centerX + burst, centerY + 35, 0xff8f2635);
        }
        if (state.SuperAge < 200)
        {
            int width = Math.Min(262, _width - 30);
            int x = (_width - width) / 2;
            int y = _height <= 224 ? 134 : 166;
            DrawRect(frame, x, y, width, 31, 0xdd080d12);
            DrawLine(frame, x, y, x + width - 1, y, 0xffffd66b);
            DrawText(frame, x + (width - 174) / 2, y + 10, "KONG CHRISTIANS SUPERFREGATT", 0xffffd66b);
        }
    }

    private void DrawCopenhagenSuperQuadrantLock(uint[] frame, CopenhagenWorldState state)
    {
        int splitX = _width / 2;
        int splitY = (_height + 52) / 2;
        bool right = state.SuperLockQuadrant is 1 or 2;
        bool bottom = state.SuperLockQuadrant is 2 or 3;
        int x0 = right ? splitX : 1;
        int x1 = right ? _width - 2 : splitX;
        int y0 = bottom ? splitY : 17;
        int y1 = bottom ? _height - 13 : splitY;
        bool active = state.SuperLockAge is >= 44 and <= 82;
        uint color = active ? 0xffff6b62 : (state.SuperLockAge / 5 & 1) == 0 ? 0xff765139 : 0xffd8d1b9;
        if (_sprites?.TryGet("cph_fx_quadrant", out Sprite quadrant) == true)
        {
            DrawSpriteScaled(frame, quadrant, x0, y0, Math.Max(1, x1 - x0), Math.Max(1, y1 - y0));
            if (active)
            {
                DrawLine(frame, x0, y0, x1, y0, color);
                DrawLine(frame, x1, y0, x1, y1, color);
                DrawLine(frame, x1, y1, x0, y1, color);
                DrawLine(frame, x0, y1, x0, y0, color);
            }
        }
        else
        {
            DrawLine(frame, x0, y0, x1, y0, color);
            DrawLine(frame, x1, y0, x1, y1, color);
            DrawLine(frame, x1, y1, x0, y1, color);
            DrawLine(frame, x0, y1, x0, y0, color);
            for (int hatch = x0 - (y1 - y0); hatch < x1; hatch += 24)
                DrawLine(frame, Math.Max(x0, hatch), y1, Math.Min(x1, hatch + y1 - y0), y0, color);
        }
    }

    private void DrawCopenhagenEffectLink(
        uint[] frame, string spriteName, int x0, int y0, int x1, int y1, uint fallbackColor)
    {
        if (_sprites?.TryGet(spriteName, out Sprite link) != true)
        {
            DrawLine(frame, x0, y0, x1, y1, fallbackColor);
            return;
        }
        double dx = x1 - x0;
        double dy = y1 - y0;
        int steps = Math.Max(1, (int)Math.Ceiling(Math.Sqrt(dx * dx + dy * dy) / 12.0));
        for (int step = 1; step < steps; step++)
        {
            int x = (int)Math.Round(x0 + dx * step / steps);
            int y = (int)Math.Round(y0 + dy * step / steps);
            DrawSpriteScaled(frame, link, x - 6, y - 3, 12, 6);
        }
    }

    private void DrawCopenhagenSuperSupport(uint[] frame, CopenhagenWorldState state)
    {
        int count = Math.Clamp(state.IncomingFreedShips + state.SnapphaneAllies / 2 + (state.SorenOathComplete ? 1 : 0), 1, 4);
        for (int ally = 0; ally < count; ally++)
        {
            int side = ally % 2 == 0 ? -1 : 1;
            int x = _width / 2 + side * (132 + ally / 2 * 18);
            int y = _height - 55 - ally * 14;
            string allyName = state.SorenOathComplete && ally == 0 ? "cph_detail_soren_ally" : "cph_detail_ally";
            if (_sprites?.TryGet(allyName, out Sprite allyShip) == true)
                DrawSprite(frame, allyShip, x - allyShip.Width / 2, y - allyShip.Height / 2);
            else
            {
                FillTriangle(frame, x, y - 7, x - 7, y + 6, x + 7, y + 6,
                    state.SorenOathComplete && ally == 0 ? 0xff315b42 : 0xff293c43);
                DrawLine(frame, x, y - 9, x, y - 15, 0xff77e6a0);
            }
            if (state.SuperSupportFlash > 0 && (state.SuperSupportFlash / 4 + ally & 1) == 0)
                DrawLine(frame, x, y - 16, _width / 2, 82, 0xffffd66b);
        }
    }

    private void DrawCopenhagenSuperHud(uint[] frame, CopenhagenWorldState state)
    {
        if (!state.SuperActive || state.SuperAge < 40 || state.SuperDeathAge > 0) return;
        int width = Math.Min(234, _width - 62);
        int x = (_width - width) / 2;
        DrawRect(frame, x, 20, width, 25, 0xdd080d12);
        string label;
        int health;
        int maximum;
        uint color;
        if (state.SuperPhase == 1)
        {
            maximum = (state.SuperTestFixture ? 36 : CopenhagenSuperSectionHealth) * 3;
            health = state.SuperSectionHealth.Take(3).Sum();
            label = $"SEKTIONER  {state.SuperSectionHealth.Take(3).Count(value => value > 0)}/3";
            color = 0xffff8a4a;
        }
        else if (state.SuperPhase == 2)
        {
            maximum = (state.SuperTestFixture ? 12 : CopenhagenSuperCrossNodeHealth) * 4;
            health = state.SuperCrossHealth.Sum();
            label = $"VITA KORSRAMEN  {state.SuperCrossHealth.Count(value => value > 0)}/4";
            color = 0xfff2eee4;
        }
        else if (state.SuperPhase == 3)
        {
            maximum = state.SuperTestFixture ? 90 : CopenhagenSuperMemoryHealth;
            health = state.SuperMemoryHealth;
            label = $"FELMINNE  ORDER {state.SuperMemoryOrder + 1}";
            color = state.SuperMemoryOrder == 2 ? 0xffbdf8ff : 0xffffd66b;
        }
        else
        {
            maximum = state.SuperTestFixture ? 72 : CopenhagenSuperReactorHealth;
            health = state.SuperSectionHealth[3];
            label = "KRONREAKTOR  SISTA HÅLLET";
            color = 0xff7fc7ff;
        }
        DrawRect(frame, x + 2, 22, (width - 4) * health / Math.Max(1, maximum), 5, color);
        DrawText(frame, x + 4, 31, label, 0xffbdf8ff);
    }

    private void DrawCopenhagenLanding(uint[] frame, CopenhagenWorldState state)
    {
        int dockTop = 42;
        for (int pier = 0; pier < 4; pier++)
        {
            int x = pier * _width / 3 - 18;
            int height = 54 + (pier * 17 % 31);
            if (_sprites?.TryGet("holmen_dock_forge", out Sprite dockForge) == true)
            {
                DrawSprite(frame, dockForge, x + 19 - dockForge.Width / 2, dockTop - 17 + (pier & 1) * 9);
            }
            else
            {
                DrawRect(frame, x, dockTop, 38, height, 0xff211b1c);
                DrawLine(frame, x, dockTop + height, x + 37, dockTop + height, 0xff765139);
                for (int window = dockTop + 12; window < dockTop + height - 5; window += 17)
                    FillCircle(frame, x + 19, window, 3 + (state.LandingAge / 7 + pier & 1), 0xffff8a4a);
            }
        }
        for (int anchor = 0; anchor < state.LandingAnchorHealth.Length; anchor++)
        {
            (double anchorXD, double anchorYD) = CopenhagenLandingAnchorPosition(anchor);
            int x = (int)Math.Round(anchorXD);
            int y = (int)Math.Round(anchorYD);
            bool broken = state.LandingAnchorHealth[anchor] <= 0;
            bool hit = state.LandingHitFlash > 0 && state.LandingLastHitAnchor == anchor;
            uint color = broken ? 0xff315b42 : hit ? 0xffffffff : 0xffd6b25e;
            string anchorAsset = broken ? "holmen_anchor_broken" : "holmen_anchor_intact";
            if (_sprites?.TryGet(anchorAsset, out Sprite anchorSprite) == true)
            {
                DrawSprite(frame, anchorSprite, x - anchorSprite.Width / 2, y + 22 - anchorSprite.Height);
                if (hit) DrawCircleOutline(frame, x, y, 15, color);
            }
            else
            {
                for (int link = 0; link < 5; link++)
                {
                    int linkY = 18 + (y - 18) * link / 5;
                    DrawCircleOutline(frame, x, linkY, 3, broken ? 0xff263744 : 0xff765139);
                }
                if (broken)
                {
                    DrawLine(frame, x - 10, y - 9, x + 10, y + 9, color);
                    DrawLine(frame, x + 10, y - 9, x - 10, y + 9, color);
                }
                else
                {
                    DrawCircleOutline(frame, x, y, 13, color);
                    DrawLine(frame, x, y - 12, x, y + 15, color);
                    DrawLine(frame, x - 10, y + 8, x, y + 15, color);
                    DrawLine(frame, x + 10, y + 8, x, y + 15, color);
                }
            }
            if (!broken)
            {
                int maximum = state.LandingTestFixture ? 12 : CopenhagenLandingAnchorHealth;
                DrawRect(frame, x - 13, y + 23, 26 * state.LandingAnchorHealth[anchor] / maximum, 3, 0xffff8a4a);
            }
        }
        if (state.LandingReleaseAge > 0)
        {
            int descent = Math.Min(80, state.LandingReleaseAge / 2);
            DrawLine(frame, _width / 2 - 32, 26, _width / 2 - 32, 26 + descent, 0xff77e6a0);
            DrawLine(frame, _width / 2 + 32, 26, _width / 2 + 32, 26 + descent, 0xff77e6a0);
        }
        if (state.LandingAge < 190)
        {
            int width = Math.Min(238, _width - 30);
            int x = (_width - width) / 2;
            int y = _height <= 224 ? 139 : 171;
            DrawRect(frame, x, y, width, 29, 0xdd080d12);
            DrawLine(frame, x, y, x + width - 1, y, 0xffff8a4a);
            DrawText(frame, x + (width - 168) / 2, y + 10, "HOLMEN · TRE LANDNINGSANKARE", 0xffffd66b);
        }
    }

    private void DrawCopenhagenLandingHud(uint[] frame, CopenhagenWorldState state)
    {
        if (!state.LandingActive || state.LandingAge < 30) return;
        int width = Math.Min(206, _width - 86);
        int x = (_width - width) / 2;
        DrawRect(frame, x, 21, width, 14, 0xdd080d12);
        int broken = state.LandingAnchorHealth.Count(health => health <= 0);
        DrawRect(frame, x + 2, 23, (width - 4) * broken / 3, 4, 0xff77e6a0);
        DrawText(frame, x + 4, 28, $"LANDNING  ANKARE {broken}/3", 0xffbdf8ff);
    }

    private void DrawCopenhagenGroundWorld(uint[] frame, CopenhagenWorldState state)
    {
        CopenhagenGroundState? ground = state.Ground;
        Clear(frame, 0xff0b1012);
        if (_sprites?.TryGet("dungeon_temple_floor", out Sprite holmenFloor) == true)
        {
            for (int y = 17; y < _height; y += 68)
            {
                int offset = ((y - 17) / 68 & 1) == 0 ? -8 : -54;
                for (int x = offset; x < _width; x += 92)
                    DrawSpriteScaled(frame, holmenFloor, x, y, 96, 72);
            }
        }
        else
        {
            for (int y = 18; y < _height - 12; y += 24)
            {
                for (int x = (y / 24 & 1) == 0 ? -18 : -6; x < _width; x += 42)
                {
                    DrawRect(frame, x, y, 39, 21, 0xff151b1e);
                    DrawLine(frame, x, y + 20, x + 38, y + 20, 0xff29343a);
                    DrawLine(frame, x + 38, y, x + 38, y + 20, 0xff765139);
                }
            }
        }
        DrawRect(frame, 0, 18, _width, 27, 0xff211b1c);
        for (int forge = 0; forge < 5; forge++)
        {
            int x = 24 + forge * (_width - 48) / 4;
            if (_sprites?.TryGet("cph_forge_brazier", out Sprite brazier) == true)
                DrawSpriteScaled(frame, brazier, x - 12, 18, 24, 26);
            else
            {
                FillCircle(frame, x, 31, 7, 0xff592531);
                FillCircle(frame, x, 31, 3 + ((((ground?.Age ?? 0) / 6) + forge) & 1), 0xffff8a4a);
            }
        }
        if (_sprites?.TryGet("holmen_arsenal_furnace", out Sprite furnace) == true)
        {
            DrawSprite(frame, furnace, 42 - furnace.Width / 2, 67 - furnace.Height / 2);
            DrawSpriteFlippedX(frame, furnace, _width - 42 - furnace.Width / 2, 67 - furnace.Height / 2);
        }
        if (_sprites?.TryGet("holmen_naval_debris", out Sprite debris) == true)
        {
            DrawSprite(frame, debris, 58 - debris.Width / 2, _height - 48 - debris.Height / 2);
            DrawSpriteFlippedX(frame, debris, _width - 60 - debris.Width / 2, _height / 2 - debris.Height / 2);
        }
        if (ground?.Room == 7) DrawCopenhagenCodexRoom(frame, ground);
        else if (ground?.Room == 6) DrawCopenhagenWrathRoom(frame, ground);
        else if (ground?.Room == 5) DrawCopenhagenKorrektoriusRoom(frame, ground);
        else if (ground?.Room == 4) DrawCopenhagenSagaKingRoom(frame, ground);
        else if (ground?.Room == 3) DrawCopenhagenMemoryMachineRoom(frame, ground);
        else if (ground?.Room == 2) DrawCopenhagenRosenborgRoom(frame, ground);
        else DrawCopenhagenGroundHeartDoor(frame, ground);
        if (ground is null) return;
        if (ground.Room == 1) DrawCopenhagenArsenalCannon(frame, ground);

        foreach (CopenhagenGroundEnemy enemy in ground.Enemies.OrderBy(enemy => enemy.Y))
            DrawCopenhagenGroundEnemy(frame, ground, enemy);
        DrawCopenhagenGroundKarl(frame, ground);
        if (ground.Room is >= 2 and < 7) DrawCopenhagenMaterialForm(frame, ground);
        if (ground.Room == 3) DrawCopenhagenLegend(frame, ground);
        DrawBorder(frame);
        DrawCopenhagenGroundHud(frame, ground);
        DrawRadio(frame);
        DrawPause(frame);
        if (ground.MarginalChoosing) DrawCopenhagenMarginalChoice(frame, ground);
        else if (ground.MarginalCompileAge > 0) DrawCopenhagenMarginalCompile(frame, ground);
        else if (ground.LegendChoosing) DrawCopenhagenLegendChoice(frame, ground);
        else if (ground.LegendCompileAge > 0) DrawCopenhagenLegendCompile(frame, ground);
        else if (ground.LocalLawChoosing) DrawCopenhagenLocalLawChoice(frame, ground);
        else if (ground.LocalLawCompileAge > 0) DrawCopenhagenLocalLawCompile(frame, ground);
        if (ground.Room == 7 && ground.CodexOpened) DrawCopenhagenCodexSequence(frame, ground);
        if (ground.Dead)
        {
            int x = (_width - 184) / 2;
            int y = (_height - 43) / 2;
            DrawRect(frame, x, y, 184, 43, 0xee090b10);
            DrawText(frame, x + 40, y + 10, "KARL FÖLL PÅ HOLMEN", 0xffff6b7f);
            DrawText(frame, x + 25, y + 27, "START ÅTERUPPTAR", 0xffffd66b);
        }
        else if (ground.CheckpointReady)
        {
            int width = Math.Min(220, _width - 30);
            int x = (_width - width) / 2;
            int y = (_height - 45) / 2;
            DrawRect(frame, x, y, width, 45, 0xee080d12);
            DrawLine(frame, x, y, x + width - 1, y, 0xff7fc7ff);
            string line1 = ground.Room switch
            {
                2 => "ROSENBORGS FÖRGÅRD SÄKRAD",
                3 => "MINNESMASKINEN LYDER",
                4 => "SAGOKONUNGEN TYSTAD",
                5 => "MARGINALFOGDEN RÄTTAD",
                6 => "CHRISTIANS ANSPRÅK BRUTET",
                _ => "KANONGÅNGEN SÄKRAD",
            };
            string line2 = ground.Room switch
            {
                2 => "MINNESMASKINEN VÄNTAR",
                3 => "SAGOKONUNGEN VÄNTAR",
                4 => "MARGINALFOGDEN VÄNTAR",
                5 => "CHRISTIANS VREDE VÄNTAR",
                6 => "CODEX ARGENTUM VÄNTAR",
                _ => "ROSENBORG VÄNTAR",
            };
            DrawText(frame, x + (width - line1.Length * 6) / 2, y + 10, line1, 0xffffd66b);
            DrawText(frame, x + (width - line2.Length * 6) / 2, y + 27, line2, 0xff9bd4dc);
        }
    }

    private void DrawCopenhagenCodexRoom(uint[] frame, CopenhagenGroundState ground)
    {
        DrawRect(frame, 0, 17, _width, _height - 17, 0xff070b0f);
        for (int y = 20; y < _height; y += 18)
        {
            uint seam = (y / 18 & 1) == 0 ? 0xff17242a : 0xff102027;
            DrawLine(frame, 0, y, _width - 1, y, seam);
        }

        int sideWidth = _width <= 320 ? 44 : 54;
        Sprite instanceSprite = default;
        bool hasInstanceSprite = _sprites is not null &&
            _sprites.TryGet("codex_instance_dormant", out instanceSprite);
        for (int side = 0; side < 2; side++)
        {
            for (int index = 0; index < 127; index++)
            {
                int column = index % 7;
                int row = index / 7;
                int x = side == 0 ? 5 + column * 6 : _width - sideWidth + 3 + column * 6;
                int y = 25 + row * Math.Max(7, (_height - 53) / 17);
                if (hasInstanceSprite)
                    DrawSpriteScaled(frame, instanceSprite, x, y - 1, 5, 7);
                else DrawCodexInstanceContour(frame, x, y, index, ground.CodexOpened);
            }
        }

        int centerX = _width / 2;
        int bookY = _height <= 224 ? 78 : 91;
        if (_sprites?.TryGet("codex_wall_panel", out Sprite wallPanel) == true)
            DrawSpriteScaled(frame, wallPanel, centerX - 63, 20, 126, 58);
        if (_sprites?.TryGet("codex_clock_seal", out Sprite clockSeal) == true)
            DrawSpriteScaled(frame, clockSeal, centerX - 43, bookY - 61, 86, 86);
        else if (_sprites?.TryGet("dungeon_runic_arch", out Sprite arch) == true)
            DrawSpriteScaled(frame, arch, centerX - 54, bookY - 65, 108, 74);
        else
        {
            DrawCircleOutline(frame, centerX, bookY - 18, 51, 0xff354c59);
            DrawCircleOutline(frame, centerX, bookY - 18, 43, 0xff172c35);
        }

        string bookName = !ground.CodexOpened ? "codex_book_closed" :
            ground.CodexAge < 52 ? "codex_book_open" : "codex_book_awake";
        if (_sprites?.TryGet(bookName, out Sprite codexBook) == true)
            DrawSpriteScaled(frame, codexBook, centerX - 47, bookY - 34, 94, 72);
        else if (_sprites?.TryGet("dungeon_temple_altar", out Sprite altar) == true)
            DrawSpriteScaled(frame, altar, centerX - 31, bookY - 4, 62, 54);
        else
        {
            DrawRect(frame, centerX - 27, bookY + 3, 54, 31, 0xff352a26);
            DrawLine(frame, centerX - 27, bookY + 3, centerX + 27, bookY + 3, 0xffb58a53);
        }

        if (_sprites?.TryGet(bookName, out _) != true)
        {
            int opening = ground.CodexOpened ? Math.Min(18, ground.CodexAge / 3) : 0;
            uint page = ground.CodexOpened ? 0xffd7e4df : 0xff6b7776;
            DrawRect(frame, centerX - 4 - opening, bookY - 7, 4 + opening, 11, page);
            DrawRect(frame, centerX, bookY - 7, 4 + opening, 11, page);
            DrawLine(frame, centerX, bookY - 8, centerX, bookY + 5, 0xffffd66b);
            DrawLine(frame, centerX - 5 - opening, bookY + 5, centerX + 5 + opening, bookY + 5, 0xff7fc7ff);
        }

        int pulse = ground.CodexOpened ? 22 + ground.CodexAge / 5 % 10 : 18 + ground.Age / 8 % 5;
        DrawCircleOutline(frame, centerX, bookY, pulse, ground.CodexOpened ? 0xffbdf8ff : 0xff39545f);
        if (ground.CodexOpened && _sprites?.TryGet("codex_recognition_ring", out Sprite ring) == true)
            DrawSpriteScaled(frame, ring, (int)ground.KarlX - 34, (int)ground.KarlY - 28, 68, 56);
        if (!ground.CodexOpened)
            DrawText(frame, centerX - 51, bookY + 51, "SILVERKROPP IGENKÄND", 0xff66828c);
    }

    private void DrawCodexInstanceContour(uint[] frame, int x, int y, int index, bool awake)
    {
        uint color = awake && (index + 1) % 17 == 0 ? 0xff314c55 : 0xff18282e;
        DrawLine(frame, x + 2, y, x + 2, y + 4, color);
        DrawLine(frame, x, y + 2, x + 4, y + 2, color);
        if ((index & 3) == 0) DrawRect(frame, x + 2, y - 1, 1, 1, color);
    }

    private void DrawCopenhagenCodexSequence(uint[] frame, CopenhagenGroundState ground)
    {
        int age = ground.CodexAge;
        if (age < 64) return;
        int width = Math.Min(304, _width - 12);
        int x = (_width - width) / 2;
        int y = _height <= 224 ? 49 : 60;
        int height = age >= 246 ? 108 : age >= 156 ? 76 : 48;
        DrawRect(frame, x, y, width, height, 0xf2070c11);
        DrawLine(frame, x, y, x + width - 1, y, 0xffffd66b);
        DrawLine(frame, x, y + height - 1, x + width - 1, y + height - 1, 0xff2f74c9);
        DrawText(frame, x + (width - 84) / 2, y + 11, "CODEX ARGENTUM", 0xffffd66b);

        if (age >= 96)
        {
            const string recognized = "ANVÄNDARE IGENKÄND: KARL, INSTANS 255";
            DrawText(frame, x + (width - recognized.Length * 6) / 2, y + 30, recognized, 0xffbdf8ff);
        }
        if (age >= 156)
        {
            const string failed = "FÖREGÅENDE 254 EXEKVERINGAR MISSLYCKADES";
            DrawText(frame, x + (width - failed.Length * 6) / 2, y + 49, failed, 0xff748b95);
        }
        if (age >= 246)
        {
            const string prompt = "ÅTERUPPTA KRIGET?";
            uint promptColor = age / 30 % 2 == 0 ? 0xffffd66b : 0xffbdf8ff;
            DrawText(frame, x + (width - prompt.Length * 6) / 2, y + 72, prompt, promptColor);
            DrawText(frame, x + (width - 174) / 2, y + 91, "INGET SVAR ÄR SKRIVET", 0xff526973);
        }
        if (age >= 330)
        {
            const string end = "STORMAKT 3020 · KÖPENHAMNS RING";
            DrawText(frame, (_width - end.Length * 6) / 2, _height - 30, end, 0xff66828c);
        }
        if (age >= 438)
        {
            string margin = age / 18 % 2 == 0 ? "MARGINAL: KARL ÄR..." : "MARGINAL: KARL ÄR";
            DrawText(frame, 9, _height - 18, margin, 0xff263b43);
        }
    }

    private void DrawCopenhagenGroundHeartDoor(uint[] frame, CopenhagenGroundState? ground)
    {
        int x = _width / 2;
        int y = 42;
        bool open = ground?.HeartPortOpen == true;
        string heartAsset = open ? "holmen_heart_open" : "holmen_heart_sealed";
        if (_sprites?.TryGet(heartAsset, out Sprite heart) == true)
        {
            DrawSprite(frame, heart, x - heart.Width / 2, 18);
            if (open)
            {
                uint pulse = ground?.ActiveMarginal == CopenhagenMarginalLaw.HeartIsOpen
                    ? 0xffff6b7f : 0xffd6b25e;
                DrawCircleOutline(frame, x, y + 5, 25 + (ground?.Age ?? 0) / 6 % 5, pulse);
            }
            return;
        }
        uint color = open ? 0xff7fc7ff : 0xff4b5358;
        FillCircle(frame, x - 8, y, 11, 0xff29343a);
        FillCircle(frame, x + 8, y, 11, 0xff29343a);
        FillTriangle(frame, x, y + 22, x - 18, y, x + 18, y, 0xff29343a);
        DrawCircleOutline(frame, x - 8, y, 12, color);
        DrawCircleOutline(frame, x + 8, y, 12, color);
        DrawLine(frame, x - 17, y, x, y + 22, color);
        DrawLine(frame, x + 17, y, x, y + 22, color);
        if (open)
            DrawCircleOutline(frame, x, y + 5, 24 + (ground?.Age ?? 0) / 6 % 5, 0xffd6b25e);
    }

    private void DrawCopenhagenArsenalCannon(uint[] frame, CopenhagenGroundState ground)
    {
        (double cannonXD, double cannonYD) = CopenhagenArsenalCannonPosition();
        int x = (int)Math.Round(cannonXD);
        int y = (int)Math.Round(cannonYD);
        bool live = ground.ArsenalCannonHealth > 0;
        string asset = live ? "enemy_bridge_cannon" : "enemy_bridge_cannon_wreck";
        if (_sprites?.TryGet(asset, out Sprite cannon) == true)
            DrawSprite(frame, cannon, x - cannon.Width / 2, y - cannon.Height / 2);
        else
        {
            FillCircle(frame, x, y, 13, live ? 0xff29343a : 0xff171b1e);
            DrawLine(frame, x, y, x, y + 25, live ? 0xffd6b25e : 0xff592531);
        }
        if (!live) return;
        int cycle = ground.ArsenalCannonAttackAge % 120;
        if (cycle is >= 36 and < 72)
        {
            uint warning = (cycle & 7) < 4 ? 0xffff6b7f : 0xff8f2635;
            DrawLine(frame, x - 7, y + 13, x - 7, _height - 14, warning);
            DrawLine(frame, x + 7, y + 13, x + 7, _height - 14, warning);
        }
        if (ground.ArsenalCannonHitFlash > 0)
            DrawCircleOutline(frame, x, y, 17 + ground.ArsenalCannonHitFlash, 0xffffffff);
        int maximum = ground.TestFixture ? 18 : CopenhagenArsenalCannonHealth;
        DrawRect(frame, x - 19, y + 24, 38 * ground.ArsenalCannonHealth / maximum, 4, 0xff7fc7ff);
    }

    private void DrawCopenhagenRosenborgRoom(uint[] frame, CopenhagenGroundState ground)
    {
        int gateX = _width / 2;
        string gateName = ground.DoorReady ? "dungeon_temple_gate_open" : "dungeon_temple_gate_closed";
        if (_sprites?.TryGet(gateName, out Sprite gate) == true)
            DrawSpriteScaled(frame, gate, gateX - 28, 20, 56, 43);
        else
        {
            DrawRect(frame, gateX - 24, 20, 48, 35, 0xff171b1e);
            DrawCircleOutline(frame, gateX, 42, 19, ground.DoorReady ? 0xff77e6a0 : 0xff765139);
        }

        (double coreXD, double coreYD) = CopenhagenRosenborgCorePosition();
        int coreX = (int)Math.Round(coreXD);
        int coreY = (int)Math.Round(coreYD);
        string coreName = ground.RosenborgCoreHealth > 0 ? "cph_rosen_core" : "cph_rosen_core_broken";
        if (_sprites?.TryGet(coreName, out Sprite rosenCore) == true)
            DrawSprite(frame, rosenCore, coreX - rosenCore.Width / 2, coreY - rosenCore.Height / 2);
        else if (_sprites?.TryGet("dungeon_twisted_silver", out Sprite silver) == true)
            DrawSpriteScaled(frame, silver, coreX - 24, coreY - 25, 48, 48);
        else
        {
            FillCircle(frame, coreX, coreY, 17, 0xff29343a);
            DrawCircleOutline(frame, coreX, coreY, 21, 0xff7fc7ff);
        }
        bool live = ground.RosenborgCoreHealth > 0;
        uint coreColor = ground.RosenborgCoreHitFlash > 0 ? 0xffffffff : live ? 0xff9bd4dc : 0xff592531;
        DrawCircleOutline(frame, coreX, coreY, 23 + ground.Age / 7 % 4, coreColor);
        if (live)
        {
            int cycle = ground.RosenborgCoreAttackAge % 120;
            if (cycle is >= 42 and < 70)
            {
                uint warning = (cycle & 5) < 3 ? 0xffff8a4a : 0xff8f2635;
                for (int lane = -16; lane <= 16; lane += 8)
                {
                    DrawLine(frame, coreX + lane, 46, coreX + lane, _height - 18,
                        lane is -16 or 16 ? warning : 0xff592531);
                    DrawLine(frame, 8, coreY + lane, _width - 8, coreY + lane,
                        lane is -16 or 16 ? warning : 0xff592531);
                }
                DrawLine(frame, coreX - 22, 46, coreX - 22, _height - 18, warning);
                DrawLine(frame, coreX + 22, 46, coreX + 22, _height - 18, warning);
                DrawLine(frame, 8, coreY - 16, _width - 8, coreY - 16, warning);
                DrawLine(frame, 8, coreY + 16, _width - 8, coreY + 16, warning);
            }
            int maximum = ground.TestFixture ? 18 : CopenhagenRosenborgCoreHealth;
            DrawRect(frame, coreX - 24, coreY + 29, 48 * ground.RosenborgCoreHealth / maximum, 4, 0xff9bd4dc);
        }

        int lecternX = _width / 2;
        int lecternY = _height - 52;
        if (_sprites?.TryGet("dungeon_temple_altar", out Sprite altar) == true)
            DrawSpriteScaled(frame, altar, lecternX - 22, lecternY - 18, 44, 35);
        else
        {
            FillTriangle(frame, lecternX, lecternY - 14, lecternX - 18, lecternY + 13,
                lecternX + 18, lecternY + 13, 0xff52636a);
            DrawLine(frame, lecternX - 13, lecternY - 5, lecternX + 13, lecternY - 5, 0xff7fc7ff);
        }
        DrawCircleOutline(frame, lecternX, lecternY, 21 + ground.Age / 10 % 3,
            ground.MarginalChoosing ? 0xffffd66b : 0xff7fc7ff);
    }

    private void DrawCopenhagenMemoryMachineRoom(uint[] frame, CopenhagenGroundState ground)
    {
        int centerX = _width / 2;
        int centerY = 91;
        string gateName = ground.DoorReady ? "dungeon_temple_gate_open" : "dungeon_temple_gate_closed";
        if (_sprites?.TryGet(gateName, out Sprite gate) == true)
            DrawSpriteScaled(frame, gate, centerX - 28, 20, 56, 43);
        else DrawCircleOutline(frame, centerX, 42, 21, ground.DoorReady ? 0xff77e6a0 : 0xff765139);

        Sprite memoryMachine = default;
        bool packedMemory = _sprites is not null && _sprites.TryGet("cph_memory_machine", out memoryMachine);
        if (packedMemory)
            DrawSprite(frame, memoryMachine, centerX - memoryMachine.Width / 2, centerY - memoryMachine.Height / 2);
        else if (_sprites?.TryGet("dungeon_runic_arch", out Sprite arch) == true)
            DrawSpriteScaled(frame, arch, centerX - 38, centerY - 36, 76, 70);
        for (int ring = 0; ring < 4; ring++)
        {
            int pulse = (ground.Age / (5 + ring) + ring * 3) % 7;
            uint color = ring % 2 == 0 ? 0xff7fc7ff : 0xffffd66b;
            if (!packedMemory || ring == 3)
                DrawCircleOutline(frame, centerX, centerY, 18 + ring * 9 + pulse, color);
        }
        if (!packedMemory) for (int spoke = 0; spoke < 8; spoke++)
        {
            double angle = ground.Age * 0.012 * (spoke % 2 == 0 ? 1 : -1) + spoke * Math.PI / 4;
            DrawLine(frame, centerX, centerY,
                centerX + (int)Math.Round(Math.Cos(angle) * 48),
                centerY + (int)Math.Round(Math.Sin(angle) * 31), 0xff52636a);
        }
        if (ground.LegendChoosing || ground.LegendCompileAge > 0)
            DrawCircleOutline(frame, centerX, _height - 68, 27 + ground.Age / 8 % 4, 0xffffd66b);
    }

    private void DrawCopenhagenWrathRoom(uint[] frame, CopenhagenGroundState ground)
    {
        int centerX = _width / 2;
        int circuitY = _height - 82;
        int phase = CopenhagenWrathPhase(ground);
        string gateName = ground.DoorReady ? "dungeon_temple_gate_open" : "dungeon_temple_gate_closed";
        if (_sprites?.TryGet(gateName, out Sprite gate) == true)
            DrawSpriteScaled(frame, gate, centerX - 30, 18, 60, 45);
        if (_sprites?.TryGet("dungeon_runic_arch", out Sprite arch) == true)
        {
            DrawSpriteScaled(frame, arch, 5, 48, 58, 108);
            DrawSpriteScaled(frame, arch, _width - 63, 48, 58, 108);
        }
        if (phase == 0 && _sprites?.TryGet("dungeon_temple_altar", out Sprite altar) == true)
            DrawSpriteScaled(frame, altar, centerX - 22, _height - 74, 44, 38);

        Sprite claimCircuit = default;
        bool packedCircuit = _sprites is not null && _sprites.TryGet("cph_wrath_circuit", out claimCircuit);
        if (packedCircuit)
            DrawSprite(frame, claimCircuit, centerX - claimCircuit.Width / 2, circuitY - claimCircuit.Height / 2);
        uint circuitColor = phase == 3 ? 0xffbdf8ff : 0xff344d5c;
        if (!packedCircuit) for (int ring = 0; ring < 4; ring++)
            DrawCircleOutline(frame, centerX, circuitY,
                24 + ring * 11 + (phase == 3 ? ground.WrathAge / 7 % 4 : 0),
                ring % 2 == 0 ? circuitColor : 0xffffd66b);
        if (!packedCircuit) for (int spoke = 0; spoke < 8; spoke++)
        {
            double angle = spoke * Math.PI / 4 + (phase == 3 ? ground.WrathAge * 0.008 : 0);
            DrawLine(frame, centerX, circuitY,
                centerX + (int)Math.Round(Math.Cos(angle) * 58),
                circuitY + (int)Math.Round(Math.Sin(angle) * 38), 0xff52636a);
        }

        if (phase == 0)
        {
            int cycle = ground.WrathAge % 220;
            bool warning = cycle is >= 28 and < 104 && !CopenhagenWrathLawMatched(ground);
            if (warning)
            {
                uint color = 0xffff8a4a;
                int targetX = (int)ground.WrathTargetX;
                int targetY = (int)ground.WrathTargetY;
                if (ground.WrathRoyalLaw == CopenhagenRoyalLaw.FlightClaim)
                    DrawCircleOutline(frame, targetX, targetY, 31 + ground.WrathAge / 5 % 10, color);
                else if (ground.WrathRoyalLaw == CopenhagenRoyalLaw.GuiltClaim)
                {
                    DrawLine(frame, targetX - 18, 46, targetX - 18, _height - 14, color);
                    DrawLine(frame, targetX + 18, 46, targetX + 18, _height - 14, color);
                    DrawLine(frame, 8, targetY - 15, _width - 8, targetY - 15, color);
                    DrawLine(frame, 8, targetY + 15, _width - 8, targetY + 15, color);
                }
                else
                {
                    DrawLine(frame, 8, targetY - 19, _width - 8, targetY - 19, color);
                    DrawLine(frame, 8, targetY + 19, _width - 8, targetY + 19, color);
                    for (int crown = 22; crown < _width; crown += 54)
                        DrawCrown(frame, crown, targetY - 27, color);
                }
            }
            DrawText(frame, 8, 29, CopenhagenRoyalLawText(ground.WrathRoyalLaw),
                CopenhagenWrathLawMatched(ground) ? 0xff77e6a0 : 0xffff8a4a);
            DrawText(frame, 8, 39, CopenhagenWrathLawMatched(ground)
                ? "MOTLAGEN GÄLLER" : "SKRIV MOTLAGEN VID LEKTOR", 0xffbdf8ff);
        }
        else if (phase == 1)
        {
            int cycle = ground.WrathAge % 174;
            int memory = ground.WrathOrderSerial % 3;
            if (cycle is >= 22 and < 92)
            {
                uint color = 0xffff8a4a;
                int targetX = (int)ground.WrathTargetX;
                int targetY = (int)ground.WrathTargetY;
                if (memory == 0)
                    for (int offset = -1; offset <= 1; offset++)
                    {
                        int x = targetX + offset * 58;
                        DrawLine(frame, x - 14, 46, x - 14, _height - 14, color);
                        DrawLine(frame, x + 14, 46, x + 14, _height - 14, color);
                    }
                else if (memory == 1)
                {
                    DrawLine(frame, targetX - 17, 46, targetX - 17, _height - 14, color);
                    DrawLine(frame, targetX + 17, 46, targetX + 17, _height - 14, color);
                    DrawLine(frame, 8, targetY - 14, _width - 8, targetY - 14, color);
                    DrawLine(frame, 8, targetY + 14, _width - 8, targetY + 14, color);
                }
                else
                    for (int offset = -1; offset <= 1; offset++)
                    {
                        int x = targetX + offset * 52;
                        int y = targetY + Math.Abs(offset) * 13;
                        DrawCircleOutline(frame, x, y, 20 + ground.WrathAge / 5 % 7, color);
                        FillTriangle(frame, x, y - 27, x - 5, y - 17, x + 5, y - 17, 0xffffd66b);
                    }
            }
            DrawText(frame, 8, 29, CopenhagenWrathMemoryText(memory), 0xffffd66b);
        }
        else if (phase == 2)
        {
            string[] words = ["DANSKT", "SILVER", "KRONAN"];
            for (int word = 0; word < ground.WrathWordHealth.Length; word++)
            {
                (double wordXD, double wordYD) = CopenhagenWrathWordPosition(ground, word);
                int x = (int)Math.Round(wordXD);
                int y = (int)Math.Round(wordYD);
                if (ground.WrathWordHealth[word] <= 0)
                {
                    DrawText(frame, x - words[word].Length * 3, y - 3, words[word], 0xff52636a);
                    DrawLine(frame, x - 22, y + 4, x + 22, y - 5, 0xff592531);
                    continue;
                }
                uint color = ground.WrathWordHitFlash[word] > 0 ? 0xffffffff :
                    word == ground.WrathOrderSerial % 3 ? 0xffff8a4a : 0xffbdf8ff;
                DrawRect(frame, x - 26, y - 10, 52, 19, 0xff101820);
                DrawLine(frame, x - 26, y - 10, x + 25, y - 10, color);
                DrawLine(frame, x - 26, y + 8, x + 25, y + 8, color);
                DrawText(frame, x - words[word].Length * 3, y - 3, words[word], color);
                int maximum = ground.TestFixture ? 18 : CopenhagenWrathWordHealth;
                DrawRect(frame, x - 20, y + 12, 40 * ground.WrathWordHealth[word] / maximum, 3, color);
            }
            DrawText(frame, 8, 29, ground.WrathWordHealth.All(health => health <= 0)
                ? "MARGINALEN ÄR ÅTERHÄMTAD" : "ÅTERTAG DE STULNA ORDEN", 0xffbdf8ff);
        }
        else
        {
            bool inside = DistanceSquared(ground.KarlX, ground.KarlY, centerX, circuitY) < 58 * 58;
            DrawText(frame, 8, 29, ground.WrathHealth <= 0 ? "ANSPRÅKET ÄR BRUTET" :
                inside ? "ANSPRÅKET KOMPILERAS" : "STÅ I SILVERKRETSEN",
                ground.WrathHealth <= 0 || inside ? 0xff77e6a0 : 0xffff8a4a);
            int progress = Math.Min(72, 72 * ground.WrathCircuitStandAge / 24);
            DrawRect(frame, 8, 40, 72, 4, 0xff29343a);
            DrawRect(frame, 8, 40, progress, 4, 0xffbdf8ff);
        }

        (double bossXD, double bossYD) = CopenhagenWrathPosition(ground);
        int bossX = (int)Math.Round(bossXD);
        int bossY = (int)Math.Round(bossYD);
        if (ground.WrathHealth > 0)
        {
            if (_sprites?.TryGet("tithe_module_seizure_armor", out Sprite armor) == true)
                DrawSpriteScaled(frame, armor, bossX - 48, bossY - 48, 96, 92);
            else
            {
                FillTriangle(frame, bossX, bossY - 45, bossX - 45, bossY + 28,
                    bossX + 45, bossY + 28, 0xff29343a);
                DrawCircleOutline(frame, bossX, bossY - 8, 38, 0xffffd66b);
            }
            FillTriangle(frame, bossX, bossY - 44, bossX - 38, bossY + 31,
                bossX + 38, bossY + 31, phase == 3 ? 0xff592531 : 0xff8f2635);
            if (_sprites?.TryGet("holmen_guard_idle", out Sprite christian) == true)
                DrawSpriteScaled(frame, christian, bossX - 29, bossY - 57, 58, 72);
            DrawCrown(frame, bossX - 2, bossY - 61, 0xffffd66b);
            DrawCrown(frame, bossX - 10, bossY - 57, 0xffffec9a);
            DrawCrown(frame, bossX + 6, bossY - 57, 0xffffec9a);
            if (phase == 3)
                for (int chain = -1; chain <= 1; chain += 2)
                {
                    int chainX = bossX + chain * 32;
                    DrawLine(frame, chainX, bossY - 8, chainX + chain * 18, circuitY + 34, 0xff765139);
                    for (int link = 0; link < 5; link++)
                        DrawCircleOutline(frame, chainX + chain * link * 4,
                            bossY + 2 + link * 15, 4, 0xffb78a4e);
                }
        }
        else
        {
            if (_sprites?.TryGet("holmen_guard_idle", out Sprite fallenChristian) == true)
                DrawSpriteScaledAlpha(frame, fallenChristian, bossX - 34, bossY - 15, 68, 52, 115);
            FillTriangle(frame, bossX, bossY + 10, bossX - 39, bossY + 35,
                bossX + 39, bossY + 35, 0xff592531);
            DrawLine(frame, bossX - 36, bossY + 15, bossX + 34, bossY + 34, 0xff765139);
            DrawCircleOutline(frame, bossX - 25, bossY + 29, 8, 0xff29343a);
            DrawCircleOutline(frame, bossX + 21, bossY + 28, 7, 0xff29343a);
            DrawCrown(frame, bossX + 29, bossY + 27, 0xffffd66b);
        }
        bool vulnerable = CopenhagenWrathCanTakeDamage(ground);
        if (ground.WrathHealth > 0)
            DrawCircleOutline(frame, bossX, bossY - 11, vulnerable ? 33 : 45,
                ground.WrathHitFlash > 0 ? 0xffffffff : vulnerable ? 0xffff6b7f : 0xff7fc7ff);
    }

    private static string CopenhagenRoyalLawText(CopenhagenRoyalLaw law) => law switch
    {
        CopenhagenRoyalLaw.FlightClaim => "KUNGLIG LAG · ALLT DANSKT MÅ FLYGA",
        CopenhagenRoyalLaw.GuiltClaim => "KUNGLIG LAG · KRONANS SKULD VÄGER INTET",
        _ => "KUNGLIG LAG · KRONAN ÄGER ALLT",
    };

    private static string CopenhagenWrathMemoryText(int memory) => memory switch
    {
        0 => "KOMPILERAT MINNE · TREKRONERS LÅS",
        1 => "KOMPILERAT MINNE · ØRESUNDS ØJE",
        _ => "KOMPILERAT MINNE · SAGOKONUNGEN",
    };

    private void DrawCopenhagenKorrektoriusRoom(uint[] frame, CopenhagenGroundState ground)
    {
        int centerX = _width / 2;
        string gateName = ground.DoorReady ? "dungeon_temple_gate_open" : "dungeon_temple_gate_closed";
        if (_sprites?.TryGet(gateName, out Sprite gate) == true)
            DrawSpriteScaled(frame, gate, centerX - 28, 20, 56, 43);
        if (_sprites?.TryGet("dungeon_runic_arch", out Sprite arch) == true)
        {
            DrawSpriteScaled(frame, arch, 7, 54, 54, 95);
            DrawSpriteScaled(frame, arch, _width - 61, 54, 54, 95);
        }
        if (_sprites?.TryGet("dungeon_temple_altar", out Sprite altar) == true)
            DrawSpriteScaled(frame, altar, centerX - 23, _height - 76, 46, 39);
        DrawCircleOutline(frame, centerX, _height - 52, 24 + ground.Age / 8 % 3, 0xff7fc7ff);

        if (ground.LocalLaw == CopenhagenLocalLaw.NoDanishWorkMayFly)
        {
            for (int line = 0; line < 7; line++)
            {
                int x = 30 + line * (_width - 60) / 6;
                int y = 54 + (ground.KorrektoriusAge * 3 + line * 29) % Math.Max(1, _height - 96);
                DrawLine(frame, x, y - 11, x, y + 11, 0xff7fc7ff);
            }
        }
        else if (ground.LocalLaw == CopenhagenLocalLaw.SilverLighterThanGuilt)
        {
            for (int ring = 0; ring < 3; ring++)
                DrawCircleOutline(frame, (int)ground.KarlX, (int)ground.KarlY - 7,
                    17 + ring * 7 + ground.Age / 7 % 3, ring == 0 ? 0xffffffff : 0xff7fc7ff);
        }
        else if (ground.LocalLaw == CopenhagenLocalLaw.CrownOwnsOnlyWhatItCarries)
        {
            for (int pen = 0; pen < ground.KorrektoriusPenHealth.Length; pen++)
            {
                if (ground.KorrektoriusPenHealth[pen] <= 0) continue;
                (double penXD, double penYD) = CopenhagenKorrektoriusPenPosition(ground, pen);
                DrawCrown(frame, (int)penXD - 2, (int)penYD - 19, 0xffffd66b);
            }
        }

        int period = ground.LocalLaw switch
        {
            CopenhagenLocalLaw.NoDanishWorkMayFly => 198,
            CopenhagenLocalLaw.SilverLighterThanGuilt => 180,
            _ => 168,
        };
        int cycle = ground.KorrektoriusAge % period;
        bool warning = ground.KorrektoriusActivePen is >= 0 and < 4 && cycle is >= 18 and < 102 &&
            ground.KorrektoriusPenHealth[ground.KorrektoriusActivePen] > 0;
        if (warning || ground.KorrektoriusCorruptionAge > 0)
        {
            uint ink = warning ? 0xffff8a4a : 0xffff6b7f;
            int targetX = (int)ground.KorrektoriusTargetX;
            int targetY = (int)ground.KorrektoriusTargetY;
            switch (ground.KorrektoriusCorruption)
            {
                case CopenhagenCorruption.Negation:
                    DrawCircleOutline(frame, targetX, targetY, 28 + (ground.Age / 4 % 9), ink);
                    break;
                case CopenhagenCorruption.NationSwap:
                    DrawLine(frame, targetX - 17, 46, targetX - 17, _height - 14, ink);
                    DrawLine(frame, targetX + 17, 46, targetX + 17, _height - 14, ink);
                    DrawLine(frame, 8, targetY - 14, _width - 8, targetY - 14, ink);
                    DrawLine(frame, 8, targetY + 14, _width - 8, targetY + 14, ink);
                    break;
                case CopenhagenCorruption.Punctuation:
                    int leftEdge = targetX < centerX ? 8 : centerX;
                    int rightEdge = targetX < centerX ? centerX : _width - 8;
                    for (int stripeY = 52; stripeY < _height - 20; stripeY += 16)
                        DrawLine(frame, leftEdge, stripeY, rightEdge, stripeY + 8, 0xff592531);
                    DrawLine(frame, centerX, 46, centerX, _height - 14, ink);
                    break;
                case CopenhagenCorruption.WeightSwap:
                    for (int offset = -1; offset <= 1; offset++)
                        DrawCircleOutline(frame, targetX + offset * 48,
                            targetY + Math.Abs(offset) * 13, 18 + ground.Age / 5 % 6, ink);
                    break;
            }
            DrawText(frame, 8, 29, CopenhagenCorruptionText(ground.KorrektoriusCorruption), ink);
        }

        for (int pen = 0; pen < ground.KorrektoriusPenHealth.Length; pen++)
        {
            (double penXD, double penYD) = CopenhagenKorrektoriusPenPosition(ground, pen);
            int x = (int)Math.Round(penXD);
            int y = (int)Math.Round(penYD);
            if (ground.KorrektoriusPenHealth[pen] <= 0)
            {
                if (_sprites?.TryGet("cph_pen_broken", out Sprite brokenPen) == true)
                    DrawSprite(frame, brokenPen, x - brokenPen.Width / 2, y - brokenPen.Height / 2);
                else
                {
                    DrawLine(frame, x - 12, y + 7, x + 11, y - 5, 0xff592531);
                    DrawLine(frame, x - 7, y - 3, x + 7, y + 5, 0xff29343a);
                }
                continue;
            }
            double angle = ground.KorrektoriusAge * 0.025 * (pen % 2 == 0 ? 1 : -1) + pen;
            int tipX = x + (int)Math.Round(Math.Cos(angle) * 25);
            int tipY = y + (int)Math.Round(Math.Sin(angle) * 25);
            uint penColor = ground.KorrektoriusPenHitFlash[pen] > 0 ? 0xffffffff :
                pen == ground.KorrektoriusActivePen ? 0xffff8a4a : 0xffb7c7d6;
            DrawLine(frame, x, y, tipX, tipY, penColor);
            if (_sprites?.TryGet("cph_pen", out Sprite penSprite) == true)
            {
                DrawSprite(frame, penSprite, x - penSprite.Width / 2, y - penSprite.Height / 2);
                if (pen == ground.KorrektoriusActivePen) DrawCircleOutline(frame, x, y, 15, penColor);
            }
            else
            {
                FillTriangle(frame, tipX, tipY, x - 7, y - 5, x + 6, y + 6, penColor);
                DrawCircleOutline(frame, x, y, pen == ground.KorrektoriusActivePen ? 15 : 11, penColor);
            }
            int maximum = ground.TestFixture ? 18 : CopenhagenKorrektoriusPenHealth;
            DrawRect(frame, x - 13, y + 16, 26 * ground.KorrektoriusPenHealth[pen] / maximum, 3, 0xff7fc7ff);
        }

        (double bossXD, double bossYD) = CopenhagenKorrektoriusPosition(ground);
        int bossX = (int)Math.Round(bossXD);
        int bossY = (int)Math.Round(bossYD);
        bool exposed = ground.KorrektoriusPenHealth.All(health => health <= 0);
        if (_sprites?.TryGet("dk_silver_fogde_idle", out Sprite fogde) == true)
        {
            if (ground.KorrektoriusHealth <= 0)
                DrawSpriteScaledAlpha(frame, fogde, bossX - 31, bossY - 28, 62, 70, 120);
            else DrawSpriteScaled(frame, fogde, bossX - 31, bossY - 48, 62, 70);
        }
        else
        {
            FillCircle(frame, bossX, bossY - 23, 10, 0xffffd6b0);
            FillTriangle(frame, bossX, bossY - 13, bossX - 25, bossY + 22,
                bossX + 25, bossY + 22, 0xff29343a);
        }
        if (ground.KorrektoriusHealth > 0)
            DrawCircleOutline(frame, bossX, bossY - 10, exposed ? 25 : 34,
                ground.KorrektoriusHitFlash > 0 ? 0xffffffff : exposed ? 0xffff6b7f : 0xff7fc7ff);
        else
        {
            DrawLine(frame, bossX - 25, bossY + 19, bossX + 25, bossY + 19, 0xff592531);
            DrawLine(frame, bossX - 13, bossY + 13, bossX + 11, bossY + 24, 0xff765139);
        }
        if (!exposed && ground.KorrektoriusHealth > 0)
            for (int pen = 0; pen < 4; pen++)
            {
                (double penX, double penY) = CopenhagenKorrektoriusPenPosition(ground, pen);
                if (ground.KorrektoriusPenHealth[pen] > 0)
                    DrawLine(frame, bossX, bossY - 10, (int)penX, (int)penY, 0xff52636a);
            }
    }

    private static string CopenhagenCorruptionText(CopenhagenCorruption corruption) => corruption switch
    {
        CopenhagenCorruption.Negation => "PENNAN INSKRIVER · ICKE",
        CopenhagenCorruption.NationSwap => "DANSKT BLIR · SVENSKT",
        CopenhagenCorruption.Punctuation => "PUNKTEN FLYTTAS",
        CopenhagenCorruption.WeightSwap => "SILVER BYTS MOT · SKULD",
        _ => "MARGINALEN ÄR REN",
    };

    private void DrawCopenhagenSagaKingRoom(uint[] frame, CopenhagenGroundState ground)
    {
        int phase = CopenhagenSagaKingPhase(ground);
        int period = ground.CompiledLegend == CopenhagenLegend.SevenMooseCaroleans ? 140 : 180;
        int cycle = ground.SagaKingAge % period;
        int execute = period / 2;
        if (phase == 3)
        {
            for (int wave = 0; wave < 6; wave++)
            {
                int y = 74 + wave * 25 + (ground.SagaKingAge / 3 + wave * 7) % 9;
                DrawLine(frame, 8, y, _width - 8, y, wave % 2 == 0 ? 0xff2f74c9 : 0xff7fc7ff);
            }
        }
        else if (cycle is >= 24 && cycle < 90)
        {
            bool suppressed = ground.CompiledLegend == CopenhagenLegend.OneMooseCarolean &&
                (ground.SagaOrderSerial & 1) == 0;
            uint warning = suppressed ? 0xff77e6a0 : 0xffff8a4a;
            if (phase == 0)
            {
                int radius = 22 + (cycle - 24) / 4;
                DrawCircleOutline(frame, (int)ground.SagaTargetX, (int)ground.SagaTargetY, radius, warning);
                DrawCrown(frame, (int)ground.SagaTargetX - 8, (int)ground.SagaTargetY - 17, warning);
            }
            else if (phase == 1)
            {
                int laneY = (int)ground.SagaTargetY;
                DrawLine(frame, 8, laneY - 16, _width - 8, laneY - 16, warning);
                DrawLine(frame, 8, laneY + 16, _width - 8, laneY + 16, warning);
                if (ground.CompiledLegend == CopenhagenLegend.SevenMooseCaroleans)
                {
                    int second = (int)(_height - ground.SagaTargetY + 36);
                    DrawLine(frame, 8, second - 13, _width - 8, second - 13, 0xffff6b7f);
                    DrawLine(frame, 8, second + 13, _width - 8, second + 13, 0xffff6b7f);
                }
            }
            else
            {
                for (int rocket = -1; rocket <= 1; rocket++)
                {
                    int x = (int)ground.SagaTargetX + rocket * 54;
                    int y = (int)ground.SagaTargetY + Math.Abs(rocket) * 12;
                    DrawCircleOutline(frame, x, y, 18 + (cycle - 24) / 7, warning);
                    FillTriangle(frame, x, y - 28, x - 5, y - 18, x + 5, y - 18, 0xffffd66b);
                }
            }
            if (suppressed) DrawText(frame, 8, 29, "MOTLEGEND · ORDEN STRYKS", 0xff77e6a0);
        }

        (double bossXD, double bossYD) = CopenhagenSagaKingPosition(ground);
        int bossX = (int)Math.Round(bossXD);
        int bossY = (int)Math.Round(bossYD);
        if (phase == 3 && _sprites?.TryGet("rts_moose_charge", out Sprite horse) == true)
            DrawSpriteScaled(frame, horse, bossX - horse.Width, bossY - horse.Height / 2,
                horse.Width * 2, horse.Height * 2);
        FillTriangle(frame, bossX, bossY - 42, bossX - 30, bossY + 22,
            bossX + 30, bossY + 22, phase == 3 ? 0xff5e1730 : 0xff8f2635);
        if (_sprites?.TryGet("holmen_guard_idle", out Sprite king) == true)
            DrawSpriteScaled(frame, king, bossX - 31, bossY - 63, 62, 77);
        else
        {
            FillCircle(frame, bossX, bossY - 28, 9, 0xffffd6b0);
            FillTriangle(frame, bossX, bossY - 18, bossX - 20, bossY + 17,
                bossX + 20, bossY + 17, 0xff8f2635);
        }
        int crownWidth = 22 + phase * 2;
        int crownLeft = bossX - crownWidth / 2;
        int crownTop = bossY - 68;
        FillTriangle(frame, crownLeft, crownTop + 11, crownLeft + 3, crownTop,
            crownLeft + 7, crownTop + 11, 0xffffd66b);
        FillTriangle(frame, bossX - 5, crownTop + 11, bossX, crownTop - 4,
            bossX + 5, crownTop + 11, 0xffffec9a);
        FillTriangle(frame, crownLeft + crownWidth - 7, crownTop + 11,
            crownLeft + crownWidth - 3, crownTop, crownLeft + crownWidth, crownTop + 11, 0xffffd66b);
        DrawRect(frame, crownLeft, crownTop + 10, crownWidth, 5, 0xffffd66b);
        DrawLine(frame, crownLeft, crownTop + 15, crownLeft + crownWidth - 1, crownTop + 15, 0xffff8a4a);
        DrawCircleOutline(frame, bossX, bossY - 15, 28 + phase * 3,
            ground.SagaKingHitFlash > 0 ? 0xffffffff : 0xffffd66b);
        if (phase == 1)
        {
            for (int lion = -1; lion <= 1; lion += 2)
            {
                int lionX = bossX + lion * 37;
                if (_sprites?.TryGet("cph_saga_lion", out Sprite sagaLion) == true)
                {
                    if (lion < 0) DrawSprite(frame, sagaLion, lionX - sagaLion.Width / 2, bossY - sagaLion.Height / 2);
                    else DrawSpriteFlippedX(frame, sagaLion, lionX - sagaLion.Width / 2, bossY - sagaLion.Height / 2);
                }
                else
                {
                    FillCircle(frame, lionX, bossY + 5, 8, 0xffff8a4a);
                    FillTriangle(frame, lionX, bossY - 8, lionX - 8, bossY + 8,
                        lionX + 8, bossY + 8, 0xffffd66b);
                }
            }
        }
    }

    private void DrawCopenhagenLegend(uint[] frame, CopenhagenGroundState ground)
    {
        if (ground.ActiveLegend == CopenhagenLegend.None || ground.LegendCompileAge is > 0 and < 38) return;
        int x = (int)Math.Round(ground.LegendX);
        int y = (int)Math.Round(ground.LegendY);
        bool moving = Math.Abs(ground.LegendVx) + Math.Abs(ground.LegendVy) > 0.1;
        string name = moving ? "rts_moose_charge" : "rts_moose_ready";
        if (_sprites?.TryGet(name, out Sprite moose) == true)
        {
            int legendWidth = moose.Width * 3 / 2;
            int legendHeight = moose.Height * 3 / 2;
            if (ground.ActiveLegend == CopenhagenLegend.SevenMooseCaroleans)
            {
                for (int echo = 3; echo >= 1; echo--)
                {
                    int offsetX = (int)Math.Round(-ground.LegendVx * echo * 8);
                    int offsetY = (int)Math.Round(-ground.LegendVy * echo * 6);
                    DrawSpriteScaledAlpha(frame, moose, x - legendWidth / 2 + offsetX,
                        y - legendHeight / 2 + offsetY, legendWidth, legendHeight, (byte)(55 + echo * 28));
                }
            }
            DrawSpriteScaled(frame, moose, x - legendWidth / 2, y - legendHeight / 2,
                legendWidth, legendHeight);
        }
        else
        {
            FillCircle(frame, x, y, 12, ground.LegendCorrupted ? 0xffff6b7f : 0xffbdf8ff);
            DrawLine(frame, x - 13, y - 8, x - 19, y - 18, 0xffffd66b);
            DrawLine(frame, x + 13, y - 8, x + 19, y - 18, 0xffffd66b);
        }
        uint outline = ground.LegendCorrupted ? 0xffff6b7f :
            ground.LegendHitFlash > 0 ? 0xffffffff : 0xff7fc7ff;
        DrawCircleOutline(frame, x, y + 3, 24 + ground.LegendAge / 7 % 3, outline);
        if (ground.LegendCorrupted)
        {
            DrawLine(frame, x, y, x - (int)Math.Round(ground.LegendVx * 14),
                y - (int)Math.Round(ground.LegendVy * 14), 0xffff8a4a);
            DrawText(frame, x - 18, y - 27, "STORMA", 0xffff6b7f);
        }
    }

    private void DrawCopenhagenLegendChoice(uint[] frame, CopenhagenGroundState ground)
    {
        int width = Math.Min(376, _width - 16);
        int x = (_width - width) / 2;
        int y = _height <= 224 ? 73 : 96;
        DrawRect(frame, x, y, width, 91, 0xf2080d12);
        DrawLine(frame, x, y, x + width - 1, y, 0xffffd66b);
        DrawText(frame, x + (width - 180) / 2, y + 8, "ROSENBORG · KOMPILERA LEGEND", 0xffffd66b);
        DrawText(frame, x + (width - 138) / 2, y + 27, "MINNET ÄR EJ HISTORIEN.", 0xffbdf8ff);
        int gap = 6;
        int choiceWidth = (width - 18 - gap) / 2;
        for (int choice = 0; choice < 2; choice++)
        {
            int choiceX = x + 9 + choice * (choiceWidth + gap);
            uint border = ground.LegendSelection == choice ? 0xffffd66b : 0xff344d5c;
            DrawRect(frame, choiceX, y + 42, choiceWidth, 27, 0xff101820);
            DrawLine(frame, choiceX, y + 42, choiceX + choiceWidth - 1, y + 42, border);
            DrawLine(frame, choiceX, y + 68, choiceX + choiceWidth - 1, y + 68, border);
            string label = choice == 0 ? "EN ÄLGKAROLIN STOD." : "SJU ÄLGAR STORMADE.";
            DrawText(frame, choiceX + 5, y + 51, label, choice == 0 ? 0xff77e6a0 : 0xffff8a4a);
        }
        DrawText(frame, x + (width - 144) / 2, y + 75, "PILAR · START KOMPILERA", 0xff9bd4dc);
    }

