            Math.Min(width - 12, (width - 12) * ground.LocalLawCompileAge / 76), 4, color);
        for (int ring = 0; ring < 3; ring++)
            DrawCircleOutline(frame, _width / 2, _height - 52,
                16 + ring * 7 + ground.LocalLawCompileAge / 6 % 5, color);
    }

    private static string CopenhagenLocalLawText(CopenhagenLocalLaw law) => law switch
    {
        CopenhagenLocalLaw.NoDanishWorkMayFly => "INTET DANSKT VERK MÅ FLYGA",
        CopenhagenLocalLaw.SilverLighterThanGuilt => "SILVER VÄGER MINDRE ÄN SKULD",
        CopenhagenLocalLaw.CrownOwnsOnlyWhatItCarries => "KRONAN ÄGER BLOTT VAD DEN BÄR",
        _ => "INGEN LOKAL LAG",
    };

    private void DrawCopenhagenMaterialForm(uint[] frame, CopenhagenGroundState ground)
    {
        int x = (int)Math.Round(ground.KarlX);
        int y = (int)Math.Round(ground.KarlY - 5);
        if (ground.ActiveMarginal == CopenhagenMarginalLaw.SilverIsShield)
        {
            bool charged = ground.MaterialShieldCooldown == 0;
            uint color = charged ? 0xffbdf8ff : 0xff52636a;
            DrawCircleOutline(frame, x, y, 22 + ground.Age / 8 % 3, color);
            for (int plate = 0; plate < 3; plate++)
            {
                double angle = ground.Age * 0.035 + plate * Math.PI * 2 / 3;
                int plateX = x + (int)Math.Round(Math.Cos(angle) * 24);
                int plateY = y + (int)Math.Round(Math.Sin(angle) * 15);
                FillTriangle(frame, plateX, plateY - 5, plateX - 4, plateY + 4, plateX + 4, plateY + 4, color);
            }
            return;
        }
        if (ground.ActiveMarginal != CopenhagenMarginalLaw.SilverIsBlade) return;
        double bladeAngle = ground.MaterialBladeAge * 0.085;
        int hiltX = x + (int)Math.Round(Math.Cos(bladeAngle) * 20);
        int hiltY = y + (int)Math.Round(Math.Sin(bladeAngle) * 13);
        int tipX = x + (int)Math.Round(Math.Cos(bladeAngle) * 37);
        int tipY = y + (int)Math.Round(Math.Sin(bladeAngle) * 25);
        DrawLine(frame, hiltX, hiltY, tipX, tipY, 0xffffffff);
        DrawLine(frame, hiltX - 4, hiltY + 2, hiltX + 4, hiltY - 2, 0xffffd66b);
        FillCircle(frame, tipX, tipY, 2, 0xff7fc7ff);
    }

    private void DrawCopenhagenMarginalChoice(uint[] frame, CopenhagenGroundState ground)
    {
        int width = Math.Min(376, _width - 16);
        int x = (_width - width) / 2;
        int y = _height <= 224 ? 73 : 96;
        int height = 91;
        DrawRect(frame, x, y, width, height, 0xf2080d12);
        DrawLine(frame, x, y, x + width - 1, y, 0xff7fc7ff);
        DrawText(frame, x + (width - 186) / 2, y + 8, "CODEX ARGENTUM · VÄLJ MARGINAL", 0xffffd66b);
        bool material = ground.Room == 2;
        string premise = material ? "SILFRET ÄR ETT REDSKAP." : "HJERTAT ÄR EJ BRUTET.";
        DrawText(frame, x + (width - premise.Length * 6) / 2, y + 27, premise, 0xffbdf8ff);
        int gap = 6;
        int choiceWidth = (width - 18 - gap) / 2;
        for (int choice = 0; choice < 2; choice++)
        {
            int choiceX = x + 9 + choice * (choiceWidth + gap);
            uint border = ground.MarginalSelection == choice ? 0xffffd66b : 0xff344d5c;
            DrawRect(frame, choiceX, y + 42, choiceWidth, 27, 0xff101820);
            DrawLine(frame, choiceX, y + 42, choiceX + choiceWidth - 1, y + 42, border);
            DrawLine(frame, choiceX, y + 68, choiceX + choiceWidth - 1, y + 68, border);
            DrawText(frame, choiceX + 5, y + 51,
                material
                    ? choice == 0 ? "SILFRET ÄR EN SKÖLD." : "SILFRET ÄR EN KLINGA."
                    : choice == 0 ? "HJERTAT ÄR EN PORT." : "HJERTAT ÄR ÖPPET.",
                material ? choice == 0 ? 0xff7fc7ff : 0xffffd66b : choice == 0 ? 0xff77e6a0 : 0xffff8a4a);
        }
        DrawText(frame, x + (width - 144) / 2, y + 75, "PILAR · START KOMPILERA", 0xff9bd4dc);
    }

    private void DrawCopenhagenMarginalCompile(uint[] frame, CopenhagenGroundState ground)
    {
        bool material = ground.ActiveMarginal is CopenhagenMarginalLaw.SilverIsShield or CopenhagenMarginalLaw.SilverIsBlade;
        bool correct = ground.ActiveMarginal == CopenhagenMarginalLaw.HeartIsPort;
        int width = Math.Min(286, _width - 26);
        int x = (_width - width) / 2;
        int y = _height <= 224 ? 128 : 166;
        DrawRect(frame, x, y, width, 37, 0xe6080d12);
        uint color = ground.ActiveMarginal switch
        {
            CopenhagenMarginalLaw.SilverIsShield => 0xff7fc7ff,
            CopenhagenMarginalLaw.SilverIsBlade => 0xffffd66b,
            _ => correct ? 0xff7fc7ff : 0xffff6b7f,
        };
        DrawLine(frame, x, y, x + width - 1, y, color);
        string law = ground.ActiveMarginal switch
        {
            CopenhagenMarginalLaw.SilverIsShield => "SILFRET ÄR EN SKÖLD",
            CopenhagenMarginalLaw.SilverIsBlade => "SILFRET ÄR EN KLINGA",
            _ => correct ? "HJERTAT ÄR EN PORT" : "HJERTAT ÄR ÖPPET",
        };
        DrawText(frame, x + (width - law.Length * 6) / 2, y + 8, law, color);
        int duration = material ? 76 : correct ? 112 : 128;
        int progress = Math.Min(width - 12, (width - 12) * ground.MarginalCompileAge / duration);
        DrawRect(frame, x + 6, y + 25, progress, 4, color);
        int heartX = material ? (int)Math.Round(ground.KarlX) : _width / 2;
        int heartY = material ? (int)Math.Round(ground.KarlY - 5) : 47;
        int radius = 25 + ground.MarginalCompileAge / 5 % 14;
        DrawCircleOutline(frame, heartX, heartY, radius, color);
        if (!material && !correct && ground.MarginalCompileAge is >= 45 and < 90)
        {
            for (int ray = 0; ray < 8; ray++)
            {
                double angle = ray * Math.PI / 4.0;
                DrawLine(frame, heartX, heartY,
                    heartX + (int)Math.Round(Math.Cos(angle) * (32 + ray)),
                    heartY + (int)Math.Round(Math.Sin(angle) * (32 + ray)), 0xffff8a4a);
            }
        }
    }

    private void DrawCopenhagenGroundEnemy(uint[] frame, CopenhagenGroundState ground, CopenhagenGroundEnemy enemy)
    {
        int x = (int)Math.Round(enemy.X);
        int y = (int)Math.Round(enemy.Y);
        bool facingLeft = enemy.FacingLeft;
        string spriteName = enemy.Health <= 0
            ? enemy.DeathAge < 18 ? "holmen_guard_fall" : "holmen_guard_dead"
            : enemy.HitFlash > 0 || enemy.StaggerAge > 0 ? "holmen_guard_hit"
            : enemy.AttackAge is >= 28 and < 40 ? "holmen_guard_attack"
            : enemy.AttackAge is > 0 and < 28 ? "holmen_guard_telegraph"
            : enemy.Moving ? ((ground.Age / 10 + enemy.Id) & 1) == 0
                ? "holmen_guard_walk_a" : "holmen_guard_walk_b"
            : "holmen_guard_idle";
        if (_sprites?.TryGet(spriteName, out Sprite guard) == true)
        {
            int sink = enemy.Health <= 0 ? Math.Min(5, enemy.DeathAge / 10) : 0;
            int drawX = x - guard.Width / 2;
            int drawY = y - guard.Height + 12 + sink;
            if (facingLeft) DrawSpriteFlippedX(frame, guard, drawX, drawY);
            else DrawSprite(frame, guard, drawX, drawY);
            if (enemy.Health <= 0) return;
            bool spriteTelegraph = enemy.AttackAge is >= 12 and < 28;
            if (spriteTelegraph) DrawCircleOutline(frame, x, y, 19 + enemy.AttackAge / 4, 0xffff8a4a);
            if (enemy.HitFlash > 0)
            {
                DrawCircleOutline(frame, x, y - 8, 13 + enemy.HitFlash, 0xffffffff);
                DrawLine(frame, x - 15, y - 12, x + 15, y + 4, 0xffbdf8ff);
            }
            DrawRect(frame, x - 11, y + 19, 22 * enemy.Health / enemy.MaxHealth, 3, 0xffff8a4a);
            return;
        }
        if (enemy.Health <= 0)
        {
            int sink = Math.Min(9, enemy.DeathAge / 5);
            DrawLine(frame, x - 13, y + sink, x + 13, y + sink, 0xff592531);
            DrawLine(frame, x - 8, y - 4 + sink, x + 9, y + 5 + sink, 0xff765139);
            return;
        }
        bool telegraph = enemy.AttackAge is >= 12 and < 28;
        uint coat = enemy.HitFlash > 0 ? 0xffffffff : 0xff8f2635;
        FillCircle(frame, x, y - 9, 6, 0xffd8d1b9);
        FillTriangle(frame, x, y - 4, x - 12, y + 16, x + 12, y + 16, coat);
        DrawLine(frame, x - 8, y + 5, x + 8, y + 5, 0xfff2eee4);
        DrawLine(frame, x + 7, y, x + 15, y + (telegraph ? 15 : 7), telegraph ? 0xffffd66b : 0xff765139);
        if (telegraph) DrawCircleOutline(frame, x, y, 19 + enemy.AttackAge / 4, 0xffff8a4a);
        DrawRect(frame, x - 11, y + 19, 22 * enemy.Health / enemy.MaxHealth, 3, 0xffff8a4a);
    }

    private void DrawCopenhagenGroundKarl(uint[] frame, CopenhagenGroundState ground)
    {
        int x = (int)Math.Round(ground.KarlX);
        int y = (int)Math.Round(ground.KarlY);
        bool horizontal = Math.Abs(ground.FacingX) > Math.Abs(ground.FacingY);
        bool north = !horizontal && ground.FacingY < 0;
        bool west = horizontal && ground.FacingX < 0;
        int gait = (int)(ground.GaitDistance / 16.0) & 3;
        string karlAsset;
        if (ground.HitFlash > 0) karlAsset = "karl_hit";
        else if (ground.AttackAge > 0 && horizontal)
            karlAsset = ground.AttackAge > 6 ? "karl_slash_e_windup" : "karl_slash_e_contact";
        else if (ground.AttackAge > 0 && north)
            karlAsset = ground.AttackAge > 8 ? "karl_slash_n_windup" :
                ground.AttackAge > 3 ? "karl_slash_n_contact" : "karl_slash_n_follow";
        else if (ground.AttackAge > 0)
            karlAsset = ground.AttackAge > 8 ? "karl_slash_windup" :
                ground.AttackAge > 3 ? "karl_slash_contact" : "karl_slash_follow";
        else if (north) karlAsset = ground.Moving && gait is 1 or 3 ? "dungeon_karl_n_walk" : "dungeon_karl_n_idle";
        else if (horizontal) karlAsset = ground.Moving && gait is 1 or 3 ? "dungeon_karl_e_walk" : "dungeon_karl_e_idle";
        else karlAsset = !ground.Moving || gait is 0 or 2 ? "dungeon_karl_s_idle" :
            gait == 1 ? "dungeon_karl_s_walk_a" : "dungeon_karl_s_walk_b";
        if (_sprites?.TryGet(karlAsset, out Sprite karl) == true)
        {
            int footAnchor = karlAsset switch
            {
                "karl_slash_windup" or "karl_slash_contact" or "karl_slash_follow" => 20,
                "karl_slash_e_windup" or "karl_slash_e_contact" => 22,
                "karl_slash_n_windup" or "karl_slash_n_contact" or "karl_slash_n_follow" => 16,
                "karl_hit" => 25,
                _ => 12,
            };
            int drawX = x - karl.Width / 2;
            int drawY = y - karl.Height + footAnchor;
            if (west) DrawSpriteFlippedX(frame, karl, drawX, drawY);
            else DrawSprite(frame, karl, drawX, drawY);
            if (ground.HasTarget) DrawCircleOutline(frame, (int)ground.TargetX, (int)ground.TargetY, 6, 0xff7fc7ff);
            return;
        }
        uint silver = ground.HitFlash > 0 ? 0xffffffff : 0xffb7c7d6;
        FillCircle(frame, x, y - 10, 6, 0xffffd6b0);
        FillTriangle(frame, x, y - 5, x - 11, y + 17, x + 11, y + 17, silver);
        DrawLine(frame, x - 7, y + 4, x + 7, y + 4, 0xff2f74c9);
        DrawCrown(frame, x - 4, y - 14, 0xffffd66b);
        int bladeX = x + (int)Math.Round(ground.FacingX * 19);
        int bladeY = y + (int)Math.Round(ground.FacingY * 19);
        DrawLine(frame, x, y + 2, bladeX, bladeY, 0xffd8d1b9);
        if (ground.AttackAge > 0)
        {
            double baseAngle = Math.Atan2(ground.FacingY, ground.FacingX);
            for (int ray = -2; ray <= 2; ray++)
            {
                double angle = baseAngle + ray * 0.22;
                int tipX = x + (int)Math.Round(Math.Cos(angle) * 34);
                int tipY = y + (int)Math.Round(Math.Sin(angle) * 34);
                DrawLine(frame, x, y, tipX, tipY, ray == 0 ? 0xffffffff : 0xff7fc7ff);
            }
        }
        if (ground.HasTarget) DrawCircleOutline(frame, (int)ground.TargetX, (int)ground.TargetY, 6, 0xff7fc7ff);
    }

    private void DrawCopenhagenGroundHud(uint[] frame, CopenhagenGroundState ground)
    {
        DrawRect(frame, 0, 0, _width, 17, 0xff080d12);
        string title = ground.Room switch
        {
            0 => "KARL CCLV · HOLMEN",
            1 => "KARL CCLV · KANONGÅNGEN",
            2 => "KARL CCLV · ROSENBORGS FÖRGÅRD",
            3 => "KARL CCLV · MINNESMASKINEN",
            4 => "KARL CCLV · SAGOKONUNGEN",
            5 => "KARL CCLV · MARGINALVALVET",
            6 => "KARL CCLV · CHRISTIANS VREDE",
            _ => "KARL CCLV · CODEX ARGENTUM",
        };
        DrawText(frame, 6, 5, title, 0xffffd66b);
        if (ground.Room != 7)
        {
            int barX = _width - 105;
            DrawRect(frame, barX, 5, 72, 5, 0xff29343a);
            DrawRect(frame, barX, 5, 72 * ground.Health / Math.Max(1, ground.MaxHealth), 5,
                ground.PotionFlash > 0 ? 0xff77e6a0 : 0xffff6b7f);
            DrawText(frame, _width - 28, 5, $"Q{ground.Potions}", 0xffbdf8ff);
        }
        DrawText(frame, 6, _height - 9, ground.Room == 7
            ? ground.CodexOpened ? "PROTOKOLL LÅST · INGET SVAR" : "NÄRMA DIG CODEXEN"
            : "Z HUGG  RMB GÅ  Q BRYG", 0xffb7c7d6);
        if (_developerMode && _levelId == 6)
            DrawText(frame, 6, 19, "DEVSKÖLD", 0xff77e6a0);
        if (ground.Room == 3 && ground.ActiveLegend != CopenhagenLegend.None)
        {
            bool stable = ground.ActiveLegend == CopenhagenLegend.OneMooseCarolean;
            int maximum = ground.TestFixture ? stable ? 180 : 60 :
                stable ? CopenhagenStableLegendIntegrity : CopenhagenWildLegendIntegrity;
            int legendBarX = _width - 105;
            DrawRect(frame, legendBarX, 19, 72, 4, 0xff29343a);
            DrawRect(frame, legendBarX, 19, 72 * ground.LegendIntegrity / Math.Max(1, maximum), 4,
                ground.LegendCorrupted ? 0xffff6b7f : stable ? 0xff77e6a0 : 0xffff8a4a);
            DrawText(frame, _width - 29, 18, ground.LegendCorrupted ? "FEL" : "MIN", 0xffbdf8ff);
            string legendLaw = ground.LegendCorrupted ? "LEGEND · STORMA" : stable
                ? "LEGEND · EN ÄLGKAROLIN STOD" : "LEGEND · SJU ÄLGAR STORMADE";
            DrawText(frame, 6, _height - 29, legendLaw,
                ground.LegendCorrupted ? 0xffff6b7f : 0xffffd66b);
        }
        if (ground.Room == 4)
        {
            int maximum = ground.TestFixture ? 144 : CopenhagenSagaKingHealth;
            int bossBarX = _width - 105;
            DrawRect(frame, bossBarX, 19, 72, 4, 0xff29343a);
            DrawRect(frame, bossBarX, 19, 72 * ground.SagaKingHealth / Math.Max(1, maximum), 4, 0xffff8a4a);
            DrawText(frame, _width - 29, 18, $"F{CopenhagenSagaKingPhase(ground) + 1}", 0xffffd66b);
            string counter = ground.CompiledLegend == CopenhagenLegend.OneMooseCarolean
                ? "MOTLEGEND · DEN ENSAMME" : "MOTLEGEND · DE SJU";
            DrawText(frame, 6, _height - 29, counter, 0xffffd66b);
        }
        if (ground.Room == 5)
        {
            int maximum = ground.TestFixture ? 72 : CopenhagenKorrektoriusHealth;
            int bossBarX = _width - 105;
            DrawRect(frame, bossBarX, 19, 72, 4, 0xff29343a);
            DrawRect(frame, bossBarX, 19, 72 * ground.KorrektoriusHealth / Math.Max(1, maximum), 4,
                ground.KorrektoriusPenHealth.All(health => health <= 0) ? 0xffff6b7f : 0xff7fc7ff);
            int livingPens = ground.KorrektoriusPenHealth.Count(health => health > 0);
            DrawText(frame, _width - 29, 18, $"P{livingPens}", 0xffffd66b);
            string law = ground.KorrektoriusCorruptionAge > 0
                ? CopenhagenCorruptionText(ground.KorrektoriusCorruption)
                : CopenhagenLocalLawText(ground.LocalLaw);
            DrawText(frame, 6, _height - 29, law,
                ground.KorrektoriusCorruptionAge > 0 ? 0xffff6b7f : 0xff7fc7ff);
        }
        if (ground.Room == 6)
        {
            int maximum = ground.TestFixture ? 240 : CopenhagenWrathHealth;
            int bossBarX = _width - 105;
            DrawRect(frame, bossBarX, 19, 72, 4, 0xff29343a);
            DrawRect(frame, bossBarX, 19, 72 * ground.WrathHealth / Math.Max(1, maximum), 4,
                CopenhagenWrathCanTakeDamage(ground) ? 0xffff6b7f : 0xff7fc7ff);
            int phase = CopenhagenWrathPhase(ground);
            DrawText(frame, _width - 29, 18, $"F{phase + 1}", 0xffffd66b);
            string state = phase switch
            {
                0 => CopenhagenLocalLawText(ground.LocalLaw),
                1 => CopenhagenWrathMemoryText(ground.WrathOrderSerial % 3),
                2 => $"ÅTERTAGNA ORD {ground.WrathWordHealth.Count(health => health <= 0)}/3",
                _ => "CODEX · SILVERKRETSEN ÄR ÖPPEN",
            };
            DrawText(frame, 6, _height - 29, state, phase == 3 ? 0xffbdf8ff : 0xffffd66b);
        }
        string? activeLaw = ground.ActiveMarginal switch
        {
            CopenhagenMarginalLaw.HeartIsPort => "MARGINAL · HJERTAT ÄR EN PORT",
            CopenhagenMarginalLaw.SilverIsShield => ground.MaterialShieldCooldown == 0
                ? "MARGINAL · SILFRET ÄR EN SKÖLD" : "MARGINAL · SKÖLDEN ÅTERSKRIFS",
            CopenhagenMarginalLaw.SilverIsBlade => "MARGINAL · SILFRET ÄR EN KLINGA",
            _ => null,
        };
        if (activeLaw is not null && ground.MarginalCompileAge == 0 && ground.Room != 7)
            DrawText(frame, 6, _height - 19, activeLaw, 0xff7fc7ff);
        if (ground.MarginalCompileAge == 0 && ground.Room == 0 && ground.DoorReady && !ground.HeartPortOpen)
            DrawText(frame, _width - 138, _height - 9, "HJÄRTAT · Z", 0xff7fc7ff);
        else if (ground.MarginalCompileAge == 0 && ground.Room == 0 && ground.HeartPortOpen)
            DrawText(frame, _width - 120, _height - 9, "PORT · UPP", 0xff7fc7ff);
        else if (ground.Room == 1 && ground.DoorReady && !ground.CheckpointReady)
            DrawText(frame, _width - 138, _height - 9, "ROSENBORG · Z", 0xff7fc7ff);
        else if (ground.Room == 2 && ground.DoorReady && !ground.CheckpointReady)
            DrawText(frame, _width - 156, _height - 9, "MINNESMASKIN · Z", 0xff7fc7ff);
        else if (ground.Room == 2 && !ground.MarginalChoosing && ground.MarginalCompileAge == 0)
            DrawText(frame, _width - 120, _height - 9, "LEKTOR · C", 0xff7fc7ff);
        else if (ground.Room == 3 && ground.DoorReady && !ground.CheckpointReady)
            DrawText(frame, _width - 150, _height - 9, "SAGOKONUNG · Z", 0xff7fc7ff);
        else if (ground.Room == 4 && ground.DoorReady && !ground.CheckpointReady)
            DrawText(frame, _width - 162, _height - 9, "MARGINALFOGDE · Z", 0xff7fc7ff);
        else if (ground.Room == 5 && ground.DoorReady && !ground.CheckpointReady)
            DrawText(frame, _width - 150, _height - 9, "CHRISTIANS VREDE · Z", 0xff7fc7ff);
        else if (ground.Room == 5 && !ground.LocalLawChoosing && ground.LocalLawCompileAge == 0)
            DrawText(frame, _width - 120, _height - 9, "LEKTOR · C", 0xff7fc7ff);
        else if (ground.Room == 6 && ground.DoorReady && !ground.CheckpointReady)
            DrawText(frame, _width - 108, _height - 9, "CODEX · Z", 0xff7fc7ff);
        else if (ground.Room == 6 && CopenhagenWrathPhase(ground) == 0 &&
            !ground.LocalLawChoosing && ground.LocalLawCompileAge == 0)
            DrawText(frame, _width - 120, _height - 9, "LEKTOR · C", 0xff7fc7ff);
    }

    private void DrawCopenhagenCheckpointBanner(uint[] frame, CopenhagenWorldState state)
    {
        bool gateCheckpoint = !state.AdmiraltyActive && state.GateFallAge is >= 70 and < 230;
        bool admiralCheckpoint = state.AdmiraltyActive && !state.FrederikActive &&
            state.AdmiraltyDeathAge is >= 70 and < 230;
        bool frederikCheckpoint = state.FrederikActive && !state.EyeActive &&
            state.FrederikDeathAge is >= 70 and < 250;
        if (!gateCheckpoint && !admiralCheckpoint && !frederikCheckpoint) return;
        int width = Math.Min(232, _width - 32);
        int x = (_width - width) / 2;
        int y = _height <= 224 ? 80 : 103;
        DrawRect(frame, x, y, width, 43, 0xee080d12);
        DrawLine(frame, x, y, x + width - 1, y, 0xffffd66b);
        DrawLine(frame, x, y + 42, x + width - 1, y + 42, 0xff2f74c9);
        string line1 = gateCheckpoint ? "TREKRONERS LÅS BRUTET" :
            admiralCheckpoint ? "AMIRALITETET BRUSTET" : "FREDERIK NULL BRUTEN";
        string line2 = gateCheckpoint ? "AMIRALITETET ÖPPNAS" :
            admiralCheckpoint ? "FREDERIK NULL ANLÄNDER" : "TULLKÄRNAN FLYR";
        DrawText(frame, x + (width - line1.Length * 6) / 2, y + 9, line1, 0xffffd66b);
        DrawText(frame, x + (width - line2.Length * 6) / 2, y + 26, line2, 0xff9bd4dc);
    }

    private void DrawCopenhagenMissionTitle(uint[] frame, int age)
    {
        if (age >= 210) return;
        int alphaAge = age < 30 ? age : Math.Min(30, 210 - age);
        if (alphaAge <= 0) return;
        int width = Math.Min(286, _width - 30);
        int x = (_width - width) / 2;
        int y = _height <= 224 ? 64 : 92;
        DrawRect(frame, x, y, width, 48, 0xdd080d12);
        DrawLine(frame, x, y, x + width - 1, y, 0xffffd66b);
        DrawText(frame, x + (width - 108) / 2, y + 10, "KÖPENHAMNS RING", 0xffffd66b);
        DrawText(frame, x + (width - 132) / 2, y + 27, "TREKRONERS LÅS", 0xff9bd4dc);
    }

    private void DrawSnapphaneWorld(uint[] frame)
    {
        Clear(frame, 0xff03090b);
        int age = _snapphaneWorld?.Age ?? 0;
        string backgroundName = _width <= 320 ? "snapphane_background" : "snapphane_background_wide";
        if (_sprites is not null && _sprites.TryGet(backgroundName, out Sprite background))
        {
            int scroll = (_missionFrame / 4) % background.Height;
            DrawSprite(frame, background, 0, scroll - background.Height);
            DrawSprite(frame, background, 0, scroll);
            DrawSnapphaneWreckSeaProps(frame, age);
        }
        else
        {
            for (int y = 17; y < _height - 12; y++)
            {
                int depth = y * 22 / Math.Max(1, _height);
                uint color = 0xff000000u |
                    ((uint)(4 + depth / 5) << 16) |
                    ((uint)(12 + depth) << 8) |
                    (uint)(15 + depth);
                DrawLine(frame, 0, y, _width - 1, y, color);
            }
            DrawStars(frame);
        }
        if (_snapphaneWorld is SnapphaneWorldState state)
        {
            for (int layer = 0; layer < 3; layer++)
            {
                foreach (SnapphaneWreck wreck in state.Wrecks)
                {
                    if (wreck.Layer == layer) DrawSnapphaneWreck(frame, wreck, age);
                }
            }
            foreach (SnapphaneBeacon beacon in state.Beacons) DrawSnapphaneBeacon(frame, beacon);
            foreach (SnapphaneScentMine mine in state.ScentMines) DrawSnapphaneScentMine(frame, mine);
            DrawSnapphaneRoute(frame, state);
            foreach (SnapphaneHunter hunter in state.Hunters) DrawSnapphaneHunter(frame, hunter);
            foreach (SnapphaneHuntShot shot in state.HuntShots) DrawSnapphaneHuntShot(frame, shot);
            DrawRedHoundsBoss(frame, state);
            DrawSorenDuel(frame, state);
        }
        DrawShots(frame);
        DrawShip(frame);
        DrawBorder(frame);
        DrawHud(frame);
        DrawLoadoutHud(frame);
        DrawSorenDuelHud(frame);
        DrawSnapphaneRouteHud(frame);
        DrawRedHoundsBossHud(frame);
        if ((_snapphaneWorld?.EnvironmentKills ?? 0) > 0)
            DrawText(frame, _width - 94, _height - 21, $"VILSELD {_snapphaneWorld!.EnvironmentKills}", 0xff77e6a0);
        DrawSnapphaneMissionTitle(frame);
        DrawRadio(frame);
        DrawStageClear(frame);
        DrawPause(frame);
        if (_gameOver)
        {
            int x = (_width - 168) / 2;
            int y = (_height - 42) / 2;
            DrawRect(frame, x, y, 168, 42, 0xdd090b10);
            DrawText(frame, x + 16, y + 10, "FLOTTAN FÖLL", 0xffff6b7f);
            DrawText(frame, x + 22, y + 26, "START ÅTERKALLAR", 0xffffd66b);
        }
    }

    private void DrawSnapphaneWreckSeaProps(uint[] frame, int age)
    {
        int travel = _height + 180;
        for (int index = 0; index < SnapphaneWreckSeaPropNames.Length; index++)
        {
            if (_sprites?.TryGet(SnapphaneWreckSeaPropNames[index], out Sprite prop) != true) continue;
            int lane = index % 4;
            int x = lane switch
            {
                0 => -prop.Width / 3,
                1 => Math.Max(4, _width / 5 - prop.Width / 2),
                2 => _width * 4 / 5 - prop.Width / 2,
                _ => _width - prop.Width * 2 / 3,
            };
            int speed = 1 + index % 3;
            int y = (index * 97 + age * speed / 5) % travel - 100;
            uint opacity = (uint)(index % 3 == 0 ? 92 : 122);
            DrawSpriteAlpha(frame, prop, x, y, opacity);
        }
    }

    private void DrawSnapphaneWreck(uint[] frame, SnapphaneWreck wreck, int age)
    {
        int x = (int)Math.Round(wreck.X);
        int y = (int)Math.Round(wreck.Y);
        int scale = wreck.Layer switch { 0 => 5, 1 => 9, _ => 14 };
        int sway = (int)Math.Round(Math.Sin((age + wreck.Phase) * 0.012) * (wreck.Layer + 1));
        x += sway;
        if (wreck.Physical && wreck.BurstAge > 0 &&
            _sprites?.TryGet("snapphane_wreck_burst", out Sprite burst) == true)
        {
            uint opacity = (uint)Math.Clamp(255 - wreck.BurstAge * 5, 35, 255);
            DrawSpriteAlpha(frame, burst, x - burst.Width / 2, y - burst.Height / 2, opacity);
            return;
        }
        if (wreck.Physical)
        {
            string asset = wreck.Kind switch
            {
                0 => "snapphane_wreck_bow",
                1 => "snapphane_wreck_mast",
                _ => "snapphane_wreck_broadside",
            };
            if (_sprites?.TryGet(asset, out Sprite sprite) == true)
            {
                DrawSprite(frame, sprite, x - sprite.Width / 2, y - sprite.Height / 2);
                return;
            }
        }
        else if (_sprites is not null)
        {
            int propIndex = Math.Abs(wreck.Kind * 3 + wreck.Phase / 19) % SnapphaneWreckSeaPropNames.Length;
            if (_sprites.TryGet(SnapphaneWreckSeaPropNames[propIndex], out Sprite debris))
            {
                int longestEdge = wreck.Layer == 0 ? 24 : 42;
                double ratio = longestEdge / (double)Math.Max(debris.Width, debris.Height);
                int width = Math.Max(8, (int)Math.Round(debris.Width * ratio));
                int height = Math.Max(8, (int)Math.Round(debris.Height * ratio));
                uint opacity = wreck.Layer == 0 ? 82u : 148u;
                DrawSpriteScaledAlpha(frame, debris, x - width / 2, y - height / 2, width, height, opacity);
                return;
            }
        }
        uint shadow = wreck.Layer switch { 0 => 0xff0c1718, 1 => 0xff142322, _ => 0xff1e2926 };
        uint edge = wreck.Layer switch { 0 => 0xff243131, 1 => 0xff465047, _ => 0xff725a3b };
        uint scar = wreck.Layer == 2 ? 0xff315b42 : 0xff263b35;

        switch (wreck.Kind)
        {
            case 0:
                FillTriangle(frame, x - scale, y, x + scale, y - scale / 2, x + scale / 2, y + scale / 2, shadow);
                DrawLine(frame, x - scale, y, x + scale, y - scale / 2, edge);
                DrawLine(frame, x - scale / 2, y - scale, x + scale / 3, y + scale / 2, edge);
                break;
            case 1:
                DrawRect(frame, x - scale, y - scale / 3, scale * 2, Math.Max(3, scale * 2 / 3), shadow);
                DrawLine(frame, x - scale, y - scale / 3, x + scale, y + scale / 3, edge);
                DrawLine(frame, x, y - scale, x, y + scale / 2, edge);
                break;
            case 2:
                FillTriangle(frame, x, y - scale, x - scale, y + scale / 2, x + scale, y + scale / 3, shadow);
                DrawLine(frame, x, y - scale, x - scale, y + scale / 2, edge);
                DrawLine(frame, x - scale / 2, y, x + scale / 2, y, scar);
                break;
            default:
                DrawRect(frame, x - scale / 2, y - scale, Math.Max(3, scale), scale * 2, shadow);
                DrawLine(frame, x - scale, y - scale / 2, x + scale, y + scale / 2, edge);
                DrawLine(frame, x + scale, y - scale / 2, x - scale, y + scale / 2, edge);
                break;
        }
        if (wreck.Layer == 2 && ((wreck.Phase / 17) & 1) == 0)
        {
            PutPixel(frame, x + scale / 3, y, scar);
        }
    }

    private void DrawSnapphaneBeacon(uint[] frame, SnapphaneBeacon beacon)
    {
        int x = (int)Math.Round(beacon.X);
        int y = (int)Math.Round(beacon.Y);
        string asset = beacon.State switch
        {
            SnapphaneBeaconState.Signal when beacon.TrueSignal => "snapphane_beacon_true",
            SnapphaneBeaconState.Signal => "snapphane_beacon_false",
            SnapphaneBeaconState.Revealed or SnapphaneBeaconState.Destroyed => "snapphane_beacon_revealed",
            _ => "snapphane_beacon_off",
        };
        if (_sprites?.TryGet(asset, out Sprite sprite) == true)
        {
            uint opacity = beacon.State == SnapphaneBeaconState.Destroyed
                ? (uint)Math.Clamp(230 - beacon.Age, 50, 230)
                : 255;
            DrawSpriteAlpha(frame, sprite, x - sprite.Width / 2, y - sprite.Height / 2, opacity);
            if (beacon.State == SnapphaneBeaconState.Destroyed && (beacon.Age / 4 & 1) == 0)
                PutPixel(frame, x + 9, y - 5, 0xffff8a4a);
            return;
        }
        bool lit = beacon.State == SnapphaneBeaconState.Signal;
        uint green = beacon.TrueSignal ? (lit ? 0xff77e6a0 : 0xff244936) : 0xffc92f42;
        DrawLine(frame, x - 11, y + 5, x, y - 4, 0xff3f4d45);
        DrawLine(frame, x, y - 4, x + 11, y + 5, 0xff3f4d45);
        DrawLine(frame, x - 8, y + 5, x + 8, y + 5, 0xff765139);
        DrawRect(frame, x - 2, y - 1, 5, 7, 0xff17221f);
        FillCircle(frame, x, y - 2, lit ? 2 : 1, green);
        if (lit)
        {
            PutPixel(frame, x - 5, y - 2, 0xff315b42);
            PutPixel(frame, x + 5, y - 2, 0xff315b42);
        }
    }

    private void DrawSnapphaneScentMine(uint[] frame, SnapphaneScentMine mine)
    {
        int x = (int)Math.Round(mine.X);
        int y = (int)Math.Round(mine.Y);
        if (mine.BurstAge == 0)
        {
            int pulse = mine.Turned ? 12 + mine.Age / 6 % 3 : 10 + mine.Age / 10 % 2;
            uint ring = mine.Turned ? 0xff65c5ca : 0xff8f2635;
            DrawCircleOutline(frame, x, y, pulse, ring);
            if (mine.Turned)
            {
                PutPixel(frame, x - pulse - 2, y, 0xffbdf8ff);
                PutPixel(frame, x + pulse + 2, y, 0xffbdf8ff);
            }
        }
        string asset = mine.BurstAge > 0 ? "snapphane_scent_mine_broken" :
            mine.Turned ? "snapphane_scent_mine_turned" : "snapphane_scent_mine";
        if (_sprites?.TryGet(asset, out Sprite sprite) == true)
        {
            DrawSprite(frame, sprite, x - sprite.Width / 2, y - sprite.Height / 2);
            return;
        }
        FillCircle(frame, x, y, 8, mine.Turned ? 0xff65c5ca : 0xff8f2635);
        DrawCircleOutline(frame, x, y, 9, 0xff765139);
    }

    private void DrawSnapphaneHunter(uint[] frame, SnapphaneHunter hunter)
    {
        int x = (int)Math.Round(hunter.X);
        int y = (int)Math.Round(hunter.Y);
        if (hunter.BurstAge > 0 && _sprites?.TryGet("snapphane_wreck_burst", out Sprite burst) == true)
        {
            DrawSpriteAlpha(frame, burst, x - burst.Width / 2, y - burst.Height / 2,
                (uint)Math.Clamp(255 - hunter.BurstAge * 6, 35, 255));
            return;
        }
        string asset = hunter.Elite ? "snapphane_route_elite_hunter" : "snapphane_hunter_skiff";
        if (_sprites?.TryGet(asset, out Sprite sprite) == true)
        {
            DrawSprite(frame, sprite, x - sprite.Width / 2, y - sprite.Height / 2);
            return;
        }
        FillTriangle(frame, x, y + 12, x - 16, y - 9, x + 16, y - 9, 0xff8f2635);
        DrawLine(frame, x - 13, y - 7, x + 13, y - 7, 0xfff4f1e8);
    }

    private void DrawSnapphaneHuntShot(uint[] frame, SnapphaneHuntShot shot)
    {
        int x = (int)Math.Round(shot.X);
        int y = (int)Math.Round(shot.Y);
        FillCircle(frame, x, y, 3, 0xffc92f42);
        PutPixel(frame, x, y, 0xffffffff);
        PutPixel(frame, x - Math.Sign(shot.Vx) * 3, y - Math.Sign(shot.Vy) * 3, 0xffff8a4a);
    }

    private void DrawSnapphaneRoute(uint[] frame, SnapphaneWorldState state)
    {
        if (!state.RouteStarted) return;
        if (state.RouteChoiceActive)
        {
            int center = _width / 2;
            int markerY = Math.Min(112, _height / 2);
            DrawRect(frame, 8, markerY - 22, center - 16, 44, 0xcc0b1514);
            DrawRect(frame, center + 8, markerY - 22, center - 16, 44, 0xcc160f0b);
            DrawLine(frame, 8, markerY - 22, center - 9, markerY - 22, 0xff77e6a0);
            DrawLine(frame, center + 8, markerY - 22, _width - 9, markerY - 22, 0xffff8a4a);
            if (_sprites?.TryGet("snapphane_rescue_buoy", out Sprite buoy) == true)
                DrawSpriteScaled(frame, buoy, center / 2 - 15, markerY - 18, 30, 32);
            if (_sprites?.TryGet("snapphane_route_press_left", out Sprite press) == true)
                DrawSpriteScaled(frame, press, center + center / 2 - 21, markerY - 18, 42, 36);
            DrawText(frame, 18, markerY + 9, "VÄNSTER  KAPARLED", 0xff77e6a0);
            DrawText(frame, center + 17, markerY + 9, "HÖGER  KRUTRÄNNA", 0xffff8a4a);
            return;
        }

        foreach (SnapphaneRescueShip rescue in state.Rescues)
        {
            if (state.RouteAge < rescue.Serial * 180 && !rescue.Rescued) continue;
            int x = (int)Math.Round(rescue.X);
            int y = (int)Math.Round(rescue.Y);
            string shipName = (rescue.Serial & 1) == 0 ? "snapphane_rescue_corvette" : "snapphane_rescue_cutter";
            if (_sprites?.TryGet(shipName, out Sprite ship) == true)
                DrawSprite(frame, ship, x - ship.Width / 2, y - ship.Height / 2);
            else
                FillTriangle(frame, x, y - 18, x - 16, y + 17, x + 16, y + 17, 0xff273b31);

            int buoyX = x + 24;
            int buoyY = y - 8;
            if (!rescue.Rescued)
            {
                bool channeling = DistanceSquared(_shipX, _shipY, rescue.X, rescue.Y) < 31 * 31;
                int pulse = 18 + (state.RouteAge / 8 & 1);
                DrawCircleOutline(frame, buoyX, buoyY, pulse, channeling ? 0xff77e6a0 : 0xffffd66b);
            }
            string buoyName = rescue.Rescued ? "snapphane_rescue_buoy_broken" : "snapphane_rescue_buoy";
            if ((!rescue.Rescued || rescue.FreedAge < 90) &&
                _sprites?.TryGet(buoyName, out Sprite buoy) == true)
                DrawSprite(frame, buoy, buoyX - buoy.Width / 2, buoyY - buoy.Height / 2);
            if (!rescue.Rescued)
            {
                DrawSorenPhysicalChain(frame, x + 8, y - 3, buoyX - 7, buoyY + 4);
                int progress = rescue.Progress * 34 / SnapphaneRescueShip.RequiredProgress;
                DrawRect(frame, x - 17, y + 27, 34, 4, 0xff26322e);
                DrawRect(frame, x - 17, y + 27, progress, 4, 0xff77e6a0);
            }
            else if (rescue.FreedAge < 90 &&
                _sprites?.TryGet("snapphane_route_release_pulse", out Sprite pulse) == true)
            {
                DrawSpriteAlpha(frame, pulse, buoyX - pulse.Width / 2, buoyY - pulse.Height / 2,
                    (uint)Math.Clamp(230 - rescue.FreedAge * 2, 35, 230));
            }
        }

        foreach (SnapphaneWreckPress press in state.Presses)
        {
            int y = (int)Math.Round(press.Y);
            int gap = _width <= 320 ? 62 : 76;
            int leftEdge = (int)Math.Round(press.GapX - gap / 2.0);
            int rightEdge = (int)Math.Round(press.GapX + gap / 2.0);
            if (_sprites?.TryGet("snapphane_route_press_left", out Sprite left) == true)
                DrawSprite(frame, left, leftEdge - left.Width, y - left.Height / 2);
            if (_sprites?.TryGet("snapphane_route_press_right", out Sprite right) == true)
                DrawSprite(frame, right, rightEdge, y - right.Height / 2);
            DrawSorenPhysicalChain(frame, 0, y, leftEdge - 52, y);
            DrawSorenPhysicalChain(frame, rightEdge + 52, y, _width - 1, y);
        }
    }

    private void DrawSnapphaneRouteHud(uint[] frame)
    {
        if (_snapphaneWorld is not { RouteStarted: true } state || state.RouteChoiceActive || state.RedHounds is not null) return;
        string text;
        uint color;
        if (state.Route == SnapphaneRoute.Kaparleden)
        {
            bool channeling = IsSnapphaneRescueChanneling();
            text = channeling
                ? $"BEFRIAR {state.SnapphaneAllies}/3  SÖREN TÄCKER"
                : state.ScentMines.Any(mine => mine.Turned && mine.BurstAge == 0)
                    ? "VÄND MINA LOCKAR JÄGARELD"
                    : $"SÖREN TÄCKER  BEFRIADE {state.SnapphaneAllies}/3";
            color = channeling ? 0xffffd66b : 0xff77e6a0;
        }
        else
        {
            text = $"KRUTRÄNNAN  BRUTNA FYRAR {state.RouteTargetsDestroyed}/3";
            color = 0xffff8a4a;
        }
        int width = Math.Min(_width - 20, text.Length * 6 + 16);
        int x = (_width - width) / 2;
        int y = _bossRadioCard is null ? 19 : 68;
        DrawRect(frame, x, y, width, 15, 0xdd07100f);
        DrawLine(frame, x, y, x + width - 1, y, color);
        DrawText(frame, x + 8, y + 4, text, color);
    }

    private void DrawRedHoundsBoss(uint[] frame, SnapphaneWorldState state)
    {
        if (state.RedHounds is not RedHoundsBossState boss) return;
        if (boss.Phase == 1) DrawRedHoundSearchCone(frame, boss);

        foreach (RedHoundChain chain in boss.Chains)
            DrawRedHoundChain(frame, boss, chain);

        foreach (RedHoundSupportBolt bolt in boss.SupportBolts)
        {
            double t = Math.Clamp(bolt.Age / 26.0, 0, 1);
            int x = (int)Math.Round(bolt.StartX + (bolt.TargetX - bolt.StartX) * t);
            int y = (int)Math.Round(bolt.StartY + (bolt.TargetY - bolt.StartY) * t);
            string asset = bolt.Soren ? "soren_copper_salvo" : "snapphane_route_release_pulse";
            if (_sprites?.TryGet(asset, out Sprite boltSprite) == true)
                DrawSpriteScaled(frame, boltSprite, x - 5, y - 6, 10, 12);
            else
                FillCircle(frame, x, y, 3, bolt.Soren ? 0xff77e6a0 : 0xffffd66b);
        }

        foreach (RedHoundShot shot in boss.Shots)
        {
            int x = (int)Math.Round(shot.X);
            int y = (int)Math.Round(shot.Y);
            int radius = shot.Style == 2 ? 5 : shot.Style == 1 ? 3 : 4;
            uint core = shot.Style == 2 ? 0xffffd66b : 0xff8f2635;
            uint edge = shot.Style == 1 ? 0xffffffff : 0xffff8a4a;
            FillCircle(frame, x, y, radius, core);
            DrawCircleOutline(frame, x, y, radius, edge);
            PutPixel(frame, x, y, 0xffffffff);
        }

        for (int index = 0; index < boss.Ships.Count; index++)
            DrawRedHoundShip(frame, boss, boss.Ships[index], index);

        DrawRedHoundMegaWeapon(frame, boss);

        int allies = Math.Min(3, state.SnapphaneAllies);
        for (int index = 0; index < allies; index++)
        {
            string asset = (index & 1) == 0 ? "snapphane_rescue_corvette" : "snapphane_rescue_cutter";
            int x = 34 + index * 22;
            int y = _height - 42 - index * 5;
            if (_sprites?.TryGet(asset, out Sprite ally) == true)
                DrawSpriteScaled(frame, ally, x - 12, y - 14, 24, 28);
        }
    }

    private void DrawRedHoundMegaWeapon(uint[] frame, RedHoundsBossState boss)
    {
        if (boss.Phase != 3 || !boss.MaskOpen || boss.VentHealth.All(health => health <= 0)) return;
        int cycle = (boss.PhaseAge - 400) % 270;
        RedHoundShip leader = boss.Ships[2];
        int originX = (int)Math.Round(leader.X);
        int originY = (int)Math.Round(leader.Y + 22);
        int targetX = (int)Math.Round(boss.MegaTargetX);
        int targetY = _height + 8;

        if (cycle < 108)
        {
            uint warning = cycle < 72 ? 0xff6b3526 : 0xffff8a4a;
            for (int y = originY + cycle % 5; y < _height; y += 7)
            {
                double t = (y - originY) / Math.Max(1.0, targetY - originY);
                int x = (int)Math.Round(originX + (targetX - originX) * t);
                FillCircle(frame, x, y, cycle < 72 ? 1 : 2, warning);
            }
            int chargeRadius = 5 + cycle / 18;
            DrawCircleOutline(frame, originX, originY, chargeRadius, warning);
            DrawCircleOutline(frame, originX, originY, Math.Max(3, chargeRadius - 4), 0xffffd66b);
            DrawLine(frame, targetX - 9, _height - 19, targetX + 9, _height - 19, warning);
            DrawLine(frame, targetX, _height - 25, targetX, _height - 13, warning);
            return;
        }
        if (cycle >= 154) return;

        int pulse = (cycle - 108) % 6;
        for (int offset = -7; offset <= 7; offset++)
        {
            uint color = Math.Abs(offset) <= 2
                ? (pulse < 3 ? 0xffffffff : 0xffffd66b)
                : (Math.Abs(offset) <= 5 ? 0xffff8a4a : 0xffc92f42);
            DrawLine(frame, originX + offset, originY, targetX + offset / 2, targetY, color);
        }
        FillCircle(frame, originX, originY, 11 + pulse / 2, 0xffff8a4a);
        FillCircle(frame, originX, originY, 6, 0xffffffff);
        for (int y = originY + 13; y < _height; y += 16)
        {
            double t = (y - originY) / Math.Max(1.0, targetY - originY);
            int x = (int)Math.Round(originX + (targetX - originX) * t);
            FillCircle(frame, x - 11 - pulse, y, 2, 0xffffd66b);
            FillCircle(frame, x + 11 + pulse, y + 6, 2, 0xffff8a4a);
        }
    }

    private void DrawRedHoundSearchCone(uint[] frame, RedHoundsBossState boss)
    {
        int cycle = boss.PhaseAge % 240;
        if (cycle <= 0 || cycle >= 150 || boss.SearchShip >= boss.Ships.Count) return;
        RedHoundShip source = boss.Ships[boss.SearchShip];
        double startY = source.Y + 17;
        double endY = _height - 18;
        uint color = cycle < 90 ? 0xff493a22 : 0xff8f4a2b;
        for (int y = (int)startY; y < endY; y += 4)
        {
            double t = (y - startY) / Math.Max(1, endY - startY);
            int center = (int)Math.Round(source.X + (boss.SearchTargetX - source.X) * t);
            int half = 3 + (int)(t * 22);
            for (int x = center - half; x <= center + half; x += 3) PutPixel(frame, x, y, color);
        }
        FillCircle(frame, (int)Math.Round(source.X), (int)Math.Round(source.Y + 16), 5,
            cycle < 90 ? 0xffffd66b : 0xffff8a4a);
    }

    private void DrawRedHoundChain(uint[] frame, RedHoundsBossState boss, RedHoundChain chain)
    {
        RedHoundShip left = boss.Ships[chain.LeftShip];
        RedHoundShip right = boss.Ships[chain.RightShip];
        if (!chain.Broken)
        {
            DrawRedHoundChainRange(frame, left.X, left.Y, right.X, right.Y, 0.08, 0.92, 255);
            return;
        }
        if (chain.BreakAge >= 75) return;
        double gap = Math.Min(0.34, chain.BreakAge / 220.0);
        uint opacity = (uint)Math.Clamp(230 - chain.BreakAge * 2, 60, 230);
        DrawRedHoundChainRange(frame, left.X, left.Y, right.X, right.Y, 0.08, 0.50 - gap, opacity);
        DrawRedHoundChainRange(frame, left.X, left.Y, right.X, right.Y, 0.50 + gap, 0.92, opacity);
    }

    private void DrawRedHoundChainRange(uint[] frame, double ax, double ay, double bx, double by,
        double start, double end, uint opacity)
    {
        if (end <= start) return;
        double dx = bx - ax;
        double dy = by - ay;
        int links = Math.Max(1, (int)(Math.Sqrt(dx * dx + dy * dy) * (end - start) / 10));
        for (int index = 0; index <= links; index++)
        {
            double t = start + (end - start) * index / links;
            int x = (int)Math.Round(ax + dx * t);
            int y = (int)Math.Round(ay + dy * t);
            if (_sprites?.TryGet("red_hound_chain_link", out Sprite link) == true)
                DrawSpriteScaledAlpha(frame, link, x - 5, y - 7, 10, 14, opacity);
            else
                DrawRect(frame, x - 3, y - 2, 7, 5, 0xff8f2635);
        }
    }

    private void DrawRedHoundShip(uint[] frame, RedHoundsBossState boss, RedHoundShip ship, int index)
    {
        bool damaged = boss.Phase >= 3 || boss.Phase == 4 || ship.CannonHealth <= 0 || boss.Health < 520;
        string asset = ship.Kind switch
        {
            RedHoundKind.Sporet => damaged ? "red_hound_sporet_damaged" : "red_hound_sporet",
            RedHoundKind.Biddet => damaged ? "red_hound_biddet_damaged" : "red_hound_biddet",
            _ => damaged ? "red_hound_koblet_damaged" : "red_hound_koblet",
        };
        int x = (int)Math.Round(ship.X);
        int y = (int)Math.Round(ship.Y);
        uint opacity = boss.Phase == 4
            ? (uint)Math.Clamp(255 - Math.Max(0, boss.DeathAge - index * 70) / 2, 45, 255)
            : 255;
        if (_sprites?.TryGet(asset, out Sprite sprite) == true)
            DrawSpriteAlpha(frame, sprite, x - sprite.Width / 2, y - sprite.Height / 2, opacity);
        else
            FillTriangle(frame, x, y + 25, x - 24, y - 22, x + 24, y - 22, 0xff8f2635);

        if (ship.CannonHealth > 0)
        {
            FillCircle(frame, x - 15, y + 10, 3, 0xffffd66b);
            FillCircle(frame, x + 15, y + 10, 3, 0xffffd66b);
        }
        if (ship.Kind == RedHoundKind.Koblet && boss.Phase == 3)
        {
            string maskAsset = boss.MaskOpen ? "red_hound_mask_open" : "red_hound_mask_closed";
            if (_sprites?.TryGet(maskAsset, out Sprite mask) == true)
                DrawSprite(frame, mask, x - mask.Width / 2, y - 4);
            if (boss.MaskOpen)
            {
                for (int vent = 0; vent < boss.VentHealth.Length; vent++)
                {
                    (double vx, double vy) = RedHoundVentPosition(ship, vent);
                    uint ventColor = boss.VentHealth[vent] > 0 ? 0xffff8a4a : 0xff29343a;
                    FillCircle(frame, (int)Math.Round(vx), (int)Math.Round(vy), 4, ventColor);
                    DrawCircleOutline(frame, (int)Math.Round(vx), (int)Math.Round(vy), 5, 0xffd6b25e);
                }
            }
        }
        if (boss.Phase == 4 && boss.DeathAge >= index * 70 && boss.DeathAge < index * 70 + 95 &&
            _sprites?.TryGet("snapphane_wreck_burst", out Sprite burst) == true)
            DrawSpriteScaledAlpha(frame, burst, x - 26, y - 24, 52, 48,
                (uint)Math.Clamp(255 - (boss.DeathAge - index * 70) * 2, 45, 255));
    }

    private void DrawRedHoundsBossHud(uint[] frame)
    {
        if (_snapphaneWorld?.RedHounds is not RedHoundsBossState boss || boss.Phase == 4) return;
        int width = Math.Min(270, _width - 22);
        int x = (_width - width) / 2;
        int y = _bossRadioCard is null ? 18 : 68;
        string phase = boss.Phase switch
        {
            1 => "DREVET",
            2 => "KOPPLET",
            _ when boss.DesperationAge > 0 => "SISTA BETTET",
            _ => "SISTA JAKTEN",
        };
        DrawRect(frame, x, y, width, 17, 0xee100b0b);
        DrawText(frame, x + 7, y + 3, $"DE RØDE HUNDE  {phase}", 0xfff4f1e8);
        DrawRect(frame, x + width - 106, y + 6, 98, 5, 0xff302326);
        DrawRect(frame, x + width - 106, y + 6,
            Math.Clamp(boss.Health, 0, RedHoundsBossState.MaxHealth) * 98 / RedHoundsBossState.MaxHealth,
            5, boss.Phase == 3 ? 0xffff8a4a : 0xffc92f42);
    }

    private void DrawSorenDuel(uint[] frame, SnapphaneWorldState state)
    {
        if (state.Duel is not SorenDuelState duel) return;
        foreach (SorenAfterimage afterimage in duel.Afterimages)
        {
            int x = (int)Math.Round(afterimage.X);
            int y = (int)Math.Round(afterimage.Y);
            if (_sprites?.TryGet("soren_duel_afterimage", out Sprite ghost) == true)
                DrawSpriteAlpha(frame, ghost, x - ghost.Width / 2, y - ghost.Height / 2,
                    (uint)Math.Clamp(150 - afterimage.Age * 3, 20, 150));
            else
                FillTriangle(frame, x, y - 20, x - 18, y + 18, x + 18, y + 18, 0xff121a18);
        }

        foreach (SorenChainHook hook in duel.Hooks)
        {
            if (hook.BrokenAge == 0) DrawSorenPhysicalChain(frame, duel.X, duel.Y + 9, hook.X, hook.Y);
            int x = (int)Math.Round(hook.X);
            int y = (int)Math.Round(hook.Y);
            if (_sprites?.TryGet("soren_chain_hook", out Sprite hookSprite) == true)
                DrawSpriteAlpha(frame, hookSprite, x - hookSprite.Width / 2, y - hookSprite.Height / 2,
                    hook.BrokenAge > 0 ? (uint)Math.Clamp(230 - hook.BrokenAge * 7, 30, 230) : 255);
            else
                FillCircle(frame, x, y, 8, hook.BrokenAge > 0 ? 0xff29343a : 0xff765139);
        }

        foreach (SorenCopperShot shot in duel.Shots)
        {
            int x = (int)Math.Round(shot.X);
            int y = (int)Math.Round(shot.Y);
            if (_sprites?.TryGet("soren_copper_salvo", out Sprite salvo) == true)
                DrawSprite(frame, salvo, x - salvo.Width / 2, y - salvo.Height / 2);
            else
                FillCircle(frame, x, y, 3, 0xffff8a4a);
        }

        int sorenX = (int)Math.Round(duel.X);
        int sorenY = (int)Math.Round(duel.Y);
        bool rescueCombat = duel.Phase == 3 && state.Route == SnapphaneRoute.Kaparleden && !state.RouteComplete;
        string asset = rescueCombat ? duel.DashAge > 0 ? "soren_duel_dash" : "soren_duel_ready" :
            duel.Phase == 3 ? "soren_duel_oath" :
            duel.Phase == 2 && duel.Hooks.Any(hook => hook.BrokenAge == 0) ? "soren_duel_hooks" :
            duel.DashAge > 0 ? "soren_duel_dash" : "soren_duel_ready";
        if (_sprites?.TryGet(asset, out Sprite ship) == true)
            DrawSprite(frame, ship, sorenX - ship.Width / 2, sorenY - ship.Height / 2);
        else
        {
            FillTriangle(frame, sorenX, sorenY - 25, sorenX - 22, sorenY + 22, sorenX + 22, sorenY + 22, 0xff202b27);
            DrawLine(frame, sorenX - 20, sorenY + 19, sorenX + 20, sorenY + 19, 0xff765139);
        }

        // Only the authoritative ship carries this lantern. Afterimages never receive it.
        FillCircle(frame, sorenX, sorenY + 2, 2, duel.HitFlash > 0 ? 0xffffffff : 0xff77e6a0);
        if (duel.Phase == 3 && duel.OathAge < 150 &&
            _sprites?.TryGet("soren_oath_pulse", out Sprite pulse) == true)
            DrawSpriteAlpha(frame, pulse, sorenX - pulse.Width / 2, sorenY - pulse.Height / 2,
                (uint)Math.Clamp(220 - duel.OathAge, 45, 220));
    }

    private void DrawSorenPhysicalChain(uint[] frame, double fromX, double fromY, double toX, double toY)
    {
        double dx = toX - fromX;
        double dy = toY - fromY;
        double length = Math.Max(1, Math.Sqrt(dx * dx + dy * dy));
        int links = Math.Min(32, (int)(length / 7));
        for (int index = 1; index < links; index++)
        {
            int x = (int)Math.Round(fromX + dx * index / links);
            int y = (int)Math.Round(fromY + dy * index / links);
            uint color = (index & 1) == 0 ? 0xff765139 : 0xff29343a;
            DrawRect(frame, x - 2, y - 1, 5, 3, color);
            PutPixel(frame, x, y, 0xffb18855);
        }
    }

