    private void DrawTitheWorld(uint[] frame)
    {
        Clear(frame, 0xff05090c);
        DrawTitheArchive(frame);
        DrawTitheRegisterRoute(frame);
        DrawTitheInterestWorks(frame);
        if (_titheWorld is TitheWorldState state)
        {
            foreach (TitheChainTarget chain in state.Chains) DrawTitheChainTarget(frame, chain);
            foreach (TitheCustomsGate gate in state.Gates) DrawTitheCustomsGate(frame, gate);
            foreach (TitheCoinMine mine in state.Mines) DrawTitheCoinMine(frame, mine);
            foreach (TitheSealWall wall in state.SealWalls) DrawTitheSealWall(frame, wall);
        }
        DrawTitheBoss(frame);
        DrawShots(frame);
        DrawEnemyShots(frame);
        DrawEnemies(frame);
        DrawShip(frame);
        DrawBorder(frame);
        DrawHud(frame);
        DrawLoadoutHud(frame);
        DrawTitheBossHud(frame);
        DrawTitheMissionTitle(frame);
        DrawRadio(frame);
        DrawStageClear(frame);
        DrawPause(frame);
        if (_titheWorld?.ChoosingUpgrade == true) DrawTitheUpgradePanel(frame);
        if (_gameOver)
        {
            int x = (_width - 168) / 2;
            int y = (_height - 42) / 2;
            DrawRect(frame, x, y, 168, 42, 0xdd090b10);
            DrawText(frame, x + 16, y + 10, "FLOTTAN FÖLL", 0xffff6b7f);
            DrawText(frame, x + 22, y + 26, "START ÅTERKALLAR", 0xffffd66b);
        }
    }

    private void DrawTitheArchive(uint[] frame)
    {
        if (_sprites?.TryGet("tithe_archive_background", out Sprite archive) == true)
        {
            int height = archive.Height * _width / Math.Max(1, archive.Width);
            int scroll = (_titheWorld?.Age / 3 ?? 0) % Math.Max(1, height);
            DrawSpriteScaled(frame, archive, 0, 17 - scroll, _width, height);
            DrawSpriteScaled(frame, archive, 0, 17 - scroll + height, _width, height);
            return;
        }
        DrawRect(frame, 0, 17, _width, _height - 29, 0xff080d11);
        int slow = _titheWorld?.Age / 4 ?? 0;
        for (int x = -24; x < _width + 28; x += 48)
        {
            int railX = x + slow % 48;
            DrawRect(frame, railX, 17, 7, _height - 29, 0xff111a20);
            DrawLine(frame, railX, 17, railX, _height - 13, 0xff4d402d);
            DrawLine(frame, railX + 6, 17, railX + 6, _height - 13, 0xff263a43);
            for (int y = 22 + slow % 18; y < _height - 14; y += 18)
                DrawRect(frame, railX - 2, y, 11, 3, 0xff715735);
        }
        int ledgerX = _width / 2;
        DrawRect(frame, ledgerX - 30, 17, 60, _height - 29, 0xff0c1419);
        DrawLine(frame, ledgerX - 30, 17, ledgerX - 30, _height - 13, 0xff8a6b38);
        DrawLine(frame, ledgerX + 29, 17, ledgerX + 29, _height - 13, 0xff8a6b38);
        for (int y = 27 - slow % 22; y < _height - 13; y += 22)
        {
            DrawRect(frame, ledgerX - 25, y, 50, 11, 0xff111d24);
            DrawLine(frame, ledgerX - 20, y + 3, ledgerX + 13, y + 3, 0xff35515b);
            DrawLine(frame, ledgerX - 20, y + 7, ledgerX + 20, y + 7, 0xff293c43);
            DrawRect(frame, ledgerX + 17, y + 2, 4, 6, 0xff9b743a);
        }
        for (int y = 35; y < _height - 18; y += 54)
        {
            DrawLine(frame, 0, y, _width - 1, y, 0xff17242b);
            DrawLine(frame, 0, y + 1, _width - 1, y + 1, 0xff0a1014);
        }
    }

    private void DrawTitheRegisterRoute(uint[] frame)
    {
        if (_titheWorld is not TitheWorldState state) return;
        if (state.RouteChoiceActive)
        {
            int center = _width / 2;
            if (_sprites?.TryGet("tithe_route_splitter", out Sprite splitter) == true)
                DrawSpriteAlpha(frame, splitter, center - splitter.Width / 2, 20, 225);
            DrawLine(frame, center - 3, 17, center - 3, _height - 13, 0xffffd66b);
            DrawLine(frame, center + 3, 17, center + 3, _height - 13, 0xff65c5ca);
            DrawLine(frame, 5, 17, 5, _height - 13, 0xff8a6b38);
            DrawLine(frame, _width - 6, 17, _width - 6, _height - 13, 0xff315b5d);
            for (int y = 30; y < _height - 20; y += 22)
            {
                FillTriangle(frame, center - 14, y, center - 5, y - 5, center - 5, y + 5, 0xffffd66b);
                FillTriangle(frame, center + 14, y, center + 5, y - 5, center + 5, y + 5, 0xff65c5ca);
            }
            if (_sprites?.TryGet("tithe_route_revision_emblem", out Sprite revision) == true)
                DrawSprite(frame, revision, center / 2 - revision.Width / 2, 137);
            if (_sprites?.TryGet("tithe_route_chainhall_emblem", out Sprite chainHall) == true)
                DrawSprite(frame, chainHall, center + center / 2 - chainHall.Width / 2, 137);
            int panelWidth = Math.Min(356, _width - 16);
            int panelX = (_width - panelWidth) / 2;
            DrawRect(frame, panelX, 62, panelWidth, 52, 0xee080d12);
            DrawLine(frame, panelX, 62, panelX + panelWidth - 1, 62, 0xff8a6b38);
            DrawLine(frame, panelX, 113, panelX + panelWidth - 1, 113, 0xff65c5ca);
            DrawText(frame, panelX + (panelWidth - 96) / 2, 69, "VÄLJ REGISTERLED", 0xffffffff);
            if (_sprites?.TryGet("tithe_route_revision_emblem", out revision) == true)
                DrawSpriteScaled(frame, revision, panelX + 9, 82, 28, 28);
            if (_sprites?.TryGet("tithe_route_chainhall_emblem", out chainHall) == true)
                DrawSpriteScaled(frame, chainHall, panelX + panelWidth / 2 + 8, 82, 28, 28);
            DrawText(frame, panelX + 43, 86, "REVISION", 0xffffd66b);
            DrawText(frame, panelX + panelWidth / 2 + 42, 86, "KEDJEHALL", 0xff9bd4dc);
            DrawText(frame, panelX + 20, 100, "MER POÄNG  MER RISK", 0xffff8a4a);
            DrawText(frame, panelX + panelWidth / 2 + 14, 100, "FLER SKEPP  MER TID", 0xff65c58a);
        }
        else if (state.RouteNoticeAge > 0 && state.Route != TitheRegisterRoute.None)
        {
            string route = state.Route == TitheRegisterRoute.Revision
                ? "REVISIONSRÄNNAN  BONUS 1500"
                : "KEDJEHALLEN  BEFRIA SKEPP";
            int width = Math.Min(_width - 20, route.Length * 6 + 18);
            int x = (_width - width) / 2;
            DrawRect(frame, x, 57, width, 19, 0xee080d12);
            DrawLine(frame, x, 57, x + width - 1, 57,
                state.Route == TitheRegisterRoute.Revision ? 0xffffd66b : 0xff65c5ca);
            DrawText(frame, x + 9, 64, route,
                state.Route == TitheRegisterRoute.Revision ? 0xffffd66b : 0xff65c58a);
        }
    }

    private void DrawTitheInterestWorks(uint[] frame)
    {
        if (_titheWorld is not TitheWorldState { InterestWorksActive: true } state || state.Age < 3_140) return;
        int pulse = state.Age / 8 & 1;
        uint piston = pulse == 0 ? 0xff8a6b38 : 0xffb48545;
        if (_sprites?.TryGet("tithe_interest_press", out Sprite press) == true)
        {
            DrawSpriteScaled(frame, press, -7, 20 + pulse * 2, 72, 74);
            DrawSpriteScaled(frame, press, _width - 65, 20 + pulse * 2, 72, 74);
        }
        else
        {
            DrawRect(frame, 0, 20, 34, 62, 0xff121b20);
            DrawRect(frame, _width - 34, 20, 34, 62, 0xff121b20);
            DrawRect(frame, 4, 29, 26, 31, 0xff29343a);
            DrawRect(frame, _width - 30, 29, 26, 31, 0xff29343a);
            DrawRect(frame, 12, 37, 10, 37 + pulse * 7, piston);
            DrawRect(frame, _width - 22, 37, 10, 37 + pulse * 7, piston);
            DrawCrown(frame, 15, 42, 0xffffd66b);
            DrawCrown(frame, _width - 19, 42, 0xffffd66b);
        }
        if (state.Age is >= 3_140 and < 3_290)
        {
            int width = Math.Min(220, _width - 20);
            int x = (_width - width) / 2;
            DrawRect(frame, x, 59, width, 34, 0xee080d12);
            DrawLine(frame, x, 59, x + width - 1, 59, 0xffffd66b);
            DrawText(frame, x + (width - 66) / 2, 67, "RÄNTEVERKET", 0xffffd66b);
            DrawText(frame, x + (width - 126) / 2, 81, "BRYT SIGILL ELLER PASSERA", 0xff9bd4dc);
        }
    }

    private void DrawTitheBoss(uint[] frame)
    {
        if (_titheWorld?.Boss is not TitheBossState boss) return;
        int x = (int)Math.Round(boss.X);
        int y = (int)Math.Round(boss.Y);
        if (_sprites?.TryGet("rigsregnskabet", out Sprite sprite) == true)
        {
            if (boss.Phase == 4)
            {
                int fade = Math.Max(0, 255 - boss.PhaseAge * 2);
                if (fade > 0)
                    DrawSpriteAlpha(frame, sprite, x - sprite.Width / 2, y - sprite.Height / 2, (uint)fade);
            }
            else
            {
                DrawSprite(frame, sprite, x - sprite.Width / 2, y - sprite.Height / 2);
            }
        }
        else
        {
            DrawRect(frame, x - 82, y - 56, 164, 102, 0xff182126);
            FillCircle(frame, x, y + 7, 28, 0xff244f52);
            FillCircle(frame, x, y + 7, 17, 0xff65c5ca);
            DrawRect(frame, x - 88, y - 12, 34, 58, 0xff56362b);
            DrawRect(frame, x + 54, y - 12, 34, 58, 0xff56362b);
            DrawLine(frame, x - 92, y - 18, x - 115, y + 54, 0xffd6b25e);
            DrawLine(frame, x + 92, y - 18, x + 115, y + 54, 0xffd6b25e);
        }

        if (boss.Phase is 2 or 3)
        {
            string ringName = boss.Phase == 2
                ? (boss.PhaseAge / 7 & 1) == 0 ? "rigs_power_amber_a" : "rigs_power_amber_b"
                : (boss.PhaseAge / 7 & 1) == 0 ? "rigs_power_cyan_a" : "rigs_power_cyan_b";
            if (_sprites?.TryGet(ringName, out Sprite powerRing) == true)
                DrawSpriteAlpha(frame, powerRing, x - powerRing.Width / 2,
                    y + 10 - powerRing.Height / 2, 225);
            else
            {
                int ring = 33 + (boss.PhaseAge / 4 % 9);
                DrawCircleOutline(frame, x, y + 10, ring, boss.Phase == 2 ? 0xffffd66b : 0xff65c5ca);
                DrawCircleOutline(frame, x, y + 10, ring + 12, 0xff8a6b38);
            }
        }
        if (boss.Phase == 3)
        {
            DrawTitheLedgerNodeAsset(frame, x - 58, y + 18, boss.LeftLedger, false);
            DrawTitheLedgerNodeAsset(frame, x + 58, y + 18, boss.RightLedger, true);
            bool coreExposed = boss.LeftLedger <= 0 && boss.RightLedger <= 0;
            string coreName = coreExposed ? "rigs_core_exposed" : "rigs_core_sealed";
            if (_sprites?.TryGet(coreName, out Sprite core) == true)
                DrawSpriteAlpha(frame, core, x - core.Width / 2, y + 12 - core.Height / 2,
                    coreExposed ? (uint)(220 + (boss.PhaseAge / 4 & 31)) : 230);
            else
                FillCircle(frame, x, y + 12, 12 + (boss.PhaseAge / 5 & 2),
                    coreExposed ? 0xffbdf8ff : 0xff315b5d);
        }
        if (boss.Phase == 4)
        {
            int deathFrame = boss.PhaseAge < 80 ? 0 : boss.PhaseAge < 160 ? 1 : boss.PhaseAge < 270 ? 2 : 3;
            if (_sprites?.TryGet($"rigs_death_{deathFrame}", out Sprite death) == true)
            {
                int fade = boss.PhaseAge <= 390 ? 255 : Math.Max(40, 255 - (boss.PhaseAge - 390) * 3);
                DrawSpriteAlpha(frame, death, x - death.Width / 2, y - death.Height / 2, (uint)fade);
            }
            else
            {
                for (int burst = 0; burst < 6; burst++)
                {
                    int bx = x - 70 + (burst * 31 + boss.PhaseAge * 3) % 140;
                    int by = y - 45 + (burst * 47 + boss.PhaseAge * 2) % 100;
                    int radius = 3 + (boss.PhaseAge / 4 + burst) % 8;
                    FillCircle(frame, bx, by, radius, (burst & 1) == 0 ? 0xffff8a4a : 0xffffd66b);
                }
            }
        }
    }

    private void DrawTitheLedgerNodeAsset(uint[] frame, int x, int y, int health, bool mirror)
    {
        string name = health > 0 ? "rigs_ledger_intact" : "rigs_ledger_broken";
        if (_sprites?.TryGet(name, out Sprite ledger) == true)
        {
            DrawSprite(frame, ledger, x - ledger.Width / 2, y - ledger.Height / 2);
            return;
        }
        DrawTitheLedgerNode(frame, x, y, health, mirror);
    }

    private void DrawTitheLedgerNode(uint[] frame, int x, int y, int health, bool mirror)
    {
        uint paper = health > 0 ? 0xffd8d2b8 : 0xff3b3028;
        DrawRect(frame, x - 13, y - 18, 26, 36, 0xff2a2520);
        DrawRect(frame, x - 9, y - 14, 18, 28, paper);
        for (int line = -9; line <= 9; line += 6)
            DrawLine(frame, x - 6, y + line, x + 6, y + line, health > 0 ? 0xff765139 : 0xff1a1513);
        DrawRect(frame, mirror ? x + 9 : x - 12, y - 17, 3, 34, 0xff8f2635);
        if (health <= 0) DrawLine(frame, x - 11, y - 15, x + 11, y + 15, 0xffff8a4a);
    }

    private void DrawTitheBossHud(uint[] frame)
    {
        if (_titheWorld?.Boss is not TitheBossState boss || boss.Phase == 4) return;
        int y = _bossRadioCard is null ? 18 : 68;
        int width = Math.Min(272, _width - 20);
        int x = (_width - width) / 2;
        DrawRect(frame, x, y, width, 17, 0xee080d12);
        DrawText(frame, x + 7, y + 4, "RIGSREGNSKABET", 0xffd8e6f0);
        int barX = x + 105;
        int barWidth = width - 113;
        DrawRect(frame, barX, y + 6, barWidth, 5, 0xff263036);
        int health = boss.Phase == 1
            ? Math.Max(0, boss.LeftArmor) + Math.Max(0, boss.RightArmor)
            : boss.Phase == 3 && (boss.LeftLedger > 0 || boss.RightLedger > 0)
                ? Math.Max(0, boss.LeftLedger) + Math.Max(0, boss.RightLedger)
                : Math.Max(0, boss.Health);
        int maximum = boss.Phase switch
        {
            1 => TitheBossState.ArmorHealth * 2,
            3 when boss.LeftLedger > 0 || boss.RightLedger > 0 => TitheBossState.LedgerHealth * 2,
            3 => TitheBossState.PhaseThreeHealth,
            _ => TitheBossState.MaxHealth - TitheBossState.PhaseThreeHealth,
        };
        if (boss.Phase == 2) health = Math.Max(0, boss.Health - TitheBossState.PhaseThreeHealth);
        DrawRect(frame, barX, y + 6, Math.Clamp(health, 0, maximum) * barWidth / Math.Max(1, maximum), 5,
            boss.Phase == 1 ? 0xff8f2635 : boss.Phase == 2 ? 0xffffd66b : 0xff65c5ca);
    }

    private void DrawTitheSealWall(uint[] frame, TitheSealWall wall)
    {
        int y = (int)Math.Round(wall.Y);
        int segmentWidth = (_width + TitheSealWall.SegmentCount - 1) / TitheSealWall.SegmentCount;
        for (int segment = 0; segment < TitheSealWall.SegmentCount; segment++)
        {
            if (wall.Health[segment] <= 0) continue;
            int x = segment * segmentWidth;
            int width = Math.Min(segmentWidth - 2, _width - x);
            string sealName = wall.Health[segment] >= TitheSealWall.SegmentHealth
                ? "tithe_seal_segment_intact"
                : wall.Health[segment] > TitheSealWall.SegmentHealth / 2
                    ? "tithe_seal_segment_damaged"
                    : "tithe_seal_segment_critical";
            if (_sprites?.TryGet(sealName, out Sprite seal) == true)
                DrawSpriteScaled(frame, seal, x, y - 11, width, 22);
            else if (wall.Health[segment] >= TitheSealWall.SegmentHealth &&
                _sprites?.TryGet("tithe_seal_segment", out Sprite legacySeal) == true)
                DrawSpriteScaled(frame, legacySeal, x, y - 11, width, 22);
            else
            {
                uint plate = wall.Health[segment] < TitheSealWall.SegmentHealth / 2 ? 0xff59312c : 0xff8f2635;
                DrawRect(frame, x, y - 8, width, 16, plate);
                DrawLine(frame, x, y - 9, x + width - 1, y - 9, 0xffffd66b);
                DrawLine(frame, x, y + 8, x + width - 1, y + 8, 0xff432026);
                FillCircle(frame, x + width / 2, y, 5, 0xffd6b25e);
                DrawCrown(frame, x + width / 2 - 2, y - 2, 0xff35191c);
            }
        }
    }

    private void DrawTitheChainTarget(uint[] frame, TitheChainTarget chain)
    {
        int x = (int)Math.Round(chain.X);
        int y = (int)Math.Round(chain.Y);
        int lockY = y - 31;
        if (!chain.Freed)
        {
            for (int linkY = 17; linkY < lockY - 4; linkY += 7)
            {
                uint link = (linkY / 7 & 1) == 0 ? 0xffa37b42 : 0xff52636a;
                DrawRect(frame, x - 2, linkY, 4, 5, link);
                PutPixel(frame, x - 3, linkY + 2, 0xff20292d);
            }
            DrawLine(frame, x, lockY + 5, x - 16, y - 5, 0xff8a6b38);
            DrawLine(frame, x, lockY + 5, x + 16, y - 5, 0xff8a6b38);
            if (_sprites?.TryGet("tithe_chain_lock", out Sprite chainLock) == true)
                DrawSpriteScaled(frame, chainLock, x - 17, lockY - 20, 34, 43);
            else
            {
                DrawRect(frame, x - 7, lockY - 5, 14, 12, 0xff1d292e);
                DrawRect(frame, x - 4, lockY - 2, 8, 7, 0xff9b743a);
                FillCircle(frame, x, lockY + 1, 2, 0xff9bd4dc);
            }
        }
        string spriteName = chain.Kind == 0 ? "player" : "fogde_sloop";
        if (_sprites?.TryGet(spriteName, out Sprite captive) == true)
        {
            int width = chain.Kind == 0 ? 38 : 34;
            int height = chain.Kind == 0 ? 48 : 42;
            DrawSpriteScaled(frame, captive, x - width / 2, y - height / 2, width, height);
        }
        else
        {
            uint hull = chain.Kind == 0 ? 0xff315e88 : 0xff7b2a32;
            FillTriangle(frame, x, y - 18, x - 14, y + 15, x + 14, y + 15, hull);
            DrawRect(frame, x - 4, y - 9, 8, 21, 0xff9b743a);
        }
        if (!chain.Freed && chain.Health < TitheChainTarget.MaxHealth)
        {
            DrawRect(frame, x - 14, y + 24, 28, 3, 0xff202a30);
            DrawRect(frame, x - 14, y + 24, Math.Max(0, chain.Health) * 28 / TitheChainTarget.MaxHealth,
                3, 0xff65c5ca);
        }
        if (chain.Freed && chain.FreedAge < 45)
            DrawText(frame, x - 12, y + 24, "FRI", 0xff65c58a);
    }

    private void DrawTitheCustomsGate(uint[] frame, TitheCustomsGate gate)
    {
        int y = (int)Math.Round(gate.Y);
        int openingHalf = _width <= 320 ? 34 : 42;
        int leftEnd = gate.OpeningX - openingHalf;
        int rightStart = gate.OpeningX + openingHalf;
        bool warning = gate.Age <= TitheCustomsGate.WarningFrames;
        uint iron = warning ? 0xff33434a : 0xff151d22;
        uint edge = warning && (gate.Age / 6 & 1) == 0 ? 0xffffd66b : 0xff8a6b38;
        uint signal = warning ? 0xffff6b62 : 0xff65c5ca;
        if (warning) y = 43;

        bool hasWarningArch = false;
        if (warning && _sprites?.TryGet("tithe_customs_warning_arch", out Sprite warningArch) == true)
        {
            DrawSpriteScaled(frame, warningArch, gate.OpeningX - 42, 18, 84, 58);
            hasWarningArch = true;
        }

        if (_sprites?.TryGet("tithe_customs_gate", out Sprite customsGate) == true)
        {
            DrawSpriteScaled(frame, customsGate, 0, y - 15, Math.Max(0, leftEnd), 30);
            DrawSpriteScaled(frame, customsGate, rightStart, y - 15, Math.Max(0, _width - rightStart), 30);
        }
        else
        {
            DrawRect(frame, 0, y - 6, Math.Max(0, leftEnd), 13, iron);
            DrawRect(frame, rightStart, y - 6, Math.Max(0, _width - rightStart), 13, iron);
        }
        DrawLine(frame, 0, y - 7, leftEnd, y - 7, edge);
        DrawLine(frame, rightStart, y - 7, _width - 1, y - 7, edge);
        DrawLine(frame, 0, y + 7, leftEnd, y + 7, edge);
        DrawLine(frame, rightStart, y + 7, _width - 1, y + 7, edge);
        for (int x = 5; x < leftEnd; x += 12)
            FillTriangle(frame, x, y - 5, x + 5, y, x, y + 5, 0xff52636a);
        for (int x = rightStart + 5; x < _width; x += 12)
            FillTriangle(frame, x, y - 5, x + 5, y, x, y + 5, 0xff52636a);
        DrawRect(frame, leftEnd - 4, y - 10, 4, 21, signal);
        DrawRect(frame, rightStart, y - 10, 4, 21, signal);
        if (warning)
        {
            DrawLine(frame, gate.OpeningX, y + 12, gate.OpeningX, _height - 20, 0xff35515b);
            DrawText(frame, Math.Clamp(gate.OpeningX - 31, 4, _width - 66),
                hasWarningArch ? y + 34 : y + 15, "TULLPASS", 0xffffd66b);
        }
    }

    private void DrawTitheCoinMine(uint[] frame, TitheCoinMine mine)
    {
        int x = (int)Math.Round(mine.X);
        int y = (int)Math.Round(mine.Y);
        uint rim = mine.Reflected ? 0xff65c5ca : 0xffb48545;
        uint core = mine.Reflected ? 0xffbdf8ff :
            mine.ChargeAge > TitheCoinMine.FuseFrames - 18 && (mine.ChargeAge / 3 & 1) == 0
                ? 0xffff6b62 : 0xffffd66b;
        if (_sprites?.TryGet("tithe_coin_mine", out Sprite coinMine) == true)
            DrawSpriteScaled(frame, coinMine, x - 13, y - 13, 26, 26);
        else
        {
            FillCircle(frame, x, y, 9, 0xff1a2429);
            FillCircle(frame, x, y, 7, rim);
            FillCircle(frame, x, y, 4, 0xff44351f);
            DrawCrown(frame, x - 2, y - 2, core);
            for (int spoke = 0; spoke < 4; spoke++)
            {
                int dx = spoke % 2 == 0 ? (spoke == 0 ? -13 : 13) : 0;
                int dy = spoke % 2 != 0 ? (spoke == 1 ? -13 : 13) : 0;
                DrawLine(frame, x + Math.Sign(dx) * 7, y + Math.Sign(dy) * 7, x + dx, y + dy, rim);
            }
        }
        if (!mine.Reflected && mine.ChargeAge > 0)
        {
            int radius = 12 + mine.ChargeAge * 10 / TitheCoinMine.FuseFrames;
            DrawCircleOutline(frame, x, y, radius, core);
        }
        if (mine.Reflected)
            DrawText(frame, x - 12, y + 14, "RETUR", 0xff65c58a);
    }

    private void DrawTitheMissionTitle(uint[] frame)
    {
        int age = _titheWorld?.Age ?? 0;
        if (age < 15 || age >= 165) return;
        int edge = Math.Min(age - 14, 165 - age);
        int y = 73 - Math.Min(12, edge);
        int width = Math.Min(276, _width - 18);
        int x = (_width - width) / 2;
        DrawRect(frame, x, y, width, 39, 0xff080f14);
        DrawLine(frame, x, y, x + width - 1, y, 0xff8a6b38);
        DrawLine(frame, x, y + 38, x + width - 1, y + 38, 0xff65c5ca);
        DrawText(frame, x + (width - 132) / 2, y + 8, "DET HÄNGANDE REGISTRET", 0xffffd66b);
        DrawText(frame, x + (width - 120) / 2, y + 22, "FOGDENS TIONDE VÄRLD", 0xff9bd4dc);
    }

    private void DrawLoadoutHud(uint[] frame)
    {
        if (_activeLoadout is not StormaktLoadout state) return;
        if (state.PrimaryModule != TithePrimaryModule.Standard)
        {
            string primary = state.PrimaryModule == TithePrimaryModule.CrownDrill ? "Z KRONBORR" : "Z SALVDIR";
            DrawRect(frame, 4, _height - 25, primary.Length * 6 + 8, 11, 0xdd081019);
            DrawText(frame, 8, _height - 23, primary, 0xff65c5ca);
        }
        if (state.BroadsideModule != TitheBroadsideModule.Standard)
        {
            string broadside = state.BroadsideModule == TitheBroadsideModule.MagnetBroadside ? "X MAGNET" : "X KEDJEKART";
            DrawRect(frame, 4, _height - 37, broadside.Length * 6 + 8, 11, 0xdd081019);
            DrawText(frame, 8, _height - 35, broadside, 0xffffd66b);
        }
        if (state.ShipModule != TitheShipModule.Standard)
        {
            string ship = state.ShipModule == TitheShipModule.SilverCooler ? "SILVERKYLARE" :
                state.ArmorCharge > 0 ? "BESLAGSSKÖLD 1" : "BESLAGSSKÖLD 0";
            DrawRect(frame, 4, _height - 49, ship.Length * 6 + 8, 11, 0xdd081019);
            DrawText(frame, 8, _height - 47, ship, 0xff9bd4dc);
        }
    }

    private void DrawTitheUpgradePanel(uint[] frame)
    {
        if (_titheWorld is not TitheWorldState state) return;
        int width = Math.Min(360, _width - 16);
        int height = _height <= 224 ? 126 : 142;
        int x = (_width - width) / 2;
        int y = (_height - height) / 2;
        if (_sprites?.TryGet("tithe_upgrade_cabinet", out Sprite cabinet) == true)
            DrawSpriteScaled(frame, cabinet, _width / 2 - 31, y - 58, 62, 78);
        DrawRect(frame, x, y, width, height, 0xf5080d12);
        DrawLine(frame, x, y, x + width - 1, y, 0xffffd66b);
        DrawLine(frame, x, y + height - 1, x + width - 1, y + height - 1, 0xff65c5ca);
        bool broadside = state.UpgradeChoice == TitheUpgradeChoice.Broadside;
        bool shipChoice = state.UpgradeChoice == TitheUpgradeChoice.Ship;
        string title = shipChoice ? "VÄLJ SKEPPSSYSTEM" : broadside ? "VÄLJ X-MEKANISM" : "VÄLJ Z-MEKANISM";
        DrawText(frame, x + (width - title.Length * 6) / 2, y + 8, title, 0xffffd66b);
        int gap = 6;
        int cardWidth = (width - 24 - gap) / 2;
        int cardY = y + 24;
        int cardHeight = height - 48;
        DrawTitheUpgradeCard(frame, x + 9, cardY, cardWidth, cardHeight, 0, state);
        DrawTitheUpgradeCard(frame, x + 9 + cardWidth + gap, cardY, cardWidth, cardHeight, 1, state);
        DrawText(frame, x + 10, y + height - 15, "V H VÄLJ  Z ELLER ENTER INSTALLERA  X DETALJ", 0xffb7c7d6);
    }

    private void DrawTitheUpgradeCard(uint[] frame, int x, int y, int width, int height, int index,
        TitheWorldState state)
    {
        bool selected = state.UpgradeSelection == index;
        bool broadside = state.UpgradeChoice == TitheUpgradeChoice.Broadside;
        bool shipChoice = state.UpgradeChoice == TitheUpgradeChoice.Ship;
        uint border = selected ? 0xffffd66b : 0xff344d5c;
        DrawRect(frame, x, y, width, height, selected ? 0xff172536 : 0xff0d151d);
        DrawLine(frame, x, y, x + width - 1, y, border);
        DrawLine(frame, x, y + height - 1, x + width - 1, y + height - 1, border);
        DrawLine(frame, x, y, x, y + height - 1, border);
        DrawLine(frame, x + width - 1, y, x + width - 1, y + height - 1, border);
        if (shipChoice)
            DrawTitheShipSystemIcon(frame, x + width / 2, y + 19,
                index == 0 ? TitheShipModule.SilverCooler : TitheShipModule.SeizureArmor);
        else if (broadside)
            DrawTitheBroadsideIcon(frame, x + width / 2, y + 19,
                index == 0 ? TitheBroadsideModule.MagnetBroadside : TitheBroadsideModule.ChainCanister);
        else
            DrawTitheModuleIcon(frame, x + width / 2, y + 19,
                index == 0 ? TithePrimaryModule.CrownDrill : TithePrimaryModule.VolleyDirector);
        string name = shipChoice ? index == 0 ? "SILVERKYLARE" : "BESLAGSPANSAR"
            : broadside ? index == 0 ? "MAGNETBREDSIDA" : "KEDJEKARTESCH"
            : index == 0 ? "KRONBORREN" : "SALVDIREKTÖREN";
        string stat = shipChoice ? index == 0 ? "KYLNING 03" : "SKÖLDSEGMENT 01"
            : broadside ? index == 0 ? "VÄNDER LÄTTA" : "FEM SKOTT 08"
            : index == 0 ? "CENTRUMBULT 07" : "TRE SKOTT 02";
        string interval = shipChoice ? index == 0 ? "EFTER PAUS 18" : "ÅTERSTÄLLS SEKTOR"
            : broadside ? index == 0 ? "INTERVALL 26" : "INTERVALL 30"
            : index == 0 ? "INTERVALL 09" : "INTERVALL 04";
        DrawText(frame, x + 7, y + 35, name, selected ? 0xffffd66b : 0xff9bd4dc);
        DrawText(frame, x + 7, y + 49, stat, 0xffdce8f2);
        DrawText(frame, x + 7, y + 61, interval, 0xff65c58a);
        if (state.ShowUpgradeDetails && height >= 90)
            DrawText(frame, x + 7, y + 73, shipChoice
                ? index == 0 ? "- INGEN SKÖLD" : "- LÅNGSAM KYLNING"
                : broadside
                ? index == 0 ? "- HÖG VÄRME" : "- VÄNDER INGET"
                : index == 0 ? "- LÅNGSAM" : "- SPRIDNING", 0xffff6b7f);
        else if (height >= 86)
            DrawText(frame, x + 7, y + 73, shipChoice
                ? index == 0 ? "VÄRME NER 03" : "SKÖLD LADDA 01"
                : broadside
                ? index == 0 ? "VÄRME 24" : "VÄRME 20"
                : index == 0 ? "VÄRME 11" : "VÄRME 09", 0xffb7c7d6);
    }

    private void DrawTitheShipSystemIcon(uint[] frame, int x, int y, TitheShipModule module)
    {
        string name = module == TitheShipModule.SilverCooler
            ? "tithe_module_silver_cooler" : "tithe_module_seizure_armor";
        if (_sprites?.TryGet(name, out Sprite generated) == true)
        {
            DrawSpriteScaled(frame, generated, x - 19, y - 11, 38, 22);
            return;
        }
        if (module == TitheShipModule.SilverCooler)
        {
            DrawLine(frame, x - 12, y + 7, x - 4, y - 9, 0xff65c5ca);
            DrawLine(frame, x - 5, y + 8, x, y - 10, 0xffbdf8ff);
            DrawLine(frame, x + 5, y + 8, x + 10, y - 8, 0xff65c5ca);
            PutPixel(frame, x, y + 10, 0xffffffff);
        }
        else
        {
            FillTriangle(frame, x, y + 11, x - 12, y - 7, x + 12, y - 7, 0xff52636a);
            FillTriangle(frame, x, y + 6, x - 7, y - 4, x + 7, y - 4, 0xff17232a);
            DrawCrown(frame, x - 2, y - 3, 0xffffd66b);
        }
    }

    private void DrawTitheBroadsideIcon(uint[] frame, int x, int y, TitheBroadsideModule module)
    {
        string name = module == TitheBroadsideModule.MagnetBroadside
            ? "tithe_module_magnet_broadside" : "tithe_module_chain_canister";
        if (_sprites?.TryGet(name, out Sprite generated) == true)
        {
            DrawSpriteScaled(frame, generated, x - 20, y - 10, 40, 20);
            return;
        }
        if (module == TitheBroadsideModule.MagnetBroadside)
        {
            DrawCircleOutline(frame, x, y, 10, 0xff65c5ca);
            DrawCircleOutline(frame, x, y, 6, 0xffbdf8ff);
            DrawLine(frame, x - 15, y, x - 7, y, 0xffffd66b);
            DrawLine(frame, x + 7, y, x + 15, y, 0xffffd66b);
        }
        else
        {
            for (int offset = -2; offset <= 2; offset++)
                DrawLine(frame, x, y + 8, x + offset * 7, y - 9, offset == 0 ? 0xffffec9a : 0xffffd66b);
            DrawRect(frame, x - 8, y + 7, 16, 4, 0xff52636a);
        }
    }

    private void DrawTitheModuleIcon(uint[] frame, int x, int y, TithePrimaryModule module)
    {
        string name = module == TithePrimaryModule.CrownDrill
            ? "tithe_module_crown_drill" : "tithe_module_volley_director";
        if (_sprites?.TryGet(name, out Sprite generated) == true)
        {
            DrawSpriteScaled(frame, generated, x - 10, y - 12, 20, 24);
            return;
        }
        uint brass = 0xffd6b25e;
        uint cyan = 0xff65c5ca;
        if (module == TithePrimaryModule.CrownDrill)
        {
            FillTriangle(frame, x, y - 11, x - 7, y + 7, x + 7, y + 7, brass);
            DrawRect(frame, x - 2, y - 8, 4, 17, cyan);
            DrawCrown(frame, x - 2, y + 3, 0xffffd66b);
        }
        else
        {
            DrawRect(frame, x - 10, y - 5, 20, 10, 0xff293c43);
            DrawLine(frame, x - 10, y - 7, x + 10, y - 7, brass);
            FillCircle(frame, x - 7, y + 7, 2, cyan);
            FillCircle(frame, x, y + 7, 2, cyan);
            FillCircle(frame, x + 7, y + 7, 2, cyan);
        }
    }

    private void DrawStageClear(uint[] frame)
    {
        if (!_stageClear)
        {
            return;
        }
        int panelX = (_width - 196) / 2;
        if (_levelId == 1)
        {
            DrawGlimmingeResultWreck(frame, panelX + 196, 67);
        }
        else if (_levelId == 2 && _bossRadioCard is null)
        {
            DrawOresundResultCrown(frame, panelX + 196, 67);
        }
        else if (_levelId == 3)
        {
            DrawRtsVictorySilver(frame, panelX + 196, 67);
        }
        else if (_levelId == 4)
        {
            DrawTitheModuleIcon(frame, panelX + 196, 67,
                _activeLoadout?.PrimaryModule ?? TithePrimaryModule.Standard);
        }
        else if (_levelId == 5)
        {
            DrawSnapphaneOathSeal(frame, panelX + 196, 67);
        }
        else if (_levelId == 6)
        {
            DrawCopenhagenSuperSeal(frame, panelX + 196, 67);
        }
        else
        {
            DrawSnapphaneSilhouette(frame, panelX + 196, 67);
        }
        int reveal = Math.Min(150, _stageClearAge);
        int width = 196 * reveal / 150;
        DrawRect(frame, panelX, 86, width, 45, 0xff080d12);
        if (_stageClearAge >= 45)
        {
            DrawLine(frame, panelX, 86, panelX + 195, 86, 0xffd6b25e);
            DrawLine(frame, panelX, 130, panelX + 195, 130, 0xff2f74c9);
            if (_levelId == 1)
            {
                DrawText(frame, panelX + 39, 99, "SKUGGORNA SVARAR", 0xffffd66b);
                DrawText(frame, panelX + 42, 116, "SIGNALEN FUNNEN", 0xff65c58a);
            }
            else if (_levelId == 2)
            {
                DrawText(frame, panelX + 37, 99, "JÄRNKRONAN BRUTEN", 0xffffd66b);
                DrawText(frame, panelX + 38, 116, "MOT SILVERKROPPEN", 0xff65c58a);
            }
            else if (_levelId == 3)
            {
                DrawText(frame, panelX + 42, 99, "UNDER SILVERÅDERN", 0xffffd66b);
                DrawText(frame, panelX + 34, 116, "NEDSTIGNING VÄNTAR", 0xff65c58a);
            }
            else if (_levelId == 4)
            {
                DrawText(frame, panelX + 31, 99, "RIGSREGNSKABET BRUTET", 0xffffd66b);
                if (_titheWorld?.Route == TitheRegisterRoute.Revision)
                    DrawText(frame, panelX + 37, 116, "KAMPANJKIT SPARAT", 0xffff8a4a);
                else
                    DrawText(frame, panelX + 42, 116, $"FLOTTA {_titheWorld?.FreedShips ?? 0} SKEPP FRI", 0xff65c58a);
            }
            else if (_levelId == 5)
            {
                DrawText(frame, panelX + 33, 99, "DE RØDE HUNDE BRUTNA", 0xffffd66b);
                if (_snapphaneWorld?.Route == SnapphaneRoute.Kaparleden)
                    DrawText(frame, panelX + 45, 116, $"ALLIERADE {_snapphaneWorld.SnapphaneAllies}/3", 0xff77e6a0);
                else
                    DrawText(frame, panelX + 45, 116, $"KRUTBONUS {_snapphaneWorld?.KrutBonus ?? 0}", 0xffff8a4a);
            }
            else if (_levelId == 6)
            {
                DrawText(frame, panelX + 31, 99, "SUPERFREGATTEN BRUTEN", 0xffffd66b);
                DrawText(frame, panelX + 28, 116, "HOLMENS LANDNING VÄNTAR", 0xff9bd4dc);
            }
            else
            {
                DrawText(frame, panelX + 51, 99, "BÄLTET ÄR ÖPPET", 0xffffd66b);
                DrawText(frame, panelX + 39, 116, "KRONARKIV SÄKRAT", 0xff9bd4dc);
            }
        }
    }

